#include <iostream>
#include <vector>
#include <algorithm> // Required for std::sort

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<int> b(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Sort both arrays.
    // The problem statement guarantees that an answer always exists.
    // A simple strategy that works is to sort both arrays and pair them up.
    // If a_i and b_i are sorted, then a_i + b_i will also be sorted
    // (or at least strictly increasing if all a_i and b_i are distinct and positive).
    // Since all a_i are distinct and all b_i are distinct, and they are positive,
    // sorting both arrays and pairing them will result in distinct sums.
    // For example, if a_i < a_{i+1} and b_i < b_{i+1}, then
    // a_i + b_i < a_{i+1} + b_i < a_{i+1} + b_{i+1}.
    // This ensures that the sums are strictly increasing and thus distinct.
    std::sort(a.begin(), a.end());
    std::sort(b.begin(), b.end());

    // Print the sorted 'a' array as the necklaces for daughters.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    // Print the sorted 'b' array as the bracelets for daughters.
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

