#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reversed permutation will always have the same fingerprint.
    // We need to ensure it's a different permutation.
    // A permutation is different from its reverse if it's not a palindrome.
    // If p is a palindrome, p_i = p_{n-1-i} for all i.
    // For example, [1, 2, 1] is a palindrome.
    // However, a permutation of length n consists of distinct integers from 1 to n.
    // If n > 1, a permutation cannot be a palindrome.
    // For example, if n=2, p=[1,2]. Reversed is [2,1]. Different.
    // If n=3, p=[1,2,3]. Reversed is [3,2,1]. Different.
    // If p_i = p_{n-1-i} for all i, then p_0 = p_{n-1}, p_1 = p_{n-2}, etc.
    // But all elements must be distinct.
    // So, p_0 must be different from p_{n-1} unless n=1 (which is not allowed, n>=2).
    // Thus, p is always different from its reverse for n >= 2.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

