int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int initial_a1 = a[0];
        int max_a1 = initial_a1;

        // Iterate through piles from 2nd to nth
        for (int i = 1; i < n; ++i) {
            // Distance from pile i+1 to pile 1 is i
            // (0-indexed pile i is (i+1)-th pile, distance is i)
            int distance = i; 

            // If we have enough days to move at least one haybale from this pile
            if (d >= distance) {
                // Calculate how many haybales can be moved from this pile
                // based on available days and haybales in the pile.
                // Each haybale costs 'distance' days.
                int haybales_to_move = std::min(a[i], d / distance);

                max_a1 += haybales_to_move;
                d -= haybales_to_move * distance;
            } else {
                // If we don't even have enough days for one haybale from this pile,
                // we can't move any more haybales from further piles either,
                // because they would require even more days.
                break; 
            }
        }
        std::cout << max_a1 << std::endl;
    }
    return 0;
}

