void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    int color_for_half_T = 0; // Alternates between 0 and 1 for elements equal to T/2

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use 2.0 for floating point division to handle T being odd
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T / 2.0, i.e., a[i] * 2 == T
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Alternate color for next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

