void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_has_one(n, false);
    std::vector<bool> col_has_one(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_has_one[i] = true;
                col_has_one[j] = true;
            }
        }
    }

    int free_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_has_one[i]) {
            free_rows++;
        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_has_one[j]) {
            free_cols++;
        }
    }

    int moves_possible = std::min(free_rows, free_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

