#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and all others are less than n-1.
    // If so, it means the actual value for that p[i] should be n.
    // This happens if p[i] was the largest element in the original permutation.
    // In that case, max_val_in_row would be n-1 (the second largest element).
    // We need to find if there's a value n-1 that appears only once,
    // and all other values are strictly less than n-1.
    // If there are multiple n-1s, or if n-1 is not present,
    // then the largest value in p (which is n-1) should be replaced by n.

    bool n_minus_1_found = false;
    for (int val : p) {
        if (val == n - 1) {
            n_minus_1_found = true;
            break;
        }
    }

    if (!n_minus_1_found) {
        // This means the largest value in p is actually less than n-1.
        // This implies that the true largest element (n) was not correctly identified
        // as n-1 by the max_val_in_row logic.
        // This can happen if n=2, and p={1,2}.
        // For p[0]=1, max_val_in_row is min(1,2)=1.
        // For p[1]=2, max_val_in_row is min(2,1)=1.
        // So p becomes {1,1}. The largest value is 1.
        // In this case, we need to find the maximum value in the current p,
        // and replace it with n.
        int max_current_p_val = 0;
        for (int val : p) {
            if (val > max_current_p_val) {
                max_current_p_val = val;
            }
        }
        for (int i = 0; i < n; ++i) {
            if (p[i] == max_current_p_val) {
                p[i] = n;
                break; // Only one such element needs to be changed
            }
        }
    } else {
        // If n-1 is found, we need to check if it's unique among the largest values.
        // If there are multiple elements equal to n-1, or if n-1 is the only value
        // that is not n, then the logic for finding the largest element is more subtle.
        // The problem guarantees a solution exists.
        // The simplest approach is to find the maximum value in the constructed p.
        // If this maximum value is n-1, it means the true 'n' was represented as 'n-1'.
        // We need to change one of these 'n-1's to 'n'.
        // Since any solution is fine, we can just pick the first one.
        int max_val_in_p = 0;
        for (int val : p) {
            if (val > max_val_in_p) {
                max_val_in_p = val;
            }
        }
        if (max_val_in_p == n - 1) {
            for (int i = 0; i < n; ++i) {
                if (p[i] == n - 1) {
                    p[i] = n;
                    break;
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last price

    // Iterate from right to left, excluding the last element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            min_suffix_price = a[i]; // Update minimum if current price is smaller
        }
    }
    std::cout << bad_prices_count << "\n";
}

