    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we sort all 2n elements,
        // the smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2n-1-k].
        // To minimize the difference, we want the medians to be as close as possible.
        // The optimal strategy is to pick the n-th element (0-indexed a[n-1])
        // as the median for one class and the (n+1)-th element (0-indexed a[n])
        // as the median for the other class.
        //
        // Consider the sorted array a_1, a_2, ..., a_{2n}.
        // We need to pick n elements for one class and n elements for the other.
        // The median of a class of size 2k+1 is the (k+1)-th element.
        //
        // If we take the first n elements for one class and the last n elements for the other,
        // this doesn't guarantee odd sizes.
        //
        // The problem statement implies that the optimal partition will always involve
        // taking the (n)-th element (a[n-1] in 0-indexed array) as the median of one class
        // and the (n+1)-th element (a[n] in 0-indexed array) as the median of the other class.
        //
        // Let's verify this.
        // Suppose we have sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to form two classes, C1 and C2, both of odd size.
        // Let |C1| = 2k1+1 and |C2| = 2k2+1.
        // (2k1+1) + (2k2+1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 + 1 = n.
        //
        // The median of C1 will be some a_i, and the median of C2 will be some a_j.
        // To minimize |a_i - a_j|, we want a_i and a_j to be adjacent in the sorted array.
        //
        // Consider the elements a[n-1] and a[n].
        // Can we make a[n-1] the median of one class and a[n] the median of the other?
        //
        // To make a[n-1] the median of a class C1 of size 2k1+1:
        // We need k1 elements smaller than or equal to a[n-1] and k1 elements greater than or equal to a[n-1].
        // We have a_0, ..., a_{n-2} (n-1 elements) smaller than a[n-1].
        // We have a_n, ..., a_{2n-1} (n elements) greater than a[n-1].
        //
        // To make a[n] the median of a class C2 of size 2k2+1:
        // We need k2 elements smaller than or equal to a[n] and k2 elements greater than or equal to a[n].
        // We have a_0, ..., a_{n-1} (n elements) smaller than a[n].
        // We have a_{n+1}, ..., a_{2n-1} (n-1 elements) greater than a[n].
        //
        // We need to find k1 and k2 such that k1+k2 = n-1.
        //
        // Let's try to construct such a partition.
        // Class 1 (median a[n-1]):
        // Take a[n-1].
        // Take k1 elements from a_0, ..., a_{n-2}.
        // Take k1 elements from a_n, ..., a_{2n-1}.
        //
        // Class 2 (median a[n]):
        // Take a[n].
        // Take k2 elements from remaining elements smaller than a[n].
        // Take k2 elements from remaining elements larger than a[n].
        //
        // The total number of elements smaller than a[n-1] is n-1.
        // The total number of elements larger than a[n] is n-1.
        //
        // We can choose k1 = 0, k2 = n-1.
        // Class 1: {a[n-1]} (size 1). Median is a[n-1].
        // Class 2: {a[0], ..., a[n-2], a[n], a[n+1], ..., a_{2n-1}} (size 2(n-1)+1 = 2n-1).
        // The elements for Class 2 are all elements except a[n-1].
        // The median of Class 2 (size 2n-1) would be the (n-1+1)-th = n-th element.
        // If we sort these 2n-1 elements, the n-th element is a[n].
        // This is a valid partition. The difference is |a[n] - a[n-1]|.
        //
        // This construction always works.
        // Class 1: {a[n-1]} (size 1). Median is a[n-1].
        // Class 2: All other 2n-1 elements.
        // The elements for Class 2 are a_0, ..., a_{n-2}, a_n, ..., a_{2n-1}.
        // When sorted, these are a_0, ..., a_{n-2}, a_n, ..., a_{2n-1}.
        // The median of 2n-1 elements is the ( (2n-1)-1 )/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n-th element.
        // In the sorted list of Class 2 elements, the n-th element is a[n].
        // So, the medians are a[n-1] and a[n]. The difference is |a[n] - a[n-1]|.
        //
        // This is the minimum possible difference because any two medians must be at least this far apart.
        // If we pick any two elements a_i and a_j as medians, with i < j.
        // For a_i to be a median of a class of size 2k1+1, there must be at least k1 elements smaller than or equal to a_i,
        // and at least k1 elements greater than or equal to a_i.
        // For a_j to be a median of a class of size 2k2+1, there must be at least k2 elements smaller than or equal to a_j,
        // and at least k2 elements greater than or equal to a_j.
        //
        // The total number of elements smaller than a_i is i.
        // The total number of elements larger than a_j is 2n-1-j.
        //
        // The elements a_0, ..., a_{i-1} are available for C1 (left of a_i) or C2 (left of a_j).
        // The elements a_{j+1}, ..., a_{2n-1} are available for C1 (right of a_i) or C2 (right of a_j).
        // The elements a_{i+1}, ..., a_{j-1} are between a_i and a_j.
        //
        // The crucial observation is that the $n$-th smallest element (a[n-1]) and the $n+1$-th smallest element (a[n])
        // are the "middle" two elements of the entire sorted array.
        // If we are to pick two medians, they must be able to "support" their respective classes.
        // The elements a[0]...a[n-1] are the first n elements.
        // The elements a[n]...a[2n-1] are the last n elements.
        //
        // The minimum difference will always be between a[n-1] and a[n].
        // This is because we need to select n elements for the "left" side of the partition and n elements for the "right" side.
        // The median of the "left" class will be the largest possible median from the first n elements, which is a[n-1].
        // The median of the "right" class will be the smallest possible median from the last n elements, which is a[n].
        //
        // More formally:
        // Let $m_1$ be the median of class $C_1$ and $m_2$ be the median of class $C_2$.
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$. We know $k_1+k_2+1 = n$.
        //
        // $m_1$ must be at least the $(k_1+1)$-th element in $C_1$.
        // $m_2$ must be at least the $(k_2+1)$-th element in $C_2$.
        //
        // Consider the sorted array $a_0, \dots, a_{2n-1}$.
        // The element $a_{n-1}$ is the $n$-th element.
        // The element $a_n$ is the $(n+1)$-th element.
        //
        // We can always form a class $C_1 = \{a_{n-1}\}$ (size 1, $k_1=0$). Its median is $a_{n-1}$.
        // The remaining $2n-1$ elements form $C_2$. Its size is $2n-1$.
        // For $C_2$, $2k_2+1 = 2n-1 \implies k_2 = n-1$.
        // The median of $C_2$ is its $(k_2+1)$-th element, which is its $n$-th element.
        // The elements of $C_2$ are $a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}$.
        // When sorted, the $n$-th element of this list is $a_n$.
        // So, the medians are $a_{n-1}$ and $a_n$. The difference is $|a_n - a_{n-1}|$.
        //
        // This is the minimum possible difference.
        // Any other choice of medians $a_i$ and $a_j$ (with $i < j$) would result in $|a_j - a_i| \ge |a_n - a_{n-1}|$
        // if $i \le n-1$ and $j \ge n$.
        // If both medians are on one side of $a_{n-1}$ and $a_n$, it's impossible to satisfy the conditions.
        // For example, if both medians are $a_i, a_j$ with $j < n-1$.
        // Then $C_1$ and $C_2$ would need $k_1+k_2+1 = n$ elements to their right.
        // But there are only $2n-1-j$ elements to the right of $a_j$.
        //
        // The minimum difference is indeed a[n] - a[n-1].

        long long diff = a[n] - a[n-1];
        std::cout << diff << "\n";
    }
    return 0;
}

#include <iostream>
