#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i+1 (s[i] is 'R').

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i, which corresponds to cell i+1.
                // The previous 'R' (or start 0) was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // If last_r_pos was -1 (start 0), the gap is (i+1) - 0 = i+1.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // The last 'R' was at index last_r_pos, corresponding to cell last_r_pos + 1.
        // The target is cell n+1.
        // The gap is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

