int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we'll use in the alternating sequence to generate k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // We can achieve this by alternating between the smallest available number and the largest available number
    // from the range [1, k+1].
    // For example, if k=2, we use numbers 1, 2, 3.
    // Sequence: 1, 3, 2. Differences: |1-3|=2, |3-2|=1. Distinct: {1, 2}.
    // If k=3, we use numbers 1, 2, 3, 4.
    // Sequence: 1, 4, 2, 3. Differences: |1-4|=3, |4-2|=2, |2-3|=1. Distinct: {1, 2, 3}.

    bool use_left = true;
    for (int i = 0; i < k + 1; ++i) {
        if (use_left) {
            std::cout << left++;
        } else {
            std::cout << right--;
        }
        if (i < n - 1) { // Print space if not the last number
            std::cout << " ";
        }
        use_left = !use_left;
    }

    // After generating k+1 numbers, we have used numbers from 1 to (k+1).
    // The remaining numbers are (k+2), (k+3), ..., n.
    // To avoid introducing new distinct differences, we can append these remaining numbers in increasing order.
    // This will only introduce a difference of 1 (e.g., |(k+1) - (k+2)| = 1), which is already among the k differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

