#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^0, 2^1, 2^2, ...
        while (true) {
            // Calculate the number of stairs for the current k.
            // n = 2*k - 1
            // Cost for n stairs = (2*k - 1) * (2*k) * (2*k + 1) / 6
            // This simplifies to k * (2*k - 1) * (2*k + 1) / 3
            // Or, more simply, (2*k^3 - k) / 3
            // The formula for the cost of a nice staircase with n = 2^p - 1 stairs is
            // (2^p * (2^p - 1) * (2^p + 1)) / 6
            // Let k = 2^p. Then n = k - 1.
            // The cost is (k * (k - 1) * (k + 1)) / 6 = (k^3 - k) / 6.
            // This is the cost for a staircase with n = 2^p - 1 stairs.
            // The problem statement implies n is the number of stairs.
            // The example image for n=7 (which is 2^3 - 1) uses squares 1x1, 2x2, 4x4.
            // The total cells for n=7 is 7 * 8 / 2 = 28.
            // The squares 1x1, 2x2, 4x4 sum to 1 + 4 + 16 = 21. This is not 28.
            // The problem states "covered by n disjoint squares".
            // The image shows 1x1, 2x2, 4x4 squares. These are 3 squares, not 7.
            // This implies the interpretation of "n stairs" and "n disjoint squares" is tricky.
            // Let's re-read: "A staircase with n stairs is called nice, if it may be covered by n disjoint squares made of cells."
            // The image for n=7 shows 3 squares. This contradicts "n disjoint squares".
            // The note for n=7 says "This is how a nice covered staircase with 7 stairs looks like".
            // This suggests that the number of squares is not necessarily 'n'.
            // The example output for x=8 is 2.
            // Nice staircases:
            // n=1: cost = 1*(1+1)/2 = 1. Squares: 1x1. (1 square)
            // n=3: cost = 3*(3+1)/2 = 6. Squares: 1x1, 2x2. (2 squares) Total 1+4=5.
            // This is still not matching. The total cells for n=3 is 6.
            // The image for n=7 shows squares of sizes 1, 2, 4. These are powers of 2.
            // If a nice staircase is formed by squares of sizes 2^0, 2^1, ..., 2^(p-1),
            // then the largest square is 2^(p-1) x 2^(p-1).
            // The number of stairs 'n' for such a staircase would be 2^p - 1.
            // For p=1, n=2^1-1=1. Squares: 1x1. Cost = 1.
            // For p=2, n=2^2-1=3. Squares: 1x1, 2x2. Cost = 1+4=5.
            // For p=3, n=2^3-1=7. Squares: 1x1, 2x2, 4x4. Cost = 1+4+16=21.
            // This interpretation matches the example image (3 squares for n=7) and the costs.
            // Let's use this interpretation.
            // The cost of a nice staircase with n = 2^p - 1 stairs is sum_{i=0}^{p-1} (2^i)^2 = sum_{i=0}^{p-1} 4^i.
            // This is a geometric series sum: (4^p - 1) / (4 - 1) = (4^p - 1) / 3.
            // Let k = 2^p. Then the cost is (k^2 - 1) / 3. No, this is wrong.
            // The sum is (4^p - 1) / 3.
            // Let's re-evaluate the cost for n=1, 3, 7, ...
            // p=1 (n=1): cost = (4^1 - 1) / 3 = 3/3 = 1. Correct.
            // p=2 (n=3): cost = (4^2 - 1) / 3 = (16 - 1) / 3 = 15/3 = 5. Correct.
            // p=3 (n=7): cost = (4^3 - 1) / 3 = (64 - 1) / 3 = 63/3 = 21. Correct.

            // So, the costs of nice staircases are 1, 5, 21, 85, ...
            // These are costs for staircases with n = 2^p - 1 stairs, where p = 1, 2, 3, ...
            // The cost for a staircase corresponding to 'p' is (4^p - 1) / 3.
            // Let's calculate the cost for the current 'p'.
            // The variable 'k' in my code is currently 2^p.
            // So, the cost is (k*k - 1) / 3.
            // No, k is 2^p. So 4^p is (2^p)^2 = k^2.
            // So the cost is (k*k - 1) / 3.
            // Let's trace k:
            // p=1: k=2. Cost = (2*2 - 1)/3 = 1.
            // p=2: k=4. Cost = (4*4 - 1)/3 = 5.
            // p=3: k=8. Cost = (8*8 - 1)/3 = 21.
            // This matches.

            long long current_staircase_cost = (k * k - 1) / 3;

            if (x >= current_staircase_cost) {
                count++;
                x -= current_staircase_cost;
                // Next k will be 2 * current k.
                // k = 2^p, next k = 2^(p+1).
                k *= 2;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Precompute the sum of last digits for one cycle (10 multiples)
        // The last digits of m*1, m*2, ..., m*10 are (m*1)%10, (m*2)%10, ..., (m*10)%10
        // The sequence of last digits (m*i)%10 is periodic with period 10.
        // (m*(i+10))%10 = (m*i + m*10)%10 = (m*i)%10
        std::vector<long long> cycle_last_digits(10);
        long long sum_cycle_last_digits = 0;
        for (int i = 0; i < 10; ++i) {
            cycle_last_digits[i] = (m * (i + 1)) % 10;
            sum_cycle_last_digits += cycle_last_digits[i];
        }

        // Calculate how many full cycles of 10 multiples are there
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * sum_cycle_last_digits;

        // Calculate the sum for the remaining multiples
        long long remaining_multiples = count % 10;
        for (int i = 0; i < remaining_multiples; ++i) {
            total_sum += cycle_last_digits[i];
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i...n-1] is non-increasing.
    // This means a[i] >= a[i+1] >= ... >= a[n-1].
    // This is the first part of the "valley" pattern.
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }

    // If i is 0, the entire array is non-increasing.
    // This means it's already a good array (e.g., [5,4,3,2,1] -> [1,2,3,4,5]).
    // Or it's already a good array (e.g., [1,1,1]).
    // In this case, the prefix to remove is 0.
    if (i == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, `i` is the first index from the left such that `a[i-1] < a[i]`,
    // and `a[i...n-1]` is non-increasing.
    // Example: [1,3,1,4,5,3,2]
    // n=7
    // i=6, a[5]=3, a[6]=2. a[5] > a[6]. i becomes 5.
    // i=5, a[4]=5, a[5]=3. a[4] > a[5]. i becomes 4.
    // i=4, a[3]=4, a[4]=5. a[3] < a[4]. Loop stops. i is 4.
    // So, a[4...6] = [5,3,2] is non-increasing.
    // The "valley" starts at index `i`.

    // Now, find the rightmost index `j` such that a[j...i-1] is non-decreasing.
    // This means a[j] <= a[j+1] <= ... <= a[i-1].
    // This is the second part of the "valley" pattern.
    // We need to find the first element from the left that breaks this non-decreasing property.
    // This means we are looking for the smallest `j` such that `a[j...n-1]` forms the "valley".
    // The elements `a[0...j-1]` are the prefix to be removed.
    int j = i; // Start checking from `i` backwards
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }

    // `j` is now the first index from the left such that `a[j...n-1]` forms a "good" array.
    // The length of the prefix to remove is `j`.
    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must always contain 1, so it must span from current_min_idx to current_max_idx.
        // To include 'm', we need to update current_min_idx and current_max_idx.
        // The value 'm' is at pos[m].
        // The new segment must cover all values from 1 to m.
        // This means the segment must span from min(current_min_idx, pos[m]) to max(current_max_idx, pos[m]).

        if (m > 1) {
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);
        }

        // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, ..., m.
        // This implies two conditions:
        // 1. The length of the segment must be m.
        // 2. The minimum value in the segment is 1 and the maximum value is m.
        //    (This is implicitly handled by how current_min_idx and current_max_idx are updated:
        //     they always span the indices of 1, 2, ..., m).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

