int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;
        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            double discriminant = d * d - 4.0 * d;
            // Since d >= 4, discriminant will be non-negative.
            // d^2 - 4d = d(d-4) >= 4(4-4) = 0
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // We need a and b to be non-negative.
            // Since d >= 4, d + sqrt_discriminant is positive. So a1 is positive.
            // For b1, d - sqrt_discriminant:
            // We know d^2 >= d^2 - 4d (since 4d >= 0)
            // So d >= sqrt(d^2 - 4d)
            // Thus d - sqrt(d^2 - 4d) >= 0. So b1 is non-negative.
            // Also, a1 >= b1 by construction.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

