    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if it's possible to form the left increasing part
    // a_0 >= 0, a_1 >= 1, ..., a_i >= i
    // This means a_i must be at least i.
    // If a_i < i for any i, then it's impossible to make a_i >= i.
    // The prefix_possible array stores true if a_i can be made >= i.
    std::vector<bool> prefix_possible(n);
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_possible[i] = true;
        } else {
            prefix_possible[i] = false;
        }
    }

    // Check if it's possible to form the right decreasing part
    // a_{n-1} >= 0, a_{n-2} >= 1, ..., a_{n-1-j} >= j
    // This means a_i must be at least (n-1-i).
    // If a_i < (n-1-i) for any i, then it's impossible to make a_i >= (n-1-i).
    // The suffix_possible array stores true if a_i can be made >= (n-1-i).
    std::vector<bool> suffix_possible(n);
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_possible[i] = true;
        } else {
            suffix_possible[i] = false;
        }
    }

    // A peak k (0-indexed) is possible if:
    // 1. The prefix up to k can be formed: a_0 < a_1 < ... < a_k
    //    This requires a_i >= i for all i <= k.
    // 2. The suffix from k can be formed: a_k > a_{k+1} > ... > a_{n-1}
    //    This requires a_i >= (n-1-i) for all i >= k.
    // So, for a given k, we need prefix_possible[k] and suffix_possible[k] to be true.
    // If such a k exists, then it's possible.

    bool found_sharpened = false;
    for (int k = 0; k < n; ++k) {
        if (prefix_possible[k] && suffix_possible[k]) {
            found_sharpened = true;
            break;
        }
    }

    if (found_sharpened) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

