    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the "larger" elements)
    for (int i = 0; i < n; ++i) { // Pointer for the "original" elements
        // We are trying to find an element a[j] such that a[j] > a[i]
        // Since both arrays are sorted, if a[j] > a[i], then any a[k] with k > j will also be >= a[j]
        // and thus potentially > a[i].
        // We want to use the smallest possible a[j] that is greater than a[i]
        // to leave larger elements for later, potentially larger a[i]'s.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element for the "larger" array
        } else {
            // No more elements in 'a' are greater than a[i]
            // Since 'a' is sorted, no subsequent a[k] (k > i) will find a match either
            break; 
        }
    }
    std::cout << count << std::endl;
