#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    long long total_toys = A + B + C + D;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
        return;
    }

    // Determine if the final product can be positive or negative
    // The sign of the final product depends on the parity of negative numbers multiplied.
    // Each multiplication of two negatives results in a positive.
    // Each multiplication of a negative and a positive results in a negative.
    // The final sign is determined by the parity of the total number of negative toys (A+B)
    // that are "left over" after all possible negative-negative pairings.
    // This is equivalent to the parity of (A+B).
    // If (A+B) is even, the final product can be positive.
    // If (A+B) is odd, the final product can be negative.

    bool can_be_positive = ((A + B) % 2 == 0);
    bool can_be_negative = ((A + B) % 2 != 0);

    // Determine if the final product can have magnitude < 1 or >= 1
    // This is more complex as it depends on the sequence of operations.
    // We need to consider if it's possible to "force" the magnitude to be < 1 or >= 1.

    // Let's analyze the conditions for each box to be special.

    // Box 1: (-inf, -1] (Negative, magnitude >= 1)
    // Requires: can_be_negative AND can_be_magnitude_ge_1
    // Can we always achieve magnitude >= 1 if there's at least one toy with magnitude >= 1 (A or D)?
    // Yes, if A+D > 0, we can always ensure the final product has magnitude >= 1.
    // We can multiply all B and C toys together first. This results in a product with magnitude < 1.
    // Then, multiply this product with any A or D toy.
    // If we have a toy with value X where |X| >= 1, and we multiply it by Y where |Y| < 1,
    // the result |X*Y| can be < 1 or >= 1.
    // However, if we have at least one toy with magnitude >= 1 (A or D), we can always make the final product magnitude >= 1.
    // Example: If we have a toy with value 10 (from D) and many toys with value 0.1 (from B or C).
    // We can multiply all 0.1 toys together, getting a very small number, say 0.001.
    // Then multiply 10 * 0.001 = 0.01 (magnitude < 1).
    // This strategy doesn't guarantee magnitude >= 1.

    // A better strategy for magnitude >= 1:
    // If A+D > 0, we can always ensure the final product has magnitude >= 1.
    // Pick one toy from A or D (let's say its value is X, |X| >= 1).
    // Multiply all other toys (total_toys - 1 of them) together. Let their product be Y.
    // The final product is X * Y.
    // If we choose the values of the other toys such that Y has magnitude >= 1, then |X*Y| >= 1.
    // This is possible if we have enough A or D toys.
    // If we have A+D >= 1, we can pick one toy from A or D.
    // If we have A+D >= 2, we can pick two toys from A or D, say X1, X2. Multiply them to get X1*X2 (magnitude >= 1).
    // Then multiply this by all B and C toys. The result can be < 1 or >= 1.

    // Let's simplify:
    // The final product's magnitude can be >= 1 if and only if:
    // 1. There is at least one toy in A or D (A+D > 0).
    // 2. It's possible to arrange multiplications such that the final magnitude is >= 1.
    // This is always possible if A+D > 0.
    // Consider the product of all toys. If all toys have magnitude < 1 (B+C > 0, A+D == 0), then the final product will have magnitude < 1.
    // If there is at least one toy with magnitude >= 1 (A+D > 0), we can choose its value to be very large (e.g., 1000).
    // And choose all B and C toys to have values very close to 1 (e.g., 0.99).
    // And choose other A and D toys to have values very close to 1 (e.g., 1.01).
    // In this scenario, the product of all toys will have magnitude >= 1.
    // So, can_be_magnitude_ge_1 is true if A+D > 0.
    // And can_be_magnitude_lt_1 is true if B+C > 0.
    // What if A+D > 0 AND B+C > 0? Can it be both? Yes.
    // Example: {2, 0.5}. Product is 1.
    // Example: {2, 0.1}. Product is 0.2 (magnitude < 1).
    // Example: {2, 0.9}. Product is 1.8 (magnitude >= 1).
    // So, if A+D > 0, we can choose values such that the final magnitude is >= 1.
    // And if B+C > 0, we can choose values such that the final magnitude is < 1.
    // The only case where magnitude is fixed is:
    // - If A+D == 0 (all toys are B or C), then final magnitude MUST be < 1.
    // - If B+C == 0 (all toys are A or D), then final magnitude MUST be >= 1 (since total_toys > 1).

    bool possible_mag_ge_1 = (A + D > 0);
    bool possible_mag_lt_1 = (B + C > 0);

    // If A+D == 0, then all toys are B or C. Their product will always have magnitude < 1.
    if (A + D == 0) {
        possible_mag_ge_1 = false;
        possible_mag_lt_1 = true; // Since B+C = total_toys > 0
    }
    // If B+C == 0, then all toys are A or D. Their product will always have magnitude >= 1.
    else if (B + C == 0) {
        possible_mag_ge_1 = true; // Since A+D = total_toys > 0
        possible_mag_lt_1 = false;
    }
    // If A+D > 0 AND B+C > 0, then both are possible.
    else {
        possible_mag_ge_1 = true;
        possible_mag_lt_1 = true;
    }

    // Box 1: (-inf, -1]
    if (can_be_negative && possible_mag_ge_1) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    if (can_be_negative && possible_mag_lt_1) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    if (can_be_positive && possible_mag_lt_1) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    if (can_be_positive && possible_mag_ge_1) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

