#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 == 1) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Taking N/2 leaves an odd number for opponent, which is good for Chanek
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 = 1
                    // Taking 1 leaves an odd number for opponent, which is good for Chanek
                    // Taking N/2 leaves an even number for opponent, which is bad for Chanek
                    // So, take 1.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, taking 1 is optimal
                    opponent_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1 && n / 2 != 1) { // N/2 is odd and N/2 > 1
                    // Taking N/2 leaves an odd number for Chanek, which is good for opponent
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 = 1
                    // Taking 1 leaves an odd number for Chanek, which is good for opponent
                    // Taking N/2 leaves an even number for Chanek, which is bad for opponent
                    // So, take 1.
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

