// Function to check if a sub-array is a permutation of 1 to len
// Uses a frequency array (or boolean array) for efficiency
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // A permutation must have non-zero length
        return false;
    }
    if (len > arr.size() - start_idx) { // Not enough elements
        return false;
    }

    std::vector<bool> seen(len + 1, false); // seen[0] is unused, indices 1 to len
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // After checking all elements, ensure max_val is exactly len
    // and all numbers from 1 to len were seen (which is guaranteed by seen[val]=true and val <= len)
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max value in prefix and suffix
    std::vector<int> prefix_max(n + 1, 0); // prefix_max[i] stores max of a[0...i-1]
    for (int i = 0; i < n; ++i) {
        prefix_max[i + 1] = std::max(prefix_max[i], a[i]);
    }

    std::vector<int> suffix_max(n + 1, 0); // suffix_max[i] stores max of a[i...n-1]
    for (int i = n - 1; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute if prefix is a permutation
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[l] is true if a[0...l-1] is perm of length l
    std::vector<bool> seen_prefix(n + 1, false);
    bool current_prefix_valid = true;
    for (int l = 1; l <= n; ++l) {
        int val = a[l - 1];
        if (val < 1 || val > l || seen_prefix[val]) {
            current_prefix_valid = false;
        }
        seen_prefix[val] = true;
        if (current_prefix_valid && prefix_max[l] == l) {
            is_prefix_perm[l] = true;
        } else {
            is_prefix_perm[l] = false;
        }
    }

    // Precompute if suffix is a permutation
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[l] is true if a[n-l...n-1] is perm of length l
    std::vector<bool> seen_suffix(n + 1, false);
    bool current_suffix_valid = true;
    for (int l = 1; l <= n; ++l) {
        int val = a[n - l];
        if (val < 1 || val > l || seen_suffix[val]) {
            current_suffix_valid = false;
        }
        seen_suffix[val] = true;
        if (current_suffix_valid && suffix_max[n - l] == l) {
            is_suffix_perm[l] = true;
        } else {
            is_suffix_perm[l] = false;
        }
    }

    // Iterate through all possible split points l1
    // l1 is the length of the first permutation p1
    // l2 is the length of the second permutation p2
    // l1 + l2 = n
    // Both l1 and l2 must be at least 1.
    // Also, a_i <= n-1, so neither l1 nor l2 can be n.
    // Thus, 1 <= l1 <= n-1, which implies 1 <= l2 <= n-1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

