#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S' = current_sum + b1 + b2 + b3
    // Let X' = current_xor_sum ^ b1 ^ b2 ^ b3
    // We need S' = 2 * X'

    // Strategy: Append at most 3 elements.
    // It's always possible to make it good by appending at most 3 elements.
    // Let's try to append 2 elements first.
    // We need to find b1, b2 such that (current_sum + b1 + b2) = 2 * (current_xor_sum ^ b1 ^ b2)
    // A common strategy for these problems is to make the XOR sum equal to some value, say X_target.
    // And then make the sum equal to 2 * X_target.

    // Let's try to append two numbers: current_xor_sum and (current_sum + current_xor_sum).
    // Let b1 = current_xor_sum.
    // Let b2 = current_sum + current_xor_sum.
    // This is a common trick.
    // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
    // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    // X' = 0 ^ (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum

    // New sum: S' = current_sum + b1 + b2
    // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    // S' = 2 * (current_sum + current_xor_sum)

    // With these two appended elements, we have:
    // S' = 2 * (current_sum + current_xor_sum)
    // X' = current_sum + current_xor_sum
    // So, S' = 2 * X' is satisfied.

    // The problem states we can append at most 3 elements.
    // The strategy above appends 2 elements.
    // The elements are b1 = current_xor_sum and b2 = current_sum + current_xor_sum.
    // These are non-negative since current_sum and current_xor_sum are non-negative.
    // The maximum value for a_i is 10^9.
    // Max current_sum is 10^5 * 10^9 = 10^14.
    // Max current_xor_sum is roughly 2^30 (since 10^9 < 2^30).
    // So b2 can be up to 10^14 + 2^30, which fits in long long.

    // Output 2 elements:
    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
}

