int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long power_of_2 = 1; // Represents 2^count_a
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will effectively "jump over" this 'b'.
            // The number of 'a's currently accumulated (count_a)
            // will contribute to the total steps.
            // Each of these 'a's will cause an operation with this 'b'.
            // The total steps for this 'b' will be `count_a`.
            // However, when an 'a' jumps over a 'b', it also creates a new 'b'.
            // This new 'b' will be to the left of the original 'b'.
            // The number of 'a's that have already passed this 'b' (count_a)
            // will effectively double the number of 'b's that are available
            // for 'a's further to the left.
            // So, when we see a 'b', the number of 'a's that will interact
            // with it (and potentially new 'b's created by it) is `count_a`.
            // This `count_a` is the number of 'a's that are currently
            // "active" and need to move past 'b's.
            // The total steps increase by `count_a`.
            total_steps = (total_steps + count_a) % mod;

            // After these `count_a` operations, each of the `count_a` 'a's
            // will have created a new 'b' to its left.
            // This effectively doubles the number of 'b's that 'a's further
            // to the left will encounter.
            // So, the effective number of 'a's that are "active" and
            // will interact with future 'b's (or 'b's created by them)
            // also doubles.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now active.
            // It will need to move past any 'b's to its right.
            // We increment the count of active 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

