// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        return "0"; // Special case for 0, its parity pattern is "0"
    }
    while (n > 0) {
        if ((n % 10) % 2 == 0) { // Even digit
            pattern += '0';
        } else { // Odd digit
            pattern += '1';
        }
        n /= 10;
    }
    // The problem states that if the integer is shorter than the pattern,
    // its decimal notation is supplemented with 0-s from the left.
    // This means we need to pad our generated pattern to a fixed length (18)
    // with '0's (even) from the left.
    // Since we build the pattern from right to left, we append '0's to the right
    // until it reaches length 18.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each parity pattern string.
    // The key will be the 18-character parity pattern string,
    // and the value will be its count in the multiset.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern 's' with '0's from the left to length 18.
            // Since 's' is read as is, and we need to match it against our
            // stored 18-char patterns, we need to pad 's' to 18 chars.
            // The problem states: "If the pattern is shorter than this integer,
            // it's supplemented with 0-s from the left."
            // Our stored patterns are 18 chars long, effectively representing
            // numbers up to 18 digits, padded with 0s.
            // So, a query pattern 's' needs to be padded to 18 chars.
            // Example: s = "1", padded to "000000000000000001"
            // Example: s = "010", padded to "000000000000000010"
            // The padding should be done from the left of the *original* pattern.
            // Since our `get_parity_pattern` function generates patterns
            // from right-to-left digits and then pads to the right,
            // a query pattern `s` like "010" corresponds to the last three
            // digits. If `s` is shorter than 18, it means the leading digits
            // are assumed to be even (0).
            // So, we need to pad `s` with '0's at the beginning to make it 18 characters long.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }

            // Now, `padded_s` is 18 characters long.
            // The `get_parity_pattern` function generates a string where
            // the first character corresponds to the rightmost digit's parity,
            // the second character to the second rightmost, and so on.
            // The query pattern `s` is given in standard left-to-right order.
            // So, if `s = "010"`, it means:
            //   - rightmost digit parity must be '0'
            //   - second rightmost digit parity must be '1'
            //   - third rightmost digit parity must be '0'
            // This means we need to reverse the query pattern `s` to match
            // the format of the keys in our `pattern_counts` map.
            std::reverse(padded_s.begin(), padded_s.end());

            // Look up the count for the reversed and padded pattern.
            // If the pattern is not found, map::operator[] will default-construct
            // an int (0), which is the correct count.
            std::cout << pattern_counts[padded_s] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (k)
    // k can range from 0 to n
    for (int k = 0; k <= n; ++k) {
        // k items from left, n-k items from right
        long long current_energy = 0;

        // Energy for items taken from left
        current_energy += prefix_sum[k] * l;

        // Energy for items taken from right
        // The sum of weights for items taken from right is (prefix_sum[n] - prefix_sum[k])
        current_energy += (prefix_sum[n] - prefix_sum[k]) * r;

        // Add penalty based on counts
        int left_count = k;
        int right_count = n - k;

        if (left_count > right_count) {
            // More items from left. The last item taken must be from the left.
            // The difference in counts is left_count - right_count.
            // If left_count = right_count + 1, no extra penalty.
            // If left_count = right_count + 2, one extra Ql.
            // If left_count = right_count + 3, two extra Ql.
            // So, (left_count - right_count - 1) * Ql
            current_energy += std::max(0, left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items from right. The last item taken must be from the right.
            // The difference in counts is right_count - left_count.
            // If right_count = left_count + 1, no extra penalty.
            // If right_count = left_count + 2, one extra Qr.
            // So, (right_count - left_count - 1) * Qr
            current_energy += std::max(0, right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no extra penalty.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

