}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string result(n, ' ');
    bool found_solution = false;

    for (int p = 0; p <= 9; ++p) { // p is the pivot digit
        std::vector<int> current_coloring(n);
        int last1 = -1; // Last digit colored 1
        int first2 = 10; // First digit colored 2

        bool possible_p = true;
        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                current_coloring[i] = 1;
                if (d[i] < last1) { // Check non-decreasing for color 1
                    possible_p = false;
                    break;
                }
                last1 = d[i];
            } else if (d[i] > p) {
                current_coloring[i] = 2;
                if (d[i] < first2) { // Check non-decreasing for color 2
                    possible_p = false;
                    break;
                }
                first2 = d[i];
            }
        }

        if (!possible_p) {
            continue;
        }

        // Now handle digits equal to p
        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (d[i] >= last1) { // Can be colored 1
                    current_coloring[i] = 1;
                    last1 = d[i];
                } else { // Must be colored 2
                    current_coloring[i] = 2;
                    if (d[i] < first2) { // Check non-decreasing for color 2
                        possible_p = false;
                        break;
                    }
                    first2 = d[i];
                }
            }
        }

        if (!possible_p) {
            continue;
        }

        // Final check: last digit of color 1 <= first digit of color 2
        // If no digits were colored 1, last1 remains -1.
        // If no digits were colored 2, first2 remains 10.
        // In these cases, the condition last1 <= first2 is trivially true.
        if (last1 > first2) {
            possible_p = false;
        }

        if (possible_p) {
            for (int i = 0; i < n; ++i) {
                result[i] = (char)(current_coloring[i] + '0');
            }
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

