            long long parity_diff = (max_coord - min_coord) % 2;

            if (parity_diff == 0) { // max_coord and min_coord have same parity difference
                if (remaining_moves % 2 == 0) {
                    ans = k;
                } else {
                    ans = k - 2;
                }
            } else { // max_coord and min_coord have different parity difference
                ans = k - 1;
            }
        }
