int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: (b-1) * b / 2
    long long sum_r = (b - 1);
    sum_r = (sum_r % MOD * (b % MOD)) % MOD;

    // Modular inverse of 2
    // Since MOD is prime (10^9 + 7), inv(2) = (MOD + 1) / 2
    long long inv2 = (MOD + 1) / 2;
    sum_r = (sum_r * inv2) % MOD;

    // Sum of (k*b + 1) for k from 1 to a
    // This is sum(k*b) + sum(1)
    // = b * sum(k) + a
    // = b * a * (a+1) / 2 + a

    long long sum_kb_plus_1 = (a % MOD * ((a + 1) % MOD)) % MOD; // a * (a+1)
    sum_kb_plus_1 = (sum_kb_plus_1 * inv2) % MOD; // a * (a+1) / 2
    sum_kb_plus_1 = (sum_kb_plus_1 * (b % MOD)) % MOD; // b * a * (a+1) / 2

    long long term_a = a % MOD;
    sum_kb_plus_1 = (sum_kb_plus_1 + term_a) % MOD; // b * a * (a+1) / 2 + a

    long long total_sum = (sum_r * sum_kb_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
