void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length(); ++i) {
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited;
    char start_char = '\0';

    // Find a starting character for a path (degree 1 or 0)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() <= 1) {
            start_char = c;
            break;
        }
    }

    // If no char with degree <= 1, it means all chars in 's' have degree 2.
    // This implies a cycle, which is not possible for a linear layout.
    // However, the problem constraints (no adjacent equal chars) and the
    // fact that we are building a path, not a general graph, means
    // we should always find a start_char if a valid path exists.
    // If s is empty or has one char, start_char will be 'a' (or any char not in s).
    // If s has multiple chars, and all chars in s have degree 2, it means
    // the graph formed by s is a cycle. A cycle cannot be embedded in a line.
    // Example: abcda -> a-b-c-d-a. 'a' has neighbors 'b' and 'd'.
    // 'b' has neighbors 'a' and 'c'. 'c' has neighbors 'b' and 'd'.
    // 'd' has neighbors 'c' and 'a'. All have degree 2.
    // This case should result in NO.
    // Let's re-evaluate: if all chars in `adj` have degree 2, it means `s` forms a cycle.
    // A cycle cannot be a path. So, if `start_char` is still `\0` after checking `adj`,
    // it means all chars in `s` have degree 2. This is an invalid case.
    // Example: abcda. a-b, b-c, c-d, d-a.
    // adj['a'] = {b,d}, adj['b'] = {a,c}, adj['c'] = {b,d}, adj['d'] = {c,a}.
    // All have degree 2. This should be NO.
    // The loop for start_char should find a char with degree <= 1 *among those present in adj*.
    // If s is "abcda", then 'a' has degree 2, 'b' has degree 2, 'c' has degree 2, 'd' has degree 2.
    // In this case, start_char will remain '\0'.
    // This is the condition for "NO".

    // If s is not empty, and all characters in adj have degree 2, it's a cycle.
    // This means start_char will remain '\0' after the loop.
    // This is the "NO" case.
    bool all_degree_2_in_s = true;
    if (!s.empty()) {
        for (char c : s) {
            if (adj[c].size() <= 1) {
                all_degree_2_in_s = false;
                break;
            }
        }
    } else { // s is empty, consider it valid, start_char will be 'a'
        all_degree_2_in_s = false;
    }

    if (all_degree_2_in_s) {
        std::cout << "NO\n";
        return;
    }

    // If start_char is still '\0', it means s was empty or only had one character.
    // In this case, any character can be the start. Let's pick 'a'.
    if (start_char == '\0') {
        start_char = 'a';
    }

    char current_char = start_char;
    while (visited.size() < adj.size()) { // Iterate through all chars that appeared in s
        if (visited.count(current_char)) {
            // This means we've encountered a cycle or a disconnected component
            // that cannot be part of a single path.
            // This should be caught by the degree check earlier, but as a safeguard.
            std::cout << "NO\n";
            return;
        }
        layout_str += current_char;
        visited.insert(current_char);

        char next_char = '\0';
        if (adj.count(current_char)) {
            for (char neighbor : adj[current_char]) {
                if (!visited.count(neighbor)) {
                    next_char = neighbor;
                    break;
                }
            }
        }

        if (next_char == '\0') { // End of path for this component
            break;
        }
        current_char = next_char;
    }

    // Add remaining characters not in 's' or not part of the main path
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited.count(c)) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        // This should ideally not happen if logic is correct, but as a safeguard.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
