#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <iomanip>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute all cyclic shifts of s
    std::vector<std::string> shifts(L);
    for (int k = 0; k < L; ++k) {
        shifts[k].resize(L);
        for (int i = 0; i < L; ++i) {
            shifts[k][i] = s[(k + i) % L];
        }
    }

    // Group shifts by their first character
    std::map<char, std::vector<int>> k_indices_by_first_char;
    for (int k = 0; k < L; ++k) {
        k_indices_by_first_char[shifts[k][0]].push_back(k);
    }

    double total_winning_probability = 0.0;

    // Iterate through each possible first character c0
    for (auto const& [c0, possible_ks_for_c0] : k_indices_by_first_char) {
        int num_possible_k_for_c0 = possible_ks_for_c0.size();

        if (num_possible_k_for_c0 == 1) {
            // If only one k matches c0, Vasya wins immediately for this c0.
            total_winning_probability += 1.0;
            continue;
        }

        // If multiple k's match c0, Vasya needs to choose a position p.
        // He wants to maximize the probability of winning for this c0.
        double max_win_prob_for_c0 = 0.0;

        // Iterate through all possible positions p (from 1 to L-1)
        for (int p = 1; p < L; ++p) {
            // Group the remaining possible k's by their character at position p
            std::map<char, std::vector<int>> k_indices_by_char_at_p;
            for (int k_val : possible_ks_for_c0) {
                k_indices_by_char_at_p[shifts[k_val][p]].push_back(k_val);
            }

            // Calculate winning probability for this specific p
            double current_p_win_prob = 0.0;
            for (auto const& [cp, final_possible_ks] : k_indices_by_char_at_p) {
                if (final_possible_ks.size() == 1) {
                    current_p_win_prob += 1.0;
                }
            }
            current_p_win_prob /= num_possible_k_for_c0; // Normalize by the number of k's that led to this c0

            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, current_p_win_prob);
        }
        total_winning_probability += max_win_prob_for_c0;
    }

    // Normalize by the total number of possible k's (which is L)
    total_winning_probability /= L;

    std::cout << std::fixed << std::setprecision(15) << total_winning_probability << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial counts
    int initial_s = 0;
    int initial_b = 0;
    for (int x : a) {
        if (x == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    // If counts are already equal, 0 jars need to be removed
    if (initial_s == initial_b) {
        std::cout << 0 << std::endl;
        return;
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // s_count[i] = count of 1s in a[0...i-1]
    // b_count[i] = count of 2s in a[0...i-1]
    // diff_left[i] = s_count[i] - b_count[i] for jars a[0...i-1]
    // This means diff_left[k] is the difference for the first k jars (a[0]...a[k-1])
    std::vector<int> diff_left(n + 1, 0);
    int current_s = 0;
    int current_b = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_left[i + 1] = current_s - current_b;
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // s_count_right[i] = count of 1s in a[i...2n-1]
    // b_count_right[i] = count of 2s in a[i...2n-1]
    // diff_right[k] = s_count_right[2n-k...2n-1] - b_count_right[2n-k...2n-1]
    // This means diff_right[k] is the difference for the last k jars (a[2n-k]...a[2n-1])
    std::vector<int> diff_right(n + 1, 0);
    current_s = 0;
    current_b = 0;
    for (int i = 2 * n - 1; i >= n; --i) {
        if (a[i] == 1) {
            current_s++;
        } else {
            current_b++;
        }
        diff_right[2 * n - i] = current_s - current_b;
    }

    // Store indices for each difference value from the left half
    // map: difference_value -> minimum_k_jars_removed_from_left
    // k_jars_removed_from_left means jars a[n-k]...a[n-1] are removed.
    // The remaining left part is a[0]...a[n-k-1].
    // The difference for this remaining part is diff_left[n-k].
    std::map<int, int> left_diff_to_removed_count;
    for (int k_removed_left = 0; k_removed_left <= n; ++k_removed_left) {
        int remaining_left_jars = n - k_removed_left;
        int current_diff = diff_left[remaining_left_jars];
        if (left_diff_to_removed_count.find(current_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_diff] = k_removed_left;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through possible number of jars removed from the right
    // k_removed_right means jars a[n]...a[n+k_removed_right-1] are removed.
    // The remaining right part is a[n+k_removed_right]...a[2n-1].
    // The difference for this remaining part is diff_right[n-k_removed_right].
    for (int k_removed_right = 0; k_removed_right <= n; ++k_removed_right) {
        int remaining_right_jars = n - k_removed_right;
        int current_diff_right = diff_right[remaining_right_jars];

        // The total difference needed for the remaining jars (left + right) to be 0
        // is (diff_left_remaining + diff_right_remaining) = 0
        // So, diff_left_remaining = -diff_right_remaining
        int target_diff_left = -current_diff_right;

        if (left_diff_to_removed_count.count(target_diff_left)) {
            int k_removed_left = left_diff_to_removed_count[target_diff_left];
            min_removed_jars = std::min(min_removed_jars, k_removed_left + k_removed_right);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (only endpoints)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, 0); // left_ones[i] = count of consecutive 1s ending at i
    std::vector<int> right_ones(n, 0); // right_ones[i] = count of consecutive 1s starting at i
    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive 0s ending at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive 0s starting at i

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = (i > 0 ? left_ones[i - 1] : 0) + 1;
        } else {
            left_zeros[i] = (i > 0 ? left_zeros[i - 1] : 0) + 1;
        }
    }

    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = (i < n - 1 ? right_ones[i + 1] : 0) + 1;
        } else {
            right_zeros[i] = (i < n - 1 ? right_zeros[i + 1] : 0) + 1;
        }
    }

    int max_len_ones = 0;
    int max_len_zeros = 0;

    for (int i = 0; i < n; ++i) {
        max_len_ones = std::max(max_len_ones, left_ones[i]);
        max_len_zeros = std::max(max_len_zeros, left_zeros[i]);
    }

    int max_k = 0;
    if (max_len_ones > 0) {
        max_k = std::max(max_k, (max_len_ones - 1) / 2);
    }
    if (max_len_zeros > 0) {
        max_k = std::max(max_k, (max_len_zeros - 1) / 2);
    }

    std::vector<int> b = a;
    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 0) { // Current is 0, can become 1 if surrounded by 1s
            if (left_ones[i - 1] >= max_k + 1 && right_ones[i + 1] >= max_k + 1) {
                b[i] = 1;
            }
        } else { // Current is 1, can become 0 if surrounded by 0s
            if (left_zeros[i - 1] >= max_k + 1 && right_zeros[i + 1] >= max_k + 1) {
                b[i] = 0;
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits set (0b1111111111)
    int current_or_mask = 0;    // All bits clear (0b0000000000)
    int current_xor_mask = 0;   // All bits clear (0b0000000000)

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;

    // Determine the final state of each bit for input 0 and input 1
    // For an input x, the j-th bit of the output is:
    // (x_j & (current_and_mask_j)) | (current_or_mask_j) ^ (current_xor_mask_j)
    // This is equivalent to:
    // (x_j & A_j) ^ B_j
    // where A_j = current_and_mask_j
    // and B_j = current_or_mask_j ^ current_xor_mask_j

    // We need to find A and B such that for any x_j:
    // (x_j & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    // is equivalent to (x_j & A_j) ^ B_j

    // Let's test for x_j = 0 and x_j = 1
    // If x_j = 0:
    // (0 & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    // = 0 | current_or_mask_j ^ current_xor_mask_j
    // = current_or_mask_j ^ current_xor_mask_j
    // This must be equal to (0 & A_j) ^ B_j = B_j
    // So, B_j = current_or_mask_j ^ current_xor_mask_j

    // If x_j = 1:
    // (1 & current_and_mask_j) | current_or_mask_j ^ current_xor_mask_j
    // = current_and_mask_j | current_or_mask_j ^ current_xor_mask_j
    // This must be equal to (1 & A_j) ^ B_j = A_j ^ B_j
    // So, A_j ^ B_j = current_and_mask_j | current_or_mask_j ^ current_xor_mask_j
    // A_j = (current_and_mask_j | current_or_mask_j ^ current_xor_mask_j) ^ B_j
    // A_j = (current_and_mask_j | current_or_mask_j ^ current_xor_mask_j) ^ (current_or_mask_j ^ current_xor_mask_j)
    // Let C_j = current_or_mask_j ^ current_xor_mask_j
    // A_j = (current_and_mask_j | C_j) ^ C_j

    // Calculate the effective A and B for the simplified form (x & A) ^ B
    int final_B = 0;
    int final_A = 0;

    for (int j = 0; j < 10; ++j) {
        int bit_0_val = ((0 & ((current_and_mask >> j) & 1)) | ((current_or_mask >> j) & 1)) ^ ((current_xor_mask >> j) & 1);
        int bit_1_val = ((1 & ((current_and_mask >> j) & 1)) | ((current_or_mask >> j) & 1)) ^ ((current_xor_mask >> j) & 1);

        // If bit_0_val == 0 and bit_1_val == 0: (x_j & 0) ^ 0 = 0
        // If bit_0_val == 0 and bit_1_val == 1: (x_j & 1) ^ 0 = x_j
        // If bit_0_val == 1 and bit_1_val == 0: (x_j & 1) ^ 1 = ~x_j (for this bit)
        // If bit_0_val == 1 and bit_1_val == 1: (x_j & 0) ^ 1 = 1

        if (bit_0_val == 0 && bit_1_val == 1) { // x_j -> x_j
            final_A |= (1 << j);
            final_B |= (0 << j);
        } else if (bit_0_val == 1 && bit_1_val == 0) { // x_j -> ~x_j
            final_A |= (1 << j);
            final_B |= (1 << j);
        } else if (bit_0_val == 0 && bit_1_val == 0) { // x_j -> 0
            final_A |= (0 << j);
            final_B |= (0 << j);
        } else if (bit_0_val == 1 && bit_1_val == 1) { // x_j -> 1
            final_A |= (0 << j);
            final_B |= (1 << j);
        }
    }

    // Now we have the target transformation (x & final_A) ^ final_B
    // We need to represent this using at most 5 operations.
    // The standard way is:
    // 1. OR with (final_B & ~final_A)
    // 2. XOR with final_B
    // 3. AND with final_A
    // This is not quite right. Let's re-evaluate.

    // The form (x & A) ^ B can be achieved with at most 3 operations:
    // 1. OR with (B & ~A)
    // 2. AND with A
    // 3. XOR with B
    // Let's verify this:
    // x' = x | (B & ~A)
    // x'' = x' & A = (x | (B & ~A)) & A = (x & A) | ((B & ~A) & A) = (x & A) | 0 = x & A
    // x''' = x'' ^ B = (x & A) ^ B
    // This works!

    // So, the three operations are:
    // 1. | (final_B & ~final_A)
    // 2. & final_A
    // 3. ^ final_B

    int or_val = final_B & (~final_A);
    int and_val = final_A;
    int xor_val = final_B;

    if (or_val != 0) {
        simplified_ops.push_back({'|', or_val});
    }
    if (and_val != 1023) { // If final_A is 1023, then & 1023 is a no-op
        simplified_ops.push_back({'&', and_val});
    }
    if (xor_val != 0) { // If final_B is 0, then ^ 0 is a no-op
        simplified_ops.push_back({'^', xor_val});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a_initial(n, std::numeric_limits<long long>::max());

    // Process type 2 operations to find upper bounds for a_initial[i]
    // a_initial[j] + current_delta[j] <= m
    // a_initial[j] <= m - current_delta[j]
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 2) {
            long long current_delta_val = 0;
            for (int k = 0; k < i; ++k) {
                if (ops[k].type == 1 && ops[k].l <= ops[i].r && ops[k].r >= ops[i].l) {
                    // This type 1 operation affects the range [ops[i].l, ops[i].r]
                    // We need to find the minimum delta applied to any element in [ops[i].l, ops[i].r]
                    // by operations before current type 2 op.
                    // This is incorrect. We need the delta for each specific j.
                    // The logic for type 2 is: a_initial[j] <= m - delta_j_at_this_point
                    // So we need to calculate delta_j_at_this_point for each j in [ops[i].l, ops[i].r]
                    // and update a_initial[j] = min(a_initial[j], m - delta_j_at_this_point).
                }
            }

            // Recalculate delta for each j in [ops[i].l, ops[i].r]
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                long long delta_j_at_this_point = 0;
                for (int k = 0; k < i; ++k) {
                    if (ops[k].type == 1 && j >= ops[k].l && j <= ops[k].r) {
                        delta_j_at_this_point += ops[k].val;
                    }
                }
                a_initial[j] = std::min(a_initial[j], ops[i].val - delta_j_at_this_point);
            }
        }
    }

    // If a_initial[j] is still max_long_long, it means it was never constrained by a type 2 operation.
    // We can set it to 0, as it satisfies |a_i| <= 10^9.
    for (int i = 0; i < n; ++i) {
        if (a_initial[i] == std::numeric_limits<long long>::max()) {
            a_initial[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> current_a = a_initial;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += ops[i].val;
            }
        } else { // type == 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, current_a[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Check initial values constraints
    for (int i = 0; i < n; ++i) {
        if (a_initial[i] < -1000000000LL || a_initial[i] > 1000000000LL) {
            std::cout << "NO\n";
            return 0;
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> a_orig(n); // a_orig[0] is unused, a_orig[i] stores a_{i+1}
    for (int i = 1; i < n; ++i) {
        std::cin >> a_orig[i];
    }

    std::vector<long long> dp_y(n + 1, -1); // dp_y[x] stores y if starting at x and moving to x+a_x, then x-a_x, etc.
    std::vector<int> dp_x(n + 1, 0); // dp_x[x] stores final x if starting at x and moving to x+a_x, then x-a_x, etc.
    std::vector<bool> visited(n + 1, false); // For cycle detection during DP calculation
    std::vector<bool> in_stack(n + 1, false); // For cycle detection during DP calculation

    // Iterate backwards to fill DP table
    // x_start is the value of x at the beginning of a step 2/3 pair.
    // The problem states x is 1-indexed, so we use 1 to n.
    for (int x_start = n; x_start >= 1; --x_start) {
        if (dp_y[x_start] != -1) { // Already computed or known to be -1 (cycle)
            continue;
        }

        std::vector<int> path;
        int current_x = x_start;
        long long current_y_accum = 0; // Accumulates y for the current path segment

        while (current_x >= 1 && current_x <= n && !visited[current_x] && !in_stack[current_x]) {
            path.push_back(current_x);
            in_stack[current_x] = true;

            long long val_a_x = a_orig[current_x - 1]; // a_x is a_orig[x-1]

            // Step 2: x = x + val_a_x, y = y + val_a_x
            long long next_x_after_step2 = current_x + val_a_x;
            current_y_accum += val_a_x;

            // Check termination after step 2
            if (next_x_after_step2 <= 0 || next_x_after_step2 > n) {
                // Terminates. This path segment leads to termination.
                // All nodes in path get this current_y_accum and final_x = next_x_after_step2.
                for (int node : path) {
                    dp_y[node] = current_y_accum;
                    dp_x[node] = next_x_after_step2;
                    visited[node] = true;
                    in_stack[node] = false;
                }
                current_x = -1; // Mark as terminated
                break;
            }

            // Step 3: x = x - val_a_x, y = y + val_a_x
            val_a_x = a_orig[next_x_after_step2 - 1]; // a_{next_x_after_step2}
            long long next_x_after_step3 = next_x_after_step2 - val_a_x;
            current_y_accum += val_a_x;

            // Check termination after step 3
            if (next_x_after_step3 <= 0 || next_x_after_step3 > n) {
                // Terminates.
                for (int node : path) {
                    dp_y[node] = current_y_accum;
                    dp_x[node] = next_x_after_step3;
                    visited[node] = true;
                    in_stack[node] = false;
                }
                current_x = -1; // Mark as terminated
                break;
            }
            current_x = next_x_after_step3;
        }

        if (current_x != -1) { // If loop terminated because of visited or in_stack
            if (in_stack[current_x]) { // Cycle detected
                for (int node : path) {
                    dp_y[node] = -1; // Mark as non-terminating
                    dp_x[node] = 0; // Or any other indicator for non-terminating
                    visited[node] = true;
                    in_stack[node] = false;
                }
            } else { // Hit an already computed state (current_x is visited but not in_stack)
                long long final_y_from_computed = dp_y[current_x];
                long long final_x_from_computed = dp_x[current_x];

                for (int node : path) {
                    if (final_y_from_computed == -1) { // If the computed state leads to non-termination
                        dp_y[node] = -1;
                        dp_x[node] = 0;
                    } else {
                        dp_y[node] = current_y_accum + final_y_from_computed;
                        dp_x[node] = final_x_from_computed;
                    }
                    visited[node] = true;
                    in_stack[node] = false;
                }
            }
        }
    }

    for (int i = 1; i < n; ++i) {
        a_orig[0] = i; // Set a_1 for this run

        long long current_x = 1;
        long long total_y = 0;

        // Step 2: x = x + a_1, y = y + a_1
        long long val_a_1 = a_orig[0];
        current_x += val_a_1;
        total_y += val_a_1;

        // Check termination after step 2
        if (current_x <= 0 || current_x > n) {
            std::cout << total_y << "\n";
            continue;
        }

        // Step 3: x = x - a_x, y = y + a_x
        long long val_a_current_x = a_orig[current_x - 1];
        current_x -= val_a_current_x;
        total_y += val_a_current_x;

        // Check termination after step 3
        if (current_x <= 0 || current_x > n) {
            std::cout << total_y << "\n";
            continue;
        }

        // Now current_x is the state where the DP table can be used
        if (dp_y[current_x] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << total_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v, d, p;
    bool in_queue;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_queue = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_queue) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_queue = false;

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_queue) {
                continue;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Apply total_d_cry_from_leaving effect
            children[j].p -= total_d_cry_from_leaving;

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_queue = false;
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

