bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The smallest possible value for the current element a[i]
                            // such that it is >= the previous element and <= m-1.
                            // This is effectively the target value for a[i] after operations.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // Case 1: current_a is already >= prev_val.
        // We need to ensure that (current_a + v_i) % m >= prev_val.
        // The smallest possible value for (current_a + v_i) % m is current_a itself (if v_i=0).
        // If current_a >= prev_val, we can potentially keep it as current_a (by choosing v_i=0).
        // We need to check if we can achieve prev_val or more.
        // If current_a >= prev_val, we can set v_i = 0, and the new value is current_a.
        // This is valid if 0 <= x.
        // The new value will be current_a.
        // We must ensure that current_a is not too large such that it cannot be made prev_val.
        // If current_a >= prev_val, we can potentially keep it as current_a.
        // The number of increments needed is 0.
        // The maximum value we can achieve is (current_a + x) % m.
        // If current_a >= prev_val, we can just keep it as current_a.
        // The number of increments needed is 0.
        // This is always possible if x >= 0.
        // So, if current_a >= prev_val, we can potentially use current_a as the new prev_val.
        // We need to check if current_a can be made prev_val.
        // This is true if current_a >= prev_val.
        // The number of increments needed is 0.
        // This is valid if 0 <= x.

        // Case 2: current_a < prev_val.
        // We must increment current_a.
        // We need to find v_i such that (current_a + v_i) % m >= prev_val.
        // The smallest such v_i would make (current_a + v_i) % m equal to prev_val.
        // This means current_a + v_i = prev_val or current_a + v_i = prev_val + m.
        // If current_a + v_i = prev_val, then v_i = prev_val - current_a.
        // If current_a + v_i = prev_val + m, then v_i = prev_val + m - current_a.
        // The smallest non-negative v_i that makes (current_a + v_i) % m >= prev_val is:
        // If current_a >= prev_val: v_i = 0. The new value is current_a.
        // If current_a < prev_val: v_i = prev_val - current_a. The new value is prev_val.
        // This v_i must be <= x.

        // Let's simplify. We want to find a value `target_val` for `a[i]` such that `target_val >= prev_val` and `target_val` can be achieved from `a[i]` with at most `x` operations.
        // The possible values for `a[i]` after operations are `(a[i] + v) % m` where `0 <= v <= x`.

        // If `a[i]` is already greater than or equal to `prev_val`:
        // We can potentially keep `a[i]` as `a[i]`. This requires `v=0` operations.
        // This is valid if `0 <= x`.
        // So, if `a[i] >= prev_val`, we can set `prev_val = a[i]` for the next iteration.
        // However, we must also consider if `a[i]` can be made smaller to `prev_val` by adding `v` operations.
        // For example, if `a[i] = 5`, `m = 7`, `prev_val = 0`, `x = 1`.
        // `a[i] >= prev_val` is true. We can keep `a[i]` as 5. `prev_val` becomes 5.
        // But we could also increment `a[i]` by 1 to `(5+1)%7 = 6`.
        // Or we could increment `a[i]` by `v` such that `(a[i]+v)%m` is `prev_val`.
        // This is `(5+v)%7 = 0`. `v=2`. But `v` must be `<= x`.
        // This is the core logic:
        // We need to find `v_i` such that `0 <= v_i <= x` and `(a[i] + v_i) % m >= prev_val`.
        // We want to make `(a[i] + v_i) % m` as small as possible, but at least `prev_val`.

        // Option 1: Don't increment `a[i]` enough to wrap around `m`.
        // The new value would be `a[i] + v_i`.
        // We need `a[i] + v_i >= prev_val`.
        // The minimum `v_i` for this is `max(0LL, prev_val - current_a)`.
        // If this `v_i <= x`, then we can achieve `max(current_a, prev_val)`.
        // In this case, the new `prev_val` for the next iteration would be `max(current_a, prev_val)`.

        // Option 2: Increment `a[i]` such that it wraps around `m`.
        // The new value would be `(a[i] + v_i) % m`.
        // This means `a[i] + v_i = K*m + target_val` for some `K >= 1`.
        // The smallest `v_i` to achieve a value `target_val` after wrap-around is `target_val + m - current_a`.
        // This `v_i` must be `<= x`.
        // If `target_val + m - current_a <= x`, then we can achieve `target_val`.
        // We want `target_val >= prev_val`.
        // The smallest `target_val` we can achieve this way is `0`.
        // If `0 + m - current_a <= x`, then we can achieve `0`.
        // If `prev_val + m - current_a <= x`, then we can achieve `prev_val`.

        // Let's consider the two possibilities for the final value of `a[i]`:
        // 1. The final value `val_i` is `a[i] + v_i` (no wrap-around).
        //    We need `val_i >= prev_val`.
        //    The minimum `v_i` required is `max(0LL, prev_val - current_a)`.
        //    If this `v_i <= x`, then we can achieve `max(current_a, prev_val)`.
        //    In this case, the new `prev_val` for the next iteration would be `max(current_a, prev_val)`.
        // 2. The final value `val_i` is `(a[i] + v_i) % m` (with wrap-around).
        //    This means `a[i] + v_i >= m`.
        //    We need `val_i >= prev_val`.
        //    The smallest `v_i` to achieve `val_i` is `val_i + m - current_a`.
        //    If `val_i + m - current_a <= x`, then we can achieve `val_i`.
        //    We want to achieve the smallest possible `val_i` that is `>= prev_val`.
        //    The smallest `val_i` we can achieve is `0`.
        //    If `0 + m - current_a <= x`, then we can achieve `0`.
        //    If `prev_val + m - current_a <= x`, then we can achieve `prev_val`.

        // Let's combine:
        // We need to find `v_i` such that `0 <= v_i <= x` and `(current_a + v_i) % m >= prev_val`.
        // If `current_a >= prev_val`:
        //   We can choose `v_i = 0`. Then `(current_a + 0) % m = current_a`. This is `>= prev_val`.
        //   This is valid if `0 <= x`.
        //   So, if `current_a >= prev_val`, we can potentially keep `current_a` as the value.
        //   However, we must also check if we can make it `prev_val` by incrementing.
        //   If `current_a + x >= m + prev_val` (i.e., `x >= m + prev_val - current_a`),
        //   then we can increment `current_a` enough to wrap around `m` and become `prev_val`.
        //   In this case, we can choose `prev_val` as the new `prev_val`.
        //   Otherwise, we must choose `current_a` as the new `prev_val`.
        //   So, if `current_a >= prev_val`:
        //     If `current_a + x >= m + prev_val` (meaning we can reach `prev_val` by wrapping around),
        //       then `prev_val` remains `prev_val`.
        //     Else (we cannot reach `prev_val` by wrapping around, or it's not necessary),
        //       then `prev_val` becomes `current_a`.
        //   This logic is flawed. We want to make `a[i]` as small as possible, but at least `prev_val`.
        //   If `current_a >= prev_val`:
        //     We can choose `v_i = 0`. The value becomes `current_a`. This is valid.
        //     Can we make it `prev_val`? Yes, if `current_a + x >= m + prev_val`.
        //     If `current_a + x >= m + prev_val`, it means we can increment `current_a` by `m + prev_val - current_a` operations.
        //     This number of operations is `m + prev_val - current_a`. If this is `<= x`, we can make it `prev_val`.
        //     So, if `current_a >= prev_val` AND `current_a + x < m + prev_val` (i.e., `x < m + prev_val - current_a`),
        //     it means we cannot wrap around and reach `prev_val`.
        //     In this case, we must keep `current_a` as the new `prev_val`.
        //     Otherwise (if `current_a + x >= m + prev_val`), we can make it `prev_val`.
        //     So, if `current_a >= prev_val` and `current_a + x < m + prev_val`, then `prev_val = current_a`.
        //     Else, `prev_val` remains `prev_val`.

        // If `current_a < prev_val`:
        //   We must increment `current_a`.
        //   We need `(current_a + v_i) % m >= prev_val`.
        //   The smallest `v_i` to make `(current_a + v_i) % m` equal to `prev_val` is `prev_val - current_a`.
        //   This `v_i` must be `<= x`.
        //   If `prev_val - current_a <= x`, then we can make `a[i]` equal to `prev_val`.
        //   So, `prev_val` remains `prev_val`.
        //   If `prev_val - current_a > x`, then we cannot make `a[i]` equal to `prev_val` without wrapping around.
        //   In fact, we cannot make `a[i]` equal to `prev_val` at all.
        //   The maximum value we can achieve is `(current_a + x) % m`.
        //   If `current_a + x < m`, then `(current_a + x) % m = current_a + x`.
        //   If `current_a + x >= m`, then `(current_a + x) % m` could be anything from `0` to `m-1`.
        //   If `current_a < prev_val` and `prev_val - current_a > x`, it means we cannot reach `prev_val` without wrapping.
        //   And even with wrapping, we can only reach `(current_a + x) % m`.
        //   If `prev_val - current_a > x`, it means we cannot reach `prev_val` by just adding `x`.
        //   So, `current_a + x < prev_val`.
        //   This means `(current_a + x) % m` will be `current_a + x` (if no wrap) or some value after wrap.
        //   If `current_a + x < prev_val`, then it's impossible to make `a[i]` at least `prev_val`.
        //   So, return `false`.

        // Let's try a simpler logic:
        // For each `a[i]`, we want to find the smallest `target_val` such that:
        // 1. `target_val >= prev_val`
        // 2. `target_val` can be obtained from `a[i]` by adding `v_i` operations, where `0 <= v_i <= x`.
        //    This means `(a[i] + v_i) % m = target_val`.
        //    The number of operations `v_i` is `(target_val - a[i] + m) % m`.
        //    So we need `(target_val - a[i] + m) % m <= x`.

        // If `a[i] >= prev_val`:
        //   We have two choices for `target_val`:
        //   a) `target_val = prev_val`. This requires `v_i = (prev_val - a[i] + m) % m` operations.
        //      If `prev_val <= a[i]`, then `v_i = prev_val - a[i] + m`. This is the wrap-around case.
        //      If `prev_val > a[i]`, this is not possible.
        //      No, `(prev_val - a[i] + m) % m` is the number of increments to go from `a[i]` to `prev_val`.
        //      If `a[i] <= prev_val`, then `v_i = prev_val - a[i]`.
        //      If `a[i] > prev_val`, then `v_i = prev_val - a[i] + m`.
        //      This is the number of increments to make `a[i]` exactly `prev_val`.
        //      If `v_i <= x`, then we can make `a[i]` equal to `prev_val`.
        //      So, if `(prev_val - a[i] + m) % m <= x`, we can set `prev_val` to `prev_val`.
        //   b) `target_val = a[i]`. This requires `v_i = 0` operations.
        //      This is always `<= x` (since `x >= 0`).
        //      So we can always set `prev_val` to `a[i]`.

        //   If `a[i] >= prev_val`:
        //     We want to keep `prev_val` as small as possible.
        //     Can we keep `prev_val` as `prev_val`?
        //     This means we need to find `v_i` such that `(a[i] + v_i) % m = prev_val`.
        //     The number of operations for this is `(prev_val - a[i] + m) % m`.
        //     If `(prev_val - a[i] + m) % m <= x`, then we can achieve `prev_val`.
        //     So, `prev_val` remains `prev_val`.
        //     Otherwise, we cannot achieve `prev_val` by wrapping around.
        //     Since `a[i] >= prev_val`, we can just keep `a[i]` as `a[i]` (0 operations).
        //     So, `prev_val` becomes `a[i]`.
        //     This is equivalent to: if `a[i] + x < m + prev_val`, then `prev_val = a[i]`.
        //     Otherwise, `prev_val` remains `prev_val`.

        // If `a[i] < prev_val`:
        //   We must increment `a[i]`.
        //   We need `(a[i] + v_i) % m >= prev_val`.
        //   The smallest `v_i` to make `(a[i] + v_i) % m` equal to `prev_val` is `prev_val - a[i]`.
        //   If `prev_val - a[i] <= x`, then we can achieve `prev_val`.
        //   So, `prev_val` remains `prev_val`.
        //   Otherwise (`prev_val - a[i] > x`), we cannot achieve `prev_val`.
        //   This means `a[i] + x < prev_val`.
        //   Even if we increment `a[i]` by `x`, the value `a[i] + x` is still less than `prev_val`.
        //   And since `a[i] + x < m` (because `prev_val <= m-1` and `a[i] + x < prev_val`), there is no wrap-around.
        //   So, it's impossible to make `a[i]` at least `prev_val`. Return `false`.

        // Combining these:
        if (current_a >= prev_val) {
            // current_a is already >= prev_val.
            // We want to keep prev_val as small as possible.
            // Can we make current_a become prev_val by incrementing?
            // This requires `v_i = (prev_val - current_a + m) % m` operations.
            // If `prev_val <= current_a`, then `v_i = prev_val - current_a + m`.
            // If `prev_val > current_a`, then `v_i = prev_val - current_a`.
            // This is `v_i = (prev_val - current_a + m) % m`.
            // If `v_i <= x`, then we can make `a[i]` equal to `prev_val`.
            // So, `prev_val` remains `prev_val`.
            // Otherwise, we cannot make `a[i]` equal to `prev_val` with `x` operations.
            // Since `current_a >= prev_val`, we must use `current_a` as the new `prev_val`.
            // So, `prev_val` becomes `current_a`.
            // This can be written as:
            // If `current_a + x < m + prev_val` (meaning we cannot reach `prev_val` by wrapping around),
            // then `prev_val = current_a`.
            // Else, `prev_val` remains `prev_val`.
            // This is equivalent to:
            // If `current_a + x < m + prev_val` (i.e., `x < m + prev_val - current_a`),
            // then `prev_val = current_a`.
            // Else, `prev_val` remains `prev_val`.
            // This is the same as: if `current_a + x < m + prev_val`, then `prev_val = current_a`.
            // This is also equivalent to: if `current_a + x < m` and `current_a < prev_val` (which is not this branch),
            // or if `current_a + x >= m` and `(current_a + x) % m < prev_val`.
            // Let's use the `v_i` logic.
            // `v_i_to_prev = (prev_val - current_a + m) % m`.
            // If `v_i_to_prev <= x`, then we can make `a[i]` equal to `prev_val`.
            // So `prev_val` stays `prev_val`.
            // Else, we cannot make `a[i]` equal to `prev_val`.
            // Since `current_a >= prev_val`, we must use `current_a` as the new `prev_val`.
            // So `prev_val = current_a`.
            if ((prev_val - current_a + m) % m > x) {
                prev_val = current_a;
            }
        } else { // current_a < prev_val
            // We must increment current_a.
            // We need `(current_a + v_i) % m >= prev_val`.
            // The minimum `v_i` to make `(current_a + v_i) % m` equal to `prev_val` is `prev_val - current_a`.
            // If `prev_val - current_a <= x`, then we can achieve `prev_val`.
            // So `prev_val` stays `prev_val`.
            // Otherwise (`prev_val - current_a > x`), we cannot achieve `prev_val`.
            // This means `current_a + x < prev_val`.
            // Since `current_a + x < prev_val <= m-1`, there is no wrap-around.
            // The maximum value we can achieve is `current_a + x`.
            // Since `current_a + x < prev_val`, it's impossible to make `a[i]` at least `prev_val`.
            // So, return `false`.
            if (prev_val - current_a > x) {
                return false;
            }
            // If `prev_val - current_a <= x`, we can make `a[i]` equal to `prev_val`.
            // So `prev_val` remains `prev_val`.
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0, high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1).
    // This means all f(a_i, a_j) = a_i + a_j.
    // Min f = a[0].value + a[1].value
    // Max f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    long long goodness_all_same = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value);
    std::vector<int> partition_all_same(n, 1);

    // Case 2: Partition where a[0] is in one subsequence (e.g., 1) and all others are in the other (e.g., 2).
    // This is a specific partition strategy that often works well when h is large.
    // Elements: a[0] in S1, a[1], ..., a[n-1] in S2.
    //
    // Possible f values:
    // 1. a_i + a_j for i, j in S2 (i.e., a[1]...a[n-1]):
    //    Min: a[1].value + a[2].value
    //    Max: a[n-1].value + a[n-2].value
    // 2. a_i + a_j + h for i in S1, j in S2 (i.e., a[0] with any of a[1]...a[n-1]):
    //    Min: a[0].value + a[1].value + h
    //    Max: a[0].value + a[n-1].value + h
    //
    // Overall min f: min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    // Overall max f: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)
    //
    // This strategy is optimal when h is large enough that it's better to put all elements
    // into one group, or isolate one element.
    //
    // Let's consider a specific partition: a[0] in S1, a[1]...a[n-1] in S2.
    // The minimum possible sum of two elements from S2 is a[1].value + a[2].value.
    // The maximum possible sum of two elements from S2 is a[n-1].value + a[n-2].value.
    // The minimum possible sum of two elements from different subsequences is a[0].value + a[1].value + h.
    // The maximum possible sum of two elements from different subsequences is a[0].value + a[n-1].value + h.
    //
    // The overall minimum f value for this partition is min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    // The overall maximum f value for this partition is max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    //
    // The goodness for this partition is:
    // max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h) - min(a[1].value + a[2].value, a[0].value + a[1].value + h)
    //
    // This can be simplified.
    // The smallest possible sum is `a[0].value + a[1].value`.
    // The largest possible sum is `a[n-1].value + a[n-2].value`.
    //
    // If we put `a[0]` in S1 and `a[1]...a[n-1]` in S2:
    // Min f value: `min(a[1].value + a[2].value, a[0].value + a[1].value + h)`
    // Max f value: `max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)`
    //
    // The goodness is `max_f - min_f`.
    //
    // Let's analyze the two critical values:
    // `a[0].value + a[1].value + h` (min cross-subsequence sum)
    // `a[n-1].value + a[n-2].value` (max same-subsequence sum)
    //
    // If `a[0].value + a[1].value + h` is greater than `a[n-1].value + a[n-2].value`,
    // then all cross-subsequence sums are greater than all same-subsequence sums.
    // In this case, the minimum f value is `a[1].value + a[2].value` (from S2).
    // The maximum f value is `a[0].value + a[n-1].value + h` (from S1-S2).
    // Goodness = `(a[0].value + a[n-1].value + h) - (a[1].value + a[2].value)`.
    // This is the "h-dominant" case.

    long long goodness_h_dominant = (a[0].value + a[n-1].value + h) - (a[1].value + a[2].value);
    std::vector<int> partition_h_dominant(n);
    partition_h_dominant[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition_h_dominant[a[i].original_index] = 2;
    }

    // Compare the two strategies
    long long min_goodness;
    std::vector<int> final_partition(n);

    if (goodness_all_same <= goodness_h_dominant) {
        min_goodness = goodness_all_same;
        final_partition = partition_all_same;
    } else {
        min_goodness = goodness_h_dominant;
        final_partition = partition_h_dominant;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

