// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1 (one cut, two pieces)
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // Cut point is after index i-1, so s[0...i-1] and s[i...n-1]
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2 (two cuts, three pieces)
    // This is always possible unless all characters are the same.
    // If all characters are the same, e.g., "aaaa", then any rearrangement
    // of pieces will result in "aaaa".
    // Example: "aaaa" -> "a" + "a" + "aa" -> "a" + "aa" + "a" = "aaaa"
    // Example: "aaaa" -> "aa" + "a" + "a" -> "a" + "aa" + "a" = "aaaa"
    // If all characters are the same, no new palindrome can be formed.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, it's always possible with 2 cuts.
        // Consider s = "abacaba". n=7.
        // Cut 1: s[0] | s[1...n-1] -> "a" | "bacaba"
        // Cut 2: s[0...n-2] | s[n-1] -> "abacab" | "a"
        //
        // A simple strategy for k=2:
        // Cut s into s[0...i-1], s[i], s[i+1...n-1]
        // For example, cut s into s[0...n/2-1], s[n/2], s[n/2+1...n-1]
        // This creates three pieces: prefix, middle char, suffix.
        // Since s is a palindrome, prefix is reverse of suffix.
        // If we swap prefix and suffix, we get a new palindrome.
        // Example: "nolon" (n=5)
        // s1 = "no", s2 = "l", s3 = "on"
        // Rearrange to s3 + s2 + s1 = "on" + "l" + "no" = "onlno"
        // "onlno" is a palindrome and "onlno" != "nolon".
        // This works as long as not all characters are the same.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // dp[i] will store the maximum 'r' such that the substring s[i...r-1]
    // does NOT contain any triple.
    // Or, more precisely, dp[i] stores the smallest 'r' such that s[i...r-1]
    // contains a triple. If no such r exists, dp[i] = n + 1.
    // We want to find the largest 'r_prime' such that s[i...r_prime-1]
    // does NOT contain a triple. This r_prime would be dp[i] - 1.
    // The number of valid (l, r) pairs starting at l=i+1 (0-indexed i)
    // that do NOT contain a triple is (dp[i] - 1) - (i+1) + 1 = dp[i] - 1 - i.
    // If dp[i] - 1 < i, then this count is 0.
    std::vector<int> dp(n + 1, n + 1); // dp[i] = smallest r (1-indexed) such that s[i...r-1] contains a triple.
                                      // Initialize to n+1, meaning no triple found up to n.

    // Iterate from right to left to fill dp array
    for (int i = n - 1; i >= 0; --i) {
        // Base case: dp[i] is at least dp[i+1]
        // If s[i+1...r-1] contains a triple, then s[i...r-1] also contains it.
        dp[i] = dp[i + 1];

        // Check for triples of the form s[i] = s[i+k] = s[i+2k]
        // Smallest k is 1, largest k is such that i+2k < n.
        // So 2k < n-i => k < (n-i)/2.
        // Max k is (n-i-1)/2.
        // We only need to check small k values because larger k values
        // would mean the triple is very spread out, and if it's the first
        // triple starting at 'i', it's likely a small k.
        // The problem constraints on n (300,000) suggest that checking
        // all k for each i would be O(N^2), which is too slow.
        // However, the maximum 'k' we need to check is small.
        // If s[i] = s[i+k] = s[i+2k], then the 'r' value for this triple is i+2k+1.
        // We are looking for the minimum such 'r'.
        // The maximum 'k' that can affect dp[i] significantly is small.
        // If k is large, say k >= 7, then i+2k >= i+14.
        // If there's a triple s[i] = s[i+k] = s[i+2k], then r = i+2k+1.
        // If there's another triple s[i'] = s[i'+k'] = s[i'+2k'] with i' >= i,
        // and i'+2k'+1 < i+2k+1, then dp[i] would be smaller.
        // The key observation is that if a substring s[l...r] contains a triple,
        // it must contain one where 2k is relatively small.
        // Specifically, if a substring of length L contains a triple, then
        // it must contain one where 2k < 14 (or some small constant).
        // This is because if all triples have 2k >= 14, then the string
        // would have to be very long to contain any triple.
        // The maximum length of a substring that does NOT contain any triple
        // is 13. (e.g., 0011001100110, length 13, no triple of form s_x=s_{x+k}=s_{x+2k}).
        // If a string has length 14 or more, it must contain such a triple.
        // For example, consider any 14 characters.
        // If s[i] == s[i+k] == s[i+2k] for k=1,2,3,4,5,6.
        // We only need to check k up to 6.
        // If k=1, check s[i], s[i+1], s[i+2]. If match, r = i+3.
        // If k=2, check s[i], s[i+2], s[i+4]. If match, r = i+5.
        // If k=3, check s[i], s[i+3], s[i+6]. If match, r = i+7.
        // If k=4, check s[i], s[i+4], s[i+8]. If match, r = i+9.
        // If k=5, check s[i], s[i+5], s[i+10]. If match, r = i+11.
        // If k=6, check s[i], s[i+6], s[i+12]. If match, r = i+13.
        // The maximum index involved is i+12. So we need n >= i+13.
        // This means we only need to check k from 1 up to 6.
        // This makes the inner loop constant time.

        for (int k = 1; k <= 6; ++k) { // k can be up to 6
            if (i + 2 * k < n) { // Check if i+2k is a valid index
                if (s[i] == s[i + k] && s[i + k] == s[i + 2 * k]) {
                    dp[i] = std::min(dp[i], i + 2 * k + 1); // r is 1-indexed
                }
            }
        }
    }

    // Calculate invalid pairs (l, r)
    // An (l, r) pair (1-indexed) is invalid if the substring s[l-1...r-1]
    // does NOT contain any triple.
    // For each starting position l (0-indexed i = l-1),
    // the valid r's (1-indexed) for an invalid pair are l, l+1, ..., dp[i]-1.
    // The number of such r's is (dp[i]-1) - l + 1 = dp[i] - l.
    // If dp[i]-1 < l, then there are 0 such r's.
    // So, for each i from 0 to n-1:
    //   The number of invalid r's (0-indexed) starting at i is (dp[i]-1) - i.
    //   This is equivalent to max(0, dp[i] - (i + 1)).
    for (int i = 0; i < n; ++i) {
        invalid_pairs += std::max(0, dp[i] - (i + 1));
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int head_idx = 0;
    int track_idx = 0;

    while (track_idx < m) {
        if (head_idx >= n) {
            return false; // No more heads to cover remaining tracks
        }

        long long current_head_pos = h[head_idx];
        long long head_reach_min = current_head_pos - T;
        long long head_reach_max = current_head_pos + T;

        // Find the first track that this head can cover
        // If p[track_idx] is already covered by a previous head, or is too far left for current head,
        // we need to advance track_idx until we find a track that current head can cover.
        // Or, if p[track_idx] is too far right for current head, this head cannot cover it.

        // Skip tracks that are too far left for the current head
        // This is implicitly handled by the greedy approach:
        // If p[track_idx] is already covered by a previous head, we would have advanced track_idx past it.
        // If p[track_idx] is not covered yet, and it's to the left of head_reach_min,
        // then this head cannot cover it. But since we process tracks in order,
        // if p[track_idx] is not covered, it must be >= head_reach_min for this head to be useful.
        // If p[track_idx] < head_reach_min, then this head cannot cover it, and no subsequent head can cover it
        // if subsequent heads are to the right (h is sorted).
        // This is not quite right. A head h_i can cover p_j if p_j is in [h_i-T, h_i+T].
        // We want to cover p_track_idx, p_track_idx+1, ...
        // We use head_idx to cover p_track_idx.
        // If p_track_idx is too far left for h_head_idx (i.e., p_track_idx < h_head_idx - T),
        // then h_head_idx cannot cover p_track_idx.
        // Since h is sorted, h_head_idx+1, h_head_idx+2, ... will be even further right,
        // so they also cannot cover p_track_idx. Thus, p_track_idx cannot be covered.
        // This means we must ensure p_track_idx >= head_reach_min.

        // If the current track p[track_idx] is to the left of what the current head can reach,
        // then this head cannot cover it, and no subsequent head can cover it (since h is sorted).
        // So, this scenario means it's impossible.
        if (p[track_idx] < head_reach_min) {
            return false;
        }

        // If the current head can cover p[track_idx], then it can cover all tracks
        // up to head_reach_max.
        // Advance track_idx as long as tracks are within this head's reach.
        while (track_idx < m && p[track_idx] <= head_reach_max) {
            track_idx++;
        }

        // Move to the next head for the remaining tracks.
        head_idx++;
    }

    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between coordinates is 10^10.
                                    // A head might need to travel 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of string a
    int parity_a = calculate_parity(a);

    // Calculate initial parity of string b
    int parity_b = calculate_parity(b);

    // Condition 1: If |a| == |b|
    // If a and b are already equal, then YES.
    // Otherwise, if they have the same length, we can only remove characters
    // or append parity. Appending parity changes length. Removing characters
    // changes length. So if lengths are equal and they are not identical,
    // we can't make them equal without changing length.
    // However, the problem states "turn a into b". This implies we can
    // perform operations. If |a| == |b|, we can't use the append operation
    // to make them equal if they are not already equal, because that would
    // change the length. We also can't use the remove operation because that
    // would make |a| < |b|. So if |a| == |b|, they must be identical.
    // But wait, the example 01011 -> 0110 shows that we can remove characters
    // first, then append.
    // The logic should be: can we reach a state where a_prime == b?
    //
    // Let's re-evaluate.
    // We can always generate a string of length |a| + k (k >= 0) by appending
    // parity bits.
    // For example, if a = "01", parity(a) = 1.
    // "01" -> "011" (length 3)
    // "011" -> "0110" (length 4)
    // "0110" -> "01101" (length 5)
    //
    // The "remove first character" operation allows us to effectively "shift"
    // the string.
    //
    // Consider the final string b.
    // If we can transform a into b, it means that at some point, a (or a string
    // derived from a) must have been equal to b.
    //
    // Let's denote the number of '1's in string s as count_ones(s).
    //
    // The key observation is about the total number of '1's.
    //
    // If we have string `s`, and we append `parity(s)`, the new string `s'` has
    // `count_ones(s') = count_ones(s) + parity(s)`.
    //
    // If `parity(s) == 0`, then `count_ones(s') = count_ones(s)`.
    // If `parity(s) == 1`, then `count_ones(s') = count_ones(s) + 1`.
    //
    // This means that `count_ones(s')` will have the same parity as `count_ones(s)`
    // if `parity(s) == 0`, and different parity if `parity(s) == 1`.
    //
    // More simply, `parity(s') = (count_ones(s) + parity(s)) % 2`.
    // If `parity(s) == 0`, `parity(s') = count_ones(s) % 2 = 0`.
    // If `parity(s) == 1`, `parity(s') = (count_ones(s) + 1) % 2 = (1 + 1) % 2 = 0`.
    //
    // This is incorrect. `parity(s')` is the parity of `s'` itself.
    // `parity(s') = (count_ones(s) + parity(s)) % 2`.
    // Example: s = "01" (parity 1). s' = "011". count_ones(s') = 2. parity(s') = 0.
    // (count_ones(s) + parity(s)) % 2 = (1 + 1) % 2 = 0. This holds.
    //
    // Example: s = "00" (parity 0). s' = "000". count_ones(s') = 0. parity(s') = 0.
    // (count_ones(s) + parity(s)) % 2 = (0 + 0) % 2 = 0. This holds.
    //
    // So, appending a parity bit means the new string's parity is `(old_ones_count + old_parity) % 2`.
    //
    // Let `N_1(s)` be the number of '1's in string `s`.
    // Let `P(s)` be the parity of string `s`. `P(s) = N_1(s) % 2`.
    //
    // Operation 1: `s` -> `s + char(P(s) + '0')`.
    // New string `s_new`. `N_1(s_new) = N_1(s) + P(s)`.
    // `P(s_new) = (N_1(s) + P(s)) % 2`.
