#include <iostream>
#include <vector>
#include <algorithm>
#include <utility> // For std::pair

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<std::pair<int, int>> a_indexed(n);
        std::vector<std::pair<int, int>> b_indexed(n);

        for (int i = 0; i < n; ++i) {
            std::cin >> a_indexed[i].first;
            a_indexed[i].second = i; // Store original index
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b_indexed[i].first;
            b_indexed[i].second = i; // Store original index
        }

        // Sort both arrays based on brightness values
        std::sort(a_indexed.begin(), a_indexed.end());
        std::sort(b_indexed.begin(), b_indexed.end());

        // Create arrays to store the final assignment for each daughter
        // The i-th daughter (original index) will receive x_final[i] and y_final[i]
        std::vector<int> x_final(n);
        std::vector<int> y_final(n);

        // Assign sorted a[i] to sorted b[i]
        // The i-th daughter in the sorted order (a_indexed[i].second)
        // receives the necklace a_indexed[i].first and bracelet b_indexed[i].first
        for (int i = 0; i < n; ++i) {
            x_final[a_indexed[i].second] = a_indexed[i].first;
            y_final[a_indexed[i].second] = b_indexed[i].first;
        }

        // Print results
        for (int i = 0; i < n; ++i) {
            std::cout << x_final[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << y_final[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <numeric> // For std::abs in C++23, though cmath's std::abs is fine for long long

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use as many 5s as possible
        presses += diff / 5;
        diff %= 5;

        // For the remaining diff (0, 1, 2, 3, 4)
        // If diff is 0, 1, 2: use diff number of 1s or 2s
        // If diff is 3: use one 2 and one 1 (2 presses)
        // If diff is 4: use two 2s (2 presses)
        if (diff == 1 || diff == 2) {
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            presses += 2;
        }
        // If diff is 0, presses remains unchanged (0 additional presses)

        std::cout << presses << "\n";
    }
    return 0;
}

