void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];
    long long remaining_days = d;

    for (int i = 1; i < n; ++i) {
        int pile_index = i; // 0-indexed
        int distance = pile_index; // days to move from pile_index to pile 0

        if (remaining_days >= distance) {
            // Calculate how many haybales can be moved from this pile
            // Each haybale takes 'distance' days.
            // We have 'a[pile_index]' haybales in this pile.
            // We have 'remaining_days' days left.

            long long haybales_can_move = remaining_days / distance;

            long long actual_haybales_to_move = std::min((long long)a[pile_index], haybales_can_move);

            current_a1 += actual_haybales_to_move;
            remaining_days -= actual_haybales_to_move * distance;
        } else {
            // Not enough days to move even one haybale from this pile
            break; 
        }
    }
    std::cout << current_a1 << std::endl;
}

