        std::cin >> n;
        if (n == 1) {
            std::cout << -1 << "\n";
        } else {
            // For n > 1, we can construct a number that satisfies the conditions.
            // A common strategy is to use digits that are not factors of each other,
            // and to make the number itself not easily divisible by small digits.
            //
            // Consider the number starting with '2' and followed by '3's.
            // For example:
            // n=2: 23
            // n=3: 233
            // n=4: 2333
            //
            // Let's check this construction:
            // 1. s > 0: Yes, it's a positive number.
            // 2. s consists of n digits: Yes, '2' followed by (n-1) '3's.
            // 3. No digit in s equals 0: Yes, only '2' and '3' are used.
            // 4. s is not divisible by any of its digits:
            //    Digits are '2' and '3'.
            //    a. Not divisible by '2':
            //       The number ends in '3', which is an odd digit.
            //       Therefore, the number is odd and not divisible by '2'.
            //    b. Not divisible by '3':
            //       The sum of digits for '2' followed by (n-1) '3's is:
            //       2 + (n-1) * 3 = 2 + 3n - 3 = 3n - 1.
            //       For a number to be divisible by '3', its sum of digits must be divisible by '3'.
            //       Here, the sum of digits is 3n - 1.
            //       3n is always divisible by 3.
            //       3n - 1 is never divisible by 3 (it leaves a remainder of 2 when divided by 3).
            //       Therefore, the number is not divisible by '3'.
            //
            // This construction works for all n > 1.

            std::cout << '2';
            for (int i = 0; i < n - 1; ++i) {
