int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i, which corresponds to cell i+1.
                // The previous 'R' (or start) was at last_r_pos.
                // The gap is (current cell) - (previous cell).
                // Current cell is (i+1).
                // Previous cell is (last_r_pos + 1) if last_r_pos >= 0, or 0 if last_r_pos == -1.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1));
                last_r_pos = i;
            }
        }
        // After iterating through the string, we need to consider the gap from the last 'R'
        // to the target cell n+1.
        // The last 'R' was at index last_r_pos, corresponding to cell last_r_pos + 1.
        // The target cell is n+1.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1));

        std::cout << max_gap << "\n";
    }
    return 0;
}

