int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top triangle up to the i-th cut (from apex)
        // should be i times the area of a single piece.
        // Total area of carrot = (1/2) * 1 * h = h/2
        // Area of one piece = (h/2) / n = h / (2n)
        // Area of top triangle up to x_i = i * (h / (2n)) = (i * h) / (2n)
        //
        // Let x_i be the height of the top triangle.
        // Due to similarity, its base will be (x_i / h) * 1 = x_i / h.
        // Area of top triangle = (1/2) * (x_i / h) * x_i = x_i^2 / (2h)
        //
        // Equating the two expressions for the area:
        // x_i^2 / (2h) = (i * h) / (2n)
        // x_i^2 = (i * h^2) / n
        // x_i = sqrt((i * h^2) / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_cost = 1; // Cost for n=1 staircase
        long long sum_of_powers_of_2 = 1; // 2^0

        while (true) {
            // Calculate the cost for the next nice staircase.
            // If current_stair_cost is for n, the next one is for 2n+1.
            // The cost for n stairs is n*(n+1)/2.
            // The cost for 2n+1 stairs is (2n+1)*(2n+2)/2 = (2n+1)*(n+1).
            // This is also 2 * (cost for n stairs) + (n+1)^2.
            // Or, more simply, the cost for a nice staircase with (2^k - 1) stairs is (2^k - 1) * (2^k) / 2 = (2^k - 1) * 2^(k-1).
            // The sequence of costs for nice staircases (n=1, 3, 7, 15, ...) is:
            // n=1: cost = 1 * 2 / 2 = 1
            // n=3: cost = 3 * 4 / 2 = 6
            // n=7: cost = 7 * 8 / 2 = 28
            // n=15: cost = 15 * 16 / 2 = 120
            // The cost for a staircase with (2^k - 1) stairs is (2^k - 1) * 2^(k-1).
            // Let's denote N_k = 2^k - 1. The cost is N_k * (N_k + 1) / 2.
            // The sequence of N_k is 1, 3, 7, 15, 31, ...
            // The sequence of costs is 1, 6, 28, 120, 496, ...
            // The current_stair_cost variable holds the cost for the current N_k.
            // The next N_k is 2 * N_k + 1.
            // The next cost is (2 * N_k + 1) * (2 * N_k + 2) / 2 = (2 * N_k + 1) * (N_k + 1).
            // This is equivalent to (2 * current_stair_cost) + (N_k + 1)^2.
            // N_k + 1 is 2^k.
            // So, the next cost is 2 * current_stair_cost + (2^k)^2 = 2 * current_stair_cost + 2^(2k).
            // The sum_of_powers_of_2 variable holds 2^k.
            // So, the next cost is 2 * current_stair_cost + (sum_of_powers_of_2)^2.

            if (x >= current_stair_cost) {
                x -= current_stair_cost;
                count++;

                // Calculate the cost for the next nice staircase
                // The number of stairs for the current nice staircase is sum_of_powers_of_2 - 1.
                // The next number of stairs is 2 * (sum_of_powers_of_2 - 1) + 1 = 2 * sum_of_powers_of_2 - 1.
                // The cost for a staircase with N stairs is N * (N + 1) / 2.
                // Let N_prev = sum_of_powers_of_2 - 1.
                // Let N_curr = 2 * N_prev + 1 = 2 * (sum_of_powers_of_2 - 1) + 1 = 2 * sum_of_powers_of_2 - 1.
                // The cost for N_curr stairs is N_curr * (N_curr + 1) / 2.
                // N_curr + 1 = 2 * sum_of_powers_of_2.
                // So, cost = (2 * sum_of_powers_of_2 - 1) * (2 * sum_of_powers_of_2) / 2
                //          = (2 * sum_of_powers_of_2 - 1) * sum_of_powers_of_2.
                // This is the next current_stair_cost.

                // Update sum_of_powers_of_2 for the next iteration (it will be 2^(k+1))
                sum_of_powers_of_2 *= 2;
                current_stair_cost = (2 * sum_of_powers_of_2 - 1) * sum_of_powers_of_2;

            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    // This is a common practice in competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q; // Read the number of queries

    // Loop through each query
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x; // Read the counts of coders, mathematicians, and unspecialized students

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders: Each team needs at least one coder, so k <= c.
        // 2. The number of mathematicians: Each team needs at least one mathematician, so k <= m.
        // 3. The total number of students: Each team needs exactly three students, so 3*k <= c + m + x.
        //    This implies k <= (c + m + x) / 3.

        // Combining these, k must be less than or equal to the minimum of these three values.
        // Let's call this potential maximum 'max_teams_possible'.
        long long max_teams_possible = std::min({c, m, (c + m + x) / 3});

        // Print the result for the current query
        std::cout << max_teams_possible << "\n";
    }

    return 0; // Indicate successful execution
}

#include <iostream>
#include <vector>
#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number used to generate k distinct differences (1 to k)

    // Generate the first k+1 elements to produce k distinct differences
    // This sequence will be: 1, k+1, 2, k, 3, k-1, ...
    // The differences will be: k, k-1, k-2, ..., 1
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index: take from left (ascending)
            p[i] = left;
            left++;
        } else { // Odd index: take from right (descending)
            p[i] = right;
            right--;
        }
    }

    // The remaining elements are simply the unused numbers in increasing order.
    // These will be numbers from (k+1)+1 up to n.
    // Since 'left' already points to the next available number after the initial k+1 elements,
    // we can just append 'left' and increment it.
    for (int i = k + 1; i < n; ++i) {
        p[i] = left;
        left++;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks to partition 2n students into two classes,
        // each with an odd number of students.
        // Let the sizes of the classes be (2k1 + 1) and (2k2 + 1).
        // (2k1 + 1) + (2k2 + 1) = 2n
        // 2k1 + 2k2 + 2 = 2n
        // k1 + k2 + 1 = n
        // k1 + k2 = n - 1
        //
        // The median of a class of size (2k+1) is the (k+1)-th element after sorting.
        //
        // Consider the sorted array A = [A_0, A_1, ..., A_{2n-1}].
        //
        // To minimize the absolute difference between medians, we want the medians
        // to be as close as possible.
        //
        // The key insight is that the optimal partition will always involve
        // taking the first n elements for one class and the last n elements for the other,
        // or some similar structure that places the medians at A_{n-1} and A_n.
        //
        // Let's consider the specific partition where:
        // Class 1 consists of elements A_0, A_1, ..., A_{n-1}. Its size is n.
        // Class 2 consists of elements A_n, A_{n+1}, ..., A_{2n-1}. Its size is n.
        //
        // This partition is valid only if n is odd.
        // If n is odd, then n = 2k+1 for some k.
        // The median of Class 1 would be A_k.
        // The median of Class 2 would be A_{n+k}.
        // This is not the general case.
        //
        // The problem statement implies that the number of students in each class
        // can be different, as long as they are odd.
        //
        // The crucial observation for this problem is that to minimize the difference
        // between two medians, we should pick the two "middle" elements of the
        // sorted array as the medians.
        //
        // If we sort the entire array `a`, the elements are `a[0], a[1], ..., a[2n-1]`.
        //
        // Consider the partition where:
        // Class 1 takes `n` elements from the beginning of the sorted array.
        // Class 2 takes `n` elements from the end of the sorted array.
        //
        // This is not quite right. The problem states that each class must have an odd number of students.
        //
        // Let's consider the elements `a[n-1]` and `a[n]`.
        // Can we make `a[n-1]` the median of one class and `a[n]` the median of the other?
        //
        // To make `a[n-1]` the median of a class of size `2k_1+1`, we need `k_1` elements smaller than or equal to `a[n-1]`
        // and `k_1` elements greater than or equal to `a[n-1]`.
        //
        // To make `a[n]` the median of a class of size `2k_2+1`, we need `k_2` elements smaller than or equal to `a[n]`
        // and `k_2` elements greater than or equal to `a[n]`.
        //
        // The simplest way to achieve this is to form two classes:
        // Class 1: {a[0], a[1], ..., a[n-1]}
        // Class 2: {a[n], a[n+1], ..., a[2n-1]}
        //
        // If we assign `a[0], ..., a[n-1]` to Class 1 and `a[n], ..., a[2n-1]` to Class 2,
        // then each class has `n` students.
        //
        // If `n` is odd, then this is a valid partition.
        // The median of Class 1 (sorted) is `a[(n-1)/2]`.
        // The median of Class 2 (sorted) is `a[n + (n-1)/2]`.
        //
        // However, the problem is simpler. The minimum difference is always `a[n] - a[n-1]`.
        //
        // Let's prove this.
        // Suppose we have two classes $C_1$ and $C_2$ with medians $M_1$ and $M_2$.
        // Let $M_1 \le M_2$. We want to minimize $M_2 - M_1$.
        //
        // Let $C_1$ have size $2k_1+1$ and $C_2$ have size $2k_2+1$.
        // $k_1+k_2 = n-1$.
        //
        // For $M_1$ to be the median of $C_1$, there must be at least $k_1$ elements in $C_1$
        // that are less than or equal to $M_1$, and at least $k_1$ elements in $C_1$
        // that are greater than or equal to $M_1$.
        //
        // Similarly for $M_2$.
        //
        // Consider the elements $a[0], \dots, a[n-1]$. There are $n$ such elements.
        // Consider the elements $a[n], \dots, a[2n-1]$. There are $n$ such elements.
        //
        // If $M_1$ is the median of $C_1$, then $C_1$ must contain $M_1$ and $k_1$ elements $\le M_1$ and $k_1$ elements $\ge M_1$.
        // If $M_2$ is the median of $C_2$, then $C_2$ must contain $M_2$ and $k_2$ elements $\le M_2$ and $k_2$ elements $\ge M_2$.
        //
        // The total number of elements $\le M_1$ in $C_1$ is at least $k_1+1$.
        // The total number of elements $\ge M_2$ in $C_2$ is at least $k_2+1$.
        //
        // Since $M_1 \le M_2$, all elements $\le M_1$ are also $\le M_2$.
        // All elements $\ge M_2$ are also $\ge M_1$.
        //
        // The $k_1+1$ smallest elements in $C_1$ must be chosen from $a[0], \dots, a[2n-1]$.
        // The $k_2+1$ largest elements in $C_2$ must be chosen from $a[0], \dots, a[2n-1]$.
        //
        // The total number of elements that are $\le M_1$ (from $C_1$) plus elements that are $\ge M_2$ (from $C_2$)
        // is at least $(k_1+1) + (k_2+1) = k_1+k_2+2 = (n-1)+2 = n+1$.
        //
        // These $n+1$ elements must be distinct.
        //
        // The elements $a[0], \dots, a[n-1]$ are $n$ elements.
        // The elements $a[n], \dots, a[2n-1]$ are $n$ elements.
        //
        // Consider the $n$ smallest elements $a[0], \dots, a[n-1]$.
        // At most $k_1$ of these can be greater than $M_1$.
        // At most $k_2$ of these can be greater than $M_2$.
        //
        // The $n$ elements $a[0], \dots, a[n-1]$ must contain at least $k_1+1$ elements from $C_1$ that are $\le M_1$.
        // This means $M_1$ must be at least $a[k_1]$.
        //
        // The $n$ elements $a[n], \dots, a[2n-1]$ must contain at least $k_2+1$ elements from $C_2$ that are $\ge M_2$.
        // This means $M_2$ must be at most $a[2n-1-k_2]$.
        //
        // This is not quite right.
        //
        // Let's use the property that if $M_1$ is the median of $C_1$ (size $2k_1+1$), then at least $k_1+1$ elements of $C_1$ are $\le M_1$.
        // And at least $k_1+1$ elements of $C_1$ are $\ge M_1$.
        //
        // Similarly for $M_2$ and $C_2$ (size $2k_2+1$).
        //
        // The total number of elements $\le M_1$ in $A$ must be at least $k_1+1$.
        // So $M_1 \ge a[k_1]$.
        // The total number of elements $\ge M_2$ in $A$ must be at least $k_2+1$.
        // So $M_2 \le a[2n - 1 - k_2]$.
        //
        // We know $k_1+k_2 = n-1$. So $k_2 = n-1-k_1$.
        // $M_2 \le a[2n - 1 - (n-1-k_1)] = a[2n - 1 - n + 1 + k_1] = a[n+k_1]$.
        //
        // So we have $M_1 \ge a[k_1]$ and $M_2 \le a[n+k_1]$.
        //
        // Therefore, $M_2 - M_1 \le a[n+k_1] - a[k_1]$.
        // This doesn't directly give $a[n] - a[n-1]$.
        //
        // Let's consider the elements $a[0], \dots, a[2n-1]$.
        // The $n$-th element is $a[n-1]$ (0-indexed).
        // The $(n+1)$-th element is $a[n]$ (0-indexed).
        //
        // We can always construct a partition where $a[n-1]$ is the median of one class and $a[n]$ is the median of the other.
        //
        // Let $C_1 = \{a[0], a[1], \dots, a[n-1]\}$. This class has $n$ elements.
        // Let $C_2 = \{a[n], a[n+1], \dots, a[2n-1]\}$. This class has $n$ elements.
        //
        // If $n$ is odd, then $n = 2k+1$.
        // Median of $C_1$ is $a[k]$.
        // Median of $C_2$ is $a[n+k]$.
        // The difference is $a[n+k] - a[k]$.
        //
        // If $n$ is even, then $n = 2k$.
        // This partition is not allowed because class sizes are even.
        //
        // The problem is simpler than trying to construct the classes.
        // The minimum possible absolute difference between the medians of two classes,
        // each of odd size, is always `a[n] - a[n-1]` after sorting the entire array.
        //
        // This is a known result for this type of problem.
        // The $n$ smallest elements are $a_0, \dots, a_{n-1}$.
        // The $n$ largest elements are $a_n, \dots, a_{2n-1}$.
        //
        // We need to pick $2k_1+1$ elements for $C_1$ and $2k_2+1$ elements for $C_2$,
        // such that $k_1+k_2 = n-1$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // Assume $M_1 \le M_2$.
        //
        // $M_1$ must be at least $a[k_1]$ (because $C_1$ needs $k_1$ elements smaller than $M_1$, and $M_1$ itself).
        // $M_2$ must be at most $a[2n-1-k_2]$ (because $C_2$ needs $k_2$ elements larger than $M_2$, and $M_2$ itself).
        //
        // So $M_2 - M_1 \ge a[2n-1-k_2] - a[k_1]$.
        // Substitute $k_2 = n-1-k_1$:
        // $M_2 - M_1 \ge a[2n-1-(n-1-k_1)] - a[k_1]$
        // $M_2 - M_1 \ge a[2n-1-n+1+k_1] - a[k_1]$
        // $M_2 - M_1 \ge a[n+k_1] - a[k_1]$.
        //
        // This inequality holds for any valid partition.
        // We want to minimize $M_2 - M_1$.
        // The expression $a[n+k_1] - a[k_1]$ is minimized when $k_1$ is chosen such that $a[n+k_1]$ and $a[k_1]$ are close.
        //
        // The minimum value of $a[j] - a[i]$ for $j > i$ is achieved when $j=i+1$.
        //
        // The minimum value of $a[n+k_1] - a[k_1]$ occurs when $k_1$ is such that $n+k_1$ and $k_1$ are "close" in the sorted array.
        //
        // The minimum difference $a[n] - a[n-1]$ is achieved by setting $k_1 = n-1$.
        // If $k_1 = n-1$, then $k_2 = 0$.
        // This means $C_1$ has size $2(n-1)+1 = 2n-1$.
        // $C_2$ has size $2(0)+1 = 1$.
        //
        // For this partition:
        // $C_1$ contains $a[0], \dots, a[2n-2]$. Its median is $a[n-1]$.
        // $C_2$ contains $a[2n-1]$. Its median is $a[2n-1]$.
        // The difference is $a[2n-1] - a[n-1]$. This is not $a[n]-a[n-1]$.
        //
        // Let's re-evaluate the bounds.
        // $M_1$ is the median of $C_1$ (size $2k_1+1$). $C_1$ has $k_1$ elements $\le M_1$ and $k_1$ elements $\ge M_1$.
        // $M_2$ is the median of $C_2$ (size $2k_2+1$). $C_2$ has $k_2$ elements $\le M_2$ and $k_2$ elements $\ge M_2$.
        //
        // Total elements: $2n$.
        //
        // Consider the elements $a[0], \dots, a[n-1]$. There are $n$ elements.
        // Consider the elements $a[n], \dots, a[2n-1]$. There are $n$ elements.
        //
        // The median $M_1$ must be one of $a[0], \dots, a[2n-1]$.
        // The median $M_2$ must be one of $a[0], \dots, a[2n-1]$.
        //
        // The $k_1+1$ elements of $C_1$ that are $\le M_1$ must be chosen from $a[0], \dots, a[M_1 \text{'s index}]$.
        // The $k_2+1$ elements of $C_2$ that are $\ge M_2$ must be chosen from $a[M_2 \text{'s index}], \dots, a[2n-1]$.
        //
        // The total number of elements in $A$ that are $\le M_1$ is at least $k_1+1$.
        // So $M_1 \ge a[k_1]$.
        // The total number of elements in $A$ that are $\ge M_2$ is at least $k_2+1$.
        // So $M_2 \le a[2n - (k_2+1)] = a[2n-1-k_2]$.
        //
        // We have $M_1 \ge a[k_1]$ and $M_2 \le a[n+k_1]$ (from $k_2 = n-1-k_1$).
        //
        // We also know that $M_1$ must be chosen from $a[0], \dots, a[2n-1]$.
        // And $M_2$ must be chosen from $a[0], \dots, a[2n-1]$.
        //
        // The crucial part is that $M_1$ and $M_2$ must be separated by at least $a[n]-a[n-1]$.
        //
        // Consider the $n$ elements $a[0], \dots, a[n-1]$.
        // Consider the $n$ elements $a[n], \dots, a[2n-1]$.
        //
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        //
        // The elements $a[0], \dots, a[n-1]$ are the $n$ smallest elements.
        // The elements $a[n], \dots, a[2n-1]$ are the $n$ largest elements.
        //
        // The total number of elements in $C_1$ that are $\le M_1$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\le M_2$ is $k_2+1$.
        //
        // The total number of elements in $C_1$ that are $\ge M_1$ is $k_1+1$.
        // The total number of elements in $C_2$ that are $\ge M_2$ is $k_2+1$.
        //
        // The sum of elements $\le M_1$ in $C_1$ and elements $\le M_2$ in $C_2$ is $k_1+1+k_2+1 = n+1$.
        // These $n+1$ elements must be distinct.
        //
        // The sum of elements $\ge M_1$ in $C_1$ and elements $\ge M_2$ in $C_2$ is $k_1+1+k_2+1 = n+1$.
        // These $n+1$ elements must be distinct.
        //
        // This implies that $M_1$ must be one of $a[0], \dots, a[n-1]$ and $M_2$ must be one of $a[n], \dots, a[2n-1]$.
        //
        // More formally:
        // Let $M_1$ be the median of $C_1$ and $M_2$ be the median of $C_2$.
        // Assume $M_1 \le M_2$.
        //
        // $C_1$ has $2k_1+1$ elements. At least $k_1+1$ elements of $C_1$ are $\le M_1$.
        // $C_2$ has $2k_2+1$ elements. At least $k_2+1$ elements of $C_2$ are $\ge M_2$.
        //
        // The set of all elements $A$ has $2n$ elements.
        //
        // Consider the $n$ elements $a[0], \dots, a[n-1]$.
        // Consider the $n$ elements $a[n], \dots, a[2n-1]$.
        //
        // The total number of elements in $A$ that are $\le M_1$ is at least $k_1+1$.
        // The total number of elements in $A$ that are $\ge M_2$ is at least $k_2+1$.
        //
        // If $M_1 \ge a[n]$, then all $n$ elements $a[0], \dots, a[n-1]$ are $\le M_1$.
        // This means $k_1+1 \le n$.
        //
        // If $M_2 \le a[n-1]$, then all $n$ elements $a[n], \dots, a[2n-1]$ are $\ge M_2$.
        // This means $k_2+1 \le n$.
        //
        // The crucial point is that the $n$ smallest elements $a[0], \dots, a[n-1]$ must contain at least $k_1+1$ elements from $C_1$ that are $\le M_1$.
        // And the $n$ largest elements $a[n], \dots, a[2n-1]$ must contain at least $k_2+1$ elements from $C_2$ that are $\ge M_2$.
        //
        // This implies that $M_1$ must be one of $a[0], \dots, a[n-1]$ and $M_2$ must be one of $a[n], \dots, a[2n-1]$.
        //
        // If $M_1$ is chosen from $a[0], \dots, a[n-1]$ and $M_2$ is chosen from $a[n], \dots, a[2n-1]$,
        // then the minimum possible difference $M_2 - M_1$ is $a[n] - a[n-1]$.
        //
        // Can we always achieve this?
        // Yes. We can construct a partition.
        // Let $C_1 = \{a[0], a[1], \dots, a[n-1]\}$ and $C_2 = \{a[n], a[n+1], \dots, a[2n-1]\}$.
        // Each class has $n$ elements.
        //
        // If $n$ is odd, this is a valid partition.
        // Median of $C_1$ is $a[(n-1)/2]$. Median of $C_2$ is $a[n+(n-1)/2]$.
        // The difference is $a[n+(n-1)/2] - a[(n-1)/2]$. This is not $a[n]-a[n-1]$ unless $n=1$.
        // For $n=1$, $a[1]-a[0]$.
        // For $n=3$, $a[3+(3-1)/2] - a[(3-1)/2] = a[3+1] - a[1] = a[4]-a[1]$.
        // Example 2: n=3, a = [1,2,3,4,5,6]. Sorted.
