void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1], which is at pos[1].
        // min_idx and max_idx are both pos[1]. Length is 1.
        // min value is 1, max value is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // We maintain the minimum and maximum indices (current_min_idx, current_max_idx)
        // that span all numbers from 1 to (m-1).
        // To include 'm', we need to update current_min_idx and current_max_idx
        // to also cover pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Now, the segment p[current_min_idx ... current_max_idx] contains all numbers
        // from 1 to m (and possibly other numbers greater than m, but not numbers
        // between 1 and m that are missing).
        // For m to be beautiful, this segment must have length exactly m.
        // The length of this segment is (current_max_idx - current_min_idx + 1).
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

