        if (a[i] < i) {
            left_limit = i;
            break;
        }
    }

    // Check for the decreasing part from the right
    // We need a_i >= n-1-i for a strictly decreasing sequence ending at 0.
    // If a[i] < n-1-i, it's impossible to make a[i] >= n-1-i.
    // The smallest possible value for a[i] in a decreasing sequence ending at 0 is n-1-i.
