int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B in ascending order based on its values
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The optimal strategy is to pair the largest A_i with the smallest B_j,
    // the second largest A_i with the second smallest B_j, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we pair A[i] with B[m-1-i].
    // However, we need to reconstruct A' based on the original indices of B.
    // So, if b_indexed[j] is the j-th smallest B value (at original index b_indexed[j].second),
    // it should be paired with a[m-1-j] (the (j+1)-th largest A value).

    for (int j = 0; j < m; ++j) {
        // b_indexed[j] contains {value, original_index}
        // The j-th smallest B value (b_indexed[j].first)
        // should be paired with the (j+1)-th largest A value (a[m-1-j]).
        // This A value goes into the position corresponding to b_indexed[j].second in A'.
        a_prime[b_indexed[j].second] = a[m - 1 - j];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

