// Function to check if a prefix of length `len` is a permutation
// `max_val_prefix[i]` stores the maximum value in `a[0...i]`
// `is_perm_prefix[i]` is true if `a[0...i]` is a permutation of length `i+1`
bool check_prefix_permutation(int len, const std::vector<int>& a, const std::vector<int>& max_val_prefix, const std::vector<bool>& is_perm_prefix) {
    if (len == 0) return false; // Permutation length must be non-zero
    return is_perm_prefix[len - 1] && max_val_prefix[len - 1] == len;
}

// Function to check if a suffix of length `len` is a permutation
// `max_val_suffix[i]` stores the maximum value in `a[i...n-1]`
// `is_perm_suffix[i]` is true if `a[i...n-1]` is a permutation of length `n-i`
bool check_suffix_permutation(int len, int n, const std::vector<int>& a, const std::vector<int>& max_val_suffix, const std::vector<bool>& is_perm_suffix) {
    if (len == 0) return false; // Permutation length must be non-zero
    int start_idx = n - len;
    return is_perm_suffix[start_idx] && max_val_suffix[start_idx] == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> max_val_prefix(n);
    std::vector<bool> is_perm_prefix(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, so size n+1
    int current_max_prefix = 0;
    bool current_is_perm_prefix = true;

    for (int i = 0; i < n; ++i) {
        current_max_prefix = std::max(current_max_prefix, a[i]);
        max_val_prefix[i] = current_max_prefix;

        if (a[i] > i + 1 || seen_prefix[a[i]]) { // a[i] must be <= current length (i+1)
            current_is_perm_prefix = false;
        }
        seen_prefix[a[i]] = true;
        is_perm_prefix[i] = current_is_perm_prefix;
    }

    // Precompute for suffixes
    std::vector<int> max_val_suffix(n);
    std::vector<bool> is_perm_suffix(n);
    std::vector<bool> seen_suffix(n + 1, false); // Max value can be n, so size n+1
    int current_max_suffix = 0;
    bool current_is_perm_suffix = true;

    for (int i = n - 1; i >= 0; --i) {
        current_max_suffix = std::max(current_max_suffix, a[i]);
        max_val_suffix[i] = current_max_suffix;

        int suffix_len = n - i;
        if (a[i] > suffix_len || seen_suffix[a[i]]) { // a[i] must be <= current suffix length
            current_is_perm_suffix = false;
        }
        seen_suffix[a[i]] = true;
        is_perm_suffix[i] = current_is_perm_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of the first permutation p1
    // l2 is the length of the second permutation p2
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (check_prefix_permutation(l1, a, max_val_prefix, is_perm_prefix) &&
            check_suffix_permutation(l2, n, a, max_val_suffix, is_perm_suffix)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

