#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // Condition: current_sum = 2 * current_xor_sum
    // If it's already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
        return;
    }

    // We need to append elements b1, b2, ... such that
    // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, say X and Y.
    // New sum: S' = current_sum + X + Y
    // New XOR sum: X' = current_xor_sum ^ X ^ Y
    // We want S' = 2 * X'

    // Consider appending current_xor_sum as the first element.
    // Let b1 = current_xor_sum.
    // New sum: S_1 = current_sum + current_xor_sum
    // New XOR sum: X_1 = current_xor_sum ^ current_xor_sum = 0

    // Now we need to append b2 such that:
    // (S_1 + b2) = 2 * (X_1 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2)
    // (current_sum + current_xor_sum + b2) = 2 * b2
    // current_sum + current_xor_sum = b2

    // So, if we append b1 = current_xor_sum and b2 = current_sum + current_xor_sum,
    // the new array will be good.
    // Let's verify:
    // Sum = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //     = 2 * (current_sum + current_xor_sum)
    // XOR sum = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //         = 0 ^ (current_sum + current_xor_sum)
    //         = current_sum + current_xor_sum
    // The condition S' = 2 * X' becomes:
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This is always true.

    // The problem states we can append at most 3 elements.
    // This strategy appends 2 elements.
    // The values can be large, up to 10^9 for initial elements, so sum can be 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 (approx 10^9).
    // b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
    // The problem statement says b_i can be up to 10^18.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

