// Function to convert a number to its parity pattern string
std::string to_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    std::reverse(pattern.begin(), pattern.end()); // Reverse to get standard order
    return pattern;
}

// Function to normalize a pattern string to a fixed length (18 for max 10^18-1)
// by padding with '0's on the left.
std::string normalize_pattern(std::string s) {
    // Max length of number is 18 digits (for 10^18 - 1).
    // Max length of pattern is also 18.
    // We need to pad to 18 digits.
    if (s.length() < 18) {
        return std::string(18 - s.length(), '0') + s;
    }
    return s; // Should already be 18 or less, if less, it's padded.
              // If it's exactly 18, return as is.
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern_str = to_parity_pattern(a);
            counts[normalize_pattern(pattern_str)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern_str = to_parity_pattern(a);
            counts[normalize_pattern(pattern_str)]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern(s)] << "\n";
        }
    }

    return 0;
}

