#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long opponent_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n == 1) {
                chanek_score += 1;
                n = 0;
            } else if (n % 2 == 1) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1
                // Remaining N-1. Opponent gets to play on N-1.
                // If N-1 is odd, opponent takes 1, N-2.
                // If N-1 is even, this path is not possible as N is even.
                // So if N is even, N-1 is odd. Opponent takes 1.
                // Chanek gets 1. Opponent gets 1.
                //
                // Option 2: Take N/2
                // Remaining N/2. Opponent gets to play on N/2.
                //
                // Chanek wants to maximize his score.
                // If N/2 is odd, opponent will take 1.
                // If N/2 is even, opponent will take N/4 (if N/2 > 2) or N/2 (if N/2=2).
                //
                // Consider N = 2^k * m, where m is odd.
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * odd_number):
                //     Chanek takes N/2. N becomes N/2 (odd).
                //     Opponent takes 1. N becomes N/2 - 1.
                //     Chanek gets N/2. Opponent gets 1.
                //     This is better for Chanek than taking 1 (Chanek gets 1, Opponent gets 1).
                //   If N/2 is even (i.e., N = 4 * something):
                //     Chanek takes N/2. N becomes N/2 (even).
                //     Opponent will then take N/4.
                //     Chanek gets N/2. Opponent gets N/4.
                //     This is better for Chanek than taking 1 (Chanek gets 1, Opponent gets 1).
                //
                // The only exception is when N=2.
                // N=2: Chanek takes 1. N=1. Opponent takes 1. Chanek:1, Opponent:1.
                // N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0. Chanek:3, Opponent:1.
                // N=6: Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0. Chanek:4, Opponent:2.
                //
                // The strategy for an even N:
                // If N is even, and N/2 is odd (e.g., N=2, 6, 10, 14, ...):
                //   Chanek takes N/2. N becomes N/2 (odd).
                //   Opponent takes 1. N becomes N/2 - 1.
                //   Chanek gets N/2. Opponent gets 1.
                //   This is better for Chanek than taking 1 (Chanek gets 1, Opponent gets 1).
                // If N is even, and N/2 is even (e.g., N=4, 8, 12, 16, ...):
                //   Chanek takes N/2. N becomes N/2 (even).
                //   Opponent will then take N/4.
                //   Chanek gets N/2. Opponent gets N/4.
                //   This is better for Chanek than taking 1 (Chanek gets 1, Opponent gets 1).
                //
                // So, if N is even, Chanek should always take N/2, unless N=2.
                // If N=2, taking 1 gives Chanek 1. Taking N/2 gives Chanek 1. Same.
                //
                // The only case where taking 1 might be better is if taking N/2 leads to a state where the opponent gets a huge advantage.
                //
                // Let's consider the case where N is even.
                // Option A: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2.
                //   Chanek gets 1. Opponent gets 1.
                // Option B: Take N/2. Remaining N/2.
                //   Chanek gets N/2. Opponent plays on N/2.
                //
                // If N/2 is odd (e.g., N=6, N/2=3):
                //   Option A: Chanek gets 1. Opponent gets 1. N=4.
                //   Option B: Chanek gets 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                //             Chanek total: 3+1=4. Opponent total: 1+1=2.
                //   Option B is better for Chanek (4 vs 1).
                //
                // If N/2 is even (e.g., N=4, N/2=2):
                //   Option A: Chanek gets 1. Opponent gets 1. N=2.
                //   Option B: Chanek gets 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                //             Chanek total: 2+1=3. Opponent total: 1.
                //   Option B is better for Chanek (3 vs 1).
                //
                // It seems Chanek should always take N/2 if N is even.
                // The only exception is if N=2, where both options yield 1 for Chanek.
                //
                // What if N is a power of 2? N = 2^k.
                // Chanek takes N/2. N becomes N/2.
                // Opponent takes N/4. N becomes N/4.
                // Chanek takes N/8. N becomes N/8.
                // ...
                // This continues until N becomes 2.
                // Chanek takes N/2 + N/8 + N/32 + ... + 2.
                // Opponent takes N/4 + N/16 + N/64 + ... + 1.
                //
                // Example N=8:
                // C: 4. N=4.
                // O: 2. N=2.
                // C: 1. N=1.
                // O: 1. N=0.
                // C: 4+1=5. O: 2+1=3.
                //
                // Example N=16:
                // C: 8. N=8.
                // O: 4. N=4.
                // C: 2. N=2.
                // O: 1. N=1.
                // C: 1. N=0.
                // C: 8+2+1=11. O: 4+1=5.
                //
                // This pattern holds.
                //
                // So, the strategy is:
                // If N is odd: take 1.
                // If N is even: take N/2.
                // This is a greedy strategy. Let's verify it.
                //
                // If N is odd:
                //   Chanek takes 1. N becomes N-1 (even).
                //   Chanek gets 1.
                // If Chanek took N/2 (not allowed).
                //
                // If N is even:
                //   Chanek can take 1 or N/2.
                //   If Chanek takes 1: N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //     Chanek gets 1. Opponent gets 1.
                //   If Chanek takes N/2: N becomes N/2.
                //     Chanek gets N/2. Opponent plays on N/2.
                //
                //   Consider the total coins. Chanek wants to maximize his share.
                //   If N is even, and N/2 is odd (e.g., N=6):
                //     Take 1: C=1, O=1. N=4.
                //     Take N/2: C=3. N=3. Opponent takes 1. N=2. C=1. N=1. O=1. N=0.
                //       Total C=3+1=4. Total O=1+1=2.
                //     Taking N/2 is better.
                //
                //   If N is even, and N/2 is even (e.g., N=4):
                //     Take 1: C=1, O=1. N=2.
                //     Take N/2: C=2. N=2. Opponent takes 1. N=1. C=1. N=0.
                //       Total C=2+1=3. Total O=1.
                //     Taking N/2 is better.
                //
                // The greedy strategy seems to be:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This is because taking N/2 gives Chanek more coins immediately, and leaves a smaller N for the opponent.
                // The only edge case is when N=2.
                // If N=2, take 1. N=1. Opponent takes 1. C=1, O=1.
                // If N=2, take N/2=1. N=1. Opponent takes 1. C=1, O=1.
                // Both are same. So the rule "take N/2 if even" works for N=2 too.
                //
                // Let's re-evaluate the example N=5:
                // C: N=5 (odd). Takes 1. C=1. N=4.
                // O: N=4 (even). Takes N/2=2. O=2. N=2.
                // C: N=2 (even). Takes N/2=1. C=1+1=2. N=1.
                // O: N=1 (odd). Takes 1. O=2+1=3. N=0.
                // Result: C=2, O=3. This matches the example.
                //
                // Example N=6:
                // C: N=6 (even). Takes N/2=3. C=3. N=3.
                // O: N=3 (odd). Takes 1. O=1. N=2.
                // C: N=2 (even). Takes N/2=1. C=3+1=4. N=1.
                // O: N=1 (odd). Takes 1. O=1+1=2. N=0.
                // Result: C=4, O=2. This matches the example.
                //
                // The greedy strategy seems correct.
                //
                // The only tricky part is when N is even, and N/2 is odd.
                // For example, N=6.
                // Chanek's turn, N=6.
                // Option 1: Take 1. N=5.
                //   Opponent's turn, N=5. Opponent takes 1. N=4.
                //   Chanek's turn, N=4. Chanek takes 2. N=2.
                //   Opponent's turn, N=2. Opponent takes 1. N=1.
                //   Chanek's turn, N=1. Chanek takes 1. N=0.
                //   Chanek total: 1+2+1 = 4. Opponent total: 1+1 = 2.
                // Option 2: Take N/2=3. N=3.
                //   Opponent's turn, N=3. Opponent takes 1. N=2.
                //   Chanek's turn, N=2. Chanek takes 1. N=1.
                //   Opponent's turn, N=1. Opponent takes 1. N=0.
                //   Chanek total: 3+1 = 4. Opponent total: 1+1 = 2.
                //
                // In this case (N=6), both options lead to the same score for Chanek.
                //
                // What if N is even, and N/2 is even?
                // For example, N=4.
                // Chanek's turn, N=4.
                // Option 1: Take 1. N=3.
                //   Opponent's turn, N=3. Opponent takes 1. N=2.
                //   Chanek's turn, N=2. Chanek takes 1. N=1.
                //   Opponent's turn, N=1. Opponent takes 1. N=0.
                //   Chanek total: 1+1 = 2. Opponent total: 1+1 = 2.
                // Option 2: Take N/2=2. N=2.
                //   Opponent's turn, N=2. Opponent takes 1. N=1.
                //   Chanek's turn, N=1. Chanek takes 1. N=0.
                //   Chanek total: 2+1 = 3. Opponent total: 1.
                //
                // Here, taking N/2 is strictly better for Chanek.
                //
                // So the rule is:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd (N = 2 * odd_number, e.g., 2, 6, 10, ...):
                //     Both taking 1 and taking N/2 lead to the same score for Chanek.
                //     Taking N/2 is simpler.
                //   If N/2 is even (N = 4 * something, e.g., 4, 8, 12, ...):
                //     Taking N/2 is strictly better for Chanek.
                //
                // Therefore, the greedy strategy "if N is odd take 1, if N is even take N/2" is optimal for Chanek.

                // The only special case is when N is even, and N/2 is odd, and N/2 > 1.
                // For example, N=6. N/2=3.
                // If Chanek takes 1, N becomes 5. Opponent takes 1. N becomes 4.
                // If Chanek takes N/2, N becomes 3. Opponent takes 1. N becomes 2.
                //
                // Let's consider the total coins taken by Chanek if he takes 1 vs N/2 when N is even.
                // Let f(N) be the maximum coins Chanek can get from N coins.
                //
                // If N is odd: Chanek takes 1. Remaining N-1. Opponent plays on N-1.
                //   Chanek gets 1 + (N-1 - f_opponent(N-1)).
                //   Since f_opponent(N-1) is the max opponent can get, and opponent plays optimally,
                //   f_opponent(N-1) is equivalent to f(N-1) if it were Chanek's turn.
                //   So Chanek gets 1 + (N-1 - f(N-1)).
                //
                // If N is even:
                //   Option 1: Take 1. Remaining N-1. Opponent plays on N-1.
                //     Chanek gets 1 + (N-1 - f(N-1)).
                //   Option 2: Take N/2. Remaining N/2. Opponent plays on N/2.
                //     Chanek gets N/2 + (N/2 - f(N/2)).
                //
                // Chanek chooses max(1 + (N-1 - f(N-1)), N/2 + (N/2 - f(N/2))).
                //
                // This is a recursive definition.
                //
                // Let's trace N=6 again with this definition.
                // f(1) = 1
                // f(2) = max(1 + (1 - f(1)), 2/2 + (2/2 - f(2/2)))
                //      = max(1 + (1 - 1), 1 + (1 - f(1)))
                //      = max(1, 1 + (1 - 1)) = max(1, 1) = 1
                // f(3) = 1 + (2 - f(2)) = 1 + (2 - 1) = 2
                // f(4) = max(1 + (3 - f(3)), 4/2 + (4/2 - f(4/2)))
                //      = max(1 + (3 - 2), 2 + (2 - f(2)))
                //      = max(1 + 1, 2 + (2 - 1))
                //      = max(2, 2 + 1) = max(2, 3) = 3
                // f(5) = 1 + (4 - f(4)) = 1 + (4 - 3) = 2
                // f(6) = max(1 + (5 - f(5)), 6/2 + (6/2 - f(6/2)))
                //      = max(1 + (5 - 2), 3 + (3 - f(3)))
                //      = max(1 + 3, 3 + (3 - 2))
                //      = max(4, 3 + 1) = max(4, 4) = 4
                //
                // The recursive definition confirms the greedy strategy for N=4, N=5, N=6.
                //
                // The greedy strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N/2 is odd (N = 2 * odd_number, but not 2 itself):
                //     Take 1. This leaves N-1 (even). Opponent takes (N-1)/2.
                //     Take N/2. This leaves N/2 (odd). Opponent takes 1.
                //     This is the specific case where the choice matters.
                //     Example N=6.
                //     Take 1: C=1. N=5. O takes 1. N=4. C takes 2. N=2. O takes 1. N=1. C takes 1. N=0.
                //       C total = 1+2+1 = 4.
                //     Take N/2=3: C=3. N=3. O takes 1. N=2. C takes 1. N=1. O takes 1. N=0.
                //       C total = 3+1 = 4.
                //     In this case, both options yield the same result for Chanek. So taking N/2 is fine.
                //   If N/2 is even (N = 4 * something):
                //     Take N/2. This is always better.
                //
                // So the simplified greedy strategy is:
                // If N is odd, take 1.
                // If N is even, take N/2.
                // This covers all cases correctly.

                if (n == 2) { // Special case for N=2, taking 1 or N/2 gives same result
                    chanek_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) { // N is even, N/2 is odd (e.g., N=6, N=10, N=14)
                    // In this specific scenario, taking 1 or N/2 leads to the same optimal score for Chanek.
                    // Taking 1: C gets 1. N becomes N-1. Opponent gets 1. N becomes N-2.
                    // Taking N/2: C gets N/2. N becomes N/2. Opponent gets 1. N becomes N/2-1.
                    // The example N=6 shows both paths lead to 4 for Chanek.
                    // So, we can just take N/2 for simplicity.
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N is even, N/2 is even (e.g., N=4, N=8, N=12)
                    // Taking N/2 is strictly better for Chanek.
                    chanek_score += n / 2;
                    n /= 2;
                }
            }
        } else { // Opponent's turn
            if (n == 1) {
                opponent_score += 1;
                n = 0;
            } else if (n % 2 == 1) { // N is odd
                opponent_score += 1;
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally to maximize their score.
                // Same logic as Chanek.
                if (n == 2) {
                    opponent_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 == 1) {
                    opponent_score += n / 2;
                    n /= 2;
                } else {
                    opponent_score += n / 2;
                    n /= 2;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

