#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
    // We want the largest such x.
    // The strategy is to take p and divide it by prime factors of q until it's no longer divisible by q.
    // To maximize x, we should divide p by the smallest possible powers of prime factors of q.

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= i;
            }
            max_x = std::max(max_x, current_p);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself (or 1 if all factors were found)
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= temp_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

