    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm> // For std::abs

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Prefix sums for counts of 'x', 'y', 'z'
    // count[0][i] stores count of 'x' in s[0...i-1]
    // count[1][i] stores count of 'y' in s[0...i-1]
    // count[2][i] stores count of 'z' in s[0...i-1]
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        counts[0][i + 1] = counts[0][i];
        counts[1][i + 1] = counts[1][i];
        counts[2][i + 1] = counts[2][i];
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing for substring s[l-1...r-1]
        // Length of substring is r - l + 1
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // The condition for infinite loop is that for any 3-character substring,
        // it must be one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' in any 3-character substring
        // must be exactly one 'x', one 'y', and one 'z'.
        // If the total counts of 'x', 'y', 'z' in the entire substring s[l-1...r-1]
        // differ by more than 1, then it's impossible to maintain this property
        // for all 3-character substrings, because some 3-character substring
        // would have to contain duplicates or be missing a character.
        // For example, if count_x = 5, count_y = 1, count_z = 1, and len = 7.
        // Then any 3-char substring must have 1x, 1y, 1z.
        // This is impossible because we have too many 'x's.
        // The only way to have all 3-char substrings be permutations of 'xyz'
        // is if the counts of 'x', 'y', 'z' in the entire substring are
        // "balanced" (differ by at most 1).
        if (std::abs(count_x - count_y) <= 1 &&
            std::abs(count_x - count_z) <= 1 &&
            std::abs(count_y - count_z) <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    std::string coloring(n, ' ');
    bool found_solution = false;

    for (int split_digit = 0; split_digit <= 9; ++split_digit) {
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        std::string current_coloring(n, ' ');
        bool possible_split = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < split_digit) {
                current_coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > split_digit) {
                current_coloring[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == split_digit
                // Try to assign to color 1 if it maintains non-decreasing order for s1
                if (!s1_digits.empty() && s1_digits.back() > d[i]) {
                    // Cannot assign to color 1, must assign to color 2
                    // But if s2_digits already has a smaller element, this is invalid
                    if (!s2_digits.empty() && s2_digits.back() > d[i]) {
                        possible_split = false;
                        break;
                    }
                    current_coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    // Can assign to color 1
                    current_coloring[i] = '1';
                    s1_digits.push_back(d[i]);
                }
            }
        }

        if (!possible_split) {
            continue;
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) {
            continue;
        }

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_split = false;
                break;
            }
        }
        if (!possible_split) {
            continue;
        }

        // Check if max(s1_digits) <= min(s2_digits)
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_split = false;
            }
        }

        if (possible_split) {
            coloring = current_coloring;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << coloring << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

