                min_x = std::max(min_x, x);
            }

            // Robot can move up (f2=1)
            // If it cannot move up (f2=0), it means it cannot reach any point above it.
            // So, the target Y must be <= its current Y.
            if (f2 == 0) { // Cannot move up (y_c + 1)
                max_y = std::min(max_y, y);
            }

            // Robot can move right (f3=1)
            // If it cannot move right (f3=0), it means it cannot reach any point to its right.
            // So, the target X must be <= its current X.
            if (f3 == 0) { // Cannot move right (x_c + 1)
                max_x = std::min(max_x, x);
            }

            // Robot can move down (f4=1)
            // If it cannot move down (f4=0), it means it cannot reach any point below it.
            // So, the target Y must be >= its current Y.
            if (f4 == 0) { // Cannot move down (y_c - 1)
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. We can pick any point within the intersection.
            // For example, (min_x, min_y)
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            // No common reachable point.
            std::cout << 0 << "\n";
        }
    }

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long total_sum = 0;
    long long MOD = 1000000007;

    // Sum of r for 1 <= r < b is (b-1)*b/2
    // This is (b-1) * (b-1+1) / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b / 2) % MOD; // (b-1)*b/2

    for (long long k = 1; k <= a; ++k) {
        // For a fixed k, x = r * (k*b + 1)
        // We need to sum r * (k*b + 1) for 1 <= r < b
        // This is (k*b + 1) * sum(r from 1 to b-1)
        // sum(r from 1 to b-1) = (b-1)*b/2

        long long kb_plus_1 = (k * b + 1) % MOD;
        long long term_sum_for_k = (kb_plus_1 * sum_r_term) % MOD;

        total_sum = (total_sum + term_sum_for_k) % MOD;
    }

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];
        adj[c1].insert(c2);
        adj[c2].insert(c1);
        used_in_s.insert(c1);
        used_in_s.insert(c2);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_s.insert(s[0]);
    }

    bool possible = true;
    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string keyboard_layout = "";
    std::set<char> visited;

    // Find a starting point for a chain (a character with only one required neighbor)
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all chars in s form cycles or are isolated.
    // If all chars in s have 2 neighbors, it must be a single cycle.
    // If s has only one character, start_char will be '\0'.
    // If s has multiple characters and forms a cycle, start_char will be '\0'.
    // In this case, pick any character from used_in_s as a start.
    if (start_char == '\0' && !used_in_s.empty()) {
        start_char = *used_in_s.begin();
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first character

        while (visited.find(current) == visited.end()) {
            keyboard_layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0' && adj[prev].size() == 2) { // This means we completed a cycle
                // If we completed a cycle, and there are still unvisited chars in used_in_s,
                // it means there are multiple disjoint chains/cycles, which is impossible.
                // However, the problem statement implies a single path/cycle for the required adjacencies.
                // If we reach here, it means we've exhausted the current chain/cycle.
                // If there are other components in used_in_s, it's an issue.
                // But the logic for `possible` already handles >2 neighbors.
                // If all chars in `s` form a single cycle, `start_char` would be picked from `used_in_s.begin()`,
                // and `current` would eventually become `start_char` again, but `visited` check prevents infinite loop.
                // The `while` loop will terminate when `current` is already visited.
                // If `current` becomes `\0` and `adj[prev].size() == 2`, it means `prev` had two neighbors,
                // and one was `prev`'s `prev`, and the other was `current` (which is now `\0`).
                // This implies `current` was the last char in a chain, but it had 2 neighbors.
                // This case should not happen if `adj[current].size() <= 2` is maintained.
                // The only way `current` becomes `\0` is if `adj[current]` is empty or only contains `prev`.
                // If `adj[current]` is empty, it's an end of a chain.
                // If `adj[current]` only contains `prev`, it's also an end of a chain.
                break; // End of chain
            }
        }
    }

    // Check if all characters from 's' have been included in the layout
    for (char c : used_in_s) {
        if (visited.find(c) == visited.end()) {
            possible = false; // There are disconnected components in 's'
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            keyboard_layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << keyboard_layout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

