#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute character occurrences for each shift
    // char_at_shift[k][char_code] = count of char_code at position k
    std::vector<std::vector<int>> char_at_shift(L, std::vector<int>(26, 0));
    for (int k = 0; k < L; ++k) {
        char_at_shift[k][s[k] - 'a']++;
    }

    // For each possible first character c0 (which is s[k_actual])
    // and for each possible second character cp (which is s[(p + k_actual) % L])
    // count how many k values satisfy s[k] = c0 and s[(p+k)%L] = cp.
    // This is stored in `counts[c0_idx][p][cp_idx]`.
    // `c0_idx` is `s[k_actual] - 'a'`.
    // `p` is the chosen second position.
    // `cp_idx` is `s[(p + k_actual) % L] - 'a'`.
    std::vector<std::vector<std::vector<int>>> counts(26, std::vector<std::vector<int>>(L, std::vector<int>(26, 0)));

    for (int k = 0; k < L; ++k) { // Iterate through all possible actual shifts k_actual
        int c0_idx = s[k] - 'a'; // The first character Vasya sees is s[k_actual]
        for (int p = 1; p < L; ++p) { // Iterate through all possible second positions p Vasya might choose
            int cp_idx = s[(p + k) % L] - 'a'; // The second character Vasya sees is s[(p + k_actual) % L]
            counts[c0_idx][p][cp_idx]++;
        }
    }

    double total_win_prob = 0.0;

    // Iterate through each possible first character Vasya might observe (c0)
    for (int c0_idx = 0; c0_idx < 26; ++c0_idx) {
        // Number of shifts k for which s[k] == c0
        int num_k_for_c0 = 0;
        for (int k = 0; k < L; ++k) {
            if (s[k] - 'a' == c0_idx) {
                num_k_for_c0++;
            }
        }

        if (num_k_for_c0 == 0) {
            continue; // This c0 will never be observed as t[0]
        }

        // Vasya plays optimally: choose p to maximize win probability for this c0
        double max_win_prob_for_c0 = 0.0;

        // Iterate through all possible second positions p Vasya can choose
        for (int p = 1; p < L; ++p) {
            double current_win_prob_for_p = 0.0;
            // For a fixed c0 and p, iterate through all possible second characters cp
            for (int cp_idx = 0; cp_idx < 26; ++cp_idx) {
                int num_matches = counts[c0_idx][p][cp_idx];
                if (num_matches == 1) {
                    // If only one k matches (c0, cp), Vasya wins for this (c0, cp) pair
                    current_win_prob_for_p += 1.0;
                }
            }
            // Divide by num_k_for_c0 because this is the number of actual k's that could lead to c0
            // and for each such k, a specific cp is observed.
            // The sum `current_win_prob_for_p` is effectively the count of unique (k, p) pairs
            // that result in a win for this c0 and chosen p.
            max_win_prob_for_c0 = std::max(max_win_prob_for_c0, current_win_prob_for_p / num_k_for_c0);
        }

        // Add the contribution of this c0 to the total probability
        // (num_k_for_c0 / L) is the probability of observing this c0 as t[0]
        total_win_prob += (static_cast<double>(num_k_for_c0) / L) * max_win_prob_for_c0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same set of adjacent sums.
        // F(p) = sort([p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n])
        // Let p' be the reverse of p: p' = [p_n, p_{n-1}, ..., p_1]
        // F(p') = sort([p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1])
        // This is the same set of sums, just in reverse order, so their sorted versions are identical.
        // The only case where p' might be equal to p is if p is a palindrome.
        // However, a permutation of distinct integers from 1 to n cannot be a palindrome
        // unless n=1 (which is not allowed, n>=2) or n=0.
        // For n >= 2, p_1 != p_n (since p_1=p_n would imply p_1 is repeated if n>1, or n=1).
        // If p_1 = p_n, then p is not a permutation of distinct integers from 1 to n.
        // For example, if p = [1, 2, 1], it's not a permutation.
        // If p = [1, 2, 3, 2, 1], it's not a permutation.
        // A permutation [p_1, ..., p_n] is a palindrome if p_i = p_{n-i+1} for all i.
        // If p is a permutation of distinct integers from 1 to n, then p_1 must be different from p_n
        // unless n=1. Since n >= 2, p_1 != p_n.
        // Therefore, reversing the permutation always yields a different permutation.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        long long count = 0;
        int n = s.length();

        for (int i = 0; i < n; ++i) {
            // Skip leading zeros for the current starting position i
            // Find the first '1' at or after index i
            int first_one_idx = -1;
            for (int k = i; k < n; ++k) {
                if (s[k] == '1') {
                    first_one_idx = k;
                    break;
                }
            }

            if (first_one_idx == -1) {
                // No '1' from index i to the end. All are '0's.
                // f(0...0) = 0. Length must be 0, but min length is 1.
                // So no good substrings starting with '0's only.
                // Except for f(0) = 0, length 1. 1 != 0.
                // So no good substrings here.
                break; // All remaining substrings will also be all '0's
            }

            // Now, first_one_idx is the index of the first '1' in s[i...n-1].
            // The actual binary value starts from s[first_one_idx].
            // The number of leading zeros for this block is `first_one_idx - i`.
            int num_leading_zeros = first_one_idx - i;

            long long current_val = 0;
            for (int j = first_one_idx; j < n; ++j) {
                // Calculate current_val for s[first_one_idx ... j]
                // Check for overflow before multiplication
                if (current_val > (2LL * n + 100) / 2) { // Max possible length is N, so max val is N.
                                                         // We need to check up to N + max_leading_zeros.
                                                         // Max N is 2e5. Max leading zeros is N.
                                                         // So max val can be 4e5.
                                                         // 2LL * N + 100 is a safe upper bound for target length.
                                                         // If current_val * 2 exceeds this, it's too large.
                    current_val = 2LL * n + 100; // Cap it to avoid overflow and continue loop
                } else {
                    current_val = current_val * 2 + (s[j] - '0');
                }

                // The length of the substring s[i...j] is (j - i + 1).
                // The decimal value is current_val.
                // The condition is (j - i + 1) == current_val.
                // However, current_val is for s[first_one_idx ... j].
                // The actual length of the substring is (j - i + 1).
                // The value f(s_i ... s_j) is current_val.
                // So we need to check if (j - i + 1) == current_val.

                // The length of the substring s[first_one_idx ... j] is (j - first_one_idx + 1).
                // The total length of s[i ... j] is (j - i + 1).
                // The value f(s_i ... s_j) is current_val.
                // So we need to check if (j - i + 1) == current_val.

                // Optimization:
                // The length of the substring s[i...j] is `len = j - i + 1`.
                // The value `current_val` is `f(s[first_one_idx...j])`.
                // We are looking for `len == current_val`.
                // `len = (j - first_one_idx + 1) + num_leading_zeros`.
                // So, `current_val == (j - first_one_idx + 1) + num_leading_zeros`.

                // The maximum possible value for `current_val` that can be equal to a length is `n + num_leading_zeros`.
                // `num_leading_zeros` can be up to `n`. So `current_val` can be up to `2n`.
                // If `current_val` exceeds `2n + 100` (a safe upper bound for any possible length),
                // then it can't be equal to any valid length anymore.
                if (current_val > 2LL * n + 100) {
                    // If current_val is already too large, it will only get larger.
                    // No need to check further for this `i`.
                    // We can break from the inner loop.
                    break;
                }

                // Check if the condition holds
                if (current_val == (long long)(j - i + 1)) {
                    count++;
                }
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit
    // For each bit position j (0 to 9):
    // bit_state[j][0] = result if input bit j is 0
    // bit_state[j][1] = result if input bit j is 1
    // Initially, if input bit j is 0, output bit j is 0. If input bit j is 1, output bit j is 1.
    // So, bit_state[j][0] = 0, bit_state[j][1] = 1
    std::vector<std::vector<int>> bit_state(10, std::vector<int>(2));
    for (int j = 0; j < 10; ++j) {
        bit_state[j][0] = 0; // If input bit j is 0, current output bit j is 0
        bit_state[j][1] = 1; // If input bit j is 1, current output bit j is 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_val = (val >> j) & 1; // j-th bit of the constant 'val'

            if (op_char == '&') {
                bit_state[j][0] &= bit_val;
                bit_state[j][1] &= bit_val;
            } else if (op_char == '|') {
                bit_state[j][0] |= bit_val;
                bit_state[j][1] |= bit_val;
            } else { // op_char == '^'
                bit_state[j][0] ^= bit_val;
                bit_state[j][1] ^= bit_val;
            }
        }
    }

    // Now, bit_state[j][0] is the final j-th bit if input j-th bit was 0.
    // And bit_state[j][1] is the final j-th bit if input j-th bit was 1.

    // We need to find A, B, C such that:
    // (x & A | B) ^ C = final_output
    // Or a shorter sequence.

    // Let's determine the values for the three potential operations:
    // 1. AND mask (A): If a bit j is forced to 0 regardless of input (bit_state[j][0]=0, bit_state[j][1]=0),
    //    then A must have 0 at bit j. Otherwise, A can have 1 at bit j.
    //    So, A_j = bit_state[j][1] (if bit_state[j][0] == 0, then A_j must be 0. If bit_state[j][0] == 1, this case is impossible for AND mask)
    //    More simply, A_j = 1 if bit_state[j][0] == 0 and bit_state[j][1] == 1 (pass-through)
    //    A_j = 0 if bit_state[j][0] == 0 and bit_state[j][1] == 0 (force to 0)
    //    A_j = 0 if bit_state[j][0] == 1 and bit_state[j][1] == 1 (force to 1, handled by OR)
    //    A_j = 0 if bit_state[j][0] == 1 and bit_state[j][1] == 0 (flip, handled by XOR)
    //    This is equivalent to A_j = bit_state[j][1] if bit_state[j][0] == 0, else 0.
    //    This is equivalent to A_j = bit_state[j][1] (if bit_state[j][0] == 0)
    //    A_j = 1 if the bit is passed through (0->0, 1->1)
    //    A_j = 0 if the bit is forced to 0 (0->0, 1->0)
    //    A_j = 0 if the bit is forced to 1 (0->1, 1->1)
    //    A_j = 0 if the bit is flipped (0->1, 1->0)
    //    So, A_j = 1 only if (bit_state[j][0] == 0 && bit_state[j][1] == 1)
    //    Otherwise A_j = 0.
    int and_val = 0;
    for (int j = 0; j < 10; ++j) {
        if (bit_state[j][0] == 0 && bit_state[j][1] == 1) {
            and_val |= (1 << j);
        }
    }

    // 2. OR mask (B): If a bit j is forced to 1 regardless of input (bit_state[j][0]=1, bit_state[j][1]=1),
    //    then B must have 1 at bit j. Otherwise, B can have 0 at bit j.
    //    So, B_j = 1 if (bit_state[j][0] == 1 && bit_state[j][1] == 1)
    //    Otherwise B_j = 0.
    int or_val = 0;
    for (int j = 0; j < 10; ++j) {
        if (bit_state[j][0] == 1 && bit_state[j][1] == 1) {
            or_val |= (1 << j);
        }
    }

    // 3. XOR mask (C): If a bit j is flipped (0->1, 1->0), then C must have 1 at bit j.
    //    This happens if (bit_state[j][0] == 1 && bit_state[j][1] == 0)
    //    Or if (bit_state[j][0] == 0 && bit_state[j][1] == 1) but after AND and OR, it's 0->0, 1->1.
    //    Let's consider the state after applying AND and OR.
    //    For an input bit x_j:
    //    (x_j & and_val_j) | or_val_j
    //    If x_j = 0: (0 & and_val_j) | or_val_j = 0 | or_val_j = or_val_j
    //    If x_j = 1: (1 & and_val_j) | or_val_j = and_val_j | or_val_j
    //
    //    We need:
    //    (0 & and_val_j | or_val_j) ^ xor_val_j = bit_state[j][0]
    //    (1 & and_val_j | or_val_j) ^ xor_val_j = bit_state[j][1]
    //
    //    So, or_val_j ^ xor_val_j = bit_state[j][0]
    //    (and_val_j | or_val_j) ^ xor_val_j = bit_state[j][1]
    //
    //    From the first equation: xor_val_j = or_val_j ^ bit_state[j][0]
    //    Let's verify this with the second equation:
    //    (and_val_j | or_val_j) ^ (or_val_j ^ bit_state[j][0])
    //    We know:
    //    If bit_state[j][0] == 0 && bit_state[j][1] == 0: and_val_j=0, or_val_j=0. xor_val_j = 0^0=0. (0|0)^0 = 0. Correct.
    //    If bit_state[j][0] == 0 && bit_state[j][1] == 1: and_val_j=1, or_val_j=0. xor_val_j = 0^0=0. (1|0)^0 = 1. Correct.
    //    If bit_state[j][0] == 1 && bit_state[j][1] == 0: and_val_j=0, or_val_j=0. xor_val_j = 0^1=1. (0|0)^1 = 1. Correct.
    //    If bit_state[j][0] == 1 && bit_state[j][1] == 1: and_val_j=0, or_val_j=1. xor_val_j = 1^1=0. (0|1)^0 = 1. Correct.
    //
    //    So, xor_val_j = or_val_j ^ bit_state[j][0] is the correct way to determine the XOR mask.
    int xor_val = 0;
    for (int j = 0; j < 10; ++j) {
        int current_bit_after_and_or_for_0 = ((0 & ((and_val >> j) & 1)) | ((or_val >> j) & 1));
