// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise (i.e., stable)
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        return false;
    }

    std::vector<int> b = a; // Create a copy for the new sequence
    bool changed = false;

    // b_1 = a_1 and b_n = a_n are handled by copying a to b initially

    for (int i = 1; i < n - 1; ++i) { // Indices 1 to n-2 correspond to a_2 to a_{n-1}
        int val_prev = a[i - 1];
        int val_curr = a[i];
        int val_next = a[i + 1];

        // Median of three 0s/1s:
        // If sum is 0 or 1, median is 0.
        // If sum is 2 or 3, median is 1.
        int new_val = (val_prev + val_curr + val_next >= 2) ? 1 : 0;

        if (b[i] != new_val) {
            b[i] = new_val;
            changed = true;
        }
    }

    a = std::move(b); // Update the original sequence
    return changed;
}

