    // So, initial_a[j] <= m_i - current_delta[j].
    // We take the minimum of this value with the current initial_a[j].
    // For type 1 operations (add d), we subtract d from current_delta for affected elements.
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 2) {
            // Type 2: max query. This operation implies an upper bound for initial_a[j].
            // a_j = initial_a[j] + current_delta[j]
            // We know max(a_j) for j in [l, r] is ops[i].val.
            // So, for all j in [l, r], a_j <= ops[i].val.
            // This means initial_a[j] + current_delta[j] <= ops[i].val.
            // Therefore, initial_a[j] <= ops[i].val - current_delta[j].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
