    long long invalid_pairs = 0;

    // last_valid_r[i] stores the maximum r such that the substring s[i...r-1]
    // contains a valid triplet pattern.
    // If no such r exists for a given i, it can be 0 or i-1.
    // Let's define it as the smallest r such that s[i...r-1] contains a pattern.
    // Or, more simply, let's find the rightmost starting position `x` for any pattern.
    // We need to find the minimum `r` for each `l` such that `s[l-1...r-1]` contains a pattern.
    // Let `min_r_for_l[l]` be the smallest `r` such that `s[l-1...r-1]` contains a pattern.
    // If no such `r` exists, `min_r_for_l[l]` can be `n+1`.

    // Let `min_r_containing_pattern[i]` be the smallest `r` such that the substring `s[i...r-1]`
    // contains at least one pattern `s_x = s_{x+k} = s_{x+2k}` where `i <= x` and `x+2k <= r`.
    // If no such `r` exists, `min_r_containing_pattern[i]` is `n+1`.
    // We want to find `min_r_containing_pattern[l-1]` for each `l`.

    // Iterate `x` from `n-1` down to `0`.
    // For each `x`, find the smallest `r` such that `s[x...r-1]` contains a pattern starting at `x`.
    // This `r` would be `x + 2k + 1`.
    // Let `next_pattern_end[i]` be the minimum `j` such that `s[i...j-1]` contains a pattern.
    // If no pattern starts at `i`, then `next_pattern_end[i]` is `next_pattern_end[i+1]`.
    // If a pattern `s_i = s_{i+k} = s_{i+2k}` exists, then `next_pattern_end[i]` is `min(i+2k+1, next_pattern_end[i+1])`.

    std::vector<int> next_pattern_end(n + 1, n + 1); // next_pattern_end[i] stores the minimum r (1-based)
                                                     // such that s[i...r-1] contains a pattern.
                                                     // If no pattern exists starting at or after i, it's n+1.

    for (int i = n - 1; i >= 0; --i) {
        // Initialize next_pattern_end[i] with the value from the right
        if (i + 1 <= n) {
            next_pattern_end[i] = next_pattern_end[i + 1];
        }

        // Check for k=1: s[i] == s[i+1] == s[i+2]
        if (i + 2 < n && s[i] == s[i+1] && s[i+1] == s[i+2]) {
            next_pattern_end[i] = std::min(next_pattern_end[i], i + 3);
        }
        // Check for k=2: s[i] == s[i+2] == s[i+4]
        if (i + 4 < n && s[i] == s[i+2] && s[i+2] == s[i+4]) {
            next_pattern_end[i] = std::min(next_pattern_end[i], i + 5);
        }
        // Check for k=3: s[i] == s[i+3] == s[i+6]
        if (i + 6 < n && s[i] == s[i+3] && s[i+3] == s[i+6]) {
            next_pattern_end[i] = std::min(next_pattern_end[i], i + 7);
        }
    }

    // Now, for each l (0-based index i), next_pattern_end[i] gives the smallest r (1-based)
    // such that the substring s[i...r-1] contains a pattern.
    // If next_pattern_end[i] is n+1, it means no pattern exists starting at or after i.
    // For a given l (0-based i), any r from next_pattern_end[i] to n will form a valid pair (l, r).
    // The number of such r's is n - next_pattern_end[i] + 1.
    // If next_pattern_end[i] > n, then this count is 0.

    for (int i = 0; i < n; ++i) { // i is the 0-based starting index (l-1)
        if (next_pattern_end[i] <= n) {
            // The number of valid r's for this l (i+1) is n - (next_pattern_end[i] - 1)
