void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    int min_val_idx = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < a[min_val_idx]) {
            min_val_idx = i;
        }
    }

    long long min_val = a[min_val_idx];
    long long total_spells = 0;

    for (int i = 0; i < n; ++i) {
        if (i == min_val_idx) {
            continue;
        }
        // For each other pile a[i], we can add min_val to it
        // as many times as possible without exceeding k.
        // The current value of a[i] is a[i].
        // We want to find max_ops such that a[i] + max_ops * min_val <= k.
        // max_ops * min_val <= k - a[i]
        // max_ops <= (k - a[i]) / min_val
        // Since max_ops must be an integer, it's floor((k - a[i]) / min_val).
        if (min_val > 0) { // To avoid division by zero, though problem constraints say a_i >= 1
            total_spells += (k - a[i]) / min_val;
        }
    }

    std::cout << total_spells << std::endl;
}

