        if (type == 1) { // Ping server 'a'
            successful_a += x;
            total_sent_a += 10;
        } else { // Ping server 'b'
            successful_b += x;
            total_sent_b += 10;
        }
    }

    // Check server 'a'
    // A server is "alive" if at least half of the packets reached it successfully.
    // This means successful_a >= total_sent_a / 2.0
    // To avoid floating point, we can use successful_a * 2 >= total_sent_a
    if (successful_a * 2 >= total_sent_a) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    // Check server 'b'
    if (successful_b * 2 >= total_sent_b) {
        std::cout << "LIVE\n";
    } else {
        std::cout << "DEAD\n";
    }

    return 0;
}

