void solve() {
    int n, d;
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    int current_a1 = a[0];
    int days_left = d;

    for (int i = 1; i < n; ++i) {
        // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0)
        // is i days.
        int cost_per_haybale = i; 

        if (days_left >= cost_per_haybale) {
            // Calculate how many haybales we can move from pile i+1
            // given the available days and the cost per haybale.
            int haybales_to_move = std::min(a[i], days_left / cost_per_haybale);

            current_a1 += haybales_to_move;
            days_left -= haybales_to_move * cost_per_haybale;
        }
        // If days_left < cost_per_haybale, we cannot move any haybale from this pile
        // or any further piles (since cost increases with distance).
        if (days_left == 0) {
            break;
        }
    }

    std::cout << current_a1 << std::endl;
}

