void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << std::endl;
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits.
        // This number will be 233...3 (n-1 times '3').
        //
        // Let's check divisibility:
        // 1. Not divisible by 2: The number ends in 3, which is odd.
        // 2. Not divisible by 3: The sum of digits is 2 + (n-1)*3.
        //    If n=2, sum is 2+3=5, not div by 3.
        //    If n=3, sum is 2+3+3=8, not div by 3.
        //    If n=4, sum is 2+3+3+3=11, not div by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    Since 3n is divisible by 3, 3n-1 is never divisible by 3.
        //
        // So, this construction works for all n >= 2.
        // The digits are 2 and 3, neither is 0.
        // The number has n digits.
        // It's not divisible by 2 (because it's odd).
        // It's not divisible by 3 (because sum of digits is 3n-1, not div by 3).
        //
        // Example:
        // n=2: 23. Not div by 2, not div by 3. Works.
        // n=3: 233. Not div by 2, not div by 3. Works.
        // n=4: 2333. Not div by 2, not div by 3. Works.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
    }
}

