void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    int color_for_half_T = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use floating point for comparison to handle T/2.0 correctly
            p[i] = 0; // White
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Black
        } else { // a[i] == T / 2.0
            // If T is even and a[i] == T/2, we alternate colors
            // This ensures that if we have multiple T/2 elements,
            // they are split between c and d as evenly as possible.
            // For example, if T=6, a=[3,3,3], then p=[0,1,0] or [1,0,1]
            // c=[3,3], d=[3] -> f(c)=1, f(d)=0 -> total 1
            // c=[3], d=[3,3] -> f(c)=0, f(d)=1 -> total 1
            // This strategy minimizes pairs of T/2 elements.
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Toggle color for next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

