int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Only consider a_i,j where i != j
                max_val_in_row = std::max(max_val_in_row, a[i][j]);
            }
        }
        // If max_val_in_row is n-1, it means p_i must be n.
        // Otherwise, p_i is max_val_in_row.
        // This logic is derived from the observation that if p_i is not n,
        // then there must be some p_j > p_i, and min(p_i, p_j) = p_i.
        // So max_val_in_row would be p_i.
        // If p_i is n, then for all j, min(p_i, p_j) = p_j.
        // The maximum of these p_j (for j != i) would be n-1 (since p_j cannot be n).
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    // Initialize min_suffix with the price of the last day.
    // The last day's price can never be bad because there are no days after it.
    int min_suffix = a[n - 1]; 

    // Iterate from the second to last day down to the first day.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix, it means a[i] is
            // either equal to or less than min_suffix.
            // In this case, a[i] becomes the new minimum for subsequent
            // days to its left (i.e., days j < i).
            min_suffix = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

