        // Or at least $n$ elements are less than $M_1$.
        //
        // This is a known result in competitive programming. The minimum difference between medians of two odd-sized partitions of $2n$ elements is $a_n - a_{n-1}$.
        //
        // The implementation is simply sorting and taking the difference.

        long long result = a[n] - a[n-1];
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos is -1, it means the frog is at cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i.
                // The previous 'R' (or start) was at last_R_pos.
                // The gap is (i - last_R_pos).
                // We need to be able to jump over this gap.
                // The frog can jump from last_R_pos to any cell in [last_R_pos + 1, min(n + 1, last_R_pos + d)].
                // To reach cell i, we need last_R_pos + d >= i.
                // So, d >= i - last_R_pos.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or start)
        // to the target cell n+1.
        // The last 'R' was at last_R_pos.
        // The target is n+1.
        // The gap is (n + 1 - last_R_pos).
        // We need d >= n + 1 - last_R_pos.
        max_gap = std::max(max_gap, n + 1 - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

