    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // This uses 'mid' from c and 'mid' from m.
            // Remaining coders: c - mid
            // Remaining mathematicians: m - mid
            // Remaining unspecialized: x
            // Total remaining students: (c - mid) + (m - mid) + x
            // Each team needs 3 members. 'mid' teams need 3 * mid members.
            // We've already assigned 'mid' coders and 'mid' mathematicians.
            // So we need 'mid' more students to fill the teams.
            // These 'mid' students can come from the remaining pool.
            if (mid <= c && mid <= m && mid <= (c - mid) + (m - mid) + x) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

