#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    int p = n - 1;
    while (p > 0 && a[p-1] <= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-decreasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // If p is 0, then the whole array is non-decreasing, so q can be 0.
    // If p > 0, we start checking from p-1.
    int q = p; // Initialize q to p. If p is 0, q remains 0.
    if (p > 0) {
        q = p - 1;
        while (q > 0 && a[q-1] >= a[q]) {
            q--;
        }
    }

    // The prefix to remove is a[0...q-1].
    // The length of this prefix is q.
    std::cout << q << std::endl;
}

