void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 1) {
        if (A == 1) ans1 = "Ya";
        if (B == 1) ans2 = "Ya";
        if (C == 1) ans3 = "Ya";
        if (D == 1) ans4 = "Ya";
    } else {
        // Box 1: (-inf, -1]
        // Final value must be negative and magnitude >= 1
        // This requires an odd number of initial negative toys.
        // And it requires that the magnitude can be >= 1.

        // Case 1: Final toy in Box 1 (negative, magnitude >= 1)
        // Number of negative toys must be odd.
        if ((A + B) % 2 != 0) {
            // Can we make magnitude >= 1?
            // If there's at least one toy in Box 1 or Box 4, we can potentially make magnitude >= 1.
            // If all toys are in Box 2 and Box 3, then magnitude will always be < 1.
            if (A > 0 || D > 0) {
                ans1 = "Ya";
            } else { // A=0, D=0. All toys are in B and C.
                // If B is odd, and C is anything, the result is negative.
                // But all values are < 1 in magnitude, so product will be < 1.
                // So if A=0 and D=0, Box 1 is impossible.
                // This is covered by the (A > 0 || D > 0) check.
            }
        } else { // (A + B) % 2 == 0, final value is positive.
            // If A+B is even, the final value is positive.
            // However, if B is odd, and A is odd, then A+B is even.
            // If A is odd, we can pair up all B toys, and all C toys, and all D toys.
            // Then we are left with an odd number of A toys.
            // If we have A toys, we can make a product that is negative and >= 1.
            // If we have an even number of negative toys, the final product is positive.
            // But we can choose to pair them up such that the last multiplication involves a negative number.
            // Example: A=2, B=0, C=0, D=0. Values {-2, -3}. Product is 6.
            // Example: A=1, B=1, C=0, D=0. Values {-2, -0.5}. Product is 1.
            // The condition (A+B)%2 != 0 is for the *final* sign.
            // But we can control the order of operations.
            // If we want a negative result, we need an odd number of negative values in the final multiplication.
            // This means we need an odd number of negative values *overall*.
            // So (A+B)%2 != 0 is correct for the final sign.
            // The only exception is if we have a zero, but fun values are real numbers, not integers, and not zero.
        }

        // Case 2: Final toy in Box 2 (-1, 0)
        // Final value must be negative and magnitude < 1
        // This requires an odd number of initial negative toys.
        // And it requires that the magnitude can be < 1.

        // If (A+B) is odd (final sign is negative):
        if ((A + B) % 2 != 0) {
            // Can we make magnitude < 1?
            // Yes, if B > 0 or C > 0.
            // If B > 0, we can use a toy from B to reduce magnitude.
            // If C > 0, we can use a toy from C to reduce magnitude.
            // If A > 0 and D > 0, we can pick values like A = {-10}, D = {0.01}, B = {-0.1}.
            // -10 * 0.01 = -0.1 (in B). Then -0.1 * -0.1 = 0.01 (in C).
            // This is about existence of a scenario.
            // If B > 0 or C > 0, we can always make the magnitude < 1.
            // What if B=0 and C=0? Then all toys are in A and D.
            // If A is odd, D is even: A toys are {-2, -3, -4}, D toys are {2, 3}.
            // Product of A toys is negative and magnitude >= 1. Product of D toys is positive and magnitude >= 1.
            // Final product is negative and magnitude >= 1. So it goes to Box 1.
            // If A is odd, D is odd: A toys are {-2, -3, -4}, D toys are {2, 3, 4}.
            // Product of A toys is negative and magnitude >= 1. Product of D toys is positive and magnitude >= 1.
            // Final product is negative and magnitude >= 1. So it goes to Box 1.
            // So if B=0 and C=0, and (A+B) is odd, the result is always in Box 1.
            // Thus, for Box 2, we need (B > 0 || C > 0).
            if (B > 0 || C > 0) {
                ans2 = "Ya";
            }
        } else { // (A + B) % 2 == 0, final sign is positive.
            // If A+B is even, the final product is positive.
            // But we can make it negative if we have at least one toy in B.
            // Example: A=1, B=1, C=0, D=0. Values {-2, -0.5}. Product is 1. (Positive)
            // Example: A=0, B=2, C=0, D=0. Values {-0.5, -0.5}. Product is 0.25. (Positive)
            // The only way to get a negative result is if (A+B) is odd.
            // So if (A+B) is even, Box 2 is impossible.
        }

        // Case 3: Final toy in Box 3 (0, 1)
        // Final value must be positive and magnitude < 1
        // This requires an even number of initial negative toys.
        // And it requires that the magnitude can be < 1.

        // If (A+B) is even (final sign is positive):
        if ((A + B) % 2 == 0) {
            // Can we make magnitude < 1?
            // Yes, if B > 0 or C > 0.
            // If B=0 and C=0, then all toys are in A and D.
            // Product of A toys is positive and magnitude >= 1. Product of D toys is positive and magnitude >= 1.
            // Final product is positive and magnitude >= 1. So it goes to Box 4.
            // Thus, for Box 3, we need (B > 0 || C > 0).
            if (B > 0 || C > 0) {
                ans3 = "Ya";
            }
        } else { // (A + B) % 2 != 0, final sign is negative.
            // If A+B is odd, the final product is negative.
            // So Box 3 is impossible.
        }

        // Case 4: Final toy in Box 4 [1, inf)
        // Final value must be positive and magnitude >= 1
        // This requires an even number of initial negative toys.
        // And it requires that the magnitude can be >= 1.

        // If (A+B) is even (final sign is positive):
        if ((A + B) % 2 == 0) {
            // Can we make magnitude >= 1?
            // Yes, if A > 0 or D > 0.
            // If A=0 and D=0, then all toys are in B and C.
            // Product of B toys is positive and magnitude < 1. Product of C toys is positive and magnitude < 1.
            // Final product is positive and magnitude < 1. So it goes to Box 3.
            // Thus, for Box 4, we need (A > 0 || D > 0).
            if (A > 0 || D > 0) {
                ans4 = "Ya";
            }
        } else { // (A + B) % 2 != 0, final sign is negative.
            // If A+B is odd, the final product is negative.
            // So Box 4 is impossible.
        }

        // Special case: If B=0 and C=0, all toys are in A and D.
        // All magnitudes are >= 1.
        // If A is even, product is positive, magnitude >= 1 -> Box 4.
        // If A is odd, product is negative, magnitude >= 1 -> Box 1.
        // In this case, Box 2 and Box 3 are impossible.
        if (B == 0 && C == 0) {
            ans2 = "Tidak";
            ans3 = "Tidak";
            if (A % 2 == 0) { // Positive result
                ans1 = "Tidak";
                ans4 = "Ya";
            } else { // Negative result
                ans1 = "Ya";
                ans4 = "Tidak";
            }
        }
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << std::endl;
}

