int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // For 0-indexed array, (n-1)/2 is the middle index

    // Cost to make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of median must be <= s
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median must be >= s
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B (with original indices) in ascending order of B_i
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // To maximize sum(F(A'_i, B_i)), we need to pair larger A_i with smaller B_i.
    // This is because F(n, k) = n / (k+1).
    // So we want to maximize sum(A'_i / (B_i + 1)).
    // This is a rearrangement inequality problem.
    // To maximize sum(x_i * y_i), if x_i are sorted, y_i should be sorted in the same order.
    // Here, we want to maximize sum(A'_i * (1 / (B_i + 1))).
    // Let x_i = A'_i and y_i = 1 / (B_i + 1).
    // To maximize sum(x_i * y_i), we should sort x_i and y_i in the same order.
    // A is sorted ascending.
    // 1 / (B_i + 1) is sorted descending if B_i is sorted ascending.
    // So, we should pair the smallest A_i with the largest 1/(B_i+1),
    // which means smallest A_i with smallest B_i.
    // This is incorrect. The rearrangement inequality states that to maximize sum(x_i * y_i),
    // if x_i are sorted ascending, y_i should also be sorted ascending.
    // So, if A'_i are sorted ascending, then 1/(B_i+1) should be sorted ascending.
    // This means B_i+1 should be sorted descending, which means B_i should be sorted descending.

    // Let's re-evaluate.
    // We have sorted A: a_0 <= a_1 <= ... <= a_{m-1}
    // We have sorted B: b_0 <= b_1 <= ... <= b_{m-1} (where b_i here refers to the value, not the original index)
    // We want to assign a_j to b_i such that sum(a_j / (b_i + 1)) is maximized.
    // Let x_j = a_j and y_i = 1 / (b_i + 1).
    // The sequence x is sorted ascending.
    // The sequence y is sorted descending (since b_i is ascending, b_i+1 is ascending, so 1/(b_i+1) is descending).
    // To maximize sum(x_j * y_i), we should pair the largest x_j with the largest y_i,
    // the second largest x_j with the second largest y_i, and so on.
    // Or, equivalently, pair the smallest x_j with the smallest y_i.
    // Since x is ascending and y is descending, to maximize the sum, we should pair
    // a_0 with y_{m-1} (which is 1/(b_{m-1}+1))
    // a_1 with y_{m-2} (which is 1/(b_{m-2}+1))
    // ...
    // a_{m-1} with y_0 (which is 1/(b_0+1))
    // This means we pair a_j with b_{m-1-j}.

    // So, we iterate through the sorted A array (a_0, a_1, ..., a_{m-1})
    // and pair a_j with the B value at index (m-1-j) from the sorted B array.
    // The original index of this B value is b_indexed[m-1-j].second.
    // We store a_j in a_prime at that original index.

    for (int i = 0; i < m; ++i) {
        // a[i] is the i-th smallest value from original A.
        // b_indexed[m - 1 - i] is the (m-1-i)-th smallest B value,
        // which means it's the i-th largest B value.
        // We pair a[i] with b_indexed[m - 1 - i].first.
        // The result should be stored at the original index of b_indexed[m - 1 - i].
        a_prime[b_indexed[m - 1 - i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
