    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case: N=2, Chanek takes 1, N becomes 1, Opponent takes 1. Chanek gets 1.
                chanek_coins += 1;
                n -= 1;
            } else if ((n / 2) % 2 != 0) { // N is even, N/2 is odd.
                                           // If Chanek takes N/2, remaining N/2 is odd. Opponent takes 1.
                                           // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                                           // Taking N/2 is better for Chanek.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N is even, N/2 is even.
                     // If Chanek takes N/2, remaining N/2 is even. Opponent can take (N/2)/2 = N/4.
                     // If Chanek takes 1, remaining N-1 is odd. Opponent takes 1.
                     // Taking 1 is better for Chanek.
                chanek_coins += 1;
                n -= 1;
            }
        }

        if (n == 0) break; // Game ends if no coins left

        // Opponent's turn (optimal play for opponent)
        if (n % 2 != 0) { // N is odd
            n -= 1;
        } else { // N is even
            if (n == 2) {
                n -= 1;
            } else if ((n / 2) % 2 != 0) {
                n /= 2;
            } else {
                n -= 1;
            }
        }
    }
    return chanek_coins;
}

