    int j = 0; // Pointer for the elements we are trying to place (the 'b' array elements)
    // We iterate through the sorted 'a' array (representing the original positions)
    // and try to find a larger element from 'a' itself (representing the 'b' array elements).
    for (int i = 0; i < n; ++i) { // i is the pointer for the 'a[i]' values
        // We want to find an element a[j] such that a[j] > a[i].
