int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
        // Let's try to append two elements: current_xor_sum and (current_sum + current_xor_sum).
        // Let b1 = current_xor_sum
        // Let b2 = current_sum + current_xor_sum
        //
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum
        //
        // New sum: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * (current_sum + current_xor_sum)
        //
        // We want S' = 2 * X'.
        // From above, S' = 2 * (current_sum + current_xor_sum) and X' = current_sum + current_xor_sum.
        // So, S' = 2 * X' is satisfied.
        //
        // The number of elements to append is 2.
        // The elements are current_xor_sum and (current_sum + current_xor_sum).
        // Note that current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
        // So b2 can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // (which we have counted in `count_a`) can potentially
            // interact with this 'b'.
            // Each 'a' to its left will eventually "jump" over this 'b'.
            // When an 'a' jumps over a 'b', it creates a new 'b'.
            // So, this 'b' effectively doubles the number of 'a's that
            // can jump over subsequent 'b's to its left.
            // The number of steps added by this 'b' is `count_a`.
            total_steps = (total_steps + count_a) % MOD;
            // After this 'b' is processed, it effectively doubles the
            // number of 'a's that can jump over 'b's further to the left.
            // This is because each 'a' that jumps over this 'b' creates
            // a new 'b'. So, for any 'a' to the left of this 'b', it
            // will eventually jump over this 'b' (1 step) AND the new 'b'
            // created by the 'a' that was originally to its right (1 step).
            // This is equivalent to saying that each 'a' to the left
            // will interact with this 'b' and the 'b' it generates.
            // So, the effective count of 'a's for 'b's further left doubles.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are available to interact with 'b's to its right.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs counted twice (those with same x AND same y)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // Step 1: Determine '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then both w[i-x] and w[i+x] (if they exist) must be '0'.
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will store the s generated from our w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        }
    }

    if (s == s_prime) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use as many 5s as possible
        presses += diff / 5;
        diff %= 5;

        // Remaining diff can be 0, 1, 2, 3, 4
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1) {
            // Can be 1 (+1) or 2 (-2, +1) or 3 (-5, +2, +2)
            // Optimal for 1 is 1 press (+1)
            presses += 1;
        } else if (diff == 2) {
            // Optimal for 2 is 1 press (+2)
            presses += 1;
        } else if (diff == 3) {
            // Can be 2 presses (+1, +2) or (+5, -2)
            // Optimal for 3 is 2 presses (+1, +2)
            presses += 2;
        } else if (diff == 4) {
            // Can be 2 presses (+2, +2) or (+5, -1)
            // Optimal for 4 is 2 presses (+2, +2)
            presses += 2;
        }

        std::cout << presses << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <map>

// Using std::map to store counts for each pattern.
// The key is the 18-digit parity pattern (as a string or long long).
// Since the pattern length is at most 18, and we pad with '0's from the left
// to make it 18 digits long, we can represent it as an 18-digit binary string
// or convert it to a long long.
// A string representation is simpler to handle directly from the input.
// The maximum value for a_i is < 10^18, so it has at most 18 digits.
// The pattern length is also at most 18.

// Function to convert a number to its 18-digit parity pattern string.
// Example: 241 -> "000000000000000101" (18 digits)
// 2 -> even (0)
// 4 -> even (0)
// 1 -> odd (1)
// So 241 becomes 00...00101 (reversed: 101)
// The problem states "i-th from the right digit", so we build it from right to left.
std::string get_parity_pattern(long long n) {
    std::string pattern = "";
    if (n == 0) {
        pattern = "0"; // Special case for 0, its parity is 0.
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) { // Even digit
                pattern += '0';
            } else { // Odd digit
                pattern += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to make it 18 digits long.
    // Since we built it from right to left, we append '0's to the end.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

int main() {
    // Optimize C++ standard streams for competitive programming.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Map to store counts of each 18-digit parity pattern.
    // Key: 18-digit parity pattern string.
    // Value: Count of numbers in the multiset matching this pattern.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            // Pad the query pattern with '0's from the left to make it 18 digits.
            // The problem states "if the pattern is shorter than this integer, it's supplemented with 0-s from the left."
            // And "if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
            // This means we effectively compare 18-digit parity strings.
            // The input pattern 's' is given from left to right.
            // Example: s = "010" means rightmost is '0', second is '1', third is '0'.
            // So, to match our internal representation (which is built right-to-left and then padded),
            // we need to reverse the input pattern and then pad.
            std::string query_pattern_reversed = "";
            for (int j = s.length() - 1; j >= 0; --j) {
                query_pattern_reversed += s[j];
            }
            while (query_pattern_reversed.length() < 18) {
                query_pattern_reversed += '0';
            }

            // The map stores patterns in the format "d17d16...d1d0" where d0 is the rightmost digit's parity.
            // get_parity_pattern(241) -> "00...00101" (1 is rightmost, 0 is second, 1 is third)
            // For query "010":
            //   Rightmost digit parity should be 0.
            //   Second from right digit parity should be 1.
            //   Third from right digit parity should be 0.
            // This matches the structure of `query_pattern_reversed`.
            // So, if s = "010", query_pattern_reversed becomes "010" (then padded to 18 "01000...00").
            // This is correct. The `get_parity_pattern` function builds the string from right to left,
            // so the first character in its string is the parity of the rightmost digit.
            // The query pattern `s` is given with the most significant digit first.
            // Example: s = "010" means 0 for 10^2 place, 1 for 10^1 place, 0 for 10^0 place.
            // So, we need to convert `s` into the same format as `get_parity_pattern` output.
            // `get_parity_pattern` for 241 gives "10100...00" (1 for 1, 0 for 4, 1 for 2).
            // Let's re-evaluate `get_parity_pattern` and the query pattern.

            // Corrected `get_parity_pattern` logic:
            // The problem states "i-th from the right digit".
            // For `x = 92`, `s = 010`.
            // `x` digits: ..., 0, 0, 9, 2
            // `s` digits: ..., 0, 0, 0, 1, 0
            // Rightmost (1st from right) digit of `x` is 2 (even). Matches `s`'s rightmost '0'.
            // 2nd from right digit of `x` is 9 (odd). Matches `s`'s 2nd from right '1'.
            // 3rd from right digit of `x` is 0 (even). Matches `s`'s 3rd from right '0'.
            // This means the pattern `s` is given with its rightmost digit at `s[s.length()-1]`.
            // My `get_parity_pattern` builds the string from right to left, so `pattern[0]` is the rightmost digit's parity.
            // Example: `get_parity_pattern(241)`:
            // 1 (odd) -> '1'
            // 4 (even) -> '0'
            // 2 (even) -> '0'
            // Result: "100" (then padded to "10000...00").
            // This is the correct internal representation.

            // Now for the query pattern `s`:
            // If `s = "010"`, it means:
            // `s[2]` ('0') is for the rightmost digit.
            // `s[1]` ('1') is for the 2nd from right digit.
            // `s[0]` ('0') is for the 3rd from right digit.
            // So, to match `get_parity_pattern`'s output, we need to reverse `s` and then pad.
            // `s = "010"` -> reversed `s` is "010".
            // Padded to 18: "010000000000000000".
            // This is the key for the map.

            std::string query_key = "";
            for (int j = s.length() - 1; j >= 0; --j) {
                query_key += s[j];
            }
            while (query_key.length() < 18) {
                query_key += '0';
            }

            std::cout << pattern_counts[query_key] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_total_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let 'i' be the number of items taken from the left (0 <= i <= n)
    // Then 'n - i' items are taken from the right.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += prefix_sum[i] * l;

        // Energy for items taken from the right
        // The items taken from the right are w[n-j], w[n-j+1], ..., w[n-1]
        // Sum of these weights is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for imbalance
        if (i > j) { // More items from left than right
            // The difference is i - j.
            // If i = j + 1, one extra item from left. No penalty.
            // If i = j + 2, two extra items from left. One penalty.
            // Penalty applies for (i - j - 1) extra items from left.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The difference is j - i.
            // If j = i + 1, one extra item from right. No penalty.
            // If j = i + 2, two extra items from right. One penalty.
            // Penalty applies for (j - i - 1) extra items from right.
            current_energy += (j - i - 1) * Qr;
        }

        if (min_total_energy == -1 || current_energy < min_total_energy) {
            min_total_energy = current_energy;
        }
    }

    std::cout << min_total_energy << std::endl;

    return 0;
}

