int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Precompute prefix sums for counts of 'x', 'y', 'z'
    // counts[0] for 'x', counts[1] for 'y', counts[2] for 'z'
    std::vector<std::vector<int>> counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            counts[j][i + 1] = counts[j][i];
        }
        if (s[i] == 'x') {
            counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            counts[1][i + 1]++;
        } else { // s[i] == 'z'
            counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) { // Substring length less than 3
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the current substring s[l-1...r-1]
        int count_x = counts[0][r] - counts[0][l - 1];
        int count_y = counts[1][r] - counts[1][l - 1];
        int count_z = counts[2][r] - counts[2][l - 1];

        // Check if the counts are "balanced" enough
        // The difference between max and min count should be at most 1
        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long ans = 1;
    long long temp_q = q;

    // Find prime factors of q
    std::vector<long long> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    // For each prime factor f of q, find the largest divisor of p
    // that is not divisible by q, by reducing the power of f in p.
    for (long long f : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= f;
        }
        ans = std::max(ans, current_p);
    }

    return ans;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string ans(n, ' ');
    bool possible = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::vector<int> color1_digits;
        std::vector<int> color2_digits;
        bool current_pivot_possible = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < pivot_digit) {
                ans[i] = '1';
                color1_digits.push_back(digit);
            } else if (digit > pivot_digit) {
                ans[i] = '2';
                color2_digits.push_back(digit);
            } else { // digit == pivot_digit
                // Try to assign to color 2 first if possible
                // This ensures that if there are multiple pivot_digits,
                // the ones that come after the first pivot_digit assigned to color 1
                // are assigned to color 2.
                // This is crucial for the "last_1 <= first_2" condition.
                // If we assign a pivot_digit to color 1, then all subsequent pivot_digits
                // must be assigned to color 2.
                // If we assign a pivot_digit to color 2, then all preceding pivot_digits
                // must have been assigned to color 1.
                // The strategy is: assign to color 2 if it maintains sorted order for color 2.
                // Otherwise, assign to color 1 if it maintains sorted order for color 1.
                // If neither works, this pivot_digit choice is invalid.

                // Check if assigning to color 2 is valid
                if (color2_digits.empty() || digit >= color2_digits.back()) {
                    ans[i] = '2';
                    color2_digits.push_back(digit);
                } else if (color1_digits.empty() || digit >= color1_digits.back()) {
                    ans[i] = '1';
                    color1_digits.push_back(digit);
                } else {
                    current_pivot_possible = false;
                    break;
                }
            }
        }

        if (current_pivot_possible) {
            // Verify the sorted property for color1_digits and color2_digits
            bool sorted1 = true;
            for (size_t i = 1; i < color1_digits.size(); ++i) {
                if (color1_digits[i] < color1_digits[i-1]) {
                    sorted1 = false;
                    break;
                }
            }
            bool sorted2 = true;
            for (size_t i = 1; i < color2_digits.size(); ++i) {
                if (color2_digits[i] < color2_digits[i-1]) {
                    sorted2 = false;
                    break;
                }
            }

            if (sorted1 && sorted2) {
                possible = true;
                break;
            }
        }
    }

    if (possible) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;

    long long min_x = -2000000000LL; // Effectively negative infinity
    long long max_x = 2000000000LL;  // Effectively positive infinity
    long long min_y = -2000000000LL; // Effectively negative infinity
    long long max_y = 2000000000LL;  // Effectively positive infinity

    for (int i = 0; i < n; ++i) {
        long long x, y;
        int f1, f2, f3, f4;
        std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

        // f1 = 1: can move left (x-1, y)
        // If f1 = 0, robot cannot move left.
        // This means any target X must be >= current x.
        // So, X >= x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }

        // f2 = 1: can move up (x, y+1)
        // If f2 = 0, robot cannot move up.
        // This means any target Y must be <= current y.
        // So, Y <= y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }

        // f3 = 1: can move right (x+1, y)
        // If f3 = 0, robot cannot move right.
        // This means any target X must be <= current x.
        // So, X <= x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }

        // f4 = 1: can move down (x, y-1)
        // If f4 = 0, robot cannot move down.
        // This means any target Y must be >= current y.
        // So, Y >= y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. The problem guarantees that if a point exists,
        // one exists with coordinates not exceeding 10^5 by absolute value.
        // So, we can just pick any point in the valid range, e.g., (min_x, min_y).
        // We need to clamp to the guaranteed range if min_x/min_y are outside,
        // but the problem statement implies that min_x/min_y will be within
        // the [-10^5, 10^5] range if a solution exists.
        // The initial coordinates are up to 10^5, so min_x/max_x/min_y/max_y
        // will be within this range.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modular inverse.
    // Modular inverse of 2 modulo 10^9+7 is (10^9+7 + 1) / 2 = 500000004.
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r must be != 0. So no nice integers.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7
        sum_r_val = (b_minus_1 % MOD * (b % MOD)) % MOD;
        sum_r_val = (sum_r_val * inv2) % MOD;
    }

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a+1) / 2
    long long sum_k_val;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7
    sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_k_b_plus_1_val = (b % MOD * sum_k_val) % MOD;
    sum_k_b_plus_1_val = (sum_k_b_plus_1_val + (a % MOD)) % MOD;

    // Total sum = (sum_r_val * sum_k_b_plus_1_val) % MOD
    long long total_sum = (sum_r_val * sum_k_b_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::vector<bool> used_in_layout(26, false); // 'a' -> 0, 'b' -> 1, etc.

    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj.count(c) && adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    if (start_char == '\0') { // All characters in adj have 0 or 2 neighbors
        // If there are any characters in adj, pick one with 2 neighbors to start a cycle
        // Or if there's only one character in s, it has 0 neighbors.
        // If s has length 1, adj is empty.
        // If s has length > 1 and all chars in adj have 2 neighbors, it's a cycle.
        // We can pick any character from adj to start.
        if (!adj.empty()) {
            start_char = adj.begin()->first;
        } else { // s has length 1, e.g., "a"
            start_char = s[0];
        }
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // Sentinel for the first character

        while (true) {
            if (used_in_layout[current_char - 'a']) { // Cycle detected or already processed
                // This can happen if we start from a character in a cycle and traverse it,
                // then try to add it again. Or if we start from a character that's part of a path
                // and then try to add it again.
                // The only valid case for this loop to terminate is if we've exhausted all
                // connected components that start_char belongs to.
                break;
            }
            layout_str += current_char;
            used_in_layout[current_char - 'a'] = true;

            char next_char = '\0';
            if (adj.count(current_char)) {
                for (char neighbor : adj[current_char]) {
                    if (neighbor != prev_char) {
                        next_char = neighbor;
                        break;
                    }
                }
            }

            if (next_char == '\0') { // End of path or isolated character
                break;
            }
            prev_char = current_char;
            current_char = next_char;
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!used_in_layout[c - 'a']) {
            layout_str += c;
        }
    }

    // Check if the constructed layout is valid
    // This check is implicitly handled by the logic above.
    // If any character had >2 neighbors, we'd have returned "NO".
    // If we formed a valid path/cycle, it's fine.
    // The only remaining check is if the graph formed by adjacencies in 's'
    // is a single path or a single cycle.
    // If it's multiple paths/cycles, our construction might fail.
    // However, the problem statement implies we just need to satisfy adjacencies.
    // The current construction strategy builds one connected component first,
    // then appends all other characters. This is always valid if the initial
    // adjacency constraints are met (max 2 neighbors).

    // The only case where this could be "NO" but not caught by >2 neighbors
    // is if the graph formed by adjacencies in 's' has multiple connected components
    // where each component is a path or a cycle, AND these components cannot be
    // "merged" into a single linear layout.
    // Example: s="ab", t="cd". This would require 'a'-'b' and 'c'-'d'.
    // Layout: abcd... is valid.
    // The current algorithm handles this: it builds "ab", then adds "c", then "d", etc.
    // So, if adjacencies are valid (max 2 neighbors), it's always YES.

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

