int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top triangle (from apex to i-th cut) should be i * (total_area / n)
        // Let A_total be the total area of the carrot. A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
        // The area of each piece is A_piece = A_total / n = (h/2) / n = h / (2n).
        // The area of the top triangle up to the i-th cut (x_i distance from apex) is i * A_piece.
        // Area_x_i = i * (h / (2n)).
        // For a triangle similar to the original, with height x_i, its area is (1/2) * (x_i/h) * x_i = x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n)).
        // x_i^2 = i * (h^2 / n).
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

