void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars n down to 1)
    // and suffix sums for the right side (jars n+1 up to 2n)
    // A value of 1 means strawberry, 2 means blueberry.
    // We can convert this to +1 for strawberry and -1 for blueberry
    // to find the difference.
    // Let's use +1 for type 1 and -1 for type 2.
    // The goal is to have the final sum of remaining jars be 0.

    // Left side: jars n-1 down to 0 (0-indexed)
    // Right side: jars n up to 2n-1 (0-indexed)

    // diff_L[k] = sum of (a[n-1-i] == 1 ? 1 : -1) for i from 0 to k-1
    // This is the balance of the first k jars eaten from the left (n, n-1, ..., n-k+1)
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[n - 1 - i] == 1 ? 1 : -1);
    }

    // diff_R[k] = sum of (a[n+i] == 1 ? 1 : -1) for i from 0 to k-1
    // This is the balance of the first k jars eaten from the right (n+1, n+2, ..., n+k)
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[n + i] == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars eaten from the left (k_L)
    // to achieve a certain balance `d`.
    // map_L[d] = k_L
    std::map<int, int> map_L;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = diff_L[k_L];
        if (map_L.find(current_diff) == map_L.end()) {
            map_L[current_diff] = k_L;
        }
    }

    int min_eaten = 2 * n; // Initialize with maximum possible jars eaten

    // Iterate through all possible numbers of jars eaten from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_R = diff_R[k_R];
        // We need to find a k_L such that diff_L[k_L] + current_diff_R = 0
        // This means diff_L[k_L] = -current_diff_R
        int target_diff_L = -current_diff_R;

        if (map_L.count(target_diff_L)) {
            int k_L = map_L[target_diff_L];
            min_eaten = std::min(min_eaten, k_L + k_R);
        }
    }

    std::cout << min_eaten << std::endl;
}

