            //   Condition: `first_one_idx - i + 2 <= 3` => `first_one_idx - i <= 1`.
            // For `k+1 = 3` (substring is '1xx'), length is `first_one_idx - i + 3`. Max value is 7.
            //   Condition: `first_one_idx - i + 3 <= 7` => `first_one_idx - i <= 4`.
            // In general, `first_one_idx - i + (k+1) <= 2^(k+1) - 1`.
            // `first_one_idx - i <= 2^(k+1) - 1 - (k+1)`.
            // The maximum value of `k+1` we need to check is small.
            // If `k+1 = 20`, `2^20 - 1 - 20` is about `10^6`.
            // `first_one_idx - i` can be at most `N`.
            // So `k+1` can be up to about 20 (since `N` is `2e5`).
            // Let's say `MAX_BITS_TO_CHECK = 20` (or 21, to be safe, as `2^20` is ~1M, `2^21` is ~2M).
            // `N` is `2e5`. `first_one_idx - i` can be up to `N`.
            // `2^(k+1) - 1 - (k+1)` must be at least `first_one_idx - i`.
            // If `k+1 = 18`, `2^18 - 1 - 18 = 262144 - 19 = 262125`. This is > `2e5`.
            // So `k+1` up to 18 is sufficient.
            // We iterate `r` from `first_one_idx` up to `min(n-1, first_one_idx + MAX_BITS_TO_CHECK - 1)`.
            // Let `MAX_K_PLUS_1 = 18`.
            // So `r` goes from `first_one_idx` to `min(n-1, first_one_idx + MAX_K_PLUS_1 - 1)`.

            long long current_val = 0;
            for (int r = first_one_idx; r < n; ++r) {
                int num_bits_after_first_one = r - first_one_idx; // k
                if (num_bits_after_first_one >= 18) { // k+1 >= 19
                    // If current_val is already large, adding more bits will make it even larger.
                    // The length `r - i + 1` grows linearly, while `current_val` grows exponentially.
                    // If `current_val` exceeds `r - i + 1` by a large margin, it will continue to do so.
                    // The condition `r - i + 1 = current_val` will likely not be met.
                    // We can break early if `current_val` becomes too large relative to `r - i + 1`.
                    // A safe upper bound for `r - i + 1` is `N`.
                    // If `current_val > N + MAX_K_PLUS_1` (e.g., `2e5 + 18`), we can break.
                    // This check is implicitly handled by `current_val > n` or `current_val > r - i + 1`.
                    // But more strictly, if `current_val` exceeds `n + MAX_K_PLUS_1` (max possible length for this `k+1`),
                    // then it's too big.
                    // `current_val` can be at most `2^18 - 1` if `k+1=18`.
                    // `r - i + 1` can be at most `n`.
                    // If `current_val` exceeds `n`, it's already too big.
                    // The maximum value of `r-i+1` is `n`.
                    // If `current_val` exceeds `n`, it can't be equal to `r-i+1`.
                    // This is a good optimization.
                    if (current_val > n) break;
                }

                current_val = (current_val << 1) | (s[r] - '0');

                // Check if current_val is too large to be a valid length
                // The maximum possible length is n.
                if (current_val > n) {
                    break;
                }

                // Calculate the required number of leading zeros
                long long required_leading_zeros = current_val - (r - first_one_idx + 1);

                // If required_leading_zeros is negative, it means current_val is too small
                // for the current number of bits (from first_one_idx to r) to match the length
                // even if there were no leading zeros before first_one_idx.
                // This can happen if current_val is 1, and r-first_one_idx+1 is 2 (e.g., '10' or '11').
                // In this case, current_val is 1, length is 2. We need 1 leading zero.
                // required_leading_zeros = 1 - 2 = -1. This means it's impossible.
                // The condition `r - i + 1 = current_val` means `(first_one_idx - i) + (r - first_one_idx + 1) = current_val`.
                // So `first_one_idx - i = current_val - (r - first_one_idx + 1)`.
                // This `first_one_idx - i` is exactly `required_leading_zeros`.
                // We need `required_leading_zeros >= 0`.
                if (required_leading_zeros < 0) {
                    continue;
                }

                // Check if the actual number of leading zeros matches the required number
                if (first_one_idx - i == required_leading_zeros) {
                    good_substring_count++;
                }
            }
        }
        std::cout << good_substring_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

// Function to check if an array can be made non-decreasing with at most 'x' operations
// 'x' represents the maximum value added to any element (modulo m)
bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_b = 0; // The value of b_{i-1} in the non-decreasing sequence
    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];
        long long current_b;

        // Case 1: a_i is already >= prev_b
        if (current_a >= prev_b) {
            // We need b_i >= prev_b.
            // If a_i + x >= prev_b, then we can potentially set b_i = prev_b.
            // This means (a_i + k) % m = prev_b for some k <= x.
            // If a_i + x >= prev_b, then we can achieve prev_b by adding 0 operations (if a_i == prev_b)
            // or by adding (prev_b - a_i) operations (if a_i > prev_b).
            // In this case, we can always choose b_i = a_i, which requires 0 operations for this element.
            // Or, if a_i + x >= m + prev_b, we can wrap around and set b_i = prev_b.
            // This means (a_i + k) % m = prev_b for some k <= x.
            // The smallest k to make (a_i + k) % m = prev_b is 0 if a_i = prev_b, or (m - a_i + prev_b) % m if a_i != prev_b.
            // If a_i >= prev_b, we can choose b_i = a_i. This requires 0 operations for this element.
            // The value of b_i must be at least prev_b.
            // If a_i + x >= m + prev_b, it means we can increment a_i enough to wrap around and reach prev_b.
            // For example, if a_i=6, m=7, prev_b=0, x=1. a_i >= prev_b.
            // We can set b_i=6 (0 ops).
            // If a_i=0, m=7, prev_b=0, x=1. a_i >= prev_b.
            // We can set b_i=0 (0 ops).
            // If a_i=6, m=7, prev_b=0, x=2. a_i >= prev_b.
            // We can set b_i=6 (0 ops). Or b_i=0 (2 ops: 6->0, 6->1->...->6->0).
            // The condition for being able to set b_i = prev_b is that the number of operations needed
            // to change a_i to prev_b (modulo m) is <= x.
            // This number of operations is (m - a_i + prev_b) % m.
            // If (m - a_i + prev_b) % m <= x, then we can set b_i = prev_b.
            // Otherwise, we must set b_i = a_i.
            if (current_a + x < m + prev_b) { // This means we cannot wrap around to reach prev_b
                                               // or any value smaller than current_a but >= prev_b.
                                               // So we must use current_a as b_i.
                current_b = current_a;
            } else { // We can wrap around to reach prev_b.
                     // This means (a_i + k) % m = prev_b for some k <= x.
                     // The smallest k is (m - a_i + prev_b) % m.
                     // If this k <= x, we can set b_i = prev_b.
                     // Otherwise, we must set b_i = a_i.
                     // The condition current_a + x >= m + prev_b implies that we can reach prev_b.
                     // Example: a_i=6, m=7, prev_b=0, x=2.
                     // current_a + x = 6+2 = 8. m + prev_b = 7+0 = 7. 8 >= 7.
                     // So we can set b_i = prev_b = 0.
                     // Example: a_i=0, m=7, prev_b=0, x=1.
                     // current_a + x = 0+1 = 1. m + prev_b = 7+0 = 7. 1 < 7.
                     // So we must set b_i = current_a = 0.
                     // Example: a_i=0, m=7, prev_b=6, x=1.
                     // current_a + x = 0+1 = 1. m + prev_b = 7+6 = 13. 1 < 13.
                     // So we must set b_i = current_a = 0. This is not >= prev_b.
                     // This case is handled by the else branch below.
                current_b = prev_b;
            }
        } else { // Case 2: a_i < prev_b
            // We must increment a_i to be at least prev_b.
            // The number of operations needed to reach prev_b from a_i is (m - a_i + prev_b) % m.
            // This is equivalent to (m - a_i + prev_b).
            // If this value is greater than x, then we cannot make a_i into prev_b (or anything larger).
            // So it's impossible.
            if (current_a + x < prev_b) { // This means we cannot even reach prev_b.
                return false;
            }
            // Otherwise, we can reach prev_b. So we set b_i = prev_b.
            current_b = prev_b;
        }
        prev_b = current_b;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int m;
    std::cin >> n >> m;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long low = 0;
    long long high = m - 1;
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> max_val_constraint(n, LLONG_MAX); // max_val_constraint[j] stores the maximum possible value for a_0[j]

    // First pass: Determine upper bounds for initial_a[j]
    // For each type 2 query (l, r, m), we know a_0[j] + delta[j] <= m for all j in [l, r].
    // This means a_0[j] <= m - delta[j].
    // We need to find the minimum of all such (m - delta[j]) values for each a_0[j].
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_constraint[j] = std::min(max_val_constraint[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Initialize initial_a with the determined upper bounds.
    // If no upper bound was set for a_0[j], it can be anything, so we set it to 0.
    // If it was set, we use that value.
    // This strategy aims to satisfy a_0[j] + delta[j] <= m for all j,
    // and then we check if a_0[k] + delta[k] == m for some k.
    for (int j = 0; j < n; ++j) {
        if (max_val_constraint[j] == LLONG_MAX) {
            initial_a[j] = 0; // Default value if no constraint
        } else {
            initial_a[j] = max_val_constraint[j];
        }
    }

    // Second pass: Verify the solution
    // For each type 2 query (l, r, m), check if max_{j=l}^{r} (initial_a[j] + delta[j]) == m.
    // Also, check if initial_a[j] + delta[j] <= m for all j in [l, r].
    // The first pass ensures initial_a[j] + delta[j] <= m.
    // So we only need to check if the maximum is exactly m.
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long current_max = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_max = std::max(current_max, initial_a[j] + current_delta[j]);
            }
            if (current_max != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            if (total_d_cry_from_leaving > 0) {
                children[j].p -= total_d_cry_from_leaving;
            }

            // Apply v_cry from current child in doctor's office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].in_line = false; // Child j leaves
                total_d_cry_from_leaving += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    int count = 0;
    for (char c : s) {
        if (c == '1') {
            count++;
        }
    }
    return count;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If initial 'a' has an odd number of '1's, we can append a '1'.
    // This increases the count of '1's by one.
    // If initial 'a' has an even number of '1's, we can append a '0'.
    // This does not change the count of '1's.
    // So, the maximum number of '1's we can achieve from 'a' is ones_a if ones_a is even,
    // or ones_a + 1 if ones_a is odd.
    // This can be simplified to (ones_a + (ones_a % 2)).
    // After this, we can always append '0's or '1's to reach any length >= current length.
    // The number of '1's can be increased by 1 if the current parity is odd.
    // The number of '1's can be kept same if the current parity is even.
    // So, if we have `k` ones, and `k` is odd, we can make it `k+1` ones.
    // If we have `k` ones, and `k` is even, we can make it `k` ones.
    // This means the maximum number of ones we can ever achieve is `ones_a` if `ones_a` is even,
    // and `ones_a + 1` if `ones_a` is odd.
    // Let's call this `max_possible_ones_from_a`.

    int max_possible_ones_from_a = ones_a;
    if (ones_a % 2 != 0) { // If ones_a is odd, we can append a '1'
        max_possible_ones_from_a++;
    }

    // We need to be able to form 'b'.
    // 1. The number of '1's in 'b' must be less than or equal to the maximum '1's we can achieve from 'a'.
    // 2. The length of 'b' must be less than or equal to the length of 'a' after any necessary operations.
    //    Since we can always remove characters from the front, the length of 'b' must be at most the length of 'a'
    //    after we've potentially appended characters to 'a'.
    //    The minimum length 'a' can have is 1 (cannot remove if empty).
    //    The maximum length 'a' can have is effectively infinite, as we can always append.
    //    So, the length constraint is simply that |b| <= |a| (after some operations).
    //    If we can reach `max_possible_ones_from_a`, we can also reach any length `L >= |a|`
    //    with `max_possible_ones_from_a` or fewer ones (by appending '0's).
    //    The crucial part is that we can always make `a` longer than `b` if needed.
    //    The only constraint is that `ones_b` must be achievable.

    if (ones_b <= max_possible_ones_from_a) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // All f values are a_i + a_j.
    // min_f = a[0].value + a[1].value
    // max_f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 1);

    // Case 2: At least one element in S1 and at least one in S2.
    // This means there will be pairs (a_i, a_j) with f = a_i + a_j + h.
    // The minimum possible f value is a[0].value + a[1].value.
    // The maximum possible f value is a[n-2].value + a[n-1].value + h.
    // So, min_f will be min(a[0].value + a[1].value, a[0].value + a[1].value + h) = a[0].value + a[1].value.
    // And max_f will be max(a[n-2].value + a[n-1].value, a[n-2].value + a[n-1].value + h) = a[n-2].value + a[n-1].value + h.
    // Goodness = (a[n-2].value + a[n-1].value + h) - (a[0].value + a[1].value).
    // This is the goodness if we have at least one element in each subsequence.
    // This is the general case for any partition that is not all-in-one.
    long long goodness2 = (a[n - 2].value + a[n - 1].value + h) - (a[0].value + a[1].value);

    // Now consider a specific partition for Case 2 that might yield a smaller goodness.
    // This happens if a[0] and a[n-1] are in different subsequences.
    // The minimum f value will be a[0].value + a[1].value (if a[0], a[1] are same) OR a[0].value + a[1].value + h (if a[0], a[1] are different).
    // The maximum f value will be a[n-2].value + a[n-1].value (if a[n-2], a[n-1] are same) OR a[n-2].value + a[n-1].value + h (if a[n-2], a[n-1] are different).
    //
    // The critical observation is that if we put a[0] in S1 and a[n-1] in S2,
    // then the smallest possible f value is a[0] + a[1] (if a[1] is in S1) or a[0] + a[1] + h (if a[1] is in S2).
    // The largest possible f value is a[n-2] + a[n-1] (if a[n-2] is in S2) or a[n-2] + a[n-1] + h (if a[n-2] is in S1).
    //
    // Let's try a specific partition: a[0] in S1, a[n-1] in S2, and all other elements a[1]...a[n-2] in S1.
    // This means S1 = {a[0], a[1], ..., a[n-2]} and S2 = {a[n-1]}.
    //
    // Pairs within S1: (a_i, a_j) for i,j in [0, n-2].
    //   Min: a[0].value + a[1].value
    //   Max: a[n-3].value + a[n-2].value (if n-2 >= 1, i.e., n >= 3)
    // Pairs within S2: None (if n-1 is the only element).
    // Pairs across S1 and S2: (a_i, a[n-1]) for i in [0, n-2].
    //   Min: a[0].value + a[n-1].value + h
    //   Max: a[n-2].value + a[n-1].value + h
    //
    // Overall min_f for this partition:
    // If n=2: S1={a[0]}, S2={a[1]}. Only cross-subsequence pair (a[0], a[1]). min_f = a[0].value + a[1].value + h.
    // If n>=3: min_f = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h).
    //
    // Overall max_f for this partition:
    // If n=2: S1={a[0]}, S2={a[1]}. Only cross-subsequence pair (a[0], a[1]). max_f = a[0].value + a[1].value + h.
    // If n>=3: max_f = std::max(a[n-3].value + a[n-2].value, a[n-2].value + a[n-1].value + h).
    //
    // Let's simplify. The minimum possible sum of two elements is a[0]+a[1].
    // The maximum possible sum of two elements is a[n-2]+a[n-1].
    //
    // Consider the partition where a[0] is in S1, a[n-1] is in S2, and all other elements a[1]...a[n-2] are in S1.
    // S1 = {a[0], a[1], ..., a[n-2]}
    // S2 = {a[n-1]}
    //
    // Values of f:
    // 1. Pairs within S1: (a_i, a_j) for i,j in [0, n-2].
    //    Range: [a[0].value + a[1].value, a[n-3].value + a[n-2].value] (if n >= 3)
    // 2. Pairs within S2: None (if n-1 is the only element).
    // 3. Pairs across S1 and S2: (a_i, a[n-1]) for i in [0, n-2].
    //    Range: [a[0].value + a[n-1].value + h, a[n-2].value + a[n-1].value + h]
    //
    // For this partition:
    // min_f_candidate = a[0].value + a[1].value (from S1)
    // max_f_candidate = a[n-2].value + a[n-1].value + h (from cross-subsequence)
    //
    // This is valid if n >= 3. If n=2, then S1={a[0]}, S2={a[1]}.
    // min_f = a[0].value + a[1].value + h
    // max_f = a[0].value + a[1].value + h
    // Goodness = 0.
    //
    // For n >= 3:
    // The minimum f value is `min(a[0].value + a[1].value, a[0].value + a[n-1].value + h)`.
    // The maximum f value is `max(a[n-3].value + a[n-2].value, a[n-2].value + a[n-1].value + h)`.
    //
    // Let's re-evaluate the min/max f values for the partition:
    // S1 = {a[0], ..., a[n-2]}, S2 = {a[n-1]}
    //
    // min_f_val:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h)
    //
    // max_f_val:
    //   If n=2: a[0].value + a[1].value + h
    //   If n>=3: std::max(a[n-3].value + a[n-2].value, a[n-2].value + a[n-1].value + h)
    //
    // Goodness for this partition: max_f_val - min_f_val.
    long long goodness3;
    std::vector<int> partition3(n);
    if (n == 2) {
        goodness3 = 0; // Only one pair, f(a[0],a[1]) = a[0]+a[1]+h. Max-Min = 0.
        partition3[a[0].original_index] = 1;
        partition3[a[1].original_index] = 2;
    } else { // n >= 3
        long long min_f_val = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
        long long max_f_val = std::max(a[n-3].value + a[n-2].value, a[n-2].value + a[n-1].value + h);
        goodness3 = max_f_val - min_f_val;

        for (int i = 0; i < n - 1; ++i) {
            partition3[a[i].original_index] = 1;
        }
        partition3[a[n-1].original_index] = 2;
    }

    // Compare goodness1, goodness2, goodness3
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        // For goodness2, any partition with at least one element in each subsequence works.
        // A simple one is a[0] in S1, all others in S2.
        // Or a[0] in S1, a[1] in S2, all others in S1.
        // Let's use a[0] in S1, all others in S2.
        best_partition.assign(n, 2);
        best_partition[a[0].original_index] = 1;
    }

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        best_partition = partition3;
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

