// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1: One cut, two pieces.
    // Try all possible cut positions.
    // s = s1 s2. New string s' = s2 s1.
    // We need s' to be a palindrome and s' != s.
    for (int i = 1; i < n; ++i) { // Cut after i characters
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2: Two cuts, three pieces.
    // s = s1 s2 s3.
    // We need to find a reordering that forms a new palindrome.
    // The problem statement implies that if k=1 is not possible,
    // we should check k=2.
    // The example "nolon" -> 2 suggests that k=2 is a general solution
    // for many cases where k=1 fails.
    //
    // Consider cutting s into s[0...i-1], s[i...j-1], s[j...n-1].
    // The simplest reordering that often works is swapping the first and last pieces.
    // s' = s3 s2 s1.
    // For s' to be a palindrome, s3 must be the reverse of s1, and s2 must be a palindrome.
    // This is not what the problem implies. The pieces can be shuffled arbitrarily.
    //
    // However, the problem statement guarantees s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any reordering of pieces
    // will result in the same string "aaaa". In this case, it's impossible to get s' != s.
    // We need to check this condition.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 is always possible.
    // Example: "nolon" (n=5)
    // Cut: no | l | on
    // Pieces: "no", "l", "on"
    // Reorder: "on" + "l" + "no" = "onlno"
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This uses 2 cuts.
    //
    // General strategy for k=2:
    // Take s[0] and s[n-1]. Since s is a palindrome, s[0] == s[n-1].
    // Consider the string s_inner = s.substr(1, n-2).
    // If s_inner is not all the same character, we can make a cut in s_inner.
    //
    // A simpler argument:
    // If s is a palindrome and not all characters are the same,
    // then s has at least two distinct characters.
    // Consider the string s_prefix = s.substr(0, n-1).
    // This is s without its last character.
    // If s_prefix is not a palindrome, then we can cut s into s_prefix and s[n-1].
    // Then s' = s[n-1] + s_prefix.
    // This would be a k=1 solution if s' is a palindrome and s' != s.
    //
    // The problem states that if k=1 is not possible, we check k=2.
    // If s is a palindrome and not all characters are the same,
    // then it's always possible to achieve a different palindrome with 2 cuts.
    //
    // Consider s = A B A, where A is a prefix of length L, B is the middle part.
    // We can cut it as A | B | A.
    // Reorder to A | B | A (original) or A | A | B or B | A | A etc.
    //
    // A common strategy for k=2 is to take the first character, the middle part, and the last character.
    // For example, s = c_0 c_1 ... c_{n-2} c_{n-1}.
    // Since s is a palindrome, c_0 = c_{n-1}.
    // Cut into: c_0 | c_1 ... c_{n-2} | c_{n-1}.
    // Reorder to: c_{n-1} | c_1 ... c_{n-2} | c_0.
    // This forms c_{n-1} c_1 ... c_{n-2} c_0.
    // Since c_0 = c_{n-1}, this is effectively c_0 c_1 ... c_{n-2} c_0.
    // This is the same as the original string s.
    //
    // The example "nolon" -> "onlno" uses cuts: no | l | on.
    // This is s[0..1] | s[2] | s[3..4].
    // Reordered: s[3..4] | s[2] | s[0..1].
    // This is a valid strategy for k=2.
    //
    // If s is a palindrome and not all characters are the same,
    // then there must be at least one character s[i] such that s[i] != s[0].
    // Consider the string s_sub = s.substr(0, n-1).
    // If s_sub is not a palindrome, then s_sub + s[n-1] is s.
    // And s[n-1] + s_sub is a candidate for k=1.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible",
    // then k=2 is the answer.
    // The only "Impossible" case is when all characters are the same.
    // If s is a palindrome and not all characters are the same,
    // then there exists at least one character s[i] such that s[i] != s[0].
    // This means the string s is not of the form "aaaaa...".
    //
    // If s is a palindrome and not all characters are the same,
    // then we can always find a solution with k=2.
    // For example, take s = "abacaba".
    // k=1: "bacabaa", "acabaab", "cabaaba", "abaacab", "baacaba", "aacabab"
    // None of these are palindromes.
    //
    // k=2: "ab" | "ac" | "aba"
    // Reorder: "aba" + "ac" + "ab" = "abaacab" (not palindrome)
    //
    // The example "nolon" -> 2.
    // "no" | "l" | "on" -> "onlno" (palindrome, different)
    //
    // The logic is:
    // 1. Check k=1. If a solution is found, print 1 and exit.
    // 2. If k=1 fails, check if all characters in s are the same.
    //    If they are, print "Impossible" and exit.
    // 3. Otherwise (k=1 failed, but not all characters are the same), print 2.
    // This covers all cases.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long N, M;
std::vector<long long> H, P;

// Function to check if all tracks can be covered within time T
bool check(long long T) {
    // dp[i] stores the minimum index of a head that can cover tracks up to P[i]
    // using heads up to some j.
    // More precisely, dp[i] is the minimum index `k` such that P[i] can be covered
    // by head `k` (or a head with index < k) AND all P[0]...P[i-1] are covered
    // by heads with indices < k.
    // This is not quite right. Let's rethink.

    // We need to cover all P[j] for j from 0 to M-1.
    // We have N heads.
    // Let's use a greedy approach for `check(T)`.
    // We iterate through the target tracks P. For each P[i], we need to find a head
    // that can cover it. We try to use the "leftmost available" head that can cover P[i].

    // `head_idx` keeps track of the current head we are trying to assign.
    int head_idx = 0;
    for (int p_idx = 0; p_idx < M; ++p_idx) {
        // For the current target track P[p_idx], find the first head `head_idx`
        // that can cover it.
        while (head_idx < N && H[head_idx] + T < P[p_idx]) {
            // This head is too far left to reach P[p_idx] even moving right for T seconds.
            head_idx++;
        }

        if (head_idx == N) {
            // No head can reach P[p_idx] or any subsequent tracks.
            return false;
        }

        // Now, H[head_idx] can potentially cover P[p_idx].
        // The range covered by H[head_idx] is [H[head_idx] - T, H[head_idx] + T].
        // We need to cover P[p_idx].
        // If P[p_idx] is within this range, we can use H[head_idx] for it.
        // After covering P[p_idx], this head can also cover other tracks to its right.
        // The crucial part is that a head can cover a contiguous range of tracks.
        // If head `k` covers P[p_idx], it can cover all tracks in
        // [max(P[p_idx], H[k] - T), H[k] + T].
        // We want to maximize the reach to the right for the current head.

        long long current_head_reach_left = H[head_idx] - T;
        long long current_head_reach_right = H[head_idx] + T;

        // If P[p_idx] is not reachable by H[head_idx], then it's impossible.
        if (P[p_idx] < current_head_reach_left) {
            return false;
        }

        // This head H[head_idx] covers P[p_idx].
        // Now, we need to find how many subsequent tracks P[p_idx+1], P[p_idx+2], ...
        // can also be covered by this same head H[head_idx].
        // This head can cover tracks up to `current_head_reach_right`.
        // We advance `p_idx` as long as P[p_idx] is within this range.
        while (p_idx < M && P[p_idx] <= current_head_reach_right) {
            p_idx++;
        }
        p_idx--; // Decrement p_idx because the outer loop will increment it.

        // Move to the next head for the next uncovered track.
        head_idx++;
    }

    return true;
}

// Function to check if all tracks can be covered within time T using a more complex DP
bool check_dp(long long T) {
    // dp[i] = minimum head index required to cover all tracks P[0...i-1]
    // If dp[i] == N, it means P[0...i-1] cannot be covered.
    // dp[0] = 0 (no tracks to cover, so 0 heads needed)
    std::vector<int> dp(M + 1, N + 1);
    dp[0] = 0;

    for (int i = 0; i < M; ++i) { // Iterate through target tracks P[i]
        if (dp[i] == N + 1) { // If P[0...i-1] cannot be covered, then P[0...i] cannot either.
            continue;
        }

        // Try to cover P[i] using heads starting from dp[i]
        for (int j = dp[i]; j < N; ++j) { // Iterate through available heads H[j]
            long long head_left_reach = H[j] - T;
            long long head_right_reach = H[j] + T;

            // If H[j] cannot even reach P[i], then it cannot cover P[i]
            if (P[i] < head_left_reach || P[i] > head_right_reach) {
                continue;
            }

            // H[j] can cover P[i].
            // Find the maximum index `k` such that P[k] can be covered by H[j].
            // All tracks P[i...k] are covered by H[j].
            // We need to find the smallest `k_prime` such that P[k_prime] > head_right_reach.
            // Then P[i...k_prime-1] are covered by H[j].
            // So, the next track to cover is P[k_prime].
            // We update dp[k_prime] with min(dp[k_prime], j+1).

            // Use std::upper_bound to find the first element > head_right_reach
            auto it = std::upper_bound(P.begin() + i, P.end(), head_right_reach);
            int k_prime = std::distance(P.begin(), it);

            // If we cover up to P[k_prime-1] using head j, then for P[k_prime]
            // we need to use head j+1 or later.
            // So, dp[k_prime] = min(dp[k_prime], j+1).
            dp[k_prime] = std::min(dp[k_prime], j + 1);
        }
    }

    return dp[M] <= N; // If dp[M] is <= N, it means all M tracks can be covered.
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N >> M;

    H.resize(N);
    for (int i = 0; i < N; ++i) {
        std::cin >> H[i];
    }

    P.resize(M);
    for (int i = 0; i < M; ++i) {
        std::cin >> P[i];
    }

    long long low = 0;
    // Max possible time:
    // Max distance from first head to last track: P[M-1] - H[0]
    // Max distance from last head to first track: H[N-1] - P[0]
    // Max distance from any head to any track: 10^10 - 1
    // A loose upper bound: (P[M-1] - P[0]) + (H[N-1] - H[0]) + 2 * 10^10
    // A tighter upper bound: max(abs(P[0] - H[N-1]), abs(P[M-1] - H[0]))
    // Since P and H are up to 10^10, max diff is 10^10.
    // If N=1, M=1, H={1}, P={10^10}, time is 10^10 - 1.
    // So, 10^10 is a good upper bound.
    long long high = 20000000000LL; // 2 * 10^10, a safe upper bound
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check_dp(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

