#include <algorithm>
#include <numeric>

void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    long long min_val = k + 1; // Initialize with a value larger than any possible a_i
    int min_idx = -1;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < min_val) {
            min_val = a[i];
            min_idx = i;
        }
    }

    long long total_operations = 0;

    // We can only use the pile with minimum candies as the source.
    // For each other pile, we add candies from the minimum pile until it exceeds k.
    // The minimum pile itself cannot be a target for this strategy,
    // as it would increase its own value, potentially changing the minimum.
    // If we use it as a source, its value doesn't change.
    for (int i = 0; i < n; ++i) {
        if (i == min_idx) {
            continue; // Skip the pile with the minimum value itself
        }
        // For each other pile 'a[i]', we can add 'min_val' candies
        // as many times as possible without exceeding 'k'.
        // The current value of a[i] is a[i].
        // We want to find max_ops such that a[i] + max_ops * min_val <= k.
        // max_ops * min_val <= k - a[i]
        // max_ops <= (k - a[i]) / min_val
        // Since min_val >= 1, this division is safe.
        total_operations += (k - a[i]) / min_val;
    }

    std::cout << total_operations << std::endl;
}

