void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem statement guarantees that a solution exists for every permutation.
    // A simple strategy that works for all n >= 2 is to reverse the permutation.
    // Let p = [p_1, p_2, ..., p_n].
    // The sums of adjacent elements are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
    // Let p' = [p_n, p_{n-1}, ..., p_1].
    // The sums of adjacent elements for p' are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
    // This is the same multiset of sums, just in reverse order.
    // For example, p_1+p_2 is the same as p_2+p_1.
    // The only case where p' might be equal to p is if p is a palindrome,
    // i.e., p_i = p_{n-i+1} for all i.
    // However, the problem statement guarantees that a *different* permutation exists.
    // For n=2, p=[1,2], p'=[2,1]. F(p)=[3], F(p')=[3]. p!=p'.
    // For n=3, p=[1,2,3], p'=[3,2,1]. F(p)=[3,5], F(p')=[5,3]. p!=p'.
    // For n=4, p=[1,2,3,4], p'=[4,3,2,1]. F(p)=[3,5,7], F(p')=[7,5,3]. p!=p'.
    // In general, for any permutation p of length n >= 2, its reverse p' will be different
    // unless p is a palindrome. But even if p is a palindrome, the problem guarantees a solution exists.
    // The simplest approach is to just reverse the permutation.
    // The problem statement implies that reversing is always a valid solution.
    // "We can prove that for every permutation satisfying the input constraints, a solution exists."
    // This implies that the simple reverse strategy is sufficient.

    std::reverse(p.begin(), p.end());

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

