int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long d; // d can be up to 100, but sum of a_i can be 100*100=10000, so days needed can be large.
                     // However, d is also up to 100. So long long for d is not strictly necessary based on constraints,
                     // but good practice for sums if intermediate calculations could exceed int max.
                     // Here, d is just a limit, so int is fine. Let's stick to int for d as per constraints.
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        long long current_a1 = a[0]; // Use long long for current_a1 to be safe, though max is 100 + 100*100 = 10100, fits int.

        // Iterate through piles from 2nd to nth (index 1 to n-1)
        for (int i = 1; i < n; ++i) {
            // Cost to move one haybale from pile i+1 (0-indexed i) to pile 1 (0-indexed 0) is i days.
            long long cost_per_haybale = i; 

            // If we don't have enough days to move even one haybale from this pile, stop.
            if (d < cost_per_haybale) {
                break;
            }

            // Calculate how many haybales we can move from this pile.
            // We have 'a[i]' haybales in this pile.
            // We have 'd' days remaining.
            // Each haybale costs 'cost_per_haybale' days.
            long long haybales_to_move = std::min((long long)a[i], d / cost_per_haybale);

            // Add these haybales to pile 1.
            current_a1 += haybales_to_move;

            // Deduct the days spent.
            d -= haybales_to_move * cost_per_haybale;
        }
        std::cout << current_a1 << std::endl;
    }
    return 0;
}

