        //    If n=3, sum is 2+3+3=8, not div by 3.
        //    If n=4, sum is 2+3+3+3=11, not div by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    Since 3n is divisible by 3, 3n-1 is never divisible by 3.
        //    So, the number is not divisible by 3.
        // This construction satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << std::endl;
