#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    // Iterate from right to left
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // Update has_pos_one/has_neg_one for elements to its left.
            if (a[i] == 1) has_pos_one = true; // This is redundant as it would have been true already if a[i] was 1
            if (a[i] == -1) has_neg_one = true; // Same here
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // This change must come from an a[k] where k < i.
        // The values of a[k] for k < i are fixed at their initial values.

        if (b[i] > a[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else { // b[i] < a[i], need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }

        // If a[i] was 1 or -1, it contributes to has_pos_one/has_neg_one for elements to its left.
        // But since we are iterating right-to-left, we are considering a[i] as a target, not a source.
        // The has_pos_one/has_neg_one flags track if there's an *original* 1 or -1 to the left of the current index.
        // When we process a[i], we check if there's a 1 or -1 among a[0]...a[i-1].
        // The flags `has_pos_one` and `has_neg_one` are updated to reflect the presence of 1s and -1s in `a[0]...a[i-1]`
        // as we move `i` from `n-1` down to `0`.
        // So, if a[i] was 1 or -1, it means it was available for elements to its right.
        // For elements to its left, it's not available.
        // The flags `has_pos_one` and `has_neg_one` should be updated *after* checking a[i] against b[i].
        // This is because for a[i], the available sources are a[0]...a[i-1].
        // The current `has_pos_one` and `has_neg_one` correctly reflect the presence of 1s and -1s in `a[0]...a[i-1]`.
    }

    std::cout << "YES\n";
}

