    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int current_color_for_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T_half) {
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T_half) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T_half
            if (T_is_even) {
                p[i] = current_color_for_half;
                current_color_for_half = 1 - current_color_for_half; // Alternate color
            } else { // T is odd, so T_half is not an integer, a[i] cannot be T_half
                     // This branch should not be reached if a[i] == T_half and T is odd.
                     // However, if T is odd, T_half is integer division, so a[i] == T_half
                     // means a[i] < T/2.0. So this case is covered by a[i] < T_half.
                     // To be precise, if T is odd, T_half = (T-1)/2.
                     // If a[i] = T_half, then a[i] < T/2.0.
                     // So a[i] == T_half implies a[i] < T/2.0 if T is odd.
                     // Thus, this 'else' branch is only for a[i] == T_half when T is even.
                p[i] = 0; // Should not happen based on problem constraints and logic
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
