    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        std::cout << l << std::endl;
    } else {
        // For any range [l, r] where l < r, the number 2 will always be a divisor
        // for at least floor(r/2) - ceil(l/2) + 1 numbers.
        // If r >= 2, there is at least one even number.
        // If l=2, r=3, numbers are {2,3}. Divisors: 2 for 2, 3 for 3. Max count is 1.
        // If l=2, r=4, numbers are {2,3,4}. Divisors: 2 for 2, 3 for 3, 2,4 for 4.
        // Count for 2: {2,4} -> 2. Count for 3: {3} -> 1. Count for 4: {4} -> 1. Max is 2.
        //
        // The count of multiples of d in [l, r] is floor(r/d) - ceil(l/d) + 1.
        // For d=2, this is floor(r/2) - (l+1)/2 + 1.
        // For any d > 2, the count of its multiples will be less than or equal to
        // the count of multiples of 2, because every multiple of d is also a multiple of 2
        // if d is even, or less frequent if d is odd.
        //
        // Specifically, the count of multiples of d is at most r/d.
        // The count of multiples of 2 is at least (r-l+1)/2 if l and r have different parity,
        // or (r-l)/2 if l and r have same parity.
        //
        // If r - l + 1 >= 2, then there are at least two numbers in the range.
        // If r - l + 1 >= 2, then there is at least one even number.
        // If r - l + 1 >= 3, then there are at least two even numbers (e.g., 2,4 or 3,4,5,6 -> 4,6).
        //
        // The maximum possible count for any divisor d is achieved by d=2,
        // unless the range is very small and contains only one multiple of 2,
        // or no multiples of 2 (which is impossible since l <= r and l >= 2).
        //
        // Example: l=19, r=29.
        // Multiples of 2: {20, 22, 24, 26, 28}. Count = 5.
        // Multiples of 3: {21, 24, 27}. Count = 3.
        // Multiples of 4: {20, 24, 28}. Count = 3.
        // Multiples of 5: {20, 25}. Count = 2.
        // ...
        // The maximum count is 5, achieved by 2.
        //
        // Example: l=3, r=6.
        // Multiples of 2: {4, 6}. Count = 2.
        // Multiples of 3: {3, 6}. Count = 2.
        // Multiples of 4: {4}. Count = 1.
        // Multiples of 5: {5}. Count = 1.
        // Multiples of 6: {6}. Count = 1.
        // Here, both 2 and 3 give a count of 2. The problem states "print any of them".
        // So 2 is a valid answer.
        //
        // The only case where 2 might not be the answer is if the range is very small,
        // for example, l=3, r=3. Then the only number is 3, its only divisor > 1 is 3.
        // But this case is handled by l == r.
        //
        // If l < r, then there are at least two numbers.
        // If r - l + 1 >= 2, then there is at least one even number.
        // If r - l + 1 >= 3, then there are at least two even numbers.
        //
        // The number 2 will always have the highest or tied-highest frequency
        // because it is the smallest prime number, and thus its multiples are the most dense.
        // Any other number d > 2 will have multiples that are less dense or equally dense
        // (if d is a power of 2, or if d is a multiple of 2).
        //
        // Consider the count of multiples of d: floor(r/d) - (l+d-1)/d + 1.
        // This count is maximized when d is minimized. The smallest possible d is 2.
        // So, 2 will always be the answer.

        std::cout << 2 << std::endl;
    }

    return 0;
}

