    int free_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_occupied[i]) {
            free_rows++;
        }
    }

    int free_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_occupied[j]) {
            free_cols++;
        }
    }

    // The number of moves possible is limited by the minimum of free_rows and free_cols.
    // Each move claims one free row and one free column.
    int moves_possible = std::min(free_rows, free_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

