#include <iostream>
#include <vector>
#include <algorithm> // For std::min

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << "\n";
        return;
    }

    int bad_prices_count = 0;
    int min_suffix_price = a[n - 1]; // Initialize with the last element

    // Iterate from right to left, starting from the second to last element
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is a new minimum for the suffix ending at i.
            // Update min_suffix_price to a[i] because any price before a[i]
            // would compare against a[i] if a[i] is smaller than previous min_suffix_price.
            min_suffix_price = a[i];
        }
    }

    std::cout << bad_prices_count << "\n";
}

int main() {
    // Optimize C++ standard streams for competitive programming.
    // This unties cin/cout from stdio and disables synchronization with C stdio.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue; // Skip a[i][i] which is 0
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is n-1 and all other p[j] are less than n-1.
    // If so, it means the actual value for p[i] should be n.
    // This happens if n is the largest value in the permutation, and it's
    // paired with n-1, making min(n, n-1) = n-1.
    // All other values min(n, x) for x < n-1 would be x.
    // So the maximum value in the row for p[i]=n would be n-1.
    // If there is exactly one element in p that is n-1, and all others are < n-1,
    // then that element must be n.

    int count_n_minus_1 = 0;
    int index_n_minus_1 = -1;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1) {
            count_n_minus_1++;
            index_n_minus_1 = i;
        }
    }

    if (count_n_minus_1 == 1) {
        // If there's exactly one element that is n-1, it means it's the largest
        // element in the permutation, which is n.
        // Its min with n-1 would be n-1, and min with any smaller value x would be x.
        // So the max in its row would be n-1.
        // All other elements in the permutation are < n.
        // If any other element p[j] (j != index_n_minus_1) was n-1, then count_n_minus_1 would be > 1.
        // If any other element p[j] (j != index_n_minus_1) was n, then p[j] would be n-1 (by the logic above),
        // which contradicts p[j] being n.
        // So, if count_n_minus_1 is 1, the element at index_n_minus_1 must be n.
        p[index_n_minus_1] = n;
    } else {
        // If count_n_minus_1 is 0, it means n is not present in the permutation, which is impossible.
        // If count_n_minus_1 > 1, it means there are multiple elements that are n-1.
        // This implies that n is not present in the permutation, or n is present but its min with n-1 is not the max in its row.
        // This case should not happen given the problem constraints and logic.
        // The problem guarantees a solution exists.
        // The only way for max_val_in_row to be n-1 is if p[i] is n or n-1.
        // If p[i] is n, then max_val_in_row is n-1 (if n-1 is present in p).
        // If p[i] is n-1, then max_val_in_row is n-1 (if n is present in p, or if n-1 is paired with something smaller).
        // The logic for count_n_minus_1 == 1 correctly identifies the 'n' value.
        // If n is not present in the permutation, then the largest value is n-1.
        // In this case, the max_val_in_row for the element that is n-1 would be some value < n-1.
        // This implies that if n is present, it must be the one that results in max_val_in_row = n-1.
        // If n is not present, then the largest value is n-1.
        // The problem states it's a permutation of 1 to n. So n is always present.
        // Thus, the count_n_minus_1 == 1 case is the only one where we need to adjust.
        // If count_n_minus_1 is 0, it means n-1 is not the max value for any row.
        // This would imply n is not present, or n-1 is not present.
        // This is a contradiction.
        // So, count_n_minus_1 must be 1.
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents 2^0 - 1, 2^1 - 1, 2^2 - 1, ...
                         // The number of stairs for the current nice staircase is 2*k - 1.
                         // The cost for a nice staircase with (2*k - 1) stairs is k * (2*k - 1).
                         // This is equivalent to (2^p - 1) stairs, costing (2^p - 1) * 2^(p-1) cells.
                         // Here, k is 2^(p-1).
        while (true) {
            long long stairs_n = 2 * k - 1;
            long long cost_n = k * stairs_n; // Cost for a staircase with stairs_n stairs

            if (current_cost + cost_n <= x) {
                current_cost += cost_n;
                count++;
                k *= 2; // Next k will be 2*k, corresponding to the next power of 2.
                        // e.g., if current k=1 (p=1), next k=2 (p=2).
                        // if current k=2 (p=2), next k=4 (p=3).
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = 0; // Represents the last position from which a right jump was possible (or start 0)
                            // This is effectively the position of the last 'R' or 0.

        // Iterate through the string, considering cells 1 to n.
        // s[i-1] corresponds to cell i.
        for (int i = 1; i <= n; ++i) {
            if (s[i-1] == 'R') {
                // If we encounter an 'R' at cell i, it means we can jump from 'last_r_pos'
                // to 'i', and then from 'i' to further right.
                // The gap we need to cover is from 'last_r_pos' to 'i'.
                // The length of this jump would be i - last_r_pos.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i; // Update last_r_pos to the current 'R' cell
            }
        }

        // After iterating through all cells up to n, we still need to reach n+1.
        // The last 'R' cell we encountered was at 'last_r_pos'.
        // We need to be able to jump from 'last_r_pos' to 'n+1'.
        // The length of this jump would be (n + 1) - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

