void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This is the first part of the "mountain" or "valley" structure.
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }

    // If p is 0, the entire array is non-decreasing.
    // If p is n-1, the last element is the only non-decreasing part.
    // In general, a[p...n-1] is non-decreasing.

    // Now, from `p-1` down to `0`, find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This is the second part of the "mountain" or "valley" structure.
    // The elements a[q...n-1] would form a "mountain" or "valley" shape.
    // Specifically, a[q...p-1] is non-increasing, and a[p...n-1] is non-decreasing.
    // The peak/valley is at index p-1 (if p > 0).
    int q = p; // Initialize q to p. If p is 0, q remains 0.
    if (p > 0) { // Only search for non-increasing part if there are elements before p
        q = p - 1;
        while (q > 0 && a[q-1] <= a[q]) {
            q--;
        }
    }

    // The elements from index `q` to `n-1` form a "good" array.
    // The prefix to erase has length `q`.
    std::cout << q << std::endl;
}

