void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its indices are pos[1].
        // min_idx = pos[1], max_idx = pos[1]. Length is 1.
        // min_val = 1, max_val = 1.
        // This is always beautiful.

        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from the minimum index found so far
        // to the maximum index found so far, considering numbers 1 to m.

        // Update current_min_idx and current_max_idx to include the position of 'm'.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for being a permutation of 1 to m.
        // 1. Length must be m: (current_max_idx - current_min_idx + 1) == m
        // 2. Minimum value in p[current_min_idx ... current_max_idx] must be 1.
        //    This is guaranteed because we always include pos[1] and expand.
        // 3. Maximum value in p[current_min_idx ... current_max_idx] must be m.
        //    This is guaranteed because we always include pos[m] and expand.

        if ((current_max_idx - current_min_idx + 1) == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

