    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2; // (n-1)/2 for 0-indexed array

    // Cost to make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // Elements to the left of median must be <= s
    // If a[i] > s, we must decrease it to s.
    // The cost is a[i] - s.
    // If a[i] <= s, no change is needed for this condition.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median must be >= s
    // If a[i] < s, we must increase it to s.
    // The cost is s - a[i].
    // If a[i] >= s, no change is needed for this condition.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

