    for (int k = 0; k < n; ++k) { // k is the 0-indexed peak index
        // For `k` to be the peak, we need:
        // 1. `a[0] < a[1] < ... < a[k]` (prefix condition)
        // 2. `a[k] > a[k+1] > ... > a[n-1]` (suffix condition)

        // Condition 1: `a[0] < a[1] < ... < a[k]`
        // This means we need `a[j] >= j` for all `0 <= j <= k`.
        // This is exactly what `prefix_ok[k]` checks.

        // Condition 2: `a[k] > a[k+1] > ... > a[n-1]`
        // This means we need `a[j] >= (n-1) - j` for all `k <= j <= n-1`.
        // This is exactly what `suffix_ok[k]` checks.

        if (prefix_ok[k] && suffix_ok[k]) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

