    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int left_ptr = 0; // Pointer for elements to be placed (the 'P' array elements)
    int right_ptr = 0; // Pointer for original positions (the 'A' array elements)

    // We want to find a_left_ptr > a_right_ptr
    // To maximize matches, for each a_right_ptr, we try to find the smallest a_left_ptr
    // such that a_left_ptr > a_right_ptr.
    // This is equivalent to iterating through the sorted array 'a' with 'right_ptr'
    // and trying to match it with an element 'a[left_ptr]' from the same sorted array
    // such that a[left_ptr] > a[right_ptr].
    // Since both arrays are sorted, we can use two pointers.
    // 'left_ptr' will always be >= 'right_ptr' because we are picking from the same set of numbers.
    // If a[left_ptr] > a[right_ptr], we found a match. Increment both pointers.
    // If a[left_ptr] <= a[right_ptr], then a[left_ptr] cannot be placed at position 'right_ptr'
    // to satisfy the condition. We need a larger element for 'right_ptr', so we increment 'left_ptr'
    // to look for a larger candidate. 'right_ptr' stays put, waiting for a suitable larger element.

    while (left_ptr < n && right_ptr < n) {
        if (a[left_ptr] > a[right_ptr]) {
            // Found an element a[left_ptr] that is greater than a[right_ptr].
            // This means we can place a[left_ptr] at the position corresponding to a[right_ptr].
            // Increment count and move both pointers to consider the next elements.
            count++;
            left_ptr++;
            right_ptr++;
        } else {
            // a[left_ptr] is not greater than a[right_ptr].
            // We need a larger element to satisfy a[right_ptr].
            // So, we try the next available element for placement.
            left_ptr++;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

