struct Element {
    long long val;
    int original_idx;
};

bool compareElements(const Element& a, const Element& b) {
    return a.val < b.val;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].val;
        a_elements[i].original_idx = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].val;
        b_elements[i].original_idx = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // The strategy is to assign the largest A_i to the B_j that results in the largest F value.
    // F(n, k) = (n+1) / (k+1).
    // To maximize sum( (A'_i+1) / (B_i+1) ), we should pair largest (A'_i+1) with smallest (B_i+1).
    // This means pairing largest A'_i with smallest B_i.
    // Since A is sorted ascending, a_elements[i].val is the i-th smallest A value.
    // Since B is sorted ascending, b_elements[i].val is the i-th smallest B value.
    // To pair largest A with smallest B, we should pair a_elements[m-1] with b_elements[0],
    // a_elements[m-2] with b_elements[1], and so on.
    // In general, a_elements[m-1-i] should be paired with b_elements[i].
    // The original index of b_elements[i] is b_elements[i].original_idx.
    // So, a_prime[b_elements[i].original_idx] should be a_elements[m-1-i].val.

    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_idx] = a_elements[m - 1 - i].val;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

