int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        long long total_toys = A + B + C + D;

        // If there's only one toy, that toy is the super toy.
        // The special box is simply the box that toy came from.
        if (total_toys == 1) {
            print_bool(A == 1);
            std::cout << " ";
            print_bool(B == 1);
            std::cout << " ";
            print_bool(C == 1);
            std::cout << " ";
            print_bool(D == 1);
            std::cout << "\n";
            continue;
        }

        // Determine if Box 1 can be the special box
        // Final value is negative, magnitude >= 1
        bool can_be_box1 = false;
        // Case 1: Odd number of negative factors, product magnitude >= 1
        // Number of negative factors is A+B.
        // If A+B is odd:
        //   If A+D >= 1 (at least one factor with magnitude >= 1)
        //     AND (A+D >= 2 OR B+C >= 1) (to ensure magnitude can be >= 1)
        //     This is simplified to: if A+D >= 1, then we can always make magnitude >= 1
        //     (e.g., by multiplying with a large value from Box 4 or another Box 1, or by multiplying with many values from Box 2/3)
        //     The only way magnitude could be < 1 is if all factors have magnitude < 1 (i.e., A=D=0).
        //     So, if A+B is odd and A+D > 0, it's possible.
        //     What if A+D=0? Then all toys are from B or C. Product will be in (-1, 1).
        //     So, A+D must be > 0.
        if ((A + B) % 2 == 1 && (A + D > 0)) {
            can_be_box1 = true;
        }
        // Case 2: Even number of negative factors, product magnitude >= 1
        // This means the final product is positive. So this case cannot result in Box 1.

        // Determine if Box 2 can be the special box
        // Final value is negative, magnitude < 1
        bool can_be_box2 = false;
        // Case 1: Odd number of negative factors, product magnitude < 1
        // Number of negative factors is A+B.
        // If A+B is odd:
        //   If A+D == 0 (all toys from B or C), then product magnitude is < 1.
        //   If A+D > 0, we can still make magnitude < 1 by carefully choosing values.
        //   For example, if we have one toy from Box 1 (e.g., -2) and many from Box 3 (e.g., 0.1),
        //   we can multiply -2 * 0.1 * 0.1 = -0.02, which is in Box 2.
        //   The only way this is impossible is if A+B is odd AND A+D=0 (all toys from B or C) AND C=0.
        //   If A+B is odd and A+D=0, then all toys are from B. The product of B toys is in (0,1) if B is even, or (-1,0) if B is odd.
        //   So if A+B is odd and A+D=0, then B must be odd. This means all toys are from Box 2.
        //   The product of B odd toys from Box 2 is in Box 2. So this is possible.
        //   If A+B is odd and A+D > 0, we can always make magnitude < 1.
        //   Example: -2 (Box 1), 0.1 (Box 3), 0.1 (Box 3). Product -0.02 (Box 2).
        //   Example: -0.5 (Box 2), 2 (Box 4), 0.1 (Box 3). Product -0.1 (Box 2).
        //   So, if A+B is odd, it's always possible to make it Box 2.
        if ((A + B) % 2 == 1) {
            can_be_box2 = true;
        }
        // Case 2: Even number of negative factors, product magnitude < 1
        // This means the final product is positive. So this case cannot result in Box 2.

        // Determine if Box 3 can be the special box
        // Final value is positive, magnitude < 1
        bool can_be_box3 = false;
        // Case 1: Odd number of negative factors, product magnitude < 1
        // This means the final product is negative. So this case cannot result in Box 3.
        // Case 2: Even number of negative factors, product magnitude < 1
        // Number of negative factors is A+B.
        // If A+B is even:
        //   If A+D == 0 (all toys from B or C), then product magnitude is < 1.
        //   If A+D > 0, we can still make magnitude < 1 by carefully choosing values.
        //   Example: -2 (Box 1), -0.5 (Box 2), 0.1 (Box 3). Product 0.1 (Box 3).
        //   Example: 2 (Box 4), 0.1 (Box 3), 0.1 (Box 3). Product 0.02 (Box 3).
        //   So, if A+B is even, it's always possible to make it Box 3.
        if ((A + B) % 2 == 0) {
            can_be_box3 = true;
        }

        // Determine if Box 4 can be the special box
        // Final value is positive, magnitude >= 1
        bool can_be_box4 = false;
        // Case 1: Odd number of negative factors, product magnitude >= 1
        // This means the final product is negative. So this case cannot result in Box 4.
        // Case 2: Even number of negative factors, product magnitude >= 1
        // Number of negative factors is A+B.
        // If A+B is even:
        //   If A+D > 0 (at least one factor with magnitude >= 1)
        //     AND (A+D >= 2 OR B+C >= 1) (to ensure magnitude can be >= 1)
        //     This is simplified to: if A+D >= 1, then we can always make magnitude >= 1
        //     (e.g., by multiplying with a large value from Box 4 or another Box 1, or by multiplying with many values from Box 2/3)
        //     The only way magnitude could be < 1 is if all factors have magnitude < 1 (i.e., A=D=0).
        //     So, if A+B is even and A+D > 0, it's possible.
        //     What if A+D=0? Then all toys are from B or C. Product will be in (-1, 1).
        //     So, A+D must be > 0.
        if ((A + B) % 2 == 0 && (A + D > 0)) {
            can_be_box4 = true;
        }

        // Special case: If A=D=0, all toys are from B or C.
        // The product of any number of toys from B and C will always have magnitude < 1.
        // So, Box 1 and Box 4 are impossible if A=D=0.
        if (A == 0 && D == 0) {
            can_be_box1 = false;
            can_be_box4 = false;
        }

        print_bool(can_be_box1);
        std::cout << " ";
        print_bool(can_be_box2);
        std::cout << " ";
        print_bool(can_be_box3);
        std::cout << " ";
        print_bool(can_be_box4);
        std::cout << "\n";
    }

    return 0;
}

