char get_winning_move(char bot_move) {
    if (bot_move == 'R') {
        return 'P';
    } else if (bot_move == 'S') {
        return 'R';
    } else { // bot_move == 'P'
        return 'S';
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
