        std::string s;
        std::cin >> s;
        int n = s.length();

        std::map<char, int> counts;
        for (char c : s) {
            counts[c]++;
        }

        char most_frequent_bot_move = ' ';
        int max_count = -1;

        // Iterate in a fixed order to ensure consistent tie-breaking if needed,
        // though any tie-breaking is fine as long as it's consistent.
        // R, P, S order is arbitrary but covers all cases.
        if (counts['R'] > max_count) {
            max_count = counts['R'];
            most_frequent_bot_move = 'R';
        }
        if (counts['P'] > max_count) {
            max_count = counts['P'];
            most_frequent_bot_move = 'P';
        }
        if (counts['S'] > max_count) {
            max_count = counts['S'];
            most_frequent_bot_move = 'S';
        }
        // If all counts are 0 (e.g., empty string, though n >= 1),
        // or if there's a tie, the choice of most_frequent_bot_move
        // might depend on the order of checks.
        // For example, if R=1, P=1, S=1, and we check R then P then S,
        // most_frequent_bot_move will be 'S'.
        // The problem statement guarantees n >= 1, so at least one char exists.
        // The specific tie-breaking doesn't matter for correctness,
        // as any of the tied most frequent moves would yield the same max average.

        char optimal_player_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_player_move;
        }
        std::cout << "\n";
    }
    return 0;
}

