void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // Let S = current_sum, X = current_xor_sum
    // We need S + b1 + b2 + b3 = 2 * (X ^ b1 ^ b2 ^ b3)

    // Strategy: Append at most 3 elements.
    // It's always possible to append 2 elements.
    // Let's try to append two elements, say Y and Z.
    // We need S + Y + Z = 2 * (X ^ Y ^ Z)
    // A simple choice for Y and Z that works:
    // Let Y = X. Then X ^ Y = X ^ X = 0.
    // The equation becomes S + X + Z = 2 * (0 ^ Z) = 2 * Z.
    // So, S + X + Z = 2Z
    // S + X = Z
    // So, if we append X and (S + X), the condition holds.
    // The elements to append are X and (S + X).
    // Let's verify:
    // New sum S' = S + X + (S + X) = 2S + 2X
    // New XOR sum X' = X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // Is S' = 2 * X'?
    // 2S + 2X = 2 * (S + X)
    // Yes, this holds.

    // The problem states we don't have to minimize the number of added elements.
    // So, we can always append 2 elements: current_xor_sum and (current_sum + current_xor_sum).
    // This strategy always works and uses exactly 2 elements.
    // The problem statement guarantees that a solution always exists.
    // The values can be up to 10^18, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

