// Function to convert a non-negative integer to its 18-digit parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str(18, '0'); // Initialize with 18 '0's
    int i = 0;
    if (n == 0) {
        // For 0, the pattern is '0' (or '00...0' for 18 digits)
        // The default initialized pattern_str is already correct for 0.
    } else {
        while (n > 0 && i < 18) {
            if ((n % 10) % 2 != 0) { // If digit is odd
                pattern_str[17 - i] = '1';
            }
            n /= 10;
            i++;
        }
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for competitive programming
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // Use a map to store counts of each 18-digit parity pattern string
    std::map<std::string, int> pattern_counts;

    for (int k = 0; k < t; ++k) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern with leading '0's to 18 digits
            std::string padded_s(18 - s.length(), '0');
            padded_s += s;
            std::cout << pattern_counts[padded_s] << "\n";
        }
    }

    return 0;
}

