    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // If s_i is '0', then w[i-x] (if exists) and w[i+x] (if exists) must be '0'.
    // This is a definitive constraint.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this constructed w can produce the given s.
    // For each s_i, check if it can be '1' based on w.
    // If s_i is '1', but our w cannot make it '1', then no solution exists.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            bool can_be_one = false;
            if (i - x >= 0 && w[i - x] == '1') {
