#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    for (int i = 0; i <= n; ++i) {
        // j is the number of items taken from the right
        // Total items taken is n. So j = n - i.
        int j = n - i;

        long long current_energy = 0;

        // Energy for items taken from the left
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // The items taken from the right are w[n-j], ..., w[n-1]
        // Their sum is prefix_sum[n] - prefix_sum[n-j]
        current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;

        // Add penalty for consecutive actions
        if (i > j) { // More items taken from left than right
            // The difference is i - j.
            // If i - j = 1, it means the last item taken was from the left, and it was the (j+1)-th item from the left.
            // The total items taken from left is i. The total items taken from right is j.
            // The number of "extra" left items is i - j.
            // This means the last (i - j) items must have been taken from the left, after all right items were taken.
            // Or, more generally, there are i-j more left items than right items.
            // This implies that at some point, we took an item from the left, and the previous item was also from the left.
            // The number of such "extra" left items is (i - j - 1).
            // For example, if i=3, j=1, then LLLR. The last two L's are consecutive. (3-1-1)=1 penalty.
            // If i=2, j=0, then LL. The last L is consecutive. (2-0-1)=1 penalty.
            // If i=1, j=0, then L. No penalty. (1-0-1)=0.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items taken from right than left
            // The number of "extra" right items is (j - i - 1).
            current_energy += (j - i - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

