    int n = s.length();

    // prefix_counts[char_idx][i] stores the count of char_idx ('x', 'y', 'z')
    // in the prefix s[0...i-1].
    // char_idx 0 for 'x', 1 for 'y', 2 for 'z'.
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r; // 1-indexed

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Get counts of 'x', 'y', 'z' in the substring s[l-1...r-1]
        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        // The algorithm terminates if it's possible to reach a state where
        // all 3-character subsequences are "zyx", "xzy", or "yxz".
        // This is possible if and only if the counts of 'x', 'y', 'z'
        // are "balanced" enough, meaning their difference is at most 1.
        // If the difference between any two counts is 2 or more,
        // it's always possible to form an "unbalanced" triplet (e.g., "xxx", "xxy")
        // which can be rearranged to "xyz", "yzx", or "zxy".
        // If we can always form such a triplet, the algorithm never terminates.
        // The only way to guarantee termination is if all triplets are "balanced"
        // (i.e., permutations of 'x', 'y', 'z'). This happens if the counts
        // of 'x', 'y', 'z' in the entire substring are nearly equal.
        // Specifically, max_count - min_count <= 1.

        int max_count = std::max({count_x, count_y, count_z});
        int min_count = std::min({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

