// Function to find prime factors of a number
// For q <= 10^9, this is efficient enough.
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            // If p is not divisible by q, then p itself is the largest divisor of p
            // and it satisfies the condition of not being divisible by q.
            std::cout << p << "\n";
        } else {
            // If p is divisible by q, then p is not a valid x.
            // We need to find the largest divisor x of p such that x is not divisible by q.

            // First, find the prime factors of q.
            // We only care about the prime factors of q that also divide p.
            // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
            // Any x that is divisible by q must be divisible by all f_j.
            // To make x not divisible by q, we need to remove at least one prime factor f_j
            // from x such that x is no longer divisible by q.
            // More precisely, if x is divisible by q, then for every prime factor f_j of q,
            // the exponent of f_j in x's prime factorization must be at least the exponent of f_j in q's prime factorization.
            // To make x not divisible by q, we must reduce the exponent of at least one f_j in x
            // to be less than its exponent in q.

            // We are looking for the largest x.
            // Consider each prime factor f of q.
            // If we divide p by f until it's no longer divisible by q, we get a candidate x.
            // We want to maximize x, so we want to divide p by the smallest possible power of f.

            std::vector<long long> q_prime_factors = get_prime_factors(q);
            long long max_x = 1;

            for (long long f : q_prime_factors) {
                // For each prime factor f of q, we want to find the largest divisor of p
                // that is not divisible by q.
                // Consider p' = p. We want to divide p' by f until p' is no longer divisible by q.
                // This means we divide p' by f until the exponent of f in p' is less than
                // the exponent of f in q.
                // Or, more simply, we divide p' by f until p' % q != 0.
                // The resulting p' is a candidate for x. We take the maximum among all such candidates.

                long long current_p = p;
                while (current_p % q == 0) {
                    current_p /= f;
                }
                // current_p is now a divisor of p, and current_p is not divisible by q.
                // This current_p is a candidate for the answer.
                // We want the maximum such candidate.
                max_x = std::max(max_x, current_p);
            }
            std::cout << max_x << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');

    for (int x = 0; x <= 9; ++x) {
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char last2 = '0' - 1; // Represents a value smaller than any digit
        bool possible_x = true;

        // First pass: assign digits based on comparison with x
        // Digits < x go to color 1
        // Digits > x go to color 2
        // Digits == x are temporarily unassigned (marked '0')
        for (int i = 0; i < n; ++i) {
            if (s[i] < (char)('0' + x)) {
                if (s[i] < last1) {
                    possible_x = false;
                    break;
                }
                result[i] = '1';
                last1 = s[i];
            } else if (s[i] > (char)('0' + x)) {
                if (s[i] < last2) {
                    possible_x = false;
                    break;
                }
                result[i] = '2';
                last2 = s[i];
            } else { // s[i] == (char)('0' + x)
                result[i] = '0'; // Mark as unassigned for now
            }
        }

        if (!possible_x) {
            continue;
        }

        // Second pass: assign digits equal to x
        // These can go to color 1 or color 2
        // To maintain non-decreasing order, all 'x's assigned to color 1 must appear before all 'x's assigned to color 2.
        // The split point for 'x's is determined by last1.
        // All 'x's before the split point go to color 1.
        // All 'x's after the split point go to color 2.
        // The split point is the first 'x' that is greater than or equal to last1.
        // If last1 is already 'x', then all subsequent 'x's must go to color 2.
        // If last1 is less than 'x', then 'x's can go to color 1 until last1 becomes 'x'.

        bool split_found = false;
        for (int i = 0; i < n; ++i) {
            if (result[i] == '0') { // This digit is 'x'
                if (!split_found) {
                    if ((char)('0' + x) >= last1) {
                        result[i] = '1';
                        last1 = (char)('0' + x);
                    } else { // (char)('0' + x) < last1, this should not happen if last1 was updated correctly
                             // This means last1 was already 'x' or greater, and we are trying to assign 'x' to color 1
                             // which would violate the non-decreasing property for color 1.
                             // So, this 'x' must go to color 2.
                        result[i] = '2';
                        last2 = (char)('0' + x);
                        split_found = true;
                    }
                } else { // Split already found, all subsequent 'x's must go to color 2
                    result[i] = '2';
                    last2 = (char)('0' + x);
                }
            }
        }

        // Final check for overall non-decreasing property
        // The last digit of color 1 sequence must be <= the first digit of color 2 sequence.
        // This is implicitly handled by `last1` and `last2` if we consider the split point.
        // If `last1` is the last digit assigned to color 1 and `last2` is the first digit assigned to color 2,
        // then we need `last1 <= last2`.
        // However, `last1` and `last2` here are just the last seen digits in their respective sequences.
        // We need to find the actual last digit of S1 and first digit of S2.

        char actual_last1 = '0' - 1;
        for (int i = 0; i < n; ++i) {
            if (result[i] == '1') {
                actual_last1 = s[i];
            }
        }

        char actual_first2 = '9' + 1;
        for (int i = 0; i < n; ++i) {
            if (result[i] == '2') {
                actual_first2 = s[i];
                break;
            }
        }

        if (actual_last1 <= actual_first2) {
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

