#include <iostream>
#include <vector>
#include <string>
#include <set>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_password.insert(s[i]);
        if (i + 1 < s.length()) {
            adj[s[i]].insert(s[i+1]);
            adj[s[i+1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find starting points for chains (characters with only one required neighbor)
    // Or any character if all have two neighbors (e.g., a cycle, or a single character)
    char start_char = '\0';
    for (char c : used_in_password) {
        if (adj[c].size() <= 1) { // A character with 0 or 1 required neighbor can be a start/end of a chain
            start_char = c;
            break;
        }
    }

    // If all characters in password have 2 neighbors, it means they form a cycle.
    // This is problematic if the cycle length is > 26, but we already checked adj.size() > 2.
    // If it's a cycle, any character can be a start.
    if (start_char == '\0' && !used_in_password.empty()) {
        start_char = *used_in_password.begin();
    }

    if (start_char != '\0') {
        char current_char = start_char;
        char prev_char = '\0'; // To keep track of the direction in the chain

        while (visited_in_layout.find(current_char) == visited_in_layout.end()) {
            layout_str += current_char;
            visited_in_layout.insert(current_char);

            char next_char = '\0';
            for (char neighbor : adj[current_char]) {
                if (neighbor != prev_char) {
                    next_char = neighbor;
                    break;
                }
            }
            prev_char = current_char;
            current_char = next_char;
            if (current_char == '\0') break; // End of chain
        }
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

