    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1}^{b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, so use long long.
    // We need to perform division by 2. Since MOD is odd, 2 has a modular inverse.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 500000004.
    long long sum_r_val = (b - 1);
    if (sum_r_val < 0) sum_r_val = 0; // If b=1, b-1=0, sum is 0.
    sum_r_val = (sum_r_val % MOD * (b % MOD)) % MOD;

    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9 + 7
    sum_r_val = (sum_r_val * inv2) % MOD;

    // Calculate sum_k_term = sum_{k=1}^{a} (k * b + 1)
    // sum_k_term = sum_{k=1}^{a} (k * b) + sum_{k=1}^{a} 1
    // sum_k_term = b * sum_{k=1}^{a} k + a
    // sum_{k=1}^{a} k = a * (a+1) / 2
    long long sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD; // This is sum_{k=1}^{a} k mod MOD

    long long term_kb = (b % MOD * sum_k_val) % MOD; // This is b * sum_{k=1}^{a} k mod MOD
    long long term_a = a % MOD; // This is sum_{k=1}^{a} 1 mod MOD

    long long sum_k_term_val = (term_kb + term_a) % MOD;

    // Total sum = sum_r_val * sum_k_term_val
    long long total_sum = (sum_r_val * sum_k_term_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
