#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> pos(26);
    for (int i = 0; i < L; ++i) {
        pos[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char t0_char = s[k_actual];
        int t0_char_idx = t0_char - 'a';

        // Find all possible k' values that could produce t0_char as the first character
        const std::vector<int>& possible_k_values = pos[t0_char_idx];

        if (possible_k_values.size() == 1) {
            // If t0_char uniquely determines k, Vasya wins regardless of p.
            total_win_prob += 1.0;
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this t0_char.
        // The win probability for a given t0_char is 1 if there exists a p
        // such that for all k' in possible_k_values, (s[k'], s[(k'+p)%L]) is unique.
        // Otherwise, it's 0.

        bool can_win_for_this_t0 = false;
        for (int p = 1; p < L; ++p) { // Vasya chooses p from 1 to L-1
            std::vector<std::pair<char, char>> observed_pairs;
            observed_pairs.reserve(possible_k_values.size());
            for (int k_prime : possible_k_values) {
                observed_pairs.push_back({s[k_prime], s[(k_prime + p) % L]});
            }

            // Check if all observed_pairs are unique
            std::sort(observed_pairs.begin(), observed_pairs.end());
            bool all_unique = true;
            for (size_t i = 0; i + 1 < observed_pairs.size(); ++i) {
                if (observed_pairs[i] == observed_pairs[i+1]) {
                    all_unique = false;
                    break;
                }
            }

            if (all_unique) {
                can_win_for_this_t0 = true;
                break; // Found a p that guarantees a win for this t0_char
            }
        }

        if (can_win_for_this_t0) {
            total_win_prob += 1.0;
        }
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::sqrt(n));
    // If n is a perfect square, k*k = n.
    // If n is not a perfect square, k*k < n.
    // We want to find the smallest k such that k*k >= n.
    // This is ceil(sqrt(n)).
    // The integer k from sqrt(n) is floor(sqrt(n)).
    // If k*k < n, then we need k+1.
    // If k*k >= n, then k is sufficient.
    // So, the target block size is ceil(sqrt(n)).
    if (k * k < n) {
        k++;
    }
    // Now k is ceil(sqrt(n)).
    // We want to construct a permutation where LIS and LDS are both k.
    // The sum will be 2*k.

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; i += k) {
        int block_start = i;
        int block_end = std::min(i + k, n);
        for (int j = block_end - 1; j >= block_start; --j) {
            p[j] = current_val--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For an input x, the j-th bit of x is x_j.
    // We want to find a transformation for each bit x_j -> y_j.
    // There are two possible initial states for x_j: 0 or 1.
    // We track what 0 becomes and what 1 becomes after all operations.
    // initial_val_0[j] = final value of j-th bit if initial x_j was 0
    // initial_val_1[j] = final value of j-th bit if initial x_j was 1
    std::vector<int> initial_val_0(10); // All bits are 0 initially
    std::vector<int> initial_val_1(10); // All bits are 1 initially

    for (int j = 0; j < 10; ++j) {
        initial_val_0[j] = 0; // If input bit is 0, it starts as 0
        initial_val_1[j] = 1; // If input bit is 1, it starts as 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x_val;
        std::cin >> op_char >> x_val;

        for (int j = 0; j < 10; ++j) {
            int bit_x = (x_val >> j) & 1; // j-th bit of constant x_val

            if (op_char == '&') {
                initial_val_0[j] &= bit_x;
                initial_val_1[j] &= bit_x;
            } else if (op_char == '|') {
                initial_val_0[j] |= bit_x;
                initial_val_1[j] |= bit_x;
            } else if (op_char == '^') {
                initial_val_0[j] ^= bit_x;
                initial_val_1[j] ^= bit_x;
            }
        }
    }

    // Now we have the final transformation for each bit.
    // For each bit j:
    // (0 -> initial_val_0[j])
    // (1 -> initial_val_1[j])

    // We want to find A, B, C such that:
    // (x & A | B ^ C) for each bit j:
    // (x_j & A_j | B_j ^ C_j) = initial_val_0[j] if x_j = 0
    // (x_j & A_j | B_j ^ C_j) = initial_val_1[j] if x_j = 1

    // Let's try to construct the three operations: AND, OR, XOR.
    // We need to find constants for these operations.
    // Let the final program be: (x & AND_CONST | OR_CONST ^ XOR_CONST)
    // This is equivalent to: ( (x & AND_CONST) | OR_CONST ) ^ XOR_CONST

    // Let's determine the constants bit by bit.
    int final_and_const = 0;
    int final_or_const = 0;
    int final_xor_const = 0;

    for (int j = 0; j < 10; ++j) {
        int val_0 = initial_val_0[j]; // What 0 becomes
        int val_1 = initial_val_1[j]; // What 1 becomes

        // We need to find A_j, B_j, C_j such that:
        // (0 & A_j | B_j ^ C_j) = val_0  => (0 | B_j ^ C_j) = val_0 => B_j ^ C_j = val_0
        // (1 & A_j | B_j ^ C_j) = val_1  => (A_j | B_j ^ C_j) = val_1 => A_j | val_0 = val_1

        // From B_j ^ C_j = val_0, we can choose B_j and C_j.
        // From A_j | val_0 = val_1, we can determine A_j.

        // Case 1: val_0 = 0, val_1 = 0
        //   B_j ^ C_j = 0  => B_j = C_j
        //   A_j | 0 = 0    => A_j = 0
        //   Choose A_j=0, B_j=0, C_j=0.
        //   (x_j & 0 | 0 ^ 0) = 0. Correct.

        // Case 2: val_0 = 0, val_1 = 1
        //   B_j ^ C_j = 0  => B_j = C_j
        //   A_j | 0 = 1    => A_j = 1
        //   Choose A_j=1, B_j=0, C_j=0.
        //   (x_j & 1 | 0 ^ 0) = x_j. Correct.

        // Case 3: val_0 = 1, val_1 = 0
        //   B_j ^ C_j = 1  => B_j != C_j
        //   A_j | 1 = 0    => IMPOSSIBLE (A_j | 1 is always 1)
        // This means the form (x & A | B ^ C) is not general enough.
        // The problem states "no more than 5 lines".
        // The standard way to represent any boolean function of one variable (x_j) is:
        // f(x_j) = (x_j AND A_j) XOR B_j
        // or f(x_j) = (x_j XOR A_j) AND B_j
        // or f(x_j) = (x_j OR A_j) XOR B_j
        //
        // Let's try to find a sequence of at most 3 operations that works for each bit.
        // The operations are independent for each bit.
        // For each bit j, we have a mapping (0 -> val_0, 1 -> val_1).
        // There are 4 possible mappings:
        // 1. (0->0, 1->0): Always 0. Can be achieved by `& 0`.
        // 2. (0->0, 1->1): Identity. Can be achieved by `& 1` (or no op).
        // 3. (0->1, 1->0): NOT x_j. Can be achieved by `^ 1`.
        // 4. (0->1, 1->1): Always 1. Can be achieved by `| 1`.

        // We can combine these into three operations:
        // Let `res_and` be the result of `x & A`.
        // Let `res_or` be the result of `res_and | B`.
        // Let `res_xor` be the result of `res_or ^ C`.

        // We need to find A, B, C such that for each bit j:
        // ( ( (x_j & A_j) | B_j ) ^ C_j )
        // This must be `val_0` when `x_j = 0`.
        // This must be `val_1` when `x_j = 1`.

        // For x_j = 0:
        // ( ( (0 & A_j) | B_j ) ^ C_j ) = ( (0 | B_j) ^ C_j ) = (B_j ^ C_j) = val_0

        // For x_j = 1:
        // ( ( (1 & A_j) | B_j ) ^ C_j ) = ( (A_j | B_j) ^ C_j ) = val_1

        // Let's define `B_j_xor_C_j = val_0`.
        // Then `(A_j | B_j) ^ C_j = val_1`.
        // We can choose `B_j` and `C_j` to satisfy `B_j ^ C_j = val_0`.
        // For example, if `val_0 = 0`, choose `B_j = 0, C_j = 0`.
        // If `val_0 = 1`, choose `B_j = 1, C_j = 0`. (Or `B_j = 0, C_j = 1`).

        // Let's try to determine A_j, B_j, C_j for each of the 4 cases:

        // Case 1: (0->0, 1->0)
        //   B_j ^ C_j = 0
        //   (A_j | B_j) ^ C_j = 0
        //   Choose B_j = 0, C_j = 0.
        //   Then (A_j | 0) ^ 0 = 0 => A_j = 0.
        //   So: A_j=0, B_j=0, C_j=0.
        //   This means `& 0` for this bit.

        // Case 2: (0->0, 1->1)
        //   B_j ^ C_j = 0
        //   (A_j | B_j) ^ C_j = 1
        //   Choose B_j = 0, C_j = 0.
        //   Then (A_j | 0) ^ 0 = 1 => A_j = 1.
        //   So: A_j=1, B_j=0, C_j=0.
        //   This means `& 1` for this bit.

        // Case 3: (0->1, 1->0)
        //   B_j ^ C_j = 1
        //   (A_j | B_j) ^ C_j = 0
        //   Choose B_j = 1, C_j = 0.
        //   Then (A_j | 1) ^ 0 = 0 => 1 ^ 0 = 0 => 1 = 0. IMPOSSIBLE.
        //   Choose B_j = 0, C_j = 1.
        //   Then (A_j | 0) ^ 1 = 0 => A_j ^ 1 = 0 => A_j = 1.
        //   So: A_j=1, B_j=0, C_j=1.
        //   This means `& 1` then `^ 1` for this bit.

        // Case 4: (0->1, 1->1)
        //   B_j ^ C_j = 1
        //   (A_j | B_j) ^ C_j = 1
        //   Choose B_j = 1, C_j = 0.
        //   Then (A_j | 1) ^ 0 = 1 => 1 ^ 0 = 1 => 1 = 1. This works.
        //   So: A_j=any, B_j=1, C_j=0. Let's pick A_j=0.
        //   This means `| 1` for this bit.

        // Summary of choices for (A_j, B_j, C_j):
        // (0->0, 1->0): A_j=0, B_j=0, C_j=0  (Effectively `& 0`)
        // (0->0, 1->1): A_j=1, B_j=0, C_j=0  (Effectively `& 1`)
        // (0->1, 1->0): A_j=1, B_j=0, C_j=1  (Effectively `& 1 ^ 1`)
        // (0->1, 1->1): A_j=0, B_j=1, C_j=0  (Effectively `| 1`)

        // Now, let's construct the constants `final_and_const`, `final_or_const`, `final_xor_const`.
        // A_j contributes to `final_and_const`.
        // B_j contributes to `final_or_const`.
        // C_j contributes to `final_xor_const`.

        if (val_0 == 0 && val_1 == 0) { // (0->0, 1->0)
            // A_j=0, B_j=0, C_j=0
            // final_and_const |= (0 << j);
            // final_or_const |= (0 << j);
            // final_xor_const |= (0 << j);
        } else if (val_0 == 0 && val_1 == 1) { // (0->0, 1->1)
            // A_j=1, B_j=0, C_j=0
            final_and_const |= (1 << j);
            // final_or_const |= (0 << j);
            // final_xor_const |= (0 << j);
        } else if (val_0 == 1 && val_1 == 0) { // (0->1, 1->0)
            // A_j=1, B_j=0, C_j=1
            final_and_const |= (1 << j);
            // final_or_const |= (0 << j);
            final_xor_const |= (1 << j);
        } else { // (val_0 == 1 && val_1 == 1) // (0->1, 1->1)
            // A_j=0, B_j=1, C_j=0
            // final_and_const |= (0 << j);
            final_or_const |= (1 << j);
            // final_xor_const |= (0 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If not all bits are 1 for AND, then we need an AND op.
                                   // If final_and_const is 1023, it means all A_j are 1.
                                   // (x & 1023) is just x for numbers up to 1023.
                                   // So, if final_and_const is 1023, we can omit the AND operation.
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If not all bits are 0 for OR, then we need an OR op.
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If not all bits are 0 for XOR, then we need an XOR op.
        result_ops.push_back({'^', final_xor_const});
    }

    // The problem states "no more than 5 lines".
    // The construction above always yields at most 3 operations.
    // The only edge case is if final_and_const is 1023.
    // If final_and_const is 1023, it means for all j, A_j=1.
    // This means the (x & A) part is effectively just x.
    // So, if final_and_const is 1023, we can omit the '&' operation.
    // The logic `if (final_and_const != 1023)` handles this.

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<int> suffix_max(n);

    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<int> freq_p1(n + 1, 0);
    int distinct_count_p1 = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] > i + 1) { // Element value cannot exceed current length
            break;
        }
        if (freq_p1[a[i]] == 0) {
            distinct_count_p1++;
        }
        freq_p1[a[i]]++;
        if (freq_p1[a[i]] > 1) { // Duplicate found
            break;
        }
        if (distinct_count_p1 == i + 1 && prefix_max[i] == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<int> freq_p2(n + 1, 0);
    int distinct_count_p2 = 0;
    for (int i = n - 1; i >= 0; --i) {
        int current_len = n - i;
        if (a[i] > current_len) { // Element value cannot exceed current length
            break;
        }
        if (freq_p2[a[i]] == 0) {
            distinct_count_p2++;
        }
        freq_p2[a[i]]++;
        if (freq_p2[a[i]] > 1) { // Duplicate found
            break;
        }
        if (distinct_count_p2 == current_len && suffix_max[i] == current_len) {
            is_suffix_perm[current_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means this 'b' can be moved past
            // all 'a's to its left that we have already counted.
            // Each 'a' to its left will form an 'ab' pair with this 'b'.
            // When 'ab' -> 'bba', the 'a' moves past the 'b' and creates a new 'b'.
            // The number of operations for this 'b' to move past all 'count_a' 'a's
            // is 'count_a'.
            // After this 'b' moves past all 'count_a' 'a's, it effectively
            // becomes 'count_a' new 'b's that are now to the left of those 'a's.
            // These new 'b's will then interact with 'a's further to the left.
            // So, the number of 'a's that will be affected by future 'b's doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is to the left of
            // all 'b's we have already processed.
            // This 'a' will form 'ab' pairs with those 'b's.
            // We just increment the count of 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total difference
    int initial_diff = 0;
    for (int x : a) {
        if (x == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Map to store the first occurrence of a prefix sum difference for the left side
    // Key: difference (S - B), Value: index (number of jars eaten from left)
    std::map<int, int> left_diff_idx;
    left_diff_idx[0] = 0; // Eating 0 jars from left results in diff 0

    int current_diff_left = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            current_diff_left++;
        } else {
            current_diff_left--;
        }
        if (left_diff_idx.find(current_diff_left) == left_diff_idx.end()) {
            left_diff_idx[current_diff_left] = (n - i);
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Case 1: No jars eaten from the right side.
    // We need to find if initial_diff can be achieved by eating only from left.
    // This means current_diff_left should be equal to initial_diff.
    // The number of jars eaten would be (n - i) for the first i that gives initial_diff.
    // This is already covered by iterating through right side and checking diff_needed.
    // Specifically, when current_diff_right = 0, diff_needed = initial_diff.
    // If initial_diff is in left_diff_idx, then min_jars_eaten will be updated.

    // Iterate through the right side, calculating suffix sums
    int current_diff_right = 0;
    for (int i = n; i < 2 * n; ++i) {
        // The difference needed from the left side to make the total difference zero
        // is `initial_diff - current_diff_right`.
        // This is because `(S_total - B_total) - (S_right_eaten - B_right_eaten) - (S_left_eaten - B_left_eaten) = 0`
        // `initial_diff - current_diff_right - current_diff_left = 0`
        // `current_diff_left = initial_diff - current_diff_right`
        int diff_needed_from_left = initial_diff - current_diff_right;

        if (left_diff_idx.count(diff_needed_from_left)) {
            int jars_eaten_from_left = left_diff_idx[diff_needed_from_left];
            int jars_eaten_from_right = (i - n + 1);
            min_jars_eaten = std::min(min_jars_eaten, jars_eaten_from_left + jars_eaten_from_right);
        }

        if (a[i] == 1) {
            current_diff_right++;
        } else {
            current_diff_right--;
        }
    }

    // After the loop, current_diff_right holds the difference for all n jars on the right.
    // Check the case where all n jars on the right are eaten.
    int diff_needed_from_left = initial_diff - current_diff_right;
    if (left_diff_idx.count(diff_needed_from_left)) {
        int jars_eaten_from_left = left_diff_idx[diff_needed_from_left];
        int jars_eaten_from_right = n; // All n jars on the right
        min_jars_eaten = std::min(min_jars_eaten, jars_eaten_from_left + jars_eaten_from_right);
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Precompute prefix sums for '0's
    // p_zeros[i] stores the count of '0's in s[0...i-1]
    std::vector<int> p_zeros(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        p_zeros[i+1] = p_zeros[i] + (s[i] == '0' ? 1 : 0);
    }

    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', it cannot be the start of a good substring
            // with a non-zero value, as f(0...) = f(...)
            // However, f(0) = 0, and length 1. So s[i...i] = "0" is good if 1 = 0, which is false.
            // So, a substring starting with '0' can only be good if its value is 0.
            // But its length must be 0, which is not possible.
            // So, if s[i] is '0', it cannot be the start of a good substring
            // unless it's part of a longer substring where the first '1' is far away.
            // The problem statement says f(000) = 0. Length is 3. 3 != 0.
            // So, a substring of all zeros is never good.
            // This means we only need to consider substrings starting with '1'.
            // This is incorrect. The example f(011)=3, length 3. This is good.
            // The example f(000100)=4, length 6. This is not good.
            // The example f(000)=0, length 3. This is not good.
            // The example f(00001)=1, length 5. This is not good.
            // The example f(00101)=5, length 5. This is good.
            // The example f(00001000)=4, length 8. This is not good.
            // The example f(0001000)=4, length 7. This is not good.
            // The example s=0110, good substrings: 011 (len 3, val 3).
            // So, substrings can start with '0'.
            // The value f(s_l...s_r) is the decimal value of the binary string.
            // Leading zeros are ignored for value calculation, but count for length.
            // Example: s=011, len=3, val=3. Good.
            // Example: s=00101, len=5, val=5. Good.

            // The maximum possible value for a substring of length L is 2^L - 1.
            // The maximum length of s is 2e5.
            // If L is large, say L=20, 2^L is 10^6.
            // If L is small, say L=1, 2^1-1 = 1.
            // If L is small, say L=2, 2^2-1 = 3.
            // If L is small, say L=3, 2^3-1 = 7.
            // If L is small, say L=18, 2^18 = 262144.
            // If L is small, say L=19, 2^19 = 524288.
            // If L is small, say L=20, 2^20 = 1048576.
            // The length of the string is at most 2e5.
            // So, if the value of the binary string is V, and its length is L, we need V=L.
            // Since V <= 2^L - 1, we must have L <= 2^L - 1. This is true for L >= 1.
            // However, if L is large, V will be much smaller than 2^L - 1.
            // For example, if L=20, V can be at most 20.
            // The maximum value of L is N.
            // The maximum value of V is N.
            // So, we only need to consider substrings whose value is at most N.
            // If a substring has length L, and its value is V, and V=L.
            // Then V must be at most N.
            // The maximum number of bits required to represent N (2e5) is log2(2e5) approx 17.6.
            // So, if a substring has a '1' at position k (from right, 0-indexed), its value is at least 2^k.
            // If 2^k > N, then this substring cannot have value N or less.
            // So, we only need to consider substrings where the most significant '1' is not too far from the right end.
            // Specifically, if the value V is L, then V <= N.
            // The number of bits in V is roughly log2(V).
            // Let's say the actual binary string is $s_l \dots s_r$.
            // Let $k$ be the index of the first '1' from the left in $s_l \dots s_r$.
            // So $s_l \dots s_{k-1}$ are all '0's.
            // The value $f(s_l \dots s_r)$ is $f(s_k \dots s_r)$.
            // The length is $r-l+1$.
