            dp[current_x] = {final_x_from_next_block, y_added_step1 + y_added_step2 + total_y_from_next_block};
        }

        visited[current_x] = 2; // Mark as finished
        return dp[current_x].first != -1;
    };

    // Compute dp for all possible starting x values (1 to n)
    for (int i = 1; i <= n; ++i) {
        compute_dp(compute_dp, i);
    }

    // For each query i from 1 to n-1:
    // a[1] is set to i.
    // Initial state: x=1, y=0.
    // Step 1: x = 1 + a[1], y = a[1].
    // Step 2: x = (1 + a[1]) - a[1+a[1]], y = a[1] + a[1+a[1]].
    // This is exactly what dp[1] would compute if a[1] was fixed.
    // But a[1] changes for each query.
    // So for each query, we need to simulate the first two steps,
    // then use the precomputed dp values for the subsequent steps.

    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current query

        long long current_y = 0;
        int current_x = 1;

        // First operation: x = x + a[x], y = y + a[x]
        long long val1 = a[current_x];
        current_x += val1;
        current_y += val1;

        // Check for termination after first operation
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Second operation: x = x - a[x], y = y + a[x]
        long long val2 = a[current_x];
        current_x -= val2;
        current_y += val2;

        // Check for termination after second operation
        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now, current_x is within [1, n].
        // The subsequent operations are exactly what dp[current_x] describes.
        // We need to add dp[current_x].second to current_y.
        // And the final x will be dp[current_x].first.
        if (dp[current_x].first == -1) { // If it leads to a loop
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + dp[current_x].second << "\n";
        }
    }

    return 0;
}

