    // Let's consider an element a_k.
    // Its value at the time of the i-th operation is initial_a[k] + sum_of_deltas_applied_to_k_before_i.
    // Let S_k(i) be the sum of all d values from type 1 operations (l, r, d) such that
    // the operation occurred before operation i, and k is in [l, r].
    // Then, for a type 2 operation (l_i, r_i, m_i), we must have:
    // initial_a[k] + S_k(i) <= m_i for all k in [l_i, r_i].
    // This implies initial_a[k] <= m_i - S_k(i).
    // So, for each k, initial_a[k] must be less than or equal to the minimum of (m_i - S_k(i))
    // over all type 2 operations (l_i, r_i, m_i) where k is in [l_i, r_i].
    // Let's call this upper bound U_k.
    // We want to find *any* suitable array. To maximize our chances, we can try to set
    // initial_a[k] = U_k. This is the largest possible value for initial_a[k] that satisfies
    // all type 2 constraints. If this choice leads to a contradiction, no solution exists.

    // Initialize initial_a with a very large value (effectively infinity)
    for (int i = 0; i < n; ++i) {
        initial_a[i] = 2000000000LL; // A value larger than 10^9 + max_delta_sum
                                     // Max delta sum: 5000 ops * 10^4 = 5*10^7
                                     // Max m: 5*10^7. So initial_a[k] could be around 5*10^7.
                                     // Max initial_a[k] is 10^9.
                                     // So 2*10^9 is a safe "infinity" for initial_a[k].
    }

    // Calculate initial_a[k] based on type 2 operations
    // We need to simulate operations to find S_k(i)
    std::vector<long long> current_deltas(n + 1, 0); // Stores current sum of deltas for each index
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply delta to current_deltas for future S_k(j) calculations
            current_deltas[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n + 1) {
                current_deltas[ops[i].r + 1] -= ops[i].val;
            }
        } else { // type 2
            long long current_delta_sum = 0;
            for (int k = 0; k < n; ++k) {
                current_delta_sum += current_deltas[k];
                if (k >= ops[i].l && k <= ops[i].r) {
                    // initial_a[k] + current_delta_sum <= ops[i].val
                    // initial_a[k] <= ops[i].val - current_delta_sum
                    initial_a[k] = std::min(initial_a[k], ops[i].val - current_delta_sum);
                }
            }
        }
    }

    // Check if the chosen initial_a satisfies all conditions
    // Reset current_deltas for re-simulation
    std::fill(current_deltas.begin(), current_deltas.end(), 0);

    for (int i = 0; i < m; ++i) {
