// Function to check if it's possible to make the array non-decreasing with at most 'x' operations.
// 'x' represents the number of times we increment certain elements.
bool check(long long x, int n, int m, const std::vector<int>& a) {
    long long prev_val = 0; // The value of b_{i-1} in the target non-decreasing array.
                            // For the first element, b_0 is effectively 0.

    for (int i = 0; i < n; ++i) {
        long long current_a = a[i];

        // We have two choices for b_i:
        // 1. Don't increment a_i: b_i = a_i. This is valid if a_i >= prev_val.
        // 2. Increment a_i by x: b_i = (a_i + x) % m. This is valid if (a_i + x) % m >= prev_val.

        bool can_use_a_i = (current_a >= prev_val);
        bool can_use_a_i_plus_x = ((current_a + x) % m >= prev_val);

        // If a_i + x wraps around (i.e., (a_i + x) % m < a_i), then (a_i + x) % m is a smaller value.
        // If a_i + x does not wrap around (i.e., (a_i + x) % m >= a_i), then a_i is a smaller value.
        // This logic is for choosing the smallest possible b_i that satisfies b_i >= prev_val.

        if (can_use_a_i && can_use_a_i_plus_x) {
            // Both options are valid. We choose the one that results in a smaller b_i
            // to make it easier for subsequent elements to satisfy the non-decreasing condition.
            // If (a_i + x) % m is smaller than a_i, it means a_i + x wrapped around.
            // In this case, we prefer (a_i + x) % m.
            // Otherwise, a_i is smaller or equal to (a_i + x) % m (if no wrap-around),
            // so we prefer a_i.
            if ((current_a + x) % m < current_a) { // (a_i + x) wrapped around
                prev_val = (current_a + x) % m;
            } else { // (a_i + x) did not wrap around, or (a_i + x) % m >= a_i
                prev_val = current_a;
            }
        } else if (can_use_a_i) {
            // Only a_i is a valid choice.
            prev_val = current_a;
        } else if (can_use_a_i_plus_x) {
            // Only (a_i + x) % m is a valid choice.
            prev_val = (current_a + x) % m;
        } else {
            // Neither choice is valid. It's impossible to make the array non-decreasing with this 'x'.
            return false;
        }
    }
    // If we successfully processed all elements, 'x' is a possible number of operations.
    return true;
}

