    // or a[n-1].value + a[n-2].value (if they are in the same subsequence).
    // The maximum possible value for f is always at least a[n-1].value + a[0].value + h.

    // Consider a partition where a[0] is in S1 and all other elements are in S2.
    // Min f:
    //   - a[1].value + a[2].value (if n >= 3, from S2)
    //   - a[0].value + a[1].value + h (from S1 and S2)
    //   So, min_f = min(a[1].value + a[2].value, a[0].value + a[1].value + h) if n >= 3
    //   If n=2, min_f = a[0].value + a[1].value + h
    // Max f:
    //   - a[n-1].value + a[n-2].value (from S2)
    //   - a[0].value + a[n-1].value + h (from S1 and S2)
    //   So, max_f = max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h)

    // Let's analyze the possible minimum and maximum values of f more generally.
    // The smallest sum a_i + a_j is a[0].value + a[1].value.
    // The largest sum a_i + a_j is a[n-1].value + a[n-2].value.
    // The smallest sum a_i + a_j + h is a[0].value + a[1].value + h.
    // The largest sum a_i + a_j + h is a[n-1].value + a[n-2].value + h.

    // The overall minimum f value will be min(a[0].value + a[1].value, a[0].value + a[1].value + h) = a[0].value + a[1].value.
    // The overall maximum f value will be max(a[n-1].value + a[n-2].value, a[n-1].value + a[n-2].value + h) = a[n-1].value + a[n-2].value + h.
    // This is true if there is at least one pair in the same subsequence AND at least one pair in different subsequences.
    // If this is the case, the goodness would be (a[n-1].value + a[n-2].value + h) - (a[0].value + a[1].value).
    // This is the "worst case" goodness for a mixed partition.

    // We need to find a partition that minimizes max_f - min_f.
    // Let's consider a partition where a[0] is in S1 and all other elements are in S2.
    // Min f values:
    //   - a[1].value + a[2].value (if n >= 3, from S2)
    //   - a[0].value + a[1].value + h (from S1 and S2)
    // Max f values:
    //   - a[n-1].value + a[n-2].value (from S2)
    //   - a[0].value + a[n-1].value + h (from S1 and S2)

    // Let's consider two specific partitions for Case 2:
    // Partition A: a[0] in S1, all others in S2.
    //   min_f_A = std::min(a[0].value + a[1].value + h, (n >= 3 ? a[1].value + a[2].value : 2e18)); // Use a large value if n<3
    //   max_f_A = std::max(a[0].value + a[n-1].value + h, a[n-1].value + a[n-2].value);
    //   goodness_A = max_f_A - min_f_A;

    // Partition B: a[n-1] in S1, all others in S2.
    //   min_f_B = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
    //   max_f_B = std::max(a[n-2].value + a[n-3].value, (n >= 3 ? a[n-1].value + a[n-2].value + h : -1e18)); // Use a small value if n<3
    //   goodness_B = max_f_B - min_f_B;

    // The key insight is that to minimize the difference, we want to make the range of values as small as possible.
    // The values are either `X` or `X+h`.
    // The minimum possible `X` is `a[0].value + a[1].value`.
    // The maximum possible `X` is `a[n-1].value + a[n-2].value`.

    // Option 1: All elements in one group.
    // Min f = a[0].value + a[1].value
    // Max f = a[n-1].value + a[n-2].value
    // Goodness = (a[n-1].value + a[n-2].value) - (a[0].value + a[1].value)
    // This is `goodness1` calculated above.

    // Option 2: Split such that a[0] is in S1, and a[1], ..., a[n-1] are in S2.
    // Pairs within S1: None (if S1 has only a[0])
    // Pairs within S2: (a[i], a[j]) for i,j in [1, n-1]. Min sum: a[1]+a[2]. Max sum: a[n-1]+a[n-2].
    // Pairs across S1 and S2: (a[0], a[j]) for j in [1, n-1]. Min sum: a[0]+a[1]+h. Max sum: a[0]+a[n-1]+h.
    //
    // Overall min f:
    //   If n=2: only (a[0], a[1]) across groups. Min f = a[0].value + a[1].value + h.
    //   If n>=3: min(a[1].value + a[2].value, a[0].value + a[1].value + h).
    // Overall max f:
    //   If n=2: only (a[0], a[1]) across groups. Max f = a[0].value + a[1].value + h.
    //   If n>=3: max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h).
    //
    // Let's calculate goodness for this partition.
    long long current_min_f_val;
    long long current_max_f_val;

    if (n == 2) {
        current_min_f_val = a[0].value + a[1].value + h;
        current_max_f_val = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f_val = std::min(a[1].value + a[2].value, a[0].value + a[1].value + h);
        current_max_f_val = std::max(a[n-1].value + a[n-2].value, a[0].value + a[n-1].value + h);
    }
    long long goodness2 = current_max_f_val - current_min_f_val;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Option 3: Split such that a[n-1] is in S1, and a[0], ..., a[n-2] are in S2.
    // Pairs within S1: None (if S1 has only a[n-1])
    // Pairs within S2: (a[i], a[j]) for i,j in [0, n-2]. Min sum: a[0]+a[1]. Max sum: a[n-2]+a[n-3].
    // Pairs across S1 and S2: (a[n-1], a[j]) for j in [0, n-2]. Min sum: a[n-1]+a[0]+h. Max sum: a[n-1]+a[n-2]+h.
    //
    // Overall min f:
    //   If n=2: only (a[0], a[1]) across groups. Min f = a[0].value + a[1].value + h.
    //   If n>=3: min(a[0].value + a[1].value, a[0].value + a[n-1].value + h).
    // Overall max f:
    //   If n=2: only (a[0], a[1]) across groups. Max f = a[0].value + a[1].value + h.
    //   If n>=3: max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h).
    //
    // Let's calculate goodness for this partition.
    if (n == 2) { // This case is identical to Option 2 for n=2
        current_min_f_val = a[0].value + a[1].value + h;
        current_max_f_val = a[0].value + a[1].value + h;
    } else { // n >= 3
        current_min_f_val = std::min(a[0].value + a[1].value, a[0].value + a[n-1].value + h);
        current_max_f_val = std::max(a[n-2].value + a[n-3].value, a[n-1].value + a[n-2].value + h);
    }
    long long goodness3 = current_max_f_val - current_min_f_val;
    std::vector<int> partition3(n);
    partition3[a[n-1].original_index] = 1;
    for (int i = 0; i < n - 1; ++i) {
        partition3[a[i].original_index] = 2;
    }

    // Compare the goodness values and print the best one.
    if (goodness1 <= goodness2 && goodness1 <= goodness3) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else if (goodness2 <= goodness1 && goodness2 <= goodness3) {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else { // goodness3 is minimal
        std::cout << goodness3 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition3[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
