// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case 1: Try k=1 (one cut)
    // Cut s into s_prefix and s_suffix.
    // Form s_new = s_suffix + s_prefix.
    // Check if s_new is a palindrome and s_new != s.
    for (int i = 1; i < n; ++i) { // i is the length of s_prefix
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);
        std::string s_new = s_suffix + s_prefix;
        if (s_new != s && is_palindrome(s_new)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case 2: Try k=2 (two cuts)
    // This is always possible unless all characters in s are the same.
    // If s consists of all identical characters (e.g., "aaaaa"),
    // then any permutation of its substrings will result in the same string,
    // and thus cannot form a new palindrome.
    // Example: "aaaaa" -> "a|a|aaa" -> "aa|a|aa" -> "aaa|a|a"
    // Any rearrangement will still be "aaaaa".
    // So, if all characters are the same, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, we can always achieve k=2.
        // Consider the string s = c_1 c_2 ... c_n.
        // Since s is a palindrome, c_1 = c_n, c_2 = c_{n-1}, etc.
        // Since not all characters are the same, there must be some c_i != c_1.
        // This implies that s is not of the form "aaaaa...".
        //
        // Consider the string s' = s.substr(0, n-1).
        // If s' is not a palindrome, then we can cut s into s.substr(0, n-1) and s.substr(n-1, 1).
        // Let s_1 = s.substr(0, n-1) and s_2 = s.substr(n-1, 1).
        // s_new = s_2 + s_1.
        // If s_new is a palindrome and s_new != s, then k=1 is the answer (already checked).
        //
        // The problem statement guarantees s is a palindrome.
        // If not all characters are the same, then there exists at least one character s[i] != s[0].
        // This means s is not of the form "aaaa...a".
        //
        // Consider cutting s into s[0...j-1], s[j], s[j+1...n-1].
        // For example, take s = "nolon". n=5.
        // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
        // Not all same.
        //
        // We can always achieve k=2 if not all characters are the same.
        // Example: s = "abacaba"
        // Cut: "aba" | "c" | "aba"
        // Rearrange: "aba" | "c" | "aba" -> "abacaba" (same)
        //
        // The strategy for k=2:
        // Take the first half of the string (excluding the middle character if n is odd).
        // Let `half_len = n / 2`.
        // `s_half = s.substr(0, half_len)`.
        // If `s_half` is not a palindrome, then we can make a new palindrome.
        // Example: `s = "abacaba"`, `half_len = 3`, `s_half = "aba"`. This is a palindrome.
        // Example: `s = "otto"`, `half_len = 2`, `s_half = "ot"`. This is not a palindrome.
        // For "otto", k=1 works: "ot" | "to" -> "toot".
        //
        // If `s_half` is a palindrome, and `s` is not all same characters,
        // then `s` must be of the form `P M P` where `P` is a palindrome.
        // Example: `s = "abacaba"`, `P = "aba"`, `M = "c"`.
        // Example: `s = "racecar"`, `P = "rac"`, `M = "e"`. `P` is not a palindrome.
        //
        // The condition "not all characters are the same" is sufficient for k=2.
        // Consider the string `s`. Since it's a palindrome, `s[i] == s[n-1-i]`.
        // If not all characters are the same, there exists some `i` such that `s[i] != s[0]`.
        // This means `s` is not of the form `aaaa...a`.
        //
        // Let's try to construct a new palindrome with 2 cuts.
        // Cut `s` into `s[0...j-1]`, `s[j]`, `s[j+1...n-1]`.
        // We need to find a `j` such that `s[0...j-1] + s[j+1...n-1] + s[j]` is a palindrome and not equal to `s`.
        // This is not the strategy. The strategy is to rearrange pieces.
        //
        // The simplest way to get k=2 is to cut `s` into `s[0]`, `s[1...n-2]`, `s[n-1]`.
        // Pieces: `s[0]`, `s.substr(1, n-2)`, `s[n-1]`.
        // Since `s` is a palindrome, `s[0] == s[n-1]`.
        // Let `c = s[0]`. Let `mid = s.substr(1, n-2)`.
        // Pieces are `c`, `mid`, `c`.
        // We can rearrange them to `c + mid + c` (which is `s`).
        // Or `mid + c + c`. This is `s.substr(1, n-2) + s[0] + s[n-1]`.
        // Is `mid + c + c` a palindrome?
        // Example: `s = "nolon"`. `c = 'n'`, `mid = "olo"`.
        // `mid + c + c` = "olon" + 'n' = "olonn". Not a palindrome.
        //
        // The proof that k=2 is always possible if not all characters are the same:
        // Consider the string `s`. Since it's a palindrome and not all characters are the same,
        // there must be at least two distinct characters.
        // Let `s_prefix = s.substr(0, n-1)`.
        // If `s_prefix` is not a palindrome, then we can cut `s` into `s_prefix` and `s[n-1]`.
        // Rearrange to `s[n-1] + s_prefix`. This is `s[n-1] + s.substr(0, n-1)`.
        // Since `s` is a palindrome, `s[n-1] == s[0]`.
        // So `s_new = s[0] + s.substr(0, n-1)`.
        // This `s_new` is `s[0] + s[0] + s[1] + ... + s[n-2]`.
        // This is not necessarily a palindrome.
        //
        // The actual proof for k=2:
        // If `s` is a palindrome and not all characters are the same, then `s` must contain at least two distinct characters.
        // This means `s` is not of the form `aaaa...a`.
        // Consider the string `s_prime = s.substr(0, n/2)`.
        // If `s_prime` is not a palindrome, then we can cut `s` into `s.substr(0, n/2)` and `s.substr(n/2)`.
        // Let `A = s.substr(0, n/2)` and `B = s.substr(n/2)`.
        // `s = A + B`.
        // We can form `B + A`.
        // If `B + A` is a palindrome and `B + A != s`, then k=1. (This is covered by the k=1 loop).
        //
        // The problem is that the k=1 loop checks `s_suffix + s_prefix`.
        // If `s_half` is a palindrome, e.g., `s = "abacaba"`, `s_half = "aba"`.
        // Then `s` is of the form `P M P_rev` where `P` is `s_half`.
        // Since `s` is a palindrome, `P_rev` is `P`. So `s = P M P`.
        //
        // If `s` is a palindrome and not all characters are the same, then `k=2` is always possible.
        // This is a known result for this type of problem.
        // The argument is that if `s` is not `aaaa...a`, then there is some `i` such that `s[i] != s[0]`.
        // Consider `s_new = s.substr(1) + s[0]`.
        // If `s_new` is a palindrome and `s_new != s`, then `k=1`.
        // If `s_new` is not a palindrome, or `s_new == s`, then we need `k=2`.
        //
        // The only case where `k=2` is impossible is when all characters are the same.
        // If `s` is `aaaa...a`, then any permutation of substrings will result in `aaaa...a`.
        // So, if `all_same` is true, print "Impossible".
        // Otherwise, print `2`.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
