int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r (0-indexed) such that the substring s[i...r]
    // does NOT contain any bad triplet.
    // Initialize with n-1, meaning s[i...n-1] is initially considered "bad" if no constraint.
    // We want to find the smallest r_prime such that s[i...r_prime] contains a bad triplet.
    // Then max_r_for_l[i] = r_prime - 1.
    // If no bad triplet starts at or after i, then max_r_for_l[i] = n-1.
    std::vector<int> max_r_for_l(n);
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible starting positions x (0-indexed) for a triplet
    for (int x = 0; x < n; ++x) {
        // Iterate through possible k values.
        // The maximum k is such that x + 2k < n.
        // So 2k < n - x, k < (n - x) / 2.
        // Since k >= 1, we start k from 1.
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet makes any substring s[l...r] bad if l <= x and r >= x+2k.
                // For any l' <= x, the maximum r' such that s[l'...r'] is good
                // must be less than x + 2k.
                // So, for all l from 0 to x, we must update max_r_for_l[l].
                // The new maximum r for s[l...r] to be good is x + 2k - 1.
                // We want to find the smallest x+2k that makes s[l...r] bad.
                // So, for each l, max_r_for_l[l] should be min(current max_r_for_l[l], x + 2k - 1).
                // This means any r >= x+2k will make the substring bad.
                // The first r that makes it bad is x+2k.
                // So, for any l <= x, the maximum valid r is x+2k-1.
                // We need to update max_r_for_l[l] for all l from 0 to x.
                // Since we iterate x from 0 to n-1, and k from 1 upwards,
                // x+2k will be increasing.
                // So, for a fixed l, max_r_for_l[l] will be updated with smaller values.
                // The smallest x+2k that satisfies the condition for a given l
                // will be the one that determines max_r_for_l[l].
                // We only need to update max_r_for_l[x] because any l' < x would have
                // already been updated by a potentially smaller x'+2k' if such a triplet exists.
                // Or, if this is the first triplet affecting l', then it will be updated.
                // The crucial observation is that for a given l, we are interested in the
                // smallest value of x+2k such that x <= l and s[x]=s[x+k]=s[x+2k].
                // Let this smallest value be R_min. Then all pairs (l, r) with r >= R_min are bad.
                // The number of good pairs for a fixed l is R_min - l.
                // If no such R_min exists, then all pairs (l, r) for r from l to n-1 are good,
                // so there are n-l good pairs.
                // The current x+2k is a candidate for R_min for all l <= x.
                // So, for each l from 0 to x, we update max_r_for_l[l] = min(max_r_for_l[l], x + 2k - 1).
                // This can be done efficiently.
                // The value x+2k-1 is the largest r (0-indexed) such that s[l...r] is good,
                // given that this specific triplet (x, x+k, x+2k) is the first one encountered.
                // We need to take the minimum over all such triplets.
                // The loop for x iterates from 0 to n-1.
                // The loop for k iterates from 1 upwards.
                // So, x+2k is increasing.
                // For a fixed l, max_r_for_l[l] should be min(max_r_for_l[l], current_x + 2*current_k - 1).
                // This means we need to update max_r_for_l[i] for all i from 0 to x.
                // This is equivalent to:
                // max_r_for_l[x] = min(max_r_for_l[x], x + 2*k - 1);
                // And then propagate this minimum backwards:
                // for (int i = x - 1; i >= 0; --i) {
                //     max_r_for_l[i] = min(max_r_for_l[i], max_r_for_l[i+1]);
                // }
                // This propagation is done after the loops.
                // For now, just update max_r_for_l[x] with the earliest possible end of a bad segment.
                max_r_for_l[x] = std::min(max_r_for_l[x], x + 2 * k - 1);
                // Optimization: if k is large, x+2k might be far.
                // The smallest k is 1. So x+2k is at least x+2.
                // If k=1, x+2. If k=2, x+4. If k=3, x+6.
                // The problem statement implies k can be up to n.
                // But x+2k < n is the actual constraint.
                // The maximum k is (n-x-1)/2.
                // The maximum value of x+2k is n-1.
                // The minimum value of x+2k is x+2.
                // The maximum value of x+2k-1 is n-2.
                // The minimum value of x+2k-1 is x+1.
                // The maximum value of k is small for large x.
                // For small x, k can be large.
                // The maximum k is around N/2.
                // The total complexity of finding all triplets is O(N^2).
                // N=300,000, N^2 is too slow.
                // We need a faster way to find the minimum x+2k for each l.

                // The maximum k we need to check is small.
                // If k is large, say k >= 7, then x+2k is at least x+14.
                // If s[x] = s[x+k] = s[x+2k], then s[x] = s[x+k] and s[x+k] = s[x+2k].
                // If k is large, it's unlikely to find such a pattern.
                // Consider the maximum distance between two identical characters.
                // If s[x] = s[x+k] = s[x+2k], then the pattern is A_A_A.
                // If k is small, say k=1, then s[x]=s[x+1]=s[x+2].
                // If k=2, then s[x]=s[x+2]=s[x+4].
                // If k=3, then s[x]=s[x+3]=s[x+6].
                // The maximum k we need to check is very small.
                // If k is large, say k >= 7, then the pattern is A.......A.......A.
                // If we have a pattern like 010101, then k=2, x=0, s[0]=s[2]=s[4]=0.
                // This gives x+2k = 0+4 = 4. So max_r_for_l[0] = min(n-1, 3).
                // Also x=1, k=2, s[1]=s[3]=s[5]=1. This gives x+2k = 1+4 = 5.
                // So max_r_for_l[1] = min(n-1, 4).
                // The maximum k that can be relevant is small.
                // If k is large, say k=7, then x+2k = x+14.
                // If we have s[x]=s[x+k]=s[x+2k], then for any l <= x, the substring s[l...r] is bad if r >= x+2k.
                // The maximum r for s[l...r] to be good is x+2k-1.
                // The maximum k we need to check is 6.
                // Why 6? Consider any string of length 7.
                // s_0 s_1 s_2 s_3 s_4 s_5 s_6.
                // If there is no triplet with k=1,2,3,4,5,6, then it's impossible to have a triplet.
                // This is a known property for "square-free" strings or similar patterns.
                // If a string has no $s_x = s_{x+k} = s_{x+2k}$ for $k \in \{1, \dots, 6\}$,
                // then it has no such triplet for any $k$.
                // This is a result from combinatorics on words, related to avoiding "cubes".
                // A string $AAA$ is a cube. $s_x s_{x+k} s_{x+2k}$ is a cube if $s_x=s_{x+k}=s_{x+2k}$.
                // The maximum $k$ to check is indeed small. For binary strings, it's often 2 or 3.
                // For $s_x = s_{x+k} = s_{x+2k}$, the maximum $k$ to check is 6.
                // So, the inner loop for $k$ only runs a constant number of times (at most 6).
                // This makes the overall complexity O(N).
                if (k > 6) break; // Optimization: only check small k values
            }
        }
    }

    // After filling max_r_for_l[x] for each x, we need to propagate the minimums.
    // For any l, max_r_for_l[l] should be min(max_r_for_l[l], max_r_for_l[l+1]).
    // This ensures that if s[l+1...r'] is bad, then s[l...r'] is also bad.
    // So, max_r_for_l[l] must be less than or equal to max_r_for_l[l+1].
    for (int i = n - 2; i >= 0; --i) {
        max_r_for_l[i] = std::min(max_r_for_l[i], max_r_for_l[i + 1]);
    }

    // Now, for each l (0-indexed), max_r_for_l[l] stores the maximum r (0-indexed)
    // such that the substring s[l...r] does NOT contain any bad triplet.
    // The number of good pairs (l, r) for a fixed l is (max_r_for_l[l] - l + 1).
    // Sum this over all l to get total good pairs.
    for (int l = 0; l < n; ++l) {
        // If max_r_for_l[l] < l, it means even s[l...l] contains a bad triplet,
        // which is impossible as a triplet needs at least 3 characters.
        // This case should not happen with correct logic.
        // max_r_for_l[l] is at least l+1 if a triplet starts at l.
        // If no triplet starts at or before l, max_r_for_l[l] is n-1.
        // The number of good r's for a given l is max_r_for_l[l] - l + 1.
        // These are r values from l to max_r_for_l[l].
        bad_pairs += (max_r_for_l[l] - l + 1);
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

