    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> first_zero_block_start_idx;
    std::vector<int> first_one_block_start_idx;

    // Find indices of first 0 in blocks of 0s
    // and first 1 in blocks of 1s
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            if (first_zero_block_start_idx.empty() || a[i-1] == 1) {
                first_zero_block_start_idx.push_back(i);
            }
        } else { // a[i] == 1
            if (first_one_block_start_idx.empty() || a[i-1] == 0) {
                first_one_block_start_idx.push_back(i);
            }
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    // Process 0-blocks
    for (int start_idx : first_zero_block_start_idx) {
        int end_idx = start_idx;
        while (end_idx + 1 < n && a[end_idx + 1] == 0) {
            end_idx++;
        }

        // If block is surrounded by 1s, or is at an edge and surrounded by 1s on one side
        // e.g., 1 0 1, 1 0 0 1, 0 1, 1 0
        if ((start_idx > 0 && a[start_idx - 1] == 1) && (end_idx < n - 1 && a[end_idx + 1] == 1)) {
            int len = end_idx - start_idx + 1;
            int steps = (len - 1) / 2;
            max_steps = std::max(max_steps, steps + 1);

            // The 0s at the ends of the block will turn to 1s
            for (int i = 0; i < steps + 1; ++i) {
                if (start_idx + i < n) final_a[start_idx + i] = 1;
                if (end_idx - i >= 0) final_a[end_idx - i] = 1;
            }
        }
    }

    // Process 1-blocks
    for (int start_idx : first_one_block_start_idx) {
        int end_idx = start_idx;
        while (end_idx + 1 < n && a[end_idx + 1] == 1) {
            end_idx++;
        }

        // If block is surrounded by 0s, or is at an edge and surrounded by 0s on one side
        // e.g., 0 1 0, 0 1 1 0, 1 0, 0 1
        if ((start_idx > 0 && a[start_idx - 1] == 0) && (end_idx < n - 1 && a[end_idx + 1] == 0)) {
            int len = end_idx - start_idx + 1;
            int steps = (len - 1) / 2;
            max_steps = std::max(max_steps, steps + 1);

            // The 1s at the ends of the block will turn to 0s
            for (int i = 0; i < steps + 1; ++i) {
                if (start_idx + i < n) final_a[start_idx + i] = 0;
                if (end_idx - i >= 0) final_a[end_idx - i] = 0;
            }
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

