void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The reversed permutation p' = [p_n, p_{n-1}, ..., p_1]
    // will have the same set of adjacent sums as p.
    // For example, if p = [p1, p2, p3], sums are [p1+p2, p2+p3].
    // p_rev = [p3, p2, p1], sums are [p3+p2, p2+p1].
    // These sets of sums are identical, so their sorted versions (fingerprints) will be identical.
    // The only case where p_rev is not different from p is if p is a palindrome.
    // However, a permutation of length n (n >= 2) cannot be a palindrome.
    // A permutation contains distinct integers from 1 to n.
    // If p were a palindrome, p_i = p_{n-i+1}.
    // For n >= 2, p_1 must be equal to p_n. But p_1 and p_n must be distinct if n > 1.
    // This is only possible if n=1, but the problem states n >= 2.
    // Therefore, p_rev will always be different from p for n >= 2.

    for (int i = n - 1; i >= 0; --i) {
        std::cout << p[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;
}

