    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use as many 5s as possible
        presses += diff / 5;
        diff %= 5;

        // Handle remaining diff (0, 1, 2, 3, 4)
        if (diff == 0) {
            // No additional presses needed
        } else if (diff == 1 || diff == 2) {
            // For 1 or 2, one press of +1/-1 or +2/-2 is optimal
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            // For 3:
            //   Option 1: one +5/-5 and one +2/-2 (if we had a 5, we could use 5-2=3)
            //             This means we effectively replace a 5-press with a 2-press and a 5-press,
            //             which is 2 presses instead of 1.
            //             So, if we had `k` fives and `diff=3`, we could use `k-1` fives and `5+3=8`.
            //             8 can be 5+2+1 (3 presses) or 5+5-2 (3 presses).
            //             Or, we could use `k` fives and `3` (2 presses: 2+1).
            //             So, for 3, it's 2 presses (2+1).
            // For 4:
            //   Option 1: one +5/-5 and one +1/-1 (if we had a 5, we could use 5-1=4)
            //             Similar logic, if we had `k` fives and `diff=4`, we could use `k-1` fives and `5+4=9`.
            //             9 can be 5+2+2 (3 presses) or 5+5-1 (3 presses).
            //             Or, we could use `k` fives and `4` (2 presses: 2+2).
            //             So, for 4, it's 2 presses (2+2).
            // In both cases (3 or 4), 2 presses are optimal.
            presses += 2;
        }
        std::cout << presses << "\n";
    }
    return 0;
}

