#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d; // d can be up to 100, but total days spent can exceed int if n is large
    std::cin >> n >> d;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0]; // Start with the initial haybales in pile 1

    // Iterate through piles from 2 to n (index 1 to n-1)
    for (int i = 1; i < n; ++i) {
        // Calculate the cost to move one haybale from pile i+1 to pile 1
        // Pile i+1 is at index i in the 0-indexed array
        // Cost is (i+1) - 1 = i days
        long long cost_per_haybale = i; 

        if (d >= cost_per_haybale) {
            // Calculate how many haybales can be moved from this pile
            // Limited by available haybales in pile a[i] and remaining days d
            long long haybales_to_move = std::min((long long)a[i], d / cost_per_haybale);

            current_a1 += haybales_to_move;
            d -= haybales_to_move * cost_per_haybale;
        } else {
            // If we don't even have enough days for one haybale from this pile,
            // we can't move any more haybales from subsequent piles either
            // because they would have an even higher cost.
            break; 
        }
    }

    std::cout << current_a1 << std::endl;
}

