#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position.
        // The presence of +1 or -1 before index i doesn't matter for this specific position,
        // but it might matter for subsequent positions.
        // The has_pos_one and has_neg_one flags are updated based on original a[i] values.
        // This is correct because a_i values are only added to a_j (j > i),
        // so a_i itself is not changed when it's used as a source for addition.
        // The values of a_i that are available for addition to a_j (j > i) are the *original* a_i values.
        // No, this is incorrect. The problem states "Add a_i to a_j".
        // If a_i itself was modified by some a_p (p < i), then the value of a_i used for a_j would be its *current* value.
        // However, the problem statement implies that the *original* a_i values are used for operations.
        // "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // This phrasing is ambiguous. Let's re-read the example:
        // "[1, -1, 0] -> [1, -1, -1] (add a_2 to a_3)"
        // Here a_2 is -1. a_3 becomes 0 + (-1) = -1.
        // "[1, -1, -1] -> [1, -1, -2] (add a_2 to a_3 again)"
        // Here a_2 is still -1. a_3 becomes -1 + (-1) = -2.
        // "[1, -1, -2] -> [1, 1, -2] (add a_1 to a_2 twice)"
        // Here a_1 is 1. a_2 becomes -1 + 1 + 1 = 1.
        // This implies that a_i refers to the *original* value of a_i.
        // If a_i could be modified and then used, the problem would be much harder.
        // The constraint $a_i \in \{-1, 0, 1\}$ for the *initial* array `a` is key.
        // If $a_i$ could change, it could become any integer, and then the set $\{-1, 0, 1\}$ would only apply to the initial state.
        // The problem is usually phrased as "add $A_i$ to $A_j$" where $A$ is the current array.
        // But given the constraints and the example, it's more likely that $a_i$ refers to the *initial* values.
        // Let's assume $a_i$ refers to the initial values.
        // The logic for `has_pos_one` and `has_neg_one` should be based on elements *before* the current index `i`.
        // So, we need to track `has_pos_one_before_i` and `has_neg_one_before_i`.

        // Update flags for the next iteration (i+1)
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

