#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            int val;
            std::cin >> val;
            if (i != j) { // Only consider a_i,j where i != j
                if (val > max_val_in_row) {
                    max_val_in_row = val;
                }
            }
        }
        // If max_val_in_row is 0, it means all other elements in the row were 0.
        // This can only happen if n=1 (not possible by constraints) or if p_i=1
        // and all other p_j are also 1 (not possible for a permutation).
        // Or, if p_i=1 and all other p_j are > 1, then min(p_i, p_j) = 1.
        // So, if max_val_in_row is 0, it means p_i must be 1.
        // However, the problem states a_i,j = min(p_i, p_j).
        // If p_i is 1, then min(p_i, p_j) is 1 for any p_j >= 1.
        // So max_val_in_row would be 1, not 0.
        // The only way max_val_in_row is 0 is if n=1, which is not allowed.
        // Or if all p_j for j!=i are 0, which is not allowed.
        // The problem guarantees a solution exists.
        // The maximum value in row i (excluding a_i,i) is p_i, unless p_i is n.
        // If p_i is n, then for any j != i, p_j < n. So min(p_i, p_j) = p_j.
        // In this case, max_{j!=i} min(p_i, p_j) = max_{j!=i} p_j = n-1.
        // So, if max_val_in_row is n-1, p_i could be n.
        // Otherwise, p_i is max_val_in_row.
        // This logic is simpler: if max_val_in_row is less than n, then p_i must be max_val_in_row.
        // If max_val_in_row is n-1, then p_i could be n.
        // We can just assign p_i = max_val_in_row, and if no element is n,
        // then the one with max_val_in_row = n-1 must be n.
        p[i] = max_val_in_row;
    }

    bool n_found = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found among the p[i] values, it means one of the p[i]
        // that was assigned n-1 should actually be n.
        // This happens for the element p_k where p_k = n.
        // For this p_k, min(p_k, p_j) = p_j for all j != k.
        // So max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j = n-1.
        // We need to find such an element and change its value to n.
        // Since it's a permutation, there's exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) { // This is the element that should be n
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

