int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' encountered, or -1 for cell 0.
                             // The distance is calculated from this position.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current 'R' is at index i, which corresponds to cell i+1.
                // The distance from the previous 'R' (or cell 0) to this 'R' is (i+1) - (last_r_pos + 1).
                // Or simply, (current cell index) - (previous cell index).
                // Current cell is i+1. Previous cell was last_r_pos+1.
                // Distance is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                max_dist = std::max(max_dist, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, we need to consider the jump from the last 'R'
        // (or cell 0 if no 'R's) to the target cell n+1.
        // The last 'R' was at index last_r_pos, corresponding to cell last_r_pos + 1.
        // The target cell is n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_dist = std::max(max_dist, n - last_r_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

