#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top 'i' pieces combined is i * (TotalArea / n)
        // Let A_total be the area of the whole carrot (h/2).
        // Area of the top 'i' pieces = i * (A_total / n) = i * (h / (2n))
        // Let x_i be the height of the triangle from the apex that contains these 'i' pieces.
        // The area of this triangle is x_i^2 / (2h).
        // So, x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
