int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences using a "ping-pong" strategy
    // This will generate differences: k, k-1, k-2, ..., 1
    // Example: k=4. left=1, right=5.
    // p: 1, 5, 2, 4, 3
    // Diffs: |1-5|=4, |5-2|=3, |2-4|=2, |4-3|=1
    // This generates k distinct differences (from 1 to k).
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left++;
        } else { // Odd index, take from right
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // For the remaining n - (k+1) numbers, just append them in increasing order.
    // This ensures all subsequent differences are 1, which is already one of the k distinct differences.
    // Example: n=5, k=2.
    // First k+1 = 3 numbers: left=1, right=3.
    // i=0: print 1 (left=2)
    // i=1: print 3 (right=2)
    // i=2: print 2 (left=3)
    // Output so far: 1 3 2
    // Remaining numbers: n - (k+1) = 5 - 3 = 2 numbers.
    // Current left is 3. We need to print 4, 5.
    // So, print 4, 5.
    // Final output: 1 3 2 4 5
    for (int i = k + 1; i < n; ++i) {
        std::cout << left++;
        std::cout << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

