#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_count = 0;
    int close_count = 0;
    int balance = 0;

    for (char c : s) {
        if (c == '(') {
            if (open_count < k / 2) {
                result += '(';
                open_count++;
                balance++;
            }
        } else { // c == ')'
            if (close_count < k / 2 && balance > 0) {
                result += ')';
                close_count++;
                balance--;
            }
        }
        if (result.length() == k) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `i` such that a[i] < a[i-1]
    // This marks the end of the first non-decreasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is a non-decreasing suffix.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost index `j` such that a[j] > a[j+1]
    // This marks the end of the first non-increasing suffix (from right to left)
    int j = i; // Start search from `i`
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is a non-increasing suffix (from right to left).
    // a[j...n-1] is the candidate suffix for being "good".
    // The prefix to remove is a[0...j-1], so its length is j.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

