int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long k = n / m; // Number of multiples of m up to n

        if (k == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for one full cycle (10 multiples of m)
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = k / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Add the sum for the remaining multiples
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

