void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] = index of val in p (0-indexed)
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. min_idx and max_idx are already set to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.
        if (m == 1) {
            result += '1';
            continue;
        }

        // For m > 1, we need to include 'm' into our current segment.
        // The current segment covers numbers 1 to m-1, from min_idx to max_idx.
        // To include 'm', we need to extend the segment to include pos[m].
        // The new min_idx will be min(current min_idx, pos[m]).
        // The new max_idx will be max(current max_idx, pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // For the segment p[min_idx ... max_idx] to be a permutation of 1...m:
        // 1. Its length must be exactly m.
        //    Length = max_idx - min_idx + 1.
        // 2. It must contain all numbers from 1 to m.
        //    This is guaranteed by how we expand min_idx and max_idx.
        //    We start with 1, then add 2, then 3, etc.
        //    So, the segment p[min_idx ... max_idx] will always contain all numbers 1 to m.
        //    The only condition left is that its length must be exactly m.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

