int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For d >= 4, d^2 - 4d >= 0, so sqrt is real.
            // a = (d + sqrt(d^2 - 4d)) / 2
            // b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa. Since a and b are interchangeable, this is fine.

            double sqrt_discriminant = std::sqrt(d * d - 4.0 * d);
            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(...) will be positive. So a > 0.
            // For b, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square them:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since we already established d >= 4, b will always be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int mid_idx = n / 2;

    // Step 1: Make the median element equal to s
    operations += std::abs(a[mid_idx] - s);

    // Step 2: Ensure elements to the left of median are <= s
    // These are elements a[0]...a[mid_idx-1]
    // If a[i] > s, it must be decreased to s.
    for (int i = 0; i < mid_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Step 3: Ensure elements to the right of median are >= s
    // These are elements a[mid_idx+1]...a[n-1]
    // If a[i] < s, it must be increased to s.
    for (int i = mid_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

