// Function to check if a specific box can be the final box
// target_box_idx: 0 for Box 1, 1 for Box 2, 2 for Box 3, 3 for Box 4
bool can_be_final_box(long long A, long long B, long long C, long long D, int target_box_idx) {
    long long total_toys = A + B + C + D;

    if (total_toys == 0) {
        return false; // Should not happen based on constraints A+B+C+D > 0
    }
    if (total_toys == 1) {
        if (A == 1 && target_box_idx == 0) return true;
        if (B == 1 && target_box_idx == 1) return true;
        if (C == 1 && target_box_idx == 2) return true;
        if (D == 1 && target_box_idx == 3) return true;
        return false;
    }

    // Parity of negative numbers determines the final sign
    // Parity of numbers with magnitude < 1 determines if final magnitude can be < 1
    // Parity of numbers with magnitude >= 1 determines if final magnitude can be >= 1

    // Let's analyze the properties of the final product based on the counts.
    // A: (-inf, -1] (N, G)
    // B: (-1, 0)    (N, L)
    // C: (0, 1)     (P, L)
    // D: [1, inf)   (P, G)

    // Total negative numbers: A + B
    // Total positive numbers: C + D
    // Total numbers with magnitude < 1: B + C
    // Total numbers with magnitude >= 1: A + D

    // Final sign:
    // If (A + B) is odd, final sign is Negative.
    // If (A + B) is even, final sign is Positive.

    // Final magnitude:
    // If (B + C) > 0, it's possible to get a magnitude < 1.
    // If (A + D) > 0, it's possible to get a magnitude >= 1.
    // If (B + C) == 0, then all initial toys have magnitude >= 1. The product will have magnitude >= 1.
    // If (A + D) == 0, then all initial toys have magnitude < 1. The product will have magnitude < 1.
    // If (B + C) > 0 AND (A + D) > 0, it's possible to get either magnitude < 1 or magnitude >= 1.
    // This is the tricky part. If we have at least one L and at least one G, we can potentially achieve either.
    // Example: L * G = L (0.5 * 1.5 = 0.75) or L * G = G (0.5 * 3 = 1.5) or L * G = 1 (0.5 * 2 = 1)
    // So if B+C > 0 and A+D > 0, we can achieve both L and G.

    bool final_sign_negative_possible;
    bool final_sign_positive_possible;

    // If A+B is odd, final sign MUST be negative.
    // If A+B is even, final sign MUST be positive.
    // This is because multiplying two negatives makes a positive, and multiplying a negative and a positive makes a negative.
    // The parity of negative numbers determines the final sign.
    if ((A + B) % 2 == 1) {
        final_sign_negative_possible = true;
        final_sign_positive_possible = false;
    } else {
        final_sign_negative_possible = false;
        final_sign_positive_possible = true;
    }

    bool final_mag_less_than_1_possible;
    bool final_mag_greater_equal_1_possible;

    // Case 1: All initial toys have magnitude < 1 (A=0, D=0)
    if (A == 0 && D == 0) {
        // All toys are in B or C. All have magnitude < 1.
        // Product of numbers with magnitude < 1 will always have magnitude < 1.
        final_mag_less_than_1_possible = true;
        final_mag_greater_equal_1_possible = false;
    }
    // Case 2: All initial toys have magnitude >= 1 (B=0, C=0)
    else if (B == 0 && C == 0) {
        // All toys are in A or D. All have magnitude >= 1.
        // Product of numbers with magnitude >= 1 will always have magnitude >= 1.
        final_mag_less_than_1_possible = false;
        final_mag_greater_equal_1_possible = true;
    }
    // Case 3: There are toys with magnitude < 1 AND toys with magnitude >= 1
    else { // (A > 0 or D > 0) AND (B > 0 or C > 0)
        // It's possible to achieve both magnitude < 1 and magnitude >= 1.
        // Example: (0.5 * 3) = 1.5 (G)
        // Example: (0.5 * 1.5) = 0.75 (L)
        // The only exception is if we have exactly one toy with magnitude >= 1 and one toy with magnitude < 1,
        // and we can't make it >= 1. But the problem states "real number", so we can always pick values.
        // For example, if we have one toy with value 0.5 and one with value 1.5, the product is 0.75 (L).
        // If we have one toy with value 0.5 and one with value 3, the product is 1.5 (G).
        // So if we have at least one L and at least one G, we can achieve both.
        final_mag_less_than_1_possible = true;
        final_mag_greater_equal_1_possible = true;
    }

    // Now combine possibilities for each target box
    // Box 1: (N, G)
    if (target_box_idx == 0) {
        return final_sign_negative_possible && final_mag_greater_equal_1_possible;
    }
    // Box 2: (N, L)
    else if (target_box_idx == 1) {
        return final_sign_negative_possible && final_mag_less_than_1_possible;
    }
    // Box 3: (P, L)
    else if (target_box_idx == 2) {
        return final_sign_positive_possible && final_mag_less_than_1_possible;
    }
    // Box 4: (P, G)
    else if (target_box_idx == 3) {
        return final_sign_positive_possible && final_mag_greater_equal_1_possible;
    }
    return false; // Should not reach here
}

