    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        for (int i = 0; i < 4; ++i) {
            if (can_be_final_box(A, B, C, D, i)) {
                std::cout << "Ya";
            } else {
                std::cout << "Tidak";
            }
            if (i < 3) {
                std::cout << " ";
            }
        }
        std::cout << "\n";
    }

    return 0;
}

