            // n_val can be up to 2^30 - 1. n_val+1 can be 2^30.
            // (n_val+1)/2 can be 2^29.
            // n_val * (n_val+1)/2 can be (2^30-1) * 2^29 which is approx 2^59.
            // This fits in long long.
            // The maximum value for n_val is when k=30, n_val = 2^30 - 1 = 1073741823.
            // The cost_val for this is (2^30 - 1) * 2^29 which is approx 0.5 * 10^18.
            // The next n_val would be 2^31 - 1.
            // The next cost_val would be (2^31 - 1) * 2^30 which is approx 2.3 * 10^18.
            // This can exceed 10^18, but it will be checked against x.
            // If x is 10^18, the last cost_val we can afford is for k=30.
            // The cost for k=31 is 2.3 * 10^18, which is > 10^18.
            // So, the loop will terminate correctly.

            // Check if n_val * (n_val + 1) / 2 would overflow before calculating.
            // Max long long is approx 9 * 10^18.
            // If n_val is approx 2 * 10^9 (2^31), then n_val * (n_val+1)/2 is approx 2 * 10^18.
            // If n_val is approx 4 * 10^9 (2^32), then n_val * (n_val+1)/2 is approx 8 * 10^18.
            // If n_val is approx 8 * 10^9 (2^33), then n_val * (n_val+1)/2 is approx 32 * 10^18, which overflows.
            // The largest n_val we need to consider is 2^30 - 1.
            // The next n_val would be 2^31 - 1.
            // For n_val = 2^31 - 1, cost_val = (2^31 - 1) * 2^30. This is approx 2.3 * 10^18.
            // This fits in long long.
            // The next n_val would be 2^32 - 1.
            // For n_val = 2^32 - 1, cost_val = (2^32 - 1) * 2^31. This is approx 9.2 * 10^18.
            // This also fits in long long.
            // The next n_val would be 2^33 - 1.
            // For n_val = 2^33 - 1, cost_val = (2^33 - 1) * 2^32. This is approx 3.6 * 10^19. This overflows.
            // So, we need to check for overflow before calculating cost_val.
            // If n_val is already large enough that (n_val + 1) / 2 > LLONG_MAX / n_val, then it will overflow.
            // A simpler check: if n_val > 2 * 10^9 (approx 2^31), then the next cost_val might overflow.
            // The maximum n_val that results in a cost_val <= 10^18 is 2^30 - 1.
            // The next n_val is 2^31 - 1. Its cost is 2.3 * 10^18.
            // So, if n_val becomes 2^31 - 1, we calculate its cost. If x is less than this cost, we stop.
            // If x is greater than or equal to this cost, we use it.
            // The next n_val would be 2^32 - 1. Its cost is 9.2 * 10^18.
            // This is still within long long.
            // The next n_val would be 2^33 - 1. Its cost is 3.6 * 10^19. This overflows.
            // So, we need to stop if n_val is about to become 2^33 - 1 or larger.
            // n_val = (n_val + 1) * 2 - 1;
            // If n_val (after this update) is greater than or equal to 2^32, then the next cost_val calculation might overflow.
            // 2^32 is 4294967296.
            if (n_val >= 4294967296LL) { // If n_val is 2^32-1 or more, next cost_val will overflow.
                break;
            }
            cost_val = (n_val * (n_val + 1)) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    std::vector<long long> prefix_min_ops(n);
    prefix_min_ops[0] = 0; // a[0] must be >= 0, which is always true. We can make it 0.
    for (int i = 1; i < n; ++i) {
        // To satisfy a[i] > a[i-1], we need a[i] >= a[i-1] + 1.
        // The minimum value a[i] can take is i.
        // So, we need a[i] >= i.
        // The minimum operations to make a[i] satisfy this is max(0, i - a[i]).
        // However, we are interested in the minimum value a[i] can be, which is i.
        // So, prefix_min_ops[i] stores the minimum value a[i] can be if it's part of an increasing sequence starting from 0.
        // This means a[i] must be at least i.
        prefix_min_ops[i] = std::min(a[i], prefix_min_ops[i-1] + 1);
    }

    std::vector<long long> suffix_min_ops(n);
    suffix_min_ops[n - 1] = 0; // a[n-1] must be >= 0, which is always true. We can make it 0.
    for (int i = n - 2; i >= 0; --i) {
        // To satisfy a[i] > a[i+1], we need a[i] >= a[i+1] + 1.
        // The minimum value a[i] can take is (n-1-i).
        // So, we need a[i] >= (n-1-i).
        // suffix_min_ops[i] stores the minimum value a[i] can be if it's part of a decreasing sequence ending at 0.
        // This means a[i] must be at least (n-1-i).
        suffix_min_ops[i] = std::min(a[i], suffix_min_ops[i+1] + 1);
    }

    bool possible = false;
    for (int k = 0; k < n; ++k) {
        // For a peak at index k, we need:
        // 1. a[0] < a[1] < ... < a[k]
        // 2. a[k] > a[k+1] > ... > a[n-1]
        //
        // The minimum value a[k] can take to satisfy the increasing part is k.
        // The minimum value a[k] can take to satisfy the decreasing part is (n-1-k).
        //
        // So, we need a[k] to be at least max(k, n-1-k).
        //
        // Our prefix_min_ops[k] stores the minimum value a[k] can be if it's part of an increasing sequence starting from 0.
        // Our suffix_min_ops[k] stores the minimum value a[k] can be if it's part of a decreasing sequence ending at 0.
        //
        // If a[k] can be made to satisfy both conditions, then it must be at least k AND at least (n-1-k).
        // This means a[k] must be at least max(k, n-1-k).
        //
        // The actual values we can achieve for a[k] are limited by a[k] itself.
        // So, we need to check if a[k] is large enough to be a peak.
        // Specifically, we need a[k] >= k (for the increasing part) AND a[k] >= (n-1-k) (for the decreasing part).
        //
        // The values in prefix_min_ops[k] and suffix_min_ops[k] already incorporate the original a[k] constraint.
        // prefix_min_ops[k] is the maximum value `x` such that we can make `a[0] < ... < a[k-1] < x` and `x <= a[k]`.
        // suffix_min_ops[k] is the maximum value `y` such that we can make `y > a[k+1] > ... > a[n-1]` and `y <= a[k]`.
        //
        // For a[k] to be a valid peak, it must be possible to make it `k` (from left) and `n-1-k` (from right).
        // So, we need `prefix_min_ops[k] >= k` and `suffix_min_ops[k] >= (n-1-k)`.
        //
        // More simply, we need to find if there exists a k such that
        // a[k] can be made to be at least k (for the left side)
        // AND a[k] can be made to be at least (n-1-k) (for the right side).
        //
        // The values `prefix_min_ops[k]` and `suffix_min_ops[k]` represent the maximum possible value `a[k]` can take
        // while still satisfying the increasing/decreasing conditions up to that point, given the original `a[k]`.
        //
        // If `prefix_min_ops[k]` is the minimum value `a[k]` can be to satisfy `a[0] < ... < a[k]`,
        // then `prefix_min_ops[k]` must be at least `k`.
        // If `suffix_min_ops[k]` is the minimum value `a[k]` can be to satisfy `a[k] > ... > a[n-1]`,
        // then `suffix_min_ops[k]` must be at least `n-1-k`.
        //
        // So, we need to check if `std::min(prefix_min_ops[k], suffix_min_ops[k])` is large enough.
        // The value `std::min(prefix_min_ops[k], suffix_min_ops[k])` represents the maximum value `a[k]` can be
        // while satisfying both the increasing sequence from left and decreasing sequence from right,
        // given the original `a[k]` and the values of `a[i]` for `i != k`.
        //
        // For `a[k]` to be a peak, it must be strictly greater than its neighbors (if they exist).
        // The minimum value `a[k]` can take is `k` (from left) and `n-1-k` (from right).
        // So, we need `a[k]` to be at least `k` and `a[k]` to be at least `n-1-k`.
        //
        // The condition is `prefix_min_ops[k] >= k` and `suffix_min_ops[k] >= (n-1-k)`.
        // No, this is not quite right. `prefix_min_ops[k]` is `min(a[k], prefix_min_ops[k-1]+1)`.
        // This means `prefix_min_ops[k]` is the maximum value `a[k]` can be while satisfying `a[i] >= i` for all `i <= k`.
        // So, if `prefix_min_ops[k] >= k`, it means `a[k]` can be made to be at least `k`.
        // Similarly, if `suffix_min_ops[k] >= (n-1-k)`, it means `a[k]` can be made to be at least `n-1-k`.
        //
        // If both conditions are met, then `a[k]` can be made to be `max(k, n-1-k)`.
        // And since `prefix_min_ops[k]` and `suffix_min_ops[k]` are both `<= a[k]`,
        // if `prefix_min_ops[k] >= k` and `suffix_min_ops[k] >= (n-1-k)`,
        // then `a[k]` is large enough to be a peak.
        //
        // The actual check is: can we find a `k` such that `a[k]` can be made to be `k` (from left) AND `a[k]` can be made to be `n-1-k` (from right)?
        // This means `a[k]` must be at least `k` AND `a[k]` must be at least `n-1-k`.
        //
        // The values `prefix_min_ops[i]` and `suffix_min_ops[i]` are the maximum values `a[i]` can take
        // while satisfying the increasing/decreasing conditions relative to its neighbors,
        // and also being less than or equal to the original `a[i]`.
        //
        // So, if `prefix_min_ops[k] >= k` and `suffix_min_ops[k] >= (n-1-k)`,
        // it means that `a[k]` is large enough to be `k` (for the left side)
        // AND `a[k]` is large enough to be `n-1-k` (for the right side).
        //
        // This is the correct condition.
        if (prefix_min_ops[k] >= k && suffix_min_ops[k] >= (n - 1 - k)) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

