struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B (with original indices) in ascending order of B_i
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // Create the result array A'
    std::vector<long long> a_prime(m);

    // Assign elements of sorted A to A' based on sorted B's original indices
    // The largest A_i should be paired with the largest B_i (which has the smallest F value)
    // The smallest A_i should be paired with the smallest B_i (which has the largest F value)
    // This means we pair sorted A in ascending order with sorted B in descending order of F_value,
    // which corresponds to sorted B in ascending order of B_i.
    // So, a[0] goes to the original position of b_elements[0].value
    // a[1] goes to the original position of b_elements[1].value, and so on.
    for (int i = 0; i < m; ++i) {
        a_prime[b_elements[i].original_index] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case: if N=2, taking 1 is better than taking N/2 for Chanek
                    chanek_coins += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // If N/2 is odd and not 1, taking N/2 leaves an odd number for opponent
                                                              // This is generally good for Chanek as opponent can only take 1
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // If N/2 is even, or N/2 is 1 (which is odd, but special case handled by n==2)
                         // Taking 1 leaves an odd number for opponent, which is good.
                         // Taking N/2 leaves an even number for opponent, which might allow opponent to take N/2.
                         // So, taking 1 is generally safer/better here.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                n -= 1;
            } else { // N is even
                if (n == 2) { // Opponent takes 1
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 != 1) { // Opponent takes N/2
                    n /= 2;
                } else { // Opponent takes 1
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

