    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        // We need to append elements b1, b2, ... such that:
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))
        // Let S_new = current_sum + sum(b_i)
        // Let X_new = current_xor_sum ^ xor_sum(b_i)
        // We need S_new = 2 * X_new

        // Strategy: Append two elements.
        // Let the first appended element be X_current.
        // New XOR sum becomes current_xor_sum ^ current_xor_sum = 0.
        // New sum becomes current_sum + current_xor_sum.
        // Now we need to append a second element 'b' such that:
        // (current_sum + current_xor_sum + b) = 2 * (0 ^ b)
        // (current_sum + current_xor_sum + b) = 2 * b
        // current_sum + current_xor_sum = b
        // So, b = current_sum + current_xor_sum.

        // Let's verify this strategy:
        // Appended elements: b1 = current_xor_sum, b2 = current_sum + current_xor_sum
        // New total sum: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * current_sum + 2 * current_xor_sum

        // New total XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum

        // Check condition: S' = 2 * X'
        // (2 * current_sum + 2 * current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This is always true.

        // This strategy always works and appends exactly 2 elements.
        // The problem statement allows appending up to 3 elements.
        // The values can be large, up to 10^18, which fits in long long.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
    }
}

