int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means all 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will contribute 'count_a' steps
            // to move past this 'b'.
            // When an 'a' moves past a 'b' (ab -> bba), it effectively
            // doubles the number of 'a's that are "waiting" to move past
            // subsequent 'b's.
            // So, the current 'count_a' (representing 'a's to the left)
            // will be added to total_steps.
            // Then, these 'a's effectively "double" for future 'b's.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of
            // 'a's that are currently "active" and waiting to interact
            // with 'b's to their right.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

