// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string pattern_str = "";
    if (n == 0) {
        pattern_str = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    // Pad with leading zeros to a fixed length (e.g., 18 for 10^18-1)
    // The problem states pattern length up to 18, and numbers up to 10^18.
    // A number like 999...9 (18 times) has 18 digits.
    // A number like 10^18 has 19 digits, but the max value is < 10^18, so 18 digits max.
    // For consistency, we can pad to 18 or 19. Let's use 18 as it's the max pattern length.
    // The problem implies padding from the left for shorter numbers/patterns.
    // Since we build from right to left, we append '0's to the right of our string.
    while (pattern_str.length() < 18) {
        pattern_str += '0';
    }
    return pattern_str;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    // A map to store counts of each parity pattern string.
    // The key is the 18-digit parity pattern string, value is its count.
    std::map<std::string, int> pattern_counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = get_parity_pattern(a);
            pattern_counts[pattern]--;
        } else if (type == '?') {
            std::string s;
            std::cin >> s;
            // Pad the query pattern 's' with leading zeros to match the fixed length.
            // Since 's' is read as a string, '0's are prepended to the string.
            // The problem states "supplemented with 0-s from the left".
            // Our `get_parity_pattern` function effectively creates a right-aligned pattern
            // and then pads with '0's to the right of the string (which corresponds to left of the number).
            // So, for a query pattern 's', we need to pad it to the left with '0's to match the fixed length.
            // Example: s = "010", fixed length 18. Padded: "000000000000000010"
            // This means we need to prepend '0's to 's' until it reaches length 18.
            std::string padded_s = s;
            while (padded_s.length() < 18) {
                padded_s = '0' + padded_s;
            }
            std::cout << pattern_counts[padded_s] << "\n";
        }
    }

    return 0;
}

