#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left (i)
    // The remaining (n-i) items must be taken from the right.
    // Let 'i' be the number of items taken from the left.
    // Let 'j' be the number of items taken from the right.
    // So, i + j = n.
    // We iterate 'i' from 0 to n.
    // For each 'i', 'j' is simply n - i.
    for (int i = 0; i <= n; ++i) {
        int j = n - i; // Number of items taken from the right

        long long current_energy = 0;

        // Energy for items taken from the left
        if (i > 0) {
            current_energy += (prefix_sum[i] - prefix_sum[0]) * l;
        }

        // Energy for items taken from the right
        if (j > 0) {
            current_energy += (prefix_sum[n] - prefix_sum[n - j]) * r;
        }

        // Add penalty for consecutive picks from the same side
        if (i > j) { // More items from left than right
            // The last item must have been taken from the left.
            // The number of "extra" left items is (i - j).
            // These (i - j - 1) items (if > 0) must have been taken consecutively from the left
            // after the right items were exhausted or after the last right item was taken.
            // The number of times we pick left consecutively after the right items are exhausted is (i - j - 1).
            // This applies if i > j.
            current_energy += (i - j - 1) * Ql;
        } else if (j > i) { // More items from right than left
            // The last item must have been taken from the right.
            // The number of "extra" right items is (j - i).
            // These (j - i - 1) items (if > 0) must have been taken consecutively from the right
            // after the left items were exhausted or after the last left item was taken.
            // The number of times we pick right consecutively after the left items are exhausted is (j - i - 1).
            // This applies if j > i.
            current_energy += (j - i - 1) * Qr;
        }
        // If i == j, no extra penalty is added because the last item could be either left or right,
        // and there are no "extra" items from one side that must have been taken consecutively.
        // The sequence could be LRLR... or RLRL...
        // In both cases, the number of consecutive picks from the same side at the end is 0.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

