int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int j = 0; // Pointer for the elements we are trying to place (the 'B' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for the original sorted array elements ('A' array elements)
        // We are trying to find an element a[j] from the available pool
        // such that a[j] > a[i].
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1], a[j+2], ...
        // are also greater than or equal to a[j], and thus potentially greater than a[i].
        // We want to use the smallest possible element from the pool that satisfies the condition
        // to leave larger elements for later, potentially larger a[i] values.
        // So, we advance j until a[j] is strictly greater than a[i].
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        // If we found such an element a[j] and it's within bounds,
        // we can form a pair (a[i], a[j]) where a[j] > a[i].
        // We increment count and move to the next element in the original sorted array (i+1)
        // and also mark a[j] as used by moving to the next available element (j+1).
        if (j < n) {
            count++;
            j++; // Move to the next element in the 'B' array pool
        } else {
            // If j reaches n, it means we have exhausted all available elements
            // that could be placed to be strictly greater than a[i] (or any subsequent a[k]).
            // So, we can break early.
            break;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

