// Function to check if a sub-array is a permutation of its length
// `arr` is the full array, `start_idx` is the starting index of the sub-array,
// `len` is the length of the sub-array.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // An empty sequence is not a permutation of any length > 0
        return false;
    }
    std::vector<bool> seen(len + 1, false); // To track seen numbers from 1 to len
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }

    // After iterating, check if all numbers from 1 to len were seen
    // and if the maximum value is indeed len.
    // The `seen` array check implicitly covers max_val == len if all numbers 1 to len are present.
    // However, explicitly checking max_val == len is a quick check.
    if (max_val != len) {
        return false;
    }

    // All numbers from 1 to len must be present.
    // This is already covered by `seen[val]` and `val > len` checks if max_val == len.
    // For example, if len=3 and we have {1,2,4}, max_val=4 != len.
    // If len=3 and we have {1,1,3}, seen[1] would catch duplicate.
    // If len=3 and we have {1,2,2}, seen[2] would catch duplicate.
    // If len=3 and we have {1,2,3}, max_val=3 == len, and all seen.
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute max prefix and max suffix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i-1], a[i]);
    }

    std::vector<int> max_suffix(n);
    max_suffix[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i+1], a[i]);
    }

    // Precompute distinct counts for prefixes and suffixes
    std::vector<int> distinct_prefix_count(n + 1, 0); // distinct_prefix_count[k] stores count of distinct elements in a[0...k-1]
    std::vector<bool> seen_prefix(n + 1, false);
    int current_distinct_prefix = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= n && !seen_prefix[a[i]]) { // a[i] can be up to n-1, so check a[i] <= n is safe
            seen_prefix[a[i]] = true;
            current_distinct_prefix++;
        }
        distinct_prefix_count[i+1] = current_distinct_prefix;
    }

    std::vector<int> distinct_suffix_count(n + 1, 0); // distinct_suffix_count[k] stores count of distinct elements in a[n-k...n-1]
    std::vector<bool> seen_suffix(n + 1, false);
    int current_distinct_suffix = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] <= n && !seen_suffix[a[i]]) {
            seen_suffix[a[i]] = true;
            current_distinct_suffix++;
        }
        distinct_suffix_count[n-i] = current_distinct_suffix;
    }

    for (int l1 = 1; l1 < n; ++l1) { // l1 is length of p1, ranges from 1 to n-1
        int l2 = n - l1; // l2 is length of p2

        // Optimization checks
        // 1. Max element in p1 must be l1
        if (max_prefix[l1-1] != l1) {
            continue;
        }
        // 2. Max element in p2 must be l2
        if (max_suffix[l1] != l2) {
            continue;
        }
        // 3. Number of distinct elements in p1 must be l1
        if (distinct_prefix_count[l1] != l1) {
            continue;
        }
        // 4. Number of distinct elements in p2 must be l2
        if (distinct_suffix_count[l2] != l2) {
            continue;
        }

        // If all quick checks pass, perform full permutation check
        if (is_permutation(a, 0, l1) && is_permutation(a, l1, l2)) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

