#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string current_result(n, ' ');
        char last1 = '0'; // Last digit in sequence 1
        char last2 = '0'; // Last digit in sequence 2
        bool possible_with_pivot = true;

        for (int i = 0; i < n; ++i) {
            char current_d = s[i];
            if (current_d < pivot_digit + '0') {
                // Must be color 1
                if (current_d < last1) {
                    possible_with_pivot = false;
                    break;
                }
                current_result[i] = '1';
                last1 = current_d;
            } else if (current_d > pivot_digit + '0') {
                // Must be color 2
                if (current_d < last2) {
                    possible_with_pivot = false;
                    break;
                }
                current_result[i] = '2';
                last2 = current_d;
            } else { // current_d == pivot_digit + '0'
                // Can be either color 1 or color 2
                // Try to put it in color 2 if possible, to keep color 1 digits smaller
                if (current_d >= last2) {
                    current_result[i] = '2';
                    last2 = current_d;
                } else if (current_d >= last1) {
                    current_result[i] = '1';
                    last1 = current_d;
                } else {
                    possible_with_pivot = false;
                    break;
                }
            }
        }

        if (possible_with_pivot) {
            // Final check: last digit of S1 <= first digit of S2
            // This is implicitly handled by the `last1` and `last2` logic
            // and the fact that all digits assigned to '1' are <= pivot_digit
            // and all digits assigned to '2' are >= pivot_digit.
            // If last1 > last2, it means we had a digit assigned to '1' that was
            // greater than a digit assigned to '2', which is impossible if
            // all '1's are <= pivot and all '2's are >= pivot.
            // The only edge case is if last1 is from a digit equal to pivot_digit
            // and last2 is from a digit equal to pivot_digit, and last1 > last2.
            // But this can't happen because last1 and last2 are always non-decreasing.
            // The critical condition is that the maximum digit in S1 must be <= minimum digit in S2.
            // Our construction ensures that max(S1) <= pivot_digit and min(S2) >= pivot_digit.
            // So max(S1) <= min(S2) is always true.

            // The only remaining check is if the sequence formed by S1 then S2 is non-decreasing.
            // This is guaranteed by:
            // 1. S1 is non-decreasing (checked by current_d >= last1)
            // 2. S2 is non-decreasing (checked by current_d >= last2)
            // 3. max(S1) <= min(S2) (guaranteed by pivot_digit logic)

            result = current_result;
            found_solution = true;
            break;
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

