    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, 0);
    std::vector<long long> current_a(n, 0);

    // Step 1: Determine upper bounds for initial_a[j]
    // For each type 2 query (l, r, m_i), we know that for any j in [l, r],
    // a_j(0) + delta_j(k) <= m_i.
    // This implies a_j(0) <= m_i - delta_j(k).
    // We want to find the tightest upper bound for each a_j(0).
    // Initialize initial_a[j] to a very large value (effectively infinity)
    // and then take the minimum of all derived upper bounds.
    for (int j = 0; j < n; ++j) {
        initial_a[j] = std::numeric_limits<long long>::max();
    }

    std::vector<long long> current_deltas(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_deltas[j]);
            }
        }
    }

    // Step 2: Verify the solution
    // Use the derived initial_a and re-simulate all operations.
    // For type 2 queries, check if the maximum is exactly m_i.
    // If it's less than m_i, then no solution exists.
    // If it's greater than m_i, then initial_a[j] was too large for some j,
    // which contradicts how initial_a was constructed (it's an upper bound).
    // So we only need to check if max_val == m_i.

    // Reset current_deltas for re-simulation
    std::fill(current_deltas.begin(), current_deltas.end(), 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_deltas[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_deltas[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int j = 0; j < n; ++j) {
        // If initial_a[j] was never constrained by a type 2 query, it remains max_long_long.
        // In this case, any value within [-10^9, 10^9] is valid. We can pick 0.
        // The problem statement says "all numbers in his array didn't exceed 10^9 in their absolute value".
        // So we should ensure the output values are within this range.
        // Since m_i is up to 5*10^7 and d_i up to 10^4, current_deltas can be up to 5000 * 10^4 = 5*10^7.
        // So m_i - current_deltas[j] can be around 5*10^7 - (-5*10^7) = 10^8.
        // This is well within 10^9. So initial_a[j] will be within bounds if constrained.
        // If not constrained, it's max_long_long, so we should output 0.
        if (initial_a[j] == std::numeric_limits<long long>::max()) {
            std::cout << 0 << (j == n - 1 ? "" : " ");
        } else {
            std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
        }
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substring_count = 0;

    // Precompute positions of '1's
    std::vector<int> one_indices;
    for (int i = 0; i < n; ++i) {
        if (s[i] == '1') {
            one_indices.push_back(i);
        }
    }

    // Iterate through each '1' as a potential starting point for a good substring
    for (int i = 0; i < one_indices.size(); ++i) {
        int l = one_indices[i]; // Current '1' is at index l

        long long current_val = 0;
        // Iterate through possible end points r for substrings starting at l
        // The maximum possible length for a substring starting with '1' is limited.
        // If len = r - l + 1, then val <= 2^len - 1.
        // We are looking for val = len.
        // For len >= 20, 2^len - 1 is much larger than len.
        // Specifically, 2^19 is about 5 * 10^5, which is greater than N.
        // So, we only need to check lengths up to about 20 (or slightly more to be safe, e.g., 22-23).
        // Max length of s is 2e5. Max value of len is 2e5.
        // Max value of binary string of length k is 2^k - 1.
        // If k = 18, 2^18 = 262144. So, if len > 18, then val can be > N.
        // If len = 18, val can be 18.
        // If len = 19, val can be 19.
        // If len = 20, val can be 20.
        // The maximum length we need to consider for `current_val` to be equal to `len`
        // is when `current_val` exceeds `n`.
        // Since `current_val` grows exponentially and `len` linearly, this happens quickly.
        // For `len` up to `n`, `current_val` can be at most `n`.
        // If `current_val` exceeds `n`, then `current_val` cannot be equal to `len` (which is at most `n`).
        // So, we can stop when `current_val` exceeds `n`.
        // Also, `len` itself cannot exceed `n`.
        // The maximum length of a substring we need to check is roughly `log2(N) + C`.
        // For N = 2e5, log2(2e5) is about 17.6. So, checking up to length 20-22 is sufficient.
        // Let's use a safe upper bound for length, e.g., 22.
        // This means r - l + 1 <= 22. So r <= l + 21.

        for (int r = l; r < std::min(n, l + 22); ++r) { // Iterate up to l + max_relevant_length - 1
            current_val = (current_val << 1) | (s[r] - '0');
            int len = r - l + 1;

            if (current_val > n) { // Optimization: if value exceeds max possible length, break
                break;
            }
            if (current_val == len) {
                good_substring_count++;
            }
        }
    }

    // Handle substrings starting with '0's
    // These substrings must have a '1' somewhere to have a non-zero value.
    // If s_l...s_r is '0...01...', then f(s_l...s_r) is the value of '1...' part.
    // Let s_l...s_r be '0...0' (k zeroes) '1' (at index j) '...'.
    // The value is f(s_j...s_r). The length is r - l + 1.
    // We need r - l + 1 = f(s_j...s_r).
    // Let k be the number of leading zeros: k = j - l.
    // Then r - l + 1 = k + (r - j + 1).
    // We need k + (r - j + 1) = f(s_j...s_r).
    // This means k = f(s_j...s_r) - (r - j + 1).
    // Let val_suffix = f(s_j...s_r) and len_suffix = r - j + 1.
    // We need k = val_suffix - len_suffix.
    // Also, k must be non-negative, so val_suffix >= len_suffix.
    // And k must be less than or equal to j - 0 (the number of zeros before s_j).
    // So, 0 <= k <= j.

    for (int i = 0; i < one_indices.size(); ++i) {
        int j = one_indices[i]; // Current '1' is at index j, this is the first '1' in the substring
        long long current_val_suffix = 0;

        // Iterate through possible end points r for substrings starting with '1' at j
        // Again, limit the length of the suffix to avoid large values and unnecessary checks.
        for (int r = j; r < std::min(n, j + 22); ++r) { // Max suffix length around 22
            current_val_suffix = (current_val_suffix << 1) | (s[r] - '0');
            int len_suffix = r - j + 1;

            if (current_val_suffix > n + 22) { // Optimization: if value exceeds max possible length + max leading zeros, break
                break;
            }

            // Calculate required number of leading zeros (k)
            long long k = current_val_suffix - len_suffix;

            if (k >= 0 && k <= j) { // Check if k is valid
                // The substring starts at l = j - k.
                // The substring is s_l...s_r.
                // Its length is r - l + 1 = r - (j - k) + 1 = (r - j + 1) + k = len_suffix + k.
                // Its value is f(s_j...s_r) = current_val_suffix.
                // We need len_suffix + k == current_val_suffix.
                // This is true by definition of k.
                // We also need s_l...s_{j-1} to be all '0's.
                // This is implicitly handled by checking k <= j.
                // The number of leading zeros before index j is j - (index of previous '1' + 1).
                // If there is no previous '1', then it's j.
                // The number of available leading zeros is j - (index of previous '1' if it exists, else -1) - 1.
                // Let prev_one_idx be the index of the '1' immediately before j.
                // If i == 0, prev_one_idx = -1.
                // Else, prev_one_idx = one_indices[i-1].
                // The number of zeros available before j is j - (prev_one_idx + 1).
                // So, we need k <= j - (prev_one_idx + 1).
                int prev_one_idx = (i == 0) ? -1 : one_indices[i-1];
                if (k <= j - (prev_one_idx + 1)) {
                    good_substring_count++;
                }
            }
        }
    }

    std::cout << good_substring_count << std::endl;
}

