#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    int parity_a = calculate_parity(a);
    int parity_b = calculate_parity(b);

    // The maximum possible number of '1's in string 'a' after appending parities
    // is its current count plus the number of parities appended.
    // If the initial 'a' has 'k' ones, and we append 'm' parities,
    // the maximum number of ones in the resulting string of length |a|+m
    // is k+m (if all appended parities are '1').
    // The minimum number of ones is k (if all appended parities are '0').
    //
    // The parity of a string 's' is 1 if count('1', s) is odd, 0 otherwise.
    //
    // Let's consider the number of '1's in string 'a'.
    // If we append a '0', the number of '1's doesn't change.
    // If we append a '1', the number of '1's increases by 1.
    //
    // The maximum number of '1's in any string derived from 'a' by appending
    // parities, up to a length of |a| + (|b| - |a|) (if |b| > |a|) or just |a|
    // (if |b| <= |a|), is `parity_a_ones + (current_length - initial_length)`.
    //
    // A simpler approach:
    // The number of '1's in 'a' can only increase or stay the same.
    // If `parity_a` is 0, it means `a` has an even number of '1's.
    // If we append '0', `parity_a` remains 0.
    // If we append '1', `parity_a` becomes 1.
    //
    // If `parity_a` is 1, it means `a` has an odd number of '1's.
    // If we append '0', `parity_a` remains 1.
    // If we append '1', `parity_a` becomes 0.
    //
    // This means that if we append a '1', the parity flips.
    // If we append a '0', the parity stays the same.
    //
    // The key observation is that we can always make the parity of 'a'
    // become 1 if it's 0, by appending '1' (which means current parity is 1).
    // And we can always make the parity of 'a' become 0 if it's 1,
    // by appending '1' (which means current parity is 0).
    //
    // More precisely, if `a` has `k` ones, its parity is `k % 2`.
    // If we append `p = k % 2`, the new string `a'` has `k + p` ones.
    // The new parity is `(k + p) % 2`.
    // If `k % 2 == 0` (p=0), new parity is `(k+0)%2 = 0`.
    // If `k % 2 == 1` (p=1), new parity is `(k+1)%2 = 0`.
    // So, appending `parity(a)` always results in a string with even parity (0).
    //
    // This is incorrect. Example: 101 (parity 0). Append 0 -> 1010 (parity 0).
    // Example: 10 (parity 1). Append 1 -> 101 (parity 0).
    //
    // Let's re-evaluate the parity rule:
    // `parity(s)` is 1 if `count('1', s)` is odd, 0 otherwise.
    //
    // Initial string `a`. `ones_a = count('1', a)`. `p_a = ones_a % 2`.
    //
    // Operation: `a` -> `a + p_a`.
    // New `ones_a'` = `ones_a + p_a`.
    // New `p_a'` = `(ones_a + p_a) % 2`.
    //
    // If `p_a == 0` (even number of ones):
    //   `ones_a'` = `ones_a + 0` = `ones_a`.
    //   `p_a'` = `ones_a % 2` = `0`.
    //   Parity remains 0.
    //
    // If `p_a == 1` (odd number of ones):
    //   `ones_a'` = `ones_a + 1`.
    //   `p_a'` = `(ones_a + 1) % 2`. Since `ones_a` is odd, `ones_a + 1` is even.
    //   `p_a'` = `0`.
    //   Parity becomes 0.
    //
    // Conclusion: After one "append parity" operation, the string `a` will always have an even number of '1's (its parity will be 0).
    // And subsequent "append parity" operations will always append '0' and keep the parity 0.
    //
    // This means that if we apply the "append parity" operation at least once,
    // the string `a` will have parity 0.
    //
    // So, if `b` has parity 1, it can only be formed if the initial `a`
    // already has parity 1 and `b` is a suffix of `a` without any append operations.
    //
    // Let's consider the number of ones in `a` and `b`.
    int ones_in_a = 0;
    for (char c : a) {
        if (c == '1') {
            ones_in_a++;
        }
    }

    int ones_in_b = 0;
    for (char c : b) {
        if (c == '1') {
            ones_in_b++;
        }
    }

    // Case 1: No append operations are needed, `b` is a suffix of `a`.
    // This means `a` can be transformed into `b` by only removing characters.
    // This is true if `a.length() >= b.length()` and `a.substr(a.length() - b.length()) == b`.
    // This is not what the problem asks. `b` must be a suffix of *some* `a'` generated from `a`.
    //
    // The problem states: "You try to turn a into b".
    // This means `b` must be equal to `a` after some operations.
    //
    // Let's re-read: "turn a into b". This implies `a` eventually becomes `b`.
    //
    // The operations are:
    // 1. `a` -> `a + parity(a)`
    // 2. `a` -> `a.substr(1)`
    //
    // We need to find if there exists a sequence of operations that transforms `a` into `b`.
    //
    // Let `current_a` be the string we are working with.
    // We can always extend `current_a` by appending its parity.
    // We can always shorten `current_a` by removing its first character (if not empty).
    //
    // The length of `b` is `|b|`.
    // The length of `a` is `|a|`.
    //
    // We need to reach a state where `current_a == b`.
    //
    // Consider the number of '1's.
    // Let `ones_a` be the count of '1's in the initial string `a`.
    // Let `ones_b` be the count of '1's in string `b`.
    //
    // If `ones_a` is even, `parity(a)` is 0.
    // If `ones_a` is odd, `parity(a)` is 1.
    //
    // If we append `parity(a)`:
    //   If `ones_a` is even, `parity(a)` is 0. `a` becomes `a + '0'`. `ones_a` remains even.
    //   If `ones_a` is odd, `parity(a)` is 1. `a` becomes `a + '1'`. `ones_a` becomes even.
    //
    // So, after at most one append operation, the number of '1's in `a` will be even.
    // And any subsequent append operations will append '0's, keeping the number of '1's even.
    //
    // This means that if `b` has an odd number of '1's (`ones_b % 2 == 1`),
    // then `a` must have had an odd number of '1's initially (`ones_a % 2 == 1`),
    // AND `b` must be achievable from `a` *without* any append operations.
    //
    // If `ones_b % 2 == 1`:
    //   Then `ones_a % 2` must be 1.
    //   And `b` must be a suffix of `a`.
    //   This means `a` can be reduced to `b` by only removing characters from the front.
    //   This implies `a.length() >= b.length()` and `a.substr(a.length() - b.length()) == b`.
    //   And `ones_a` must be equal to `ones_b` (since no '1's are added or removed from the end).
    //   This is equivalent to `ones_a % 2 == ones_b % 2`.
    //
    // If `ones_b % 2 == 0`:
    //   Then `a` can be transformed into `b` if:
    //   1. `ones_a % 2 == 0`: We can potentially just remove characters from `a` to get `b`,
    //      or append '0's and then remove characters.
    //   2. `ones_a % 2 == 1`: We must append '1' once to make `ones_a` even, then append '0's,
    //      and then remove characters.
    //
    // In summary:
    // Let `max_ones_a` be the maximum number of '1's we can have in `a` after some append operations.
    // If `ones_a % 2 == 0`, then `max_ones_a = ones_a`. (We only append '0's).
    // If `ones_a % 2 == 1`, then `max_ones_a = ones_a + 1`. (We append '1' once, then '0's).
    //
    // So, the effective number of '1's we can achieve in `a` (let's call it `effective_ones_a`)
    // is `ones_a` if `ones_a` is even, and `ones_a + 1` if `ones_a` is odd.
    // This can be written as `ones_a + (ones_a % 2)`.
    //
    // For `a` to be transformable into `b`:
    // 1. The number of '1's in `b` (`ones_in_b`) must be less than or equal to the
    //    maximum possible number of '1's we can have in `a` (`effective_ones_a`).
    //    `ones_in_b <= effective_ones_a`.
    // 2. The length of `b` (`|b|`) must be less than or equal to the length of `a`
    //    after potentially appending enough characters to match `effective_ones_a`.
    //    The length of `a` can be extended arbitrarily.
    //    The length of `a` can be reduced to `1`.
    //
    // The condition is simply: `ones_in_b <= ones_in_a + (ones_in_a % 2)`.
    //
    // Let's test this logic with examples:
    // Example 1: a = 01011, b = 0110
    // ones_in_a = 3 (odd)
    // ones_in_b = 2 (even)
    // effective_ones_a = 3 + (3 % 2) = 3 + 1 = 4.
    // Is `ones_in_b <= effective_ones_a`? `2 <= 4`? YES.
    // Output: YES. Matches.

    // Example 2: a = 0011, b = 1110
    // ones_in_a = 2 (even)
    // ones_in_b = 3 (odd)
    // effective_ones_a = 2 + (2 % 2) = 2 + 0 = 2.
    // Is `ones_in_b <= effective_ones_a`? `3 <= 2`? NO.
    // Output: NO. Matches.

    // Let's consider edge cases:
    // a = "0", b = "0"
    // ones_in_a = 0, ones_in_b = 0
    // effective_ones_a = 0 + (0 % 2) = 0.
    // 0 <= 0? YES. Output: YES. (0 -> 0)

    // a = "1", b = "1"
    // ones_in_a = 1, ones_in_b = 1
    // effective_ones_a = 1 + (1 % 2) = 2.
    // 1 <= 2? YES. Output: YES. (1 -> 1)

    // a = "1", b = "0"
    // ones_in_a = 1, ones_in_b = 0
    // effective_ones_a = 1 + (1 % 2) = 2.
    // 0 <= 2? YES. Output: YES. (1 -> 11 -> 1 -> 0)

    // a = "0", b = "1"
    // ones_in_a = 0, ones_in_b = 1
    // effective_ones_a = 0 + (0 % 2) = 0.
    // 1 <= 0? NO. Output: NO. (0 -> 00 -> 0. Cannot get a '1')

    // The logic seems sound. The length constraint is implicitly handled because we can always extend `a` to be long enough,
    // and then remove characters from the front. The only constraint is the number of '1's.
    // We can always make `a` long enough to contain `b` as a suffix, and then remove characters from the front.
    // The only thing that matters is if the number of '1's in `b` can be achieved.

    if (ones_in_b <= (ones_in_a + (ones_in_a % 2))) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v; // cry volume in office
    long long d; // cry volume in hall
    long long p; // confidence
    int original_index; // 1-based original index
    bool in_line; // true if still in line, false if left

    Child(long long v_val, long long d_val, long long p_val, int idx)
        : v(v_val), d(d_val), p(p_val), original_index(idx), in_line(true) {}
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children;
    children.reserve(n);
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children.emplace_back(v_val, d_val, p_val, i + 1);
    }

    std::vector<int> cured_children_indices;
    long long total_hall_cry_volume = 0; // Accumulates d_j from children leaving due to p < 0

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child already left
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child goes to doctor

        long long current_office_cry_volume = children[i].v;
        total_hall_cry_volume = 0; // Reset for this new office cry event

        // Apply office cry and accumulated hall cries to children after current one
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply office cry effect
            if (current_office_cry_volume > 0) {
                children[j].p -= current_office_cry_volume;
                current_office_cry_volume--;
            }

            // Apply accumulated hall cry effect
            children[j].p -= total_hall_cry_volume;

            // Check if child j leaves due to low confidence
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_hall_cry_volume += children[j].d; // Add to accumulated hall cry
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    int value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., all in subsequence 1)
    // min_f = a_1 + a_2
    // max_f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (long long)elements[n - 1].value + elements[n - 2].value - ((long long)elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: At least one element in each subsequence.
    // This implies there must be at least one pair (a_i, a_j) with a_i and a_j in different subsequences.
    // So, a_1 + a_2 + h is a possible value.
    // The minimum possible f value is min(a_1 + a_2, a_1 + a_2 + h).
    // The maximum possible f value is max(a_{n-1} + a_n, a_{n-1} + a_n + h).
    //
    // To minimize max_f - min_f, we want to make min_f as large as possible
    // and max_f as small as possible.
    //
    // Consider the partition where elements[0] is in subsequence 1, and all others are in subsequence 2.
    // Or elements[0] is in subsequence 2, and all others are in subsequence 1.
    // This ensures a_0 is separated from at least one other element.
    //
    // The smallest sum of two elements is elements[0].value + elements[1].value.
    // The largest sum of two elements is elements[n-1].value + elements[n-2].value.
    //
    // If elements[0] is in subseq 1, and elements[1]...elements[n-1] are in subseq 2:
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    //
    // The crucial observation is that if we separate elements[0] from elements[1],
    // then a_0 + a_1 + h is a possible value.
    // If we separate elements[n-1] from elements[n-2],
    // then a_{n-1} + a_{n-2} + h is a possible value.
    //
    // Let's consider a partition where elements[0] is in subseq 1, and elements[1]...elements[n-1] are in subseq 2.
    //
    // Values of f:
    // 1. elements[0].value + elements[i].value + h (for i=1 to n-1)
    // 2. elements[i].value + elements[j].value (for i,j from 1 to n-1, i!=j)
    //
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    //
    // This is the partition where elements[0] is in one group, and all other elements are in the other group.
    //
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-1].value + elements[0].value + h`.
    //
    // If we put elements[0] in group 1, and all other elements in group 2:
    // min_f = min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    // max_f = max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    //
    // The minimum value of f will be `elements[0].value + elements[1].value + h` (if elements[0] and elements[1] are separated)
    // OR `elements[1].value + elements[2].value` (if elements[1] and elements[2] are in the same group).
    //
    // The maximum value of f will be `elements[n-1].value + elements[0].value + h` (if elements[n-1] and elements[0] are separated)
    // OR `elements[n-1].value + elements[n-2].value` (if elements[n-1] and elements[n-2] are in the same group).
    //
    // Consider the partition where elements[0] is in group 1, and elements[1]...elements[n-1] are in group 2.
    // The values are:
    //   - elements[0].value + elements[i].value + h (for i=1 to n-1)
    //   - elements[i].value + elements[j].value (for i,j from 1 to n-1, i!=j)
    //
    // The minimum value in this partition is `min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)`.
    // The maximum value in this partition is `max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)`.
    //
    // Let's simplify. The overall minimum possible sum is `elements[0].value + elements[1].value`.
    // The overall maximum possible sum is `elements[n-1].value + elements[n-2].value`.
    //
    // If we separate elements[0] from elements[n-1], then `elements[0].value + elements[n-1].value + h` is a value.
    //
    // The key insight is that if we have at least one element in each subsequence,
    // then `min_f` will be at least `elements[0].value + elements[1].value`.
    // And `max_f` will be at least `elements[n-1].value + elements[0].value + h` (if elements[0] and elements[n-1] are separated).
    //
    // Consider the partition where elements[0] is in group 1, and all other elements (elements[1] to elements[n-1]) are in group 2.
    //
    // The minimum value of f in this partition:
    //   - `elements[0].value + elements[1].value + h` (from elements[0] and elements[1] being in different groups)
    //   - `elements[1].value + elements[2].value` (from elements[1] and elements[2] being in the same group)
    // So, `min_f_val = std::min((long long)elements[0].value + elements[1].value + h, (long long)elements[1].value + elements[2].value);`
    //
    // The maximum value of f in this partition:
    //   - `elements[0].value + elements[n-1].value + h` (from elements[0] and elements[n-1] being in different groups)
    //   - `elements[n-1].value + elements[n-2].value` (from elements[n-1] and elements[n-2] being in the same group)
    // So, `max_f_val = std::max((long long)elements[0].value + elements[n-1].value + h, (long long)elements[n-1].value + elements[n-2].value);`
    //
    // Goodness for this partition: `max_f_val - min_f_val`.
    //
    // This partition is optimal when h is large enough to make separating elements[0] from others beneficial.
    //
    // Let's calculate the goodness for this specific partition:
    // elements[0] in group 1, elements[1]...elements[n-1] in group 2.
    long long min_f_val_case2;
    if (n == 2) { // Special case for n=2, only one pair (a_0, a_1)
        min_f_val_case2 = (long long)elements[0].value + elements[1].value + h;
    } else {
        min_f_val_case2 = std::min((long long)elements[0].value + elements[1].value + h, (long long)elements[1].value + elements[2].value);
    }

    long long max_f_val_case2 = std::max((long long)elements[0].value + elements[n - 1].value + h, (long long)elements[n - 1].value + elements[n - 2].value);

    long long goodness2 = max_f_val_case2 - min_f_val_case2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[elements[i].original_index] = 2;
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

