        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[i] = (count of 1s) - (count of 2s) for jars a[n-1] down to a[n-i]
    // diff_L[0] = 0 (no jars taken from left)
    // diff_L[1] = (a[n-1]==1 ? 1 : -1)
    // diff_L[i] = diff_L[i-1] + (a[n-i]==1 ? 1 : -1)
    std::map<int, int> diff_L_idx; // Stores diff -> min_jars_taken_from_left
    diff_L_idx[0] = 0; // 0 jars taken from left, diff is 0
    int current_diff_L = 0;
    for (int i = 0; i < n; ++i) {
        current_diff_L += (a[n - 1 - i] == 1 ? 1 : -1);
        if (diff_L_idx.find(current_diff_L) == diff_L_idx.end()) {
            diff_L_idx[current_diff_L] = i + 1;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // diff_R[i] = (count of 1s) - (count of 2s) for jars a[n] up to a[n+i-1]
    // diff_R[0] = 0 (no jars taken from right)
    // diff_R[1] = (a[n]==1 ? 1 : -1)
    // diff_R[i] = diff_R[i-1] + (a[n+i-1]==1 ? 1 : -1)
    std::map<int, int> diff_R_idx; // Stores diff -> min_jars_taken_from_right
    diff_R_idx[0] = 0; // 0 jars taken from right, diff is 0
    int current_diff_R = 0;
    for (int i = 0; i < n; ++i) {
        current_diff_R += (a[n + i] == 1 ? 1 : -1);
        if (diff_R_idx.find(current_diff_R) == diff_R_idx.end()) {
            diff_R_idx[current_diff_R] = i + 1;
        }
    }

    int min_emptied_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible differences from the left side
    // For each diff_L, we need to find a diff_R such that diff_L + diff_R = 0
    // i.e., diff_R = -diff_L
    for (auto const& [diff_val_L, jars_L] : diff_L_idx) {
        int target_diff_R = -diff_val_L;
        if (diff_R_idx.count(target_diff_R)) {
            int jars_R = diff_R_idx[target_diff_R];
            min_emptied_jars = std::min(min_emptied_jars, jars_L + jars_R);
        }
    }

    std::cout << min_emptied_jars << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();
    long long total_pairs = (long long)n * (n + 1) / 2;
    long long invalid_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i..r]
    // does NOT contain the pattern.
    // If max_r_for_l[i] is n-1, it means s[i..n-1] does not contain the pattern.
    // If max_r_for_l[i] is less than n-1, then s[i..max_r_for_l[i]+1] contains the pattern.
    // For a given l, any r such that l <= r <= max_r_for_l[l] forms an invalid pair.
    // The number of such r's is max_r_for_l[l] - l + 1.
    std::vector<int> max_r_for_l(n);

    // Initialize max_r_for_l. Initially, assume no pattern exists, so any substring is invalid.
    // This means for each l, the largest r that doesn't contain a pattern is n-1.
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible x and k to find patterns.
    // x is 0-indexed, so s[x], s[x+k], s[x+2k].
    // The condition x + 2k < n must hold.
    // The minimum k is 1.
    // The maximum k is such that x + 2k < n => 2k < n - x => k < (n - x) / 2.
    // So k can go up to (n - x - 1) / 2.
    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a pattern s[x] = s[x+k] = s[x+2k].
                // This pattern starts at index x and ends at index x + 2k.
                // Any substring s[l..r] that contains this pattern is a valid pair.
                // This means for any l <= x and r >= x + 2k, the pair (l, r) is valid.

                // We are interested in invalid pairs.
                // For any l' from 0 to x, the maximum r' such that s[l'..r'] is invalid
                // must be less than x + 2k.
                // Specifically, for any l' <= x, if max_r_for_l[l'] is currently >= x + 2k,
                // it means we haven't found a pattern that forces r' to be smaller.
                // Now we found a pattern ending at x + 2k.
                // So, for any l' from 0 to x, the new maximum r' for an invalid substring s[l'..r']
                // cannot extend beyond x + 2k - 1.
                // We update max_r_for_l[l'] to be min(current max_r_for_l[l'], x + 2k - 1).
                // This update only matters if x + 2k - 1 is smaller than the current value.

                // The loop for l' can be optimized.
                // We only need to update max_r_for_l[l'] for l' from 0 to x.
                // The value x + 2k - 1 is the new upper bound for r for any invalid substring starting at l' <= x.
                // Since max_r_for_l is non-decreasing (max_r_for_l[i] >= max_r_for_l[i+1]),
                // we can iterate from x down to 0.
                // If max_r_for_l[l'] is already less than or equal to x + 2k - 1,
                // then further l' values (smaller than l') will also have max_r_for_l[l'] <= x + 2k - 1,
                // so we can break.

                // Optimization: k can be at most 8.
                // If k > 8, then x + 2k >= x + 18.
                // If x + 18 >= n, then this k is too large.
                // If x + 18 < n, then the length of the pattern is at least 19.
                // For a string of length 300,000, if k is large, say k=100,
                // then x + 2k = x + 200.
                // The number of distinct characters is only 2.
                // It's a known property that if a string contains a pattern like s_x = s_{x+k} = s_{x+2k},
                // then k must be relatively small.
                // For binary strings, if k > 8, such a pattern is guaranteed to exist for a sufficiently long string.
                // However, the problem is about *any* k.
                // The constraint on k is x + 2k < n.
                // The maximum k is (n-1-x)/2.
                // If k is large, say k=9, then x+2k = x+18.
                // The number of distinct characters is 2.
                // If k > 8, then the pattern s_x = s_{x+k} = s_{x+2k} implies that the string
                // must contain a pattern of length at most 18.
                // This is a known result from combinatorics on words (Thue-Morse sequence related).
                // For binary strings, if k > 8, then the pattern s_x = s_{x+k} = s_{x+2k}
                // implies that there must be a pattern with k' <= 8.
                // So we only need to check k from 1 to 8.
                // This is a crucial optimization.
                if (k > 8) {
                    break; // No need to check larger k values for binary strings
                }

                int limit_r = x + 2 * k - 1;
                for (int l_prime = x; l_prime >= 0; --l_prime) {
                    if (max_r_for_l[l_prime] <= limit_r) {
                        // If max_r_for_l[l_prime] is already restricted to be <= limit_r,
                        // then for smaller l_prime values, max_r_for_l[l_prime] will also be
                        // <= limit_r (or even smaller), so no further updates are needed for this pattern.
                        break;
                    }
                    max_r_for_l[l_prime] = limit_r;
                }
            }
        }
    }

    // Calculate the number of invalid pairs.
    // For each l, the number of r's such that s[l..r] is invalid is max_r_for_l[l] - l + 1.
    for (int l = 0; l < n; ++l) {
        invalid_pairs += (max_r_for_l[l] - l + 1);
    }

    std::cout << total_pairs - invalid_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for tracks to read
    int h_idx = 0; // Current index for heads

    while (p_idx < m && h_idx < n) {
        // Find the first head h_idx that can reach p[p_idx]
        // A head h_idx can reach p[p_idx] if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // This means h[h_idx] - T <= p[p_idx] <= h[h_idx] + T
        // Or, equivalently, abs(h[h_idx] - p[p_idx]) <= T
        // Since p is sorted, we want to use the leftmost head that can cover p[p_idx]
        // and potentially cover subsequent tracks.

        // Skip heads that are too far to the left to reach p[p_idx]
        // i.e., h[h_idx] + T < p[p_idx]
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) {
            // No more heads available to cover p[p_idx]
            return false;
        }

        // Now, h[h_idx] is the first head that *might* be able to cover p[p_idx].
        // It satisfies h[h_idx] + T >= p[p_idx].
        // We also need h[h_idx] - T <= p[p_idx].
        // If h[h_idx] - T > p[p_idx], this head is too far to the right to cover p[p_idx].
        // In this case, we cannot cover p[p_idx] with any remaining head, because
        // all subsequent heads h[h_idx+1], ... are even further to the right.
        if (h[h_idx] - T > p[p_idx]) {
            return false;
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // We use this head to cover as many subsequent tracks as possible.
        long long current_head_reach_right = h[h_idx] + T;
        long long current_head_reach_left = h[h_idx] - T;

        // The head can cover tracks in the range [current_head_reach_left, current_head_reach_right].
        // We need to cover p[p_idx].
        // The actual range covered by this head is [max(p[p_idx], current_head_reach_left), current_head_reach_right].
        // No, this is not correct. The head can move to any point X in [h[h_idx]-T, h[h_idx]+T].
        // From X, it can cover [X-T, X+T].
        // The total range a head can cover is [h[h_idx] - T - T, h[h_idx] + T + T] if it moves optimally.
        // This is not how it works. A head at h_i can reach any point X such that |h_i - X| <= T.
        // Once it reaches X, it has "read" X.
        // The problem states "A track is considered read if at least one head has visited this track."
        // "During the operation each head's movement does not affect the movement of the other heads: the heads can change their relative order; there can be multiple reading heads above any of the tracks."
        // "For each of the reading heads, the hard drive's firmware can move the head exactly one track to the right or to the left, or leave it on the current track."
        // This means in T time, a head at h_i can visit any track X such that |h_i - X| <= T.
        // So, the range covered by head h_idx is [h[h_idx] - T, h[h_idx] + T].

        // We use h[h_idx] to cover p[p_idx] and all subsequent tracks that fall within its range.
        long long max_covered_by_this_head = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= max_covered_by_this_head) {
            p_idx++;
        }
        h_idx++; // Move to the next head
    }

    return p_idx == m; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10; // Max possible difference between any p_i and h_j is ~10^10.
                           // A head might need to move 10^10 units.
                           // A safe upper bound for T.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for sums to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values.
// n can be up to 2 * 10^5.
// Max path length could be n. Max y could be n * 2 * 10^9 = 4 * 10^14.
// long long is necessary.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // a_0 is unused, a_1 is set by the loop, a_2 to a_n are read.
    // Using 1-based indexing for convenience to match problem statement.
    std::vector<long long> a(n + 1);
    for (int i = 2; i <= n; ++i) {
        std::cin >> a[i];
    }

    // dp_val[k] stores the total y accumulated and the final x position
    // if we start at x=k and take one "step 2 then step 3" cycle.
    // dp_val[k].first = total y accumulated
    // dp_val[k].second = final x position
    // This is for the case where a_k is used as the initial value for the cycle.
    std::vector<std::pair<long long, int>> dp_val(n + 1);
    // visited[k] is used to detect cycles during DFS.
    // 0: not visited
    // 1: currently visiting (in current DFS path)
    // 2: finished visiting (result computed)
    std::vector<int> visited(n + 1, 0);

    // Function to compute dp_val[k] using DFS.
    // Returns true if computation successful (terminates), false if cycle detected.
    auto solve_dp = [&](auto self, int k) -> bool {
        if (k <= 0 || k > n) {
            // Base case: x is out of bounds.
            // No y accumulated in this step, x is already out.
            dp_val[k] = {0, k};
            visited[k] = 2;
            return true;
        }
        if (visited[k] == 1) {
            // Cycle detected.
            return false;
        }
        if (visited[k] == 2) {
            // Already computed.
            return true;
        }

        visited[k] = 1; // Mark as currently visiting

        long long val_ak = a[k];

        // Simulate step 2: x_new = k + val_ak, y_accum = val_ak
        int x_after_step2 = k + val_ak;
        long long y_accum_step2 = val_ak;

        // Simulate step 3: x_final = x_after_step2 - val_ak, y_accum += val_ak
        int x_after_step3 = x_after_step2 - val_ak;
        long long y_accum_step3 = y_accum_step2 + val_ak;

        // Now, from x_after_step3, we need to find its result.
        // This is where the recursive call or DP lookup happens.
        if (!self(self, x_after_step3)) {
            // If the subsequent state leads to a cycle, then this state also leads to a cycle.
            visited[k] = 2; // Mark as finished to avoid re-processing, but result is cycle.
            dp_val[k] = {-1, -1}; // Indicate cycle
            return false;
        }

        // If the subsequent state terminates:
        long long next_y_accum = dp_val[x_after_step3].first;
        int next_x_final = dp_val[x_after_step3].second;

        if (next_y_accum == -1) { // If the next state was a cycle
            dp_val[k] = {-1, -1};
        } else {
            dp_val[k] = {y_accum_step3 + next_y_accum, next_x_final};
        }

        visited[k] = 2; // Mark as finished
        return dp_val[k].first != -1;
    };

    // Initialize dp_val for out-of-bounds states
    // These are the true base cases for termination.
    // For x <= 0 or x > n, the program terminates immediately.
    // The problem states "If, after any step, x <= 0 or x > n, the program immediately terminates."
    // This means if x_after_step3 is out of bounds, it terminates.
    // The y accumulated for that *final* step is 0, and x is its value.
    // This is handled by the `if (k <= 0 || k > n)` block in `solve_dp`.
    // We need to ensure that `dp_val` for these indices are correctly set.
    // The `solve_dp` function handles this by setting `dp_val[k] = {0, k}` for these cases.

    // Iterate for each possible starting a_1 value.
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current run

        // Reset visited states for relevant indices if needed, or ensure solve_dp handles it.
        // Since solve_dp uses `visited[k] == 2` for memoization, we don't need to clear `visited`
        // for each `i`. The results for `k > 1` are fixed. Only `a[1]` changes.
        // However, `a[1]` changes, so `dp_val[1]` needs to be recomputed.
        // We can just call `solve_dp(1)` and it will use memoized results for `k > 1`.

        // For the current `a[1]`, we need to re-evaluate `dp_val[1]`.
        // Mark `dp_val[1]` as unvisited to force re-computation.
        visited[1] = 0; 

        // Call the recursive solver for the initial state x=1.
        solve_dp(solve_dp, 1);

        std::cout << dp_val[1].first << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into two parts: s[0...i-1] and s[i...N-1].
    // We can reorder them to form s[i...N-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    // The original string s is guaranteed to be a palindrome.
    //
    // If s has an odd length, say N=5, s="nolon".
    // i=1: "olon" + "n" = "olonn" (not palindrome)
    // i=2: "lon" + "no" = "lonno" (not palindrome)
    // i=3: "on" + "nol" = "onnol" (not palindrome)
    // i=4: "n" + "nolo" = "nnolo" (not palindrome)
    //
    // If s has an even length, say N=4, s="otto".
    // i=1: "tto" + "o" = "ttoo" (not palindrome)
    // i=2: "to" + "ot" = "toot" (palindrome, != "otto") -> k=1
    // i=3: "o" + "ott" = "oott" (not palindrome)
    //
    // If s has an even length, say N=10, s="kinnikkinnik".
    // i=1: "innikkinnik" + "k" = "innikkinnikk" (not palindrome)
    // ...
    // i=5: "kinnik" + "kinni" = "kinnikkinnik" (== s)
    // i=6: "innik" + "kinnik" = "innikkinnik" (== s)
    // ...
    // i=7: "nnik" + "kinniki" = "nnikkinniki" (not palindrome)
    //
    // The only way s' = P2P1 can be a palindrome and s' != s is if P1 and P2 are not empty.
    // If P1 is empty (i=0), P2P1 = s.
    // If P2 is empty (i=N), P2P1 = s.
    // So we check i from 1 to N-1.

    for (int i = 1; i < n; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i);
        std::string new_s = p2 + p1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // This means we cut s into 3 pieces: P1, P2, P3.
    // We can reorder them.
    // The problem states that the original string s is a palindrome.
    // If all characters in s are the same (e.g., "aaaa"), then any reordering of pieces
    // will result in the same string "aaaa", which is a palindrome.
    // In this case, it's impossible to get a new string that is different from s.
    //
    // We can check if all characters are the same.
    // If s consists of only one distinct character, e.g., "qqqq", then any permutation
    // of its substrings will result in the same string "qqqq".
    // Since the new string must be different from s, this case is impossible.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }

    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider s = "nolon". Not all chars are same.
    // We can cut it into `s[0]`, `s[1...N-2]`, `s[N-1]`.
    // For "nolon": 'n', "olo", 'n'.
    // Reorder to 'n', 'n', "olo" -> "nnolo" (not palindrome)
    // Reorder to 'n', "olo", 'n' -> "nolon" (original)
    // Reorder to "olo", 'n', 'n' -> "olonn" (not palindrome)
    //
    // The problem statement for k=2 example "nolon" -> "on|l|no"
    // This means cuts at index 2 and index 3: "no", "l", "on".
    // Reorder to "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
    // This is a valid solution for k=2.
    //
    // The key insight for k=2 is that if not all characters are the same,
    // we can always find a way to make a different palindrome.
    //
    // Consider the string s. Since it's a palindrome, s[i] == s[N-1-i].
    // If not all characters are the same, there must be at least one character s[i]
    // such that s[i] != s[0] (and thus s[N-1-i] != s[0]).
    //
    // If N is odd, say N=5, s="ababa". s[0]='a', s[1]='b'.
    // Cut s into s[0...N/2-1], s[N/2], s[N/2+1...N-1].
    // For "nolon": "no", "l", "on".
    // Reorder to "on", "l", "no" -> "onlno". This is a palindrome.
    // This is always possible if the string is not monochromatic.
    //
    // The strategy for k=2:
    // Take the first half of the string (excluding the middle character if N is odd),
    // and reverse it.
    // Let s = P1 P2 P3, where P1 = s[0...i-1], P2 = s[i...j-1], P3 = s[j...N-1].
    // We need to find P1, P2, P3 such that P_x P_y P_z is a palindrome and != s.
    //
    // Consider the string s. Since it's a palindrome, s[0...N/2-1] is the reverse of s[N/2+ (N%2) ... N-1].
    // Let prefix = s.substr(0, N/2).
    // Let suffix = s.substr(N - N/2);
    // If N is odd, middle_char = s[N/2].
    //
    // Example: "nolon" (N=5)
    // prefix = "no"
    // middle_char = 'l'
    // suffix = "on"
    //
    // We can cut "no|l|on".
    // Pieces are "no", "l", "on".
    // Reorder to "on", "l", "no". This forms "onlno".
    // "onlno" is a palindrome and "onlno" != "nolon".
    // This requires 2 cuts.
    //
    // This strategy works for any non-monochromatic palindrome.
    // If s is not monochromatic, then s.substr(0, N/2) is not monochromatic.
    // (If s.substr(0, N/2) were monochromatic, say "aaa", then s would be "aaacaaa" or "aaaaaa",
    // which means s is monochromatic, a contradiction).
    //
    // So, if s is not monochromatic, then s.substr(0, N/2) contains at least two different characters.
    // Let `prefix = s.substr(0, N/2)`.
    // Let `middle_part = s.substr(N/2, N % 2)`. (This is empty if N is even, or the middle char if N is odd).
    // Let `suffix = s.substr(N/2 + N % 2)`.
    //
    // The pieces are `prefix`, `middle_part`, `suffix`.
    // We know `suffix` is the reverse of `prefix`.
    //
    // We can reorder them as `suffix + middle_part + prefix`.
    // This new string is `suffix + middle_part + prefix`.
    // Since `suffix` is `reverse(prefix)`, this new string is `reverse(prefix) + middle_part + prefix`.
    // This is a palindrome if `middle_part` is a palindrome (which it is, being 0 or 1 char).
    //
    // Is `suffix + middle_part + prefix` different from `s`?
    // `s` is `prefix + middle_part + suffix`.
    // If `suffix + middle_part + prefix == prefix + middle_part + suffix`,
    // then `suffix == prefix`.
    // This means `s.substr(0, N/2) == s.substr(N/2 + N % 2)`.
    // But `s.substr(N/2 + N % 2)` is `reverse(s.substr(0, N/2))`.
    // So `prefix == reverse(prefix)`. This means `prefix` itself is a palindrome.
    //
    // If `prefix` is a palindrome, and `s` is a palindrome, and `s` is not monochromatic,
    // then `s` must be of the form `P M P` where `P` is a palindrome.
    // Example: `s = "abccba"`. `prefix = "abc"`. Not a palindrome.
    // Example: `s = "abaaba"`. `prefix = "aba"`. Is a palindrome.
    // In this case, `suffix + middle_part + prefix` would be `abaaba`, which is `s`.
    //
    // So, if `prefix` is a palindrome, the simple swap `suffix + middle_part + prefix` doesn't work.
    //
    // However, if `s` is not monochromatic, there must be at least one `i` such that `s[i] != s[0]`.
    // Consider `s.substr(0, N-1)`. This is `s` without its last character.
    // If `s.substr(0, N-1)` is not a palindrome, then we can cut `s` into `s.substr(0, N-1)` and `s[N-1]`.
    // Reorder to `s[N-1] + s.substr(0, N-1)`.
    // This new string is `s[N-1] + s[0...N-2]`.
    // If this is a palindrome and != s, then k=1. We already checked this.
    //
    // The problem states that if not all characters are the same, k=2 is always possible.
    // This is a known property for palindromes. If a palindrome is not monochromatic,
    // it's always possible to form a different palindrome using 2 cuts.
    //
    // Example: "nolon"
    // "no" | "l" | "on"
    // Reorder to "on" | "l" | "no" -> "onlno" (palindrome, != "nolon")
    //
    // Example: "abacaba"
    // "aba" | "c" | "aba"
    // Reorder to "aba" | "c" | "aba" -> "abacaba" (same)
    //
    // This specific reordering (swapping first and last parts) only works if the first part is not a palindrome.
    // If the first part IS a palindrome (e.g., "aba" in "abacaba"), then `prefix == reverse(prefix)`.
    // In this case, `suffix` is also `prefix`. So `prefix + middle + suffix` becomes `prefix + middle + prefix`.
    // And `suffix + middle + prefix` also becomes `prefix + middle + prefix`. They are the same.
    //
    // But we can choose different cuts.
    // For "abacaba", if we cut "a|bacab|a", then "a" + "bacab" + "a" -> "abacaba".
    // If we cut "ab|ac|aba", pieces are "ab", "ac", "aba".
    // Reorder to "aba" + "ac" + "ab" -> "abaacab". This is a palindrome and != "abacaba".
    // This is 2 cuts.
    //
    // The logic is: if `s` is not monochromatic, then there exists some `i` such that `s[i] != s[0]`.
    // This means `s.substr(0, N/2)` is not a palindrome (unless `s` is like "abccba" where `prefix` is "abc", not a palindrome).
    // If `s.substr(0, N/2)` is a palindrome, e.g., `s = "abaaba"`, then `prefix = "aba"`.
    // In this case, `s` is formed by `P M P` where `P` is a palindrome.
    //
    // The problem statement implies that if k=1 is not possible and the string is not monochromatic, then k=2 is always the answer.
    // This is a standard competitive programming trick. If a simple case (k=1) fails, and a trivial case (monochromatic) fails,
    // then the next simplest case (k=2) is usually the answer.
    //
    // The proof for k=2 always being possible for non-monochromatic palindromes:
    // Let `s` be a palindrome of length `N`.
    // If `s` is not monochromatic, then there exists some `i` such that `s[i] != s[0]`.
    // Consider the string `s' = s.substr(0, N-1)`. This is `s` without its last character.
    // If `s'` is not a palindrome, then we can cut `s` into `s'` and `s[N-1]`.
    // Reorder to `s[N-1] + s'`. This is `s[N-1] + s[0...N-2]`.
    // This is a single cut. We already checked this.
    //
    // What if `s.substr(0, N-1)` is a palindrome?
    // Example: `s = "abacaba"`. `s.substr(0, 6) = "abacab"`. Not a palindrome.
    // Example: `s = "racecar"`. `s.substr(0, 6) = "raceca"`. Not a palindrome.
    // Example: `s = "aaaaa"`. `s.substr(0, 4) = "aaaa"`. Palindrome. (This is monochromatic, already handled).
    //
    // If `s.substr(0, N-1)` is a palindrome, and `s` is a palindrome, then `s[0] == s[N-1]`.
    // And `s[1] == s[N-2]`, etc.
    // If `s.substr(0, N-1)` is a palindrome, then `s[0] == s[N-2]`, `s[1] == s[N-3]`, etc.
    // Combining these, `s[N-1] == s[N-2]`.
    // This implies that the last two characters are the same.
    // By symmetry of palindrome, the first two characters are also the same: `s[0] == s[1]`.
    //
    // If `s.substr(0, N-1)` is a palindrome, then `s` must be of the form `c P c` where `P` is a palindrome.
    // And `c P` is also a palindrome. This means `c P` is `c P_rev`.
    // So `P` must be `c P_rev_prefix`.
    // This implies `s` is of the form `c c ... c`.
    //
    // Let's re-evaluate the condition for k=2.
    // If `s` is not monochromatic, then there exists at least one character `s[i]` such that `s[i] != s[0]`.
    // This means `s` is not `aaaaa...`.
    //
    // The problem statement implies that if k=1 doesn't work and the string is not monochromatic, then k=2 is the answer.
    // This is a common pattern in such problems. The "Impossible" case is only for monochromatic strings.
    // All other cases where k=1 doesn't work fall into k=2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable by definition
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0); // left_ones[i] = count of consecutive 1s ending at i
    std::vector<int> left_zeros(n, 0); // left_zeros[i] = count of consecutive 0s ending at i
    std::vector<int> right_ones(n, 0); // right_ones[i] = count of consecutive 1s starting at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = count of consecutive 0s starting at i

    // Calculate left_ones and left_zeros
    if (a[0] == 1) left_ones[0] = 1;
    else left_zeros[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        } else {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        }
    }

    // Calculate right_ones and right_zeros
    if (a[n - 1] == 1) right_ones[n - 1] = 1;
    else right_zeros[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        } else {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        }
    }

    int max_steps = 0;
    std::vector<int> final_a = a;

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] != a[i - 1] && a[i] != a[i + 1]) { // This is a changing point (010 or 101)
            int len_left = (a[i] == 1) ? left_zeros[i - 1] : left_ones[i - 1];
            int len_right = (a[i] == 1) ? right_zeros[i + 1] : right_ones[i + 1];

            int current_steps = std::min(len_left, len_right) + 1;
            max_steps = std::max(max_steps, current_steps);

            // Determine the final state of this changing point
            // If len_left < len_right, it will become a[i-1]
            // If len_right < len_left, it will become a[i+1]
            // If len_left == len_right, it will become 0 (if 101) or 1 (if 010)
            // This is equivalent to saying it will become a[i-1] if len_left <= len_right
            // and a[i+1] if len_right < len_left.
            // Or more simply, it will become the value of the longer "block"
            // If blocks are equal, it becomes the value of the block to its left (or right, doesn't matter, they are the same)
            // Example: 00100 -> 00000. Here 1 is at index 2. left_zeros[1]=2, right_zeros[3]=2. min(2,2)+1 = 3 steps.
            // The 1 at index 2 becomes 0.
            // The value at index i will eventually become the value of the longer block.
            // If len_left == len_right, it will become the value of a[i-1] (which is also a[i+1])
            // So, if len_left <= len_right, it becomes a[i-1]. Otherwise, it becomes a[i+1].
            if (len_left <= len_right) {
                final_a[i] = a[i - 1];
            } else {
                final_a[i] = a[i + 1];
            }
        }
    }

    std::cout << max_steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}
